// ─── Permission helper ────────────────────────────────────────────────────────
// Usage: perm(user, "rfi", "edit")  perm(user, "delete")  perm(user, "finance", "view")
// Returns: "full" | "view" | "none"

var perm = function(user, feature, action) {
  if(!user) return "none";
  var r = user.role;
  var act = action || "full";

  // Admin gets everything
  if(r === ROLES.ADMIN) return "full";

  // Delete: admin only
  if(feature === "delete") return "none";

  var R = ROLES;

  var matrix = {
    // ── Jobs ──────────────────────────────────────────────────────────────
    jobs_edit:     [R.EXECUTIVE, R.PM],
    jobs_view:     [R.EXECUTIVE, R.ACCOUNTING, R.PM, R.PE, R.SUPER, R.FIELD, R.SUB, R.OWNER, R.ARCH],

    // ── Directory ─────────────────────────────────────────────────────────
    directory_edit: [R.EXECUTIVE, R.ACCOUNTING, R.PM, R.PE],
    directory_view: [R.EXECUTIVE, R.ACCOUNTING, R.PM, R.PE, R.SUPER, R.FIELD],

    // ── PreCon ────────────────────────────────────────────────────────────
    precon:        [R.EXECUTIVE, R.PM],

    // ── Contracts ─────────────────────────────────────────────────────────
    contract_full: [R.EXECUTIVE, R.PM],
    contract_view: [R.ACCOUNTING, R.PE, R.SUPER, R.OWNER],

    // ── Subcontracts ──────────────────────────────────────────────────────
    subcontract_full: [R.EXECUTIVE, R.ACCOUNTING, R.PM],
    subcontract_view: [R.PE, R.SUPER, R.FIELD, R.SUB],

    // ── Lien Waivers ──────────────────────────────────────────────────────
    lienwaiver_full: [R.EXECUTIVE, R.ACCOUNTING, R.PM],
    lienwaiver_view: [R.PE, R.SUPER, R.SUB],

    // ── Change Orders ─────────────────────────────────────────────────────
    co_full:       [R.EXECUTIVE, R.ACCOUNTING, R.PM],
    co_view:       [R.PE, R.SUPER, R.OWNER, R.SUB],

    // ── Budget ────────────────────────────────────────────────────────────
    budget_full:   [R.EXECUTIVE, R.ACCOUNTING, R.PM],
    budget_view:   [R.PE, R.SUPER],

    // ── Cost Entry / Financials ───────────────────────────────────────────
    costentry:     [R.EXECUTIVE, R.ACCOUNTING, R.PM],
    financials:    [R.EXECUTIVE, R.ACCOUNTING, R.PM],

    // ── Company Finance / WIP / Profit Fade ───────────────────────────────
    company_finance: [R.EXECUTIVE],
    profit_fade:     [R.EXECUTIVE],

    // ── Field tools ───────────────────────────────────────────────────────
    rfi:           [R.EXECUTIVE, R.PM, R.PE, R.SUPER, R.FIELD],
    rfi_view:      [R.ACCOUNTING, R.ARCH],
    submittal:     [R.EXECUTIVE, R.PM, R.PE, R.SUPER, R.FIELD],
    submittal_view:[R.ARCH],
    schedule_full: [R.EXECUTIVE, R.PM, R.PE, R.SUPER],
    schedule_view: [R.ACCOUNTING, R.FIELD, R.OWNER, R.ARCH],
    daily_log:     [R.EXECUTIVE, R.PM, R.PE, R.SUPER, R.FIELD],
    safety:        [R.EXECUTIVE, R.PM, R.PE, R.SUPER, R.FIELD],
    punch:         [R.EXECUTIVE, R.PM, R.PE, R.SUPER, R.FIELD],
    punch_view:    [R.ACCOUNTING, R.OWNER, R.ARCH],
    photos:        [R.EXECUTIVE, R.ACCOUNTING, R.PM, R.PE, R.SUPER, R.FIELD],
    meetings_full: [R.EXECUTIVE, R.PM, R.PE, R.SUPER],
    meetings_view: [R.ACCOUNTING, R.FIELD, R.OWNER, R.ARCH],
    inspections_full:[R.EXECUTIVE, R.PM, R.PE, R.SUPER],
    inspections_view:[R.ACCOUNTING, R.FIELD],
    closeout_full: [R.EXECUTIVE, R.PM],
    closeout_view: [R.PE, R.SUPER],

    // ── Timecards ─────────────────────────────────────────────────────────
    timecards_all:     [R.EXECUTIVE],
    timecards_project: [R.PM, R.PE, R.SUPER],
    timecards_own:     [R.ACCOUNTING, R.FIELD],

    // ── Library / Templates ───────────────────────────────────────────────
    master_docs_full:  [R.EXECUTIVE, R.PM],
    master_docs_view:  [R.PE, R.SUPER],
    template_upload:   [R.EXECUTIVE, R.PM],

    // ── Equipment ─────────────────────────────────────────────────────────
    equipment:     [R.EXECUTIVE, R.PM, R.PE, R.SUPER, R.FIELD],

    // ── Reports ───────────────────────────────────────────────────────────
    reports:       [R.EXECUTIVE, R.PM, R.PE, R.SUPER],
    social_media:  [R.EXECUTIVE, R.PM],
    company_reports:[R.EXECUTIVE],

    // ── Review portal ─────────────────────────────────────────────────────
    review_portal: [R.EXECUTIVE, R.PM, R.PE, R.SUPER, R.ARCH],
  };

  // Check the requested feature+action
  var key = feature + (act !== "full" ? "_"+act : "");
  var fullKey = feature + "_full";
  var viewKey = feature + "_view";

  if(matrix[key] && matrix[key].includes(r)) return "full";
  if(matrix[fullKey] && matrix[fullKey].includes(r)) return "full";
  if(matrix[viewKey] && matrix[viewKey].includes(r)) return "view";
  if(matrix[feature] && matrix[feature].includes(r)) return "full";

  // View fallbacks for view-only roles on specific features
  if(act === "view") {
    if(feature==="contract"   && matrix.contract_view.includes(r))    return "view";
    if(feature==="subcontract"&& matrix.subcontract_view.includes(r)) return "view";
    if(feature==="lienwaiver" && matrix.lienwaiver_view.includes(r))  return "view";
    if(feature==="co"         && matrix.co_view.includes(r))          return "view";
    if(feature==="budget"     && matrix.budget_view.includes(r))      return "view";
    if(feature==="rfi"        && matrix.rfi_view.includes(r))         return "view";
    if(feature==="submittal"  && matrix.submittal_view.includes(r))   return "view";
    if(feature==="schedule"   && matrix.schedule_view.includes(r))    return "view";
    if(feature==="punch"      && matrix.punch_view.includes(r))       return "view";
    if(feature==="meetings"   && matrix.meetings_view.includes(r))    return "view";
    if(feature==="inspections"&& matrix.inspections_view.includes(r)) return "view";
    if(feature==="closeout"   && matrix.closeout_view.includes(r))    return "view";
    if(feature==="master_docs"&& matrix.master_docs_view.includes(r)) return "view";
    if(feature==="directory"  && matrix.directory_view.includes(r))   return "view";
  }

  return "none";
};

// Shorthand helpers
var canView = function(user, feature) { var p=perm(user,feature,"view"); return p==="full"||p==="view"; };
var canEdit = function(user, feature) { return perm(user,feature)==="full"; };
var canDel  = function(user)          { return user&&user.role===ROLES.ADMIN; };

// Project access check — for non-admin, non-exec: only assigned projects
// Admin and Exec see all projects
var canAccessJob = function(user, jobId) {
  if(!user) return false;
  if(user.role===ROLES.ADMIN||user.role===ROLES.EXECUTIVE) return true;
  if(!user.projectIds||user.projectIds.length===0) return true; // not yet restricted
  return user.projectIds.includes(jobId);
};

// Sub-specific: can they see this subcontract?
var canAccessSubcontract = function(user, sc) {
  if(!user) return "none";
  if(user.role===ROLES.ADMIN||user.role===ROLES.EXECUTIVE||user.role===ROLES.ACCOUNTING||user.role===ROLES.PM) return "full";
  if(user.role===ROLES.PE||user.role===ROLES.SUPER||user.role===ROLES.FIELD) return "view";
  if(user.role===ROLES.SUB) return user.subId===sc.dirId ? "view" : "none";
  return "none";
};

// User management: Admin always, Executive also
var canManageUsers = function(user) {
  if(!user) return false;
  return user.role===ROLES.ADMIN || user.role===ROLES.EXECUTIVE;
};

// Timecard access
var canAccessTimecard = function(user, tc) {
  if(!user) return "none";
  if(user.role===ROLES.ADMIN||user.role===ROLES.EXECUTIVE) return "full";
  if(user.role===ROLES.PM||user.role===ROLES.PE||user.role===ROLES.SUPER) return "view";
  if(user.role===ROLES.FIELD) return tc.employeeId===user.id ? "full" : "none";
  return "none";
};

