const fmt=n=>n<0?"-$"+Math.abs(n).toLocaleString():"$"+n.toLocaleString();
const mc=p=>p>=22?"var(--green)":p>=15?"var(--yellow)":"var(--red)";
const parseHrs=h=>parseFloat(h)||0;
const fmtDate=d=>new Date(d+"T12:00:00").toLocaleDateString("en-US",{weekday:"short",month:"short",day:"numeric"});
const hasToday=(logs,jid)=>logs.some(l=>l.jobId===jid&&l.date===TODAY);
const insColor=d=>{if(!d)return"";const days=(new Date(d)-new Date(TODAY))/86400000;return days<0?"ins-exp":days<60?"ins-warn":"ins-ok";};
const insLabel=d=>{if(!d)return"-";const days=Math.round((new Date(d)-new Date(TODAY))/86400000);if(days<0)return"EXPIRED "+d;if(days<60)return d+" ("+days+"d)";return d;};
const uid=()=>"id_"+Date.now()+"_"+Math.random().toString(36).slice(2,6);
const readFile=file=>new Promise(res=>{const r=new FileReader();r.onload=e=>res(e.target.result);r.readAsDataURL(file);});
const addDays=(d,n)=>{const dt=new Date(d);dt.setDate(dt.getDate()+n);return dt.toISOString().split("T")[0];};
const daysDiff=d=>Math.round((new Date(d)-new Date(TODAY))/86400000);
const calcJob=j=>{
  const aO=j.ownerCOs.filter(c=>c.status==="Approved").reduce((s,c)=>s+c.amount,0);
  const pO=j.ownerCOs.filter(c=>c.status==="Pending").reduce((s,c)=>s+c.amount,0);
  const aS=j.subCOs.filter(c=>c.status==="Approved").reduce((s,c)=>s+c.amount,0);
  const cc=j.originalContract+aO,pc=j.originalCost+aS,pm=cc-pc;
  return{aO,pO,aS,cc,pc,pm,pmpct:cc>0?(pm/cc)*100:0};
};
const getEquipHealth=eq=>{
  if(eq.status==="maintenance")return{cls:"eq-health-out",label:"Maintenance",color:"var(--red)"};
  if(!eq.interval)return{cls:"eq-health-good",label:"Good",color:"var(--green)"};
  const base=eq.lastSvc||eq.purchased;
  if(!base)return{cls:"eq-health-warn",label:"Unknown",color:"var(--yellow)"};
  const due=addDays(base,Number(eq.interval));
  const d=daysDiff(due);
  if(d<0)return{cls:"eq-health-out",label:"Overdue "+Math.abs(d)+"d",color:"var(--red)"};
  if(d<=14)return{cls:"eq-health-warn",label:"Due "+d+"d",color:"var(--yellow)"};
  return{cls:"eq-health-good",label:"Good",color:"var(--green)"};
};

// --- EQUIPMENT SYNC HOOK -----------------------------------------------------
const useEquipSync=(trackerSite)=>{
  const[allEquip,setAllEquip]=useState([]);
  const[syncReady,setSyncReady]=useState(false);
  const[hasStorage,setHasStorage]=useState(true);

  useEffect(()=>{
    (async()=>{
      if(!window.storage){setHasStorage(false);setSyncReady(true);return;}
      try{
        const r=await window.storage.get(EQUIP_KEY);
        if(r&&r.value){const d=JSON.parse(r.value);setAllEquip(d.equip??[]);}
      }catch(e){
        // Key not found or parse error - storage is available, just no data yet
        console.log("Equipment tracker not yet initialized",e.message);
      }
      setSyncReady(true);
    })();
  },[]);

  const writeBack=async(updated)=>{
    setAllEquip(updated);
    if(!hasStorage)return;
    try{
      let cur={};
      try{const r=await window.storage.get(EQUIP_KEY);if(r&&r.value)cur=JSON.parse(r.value);}catch(e2){}
      await window.storage.set(EQUIP_KEY,JSON.stringify({...cur,equip:updated}));
    }catch(e){console.error("Equip sync write failed",e.message);}
  };

  const submitRequest=async(req)=>{
    if(!hasStorage)return;
    try{
      let existing=[];
      try{const r=await window.storage.get(REQ_KEY);if(r&&r.value)existing=JSON.parse(r.value);}catch(e2){}
      await window.storage.set(REQ_KEY,JSON.stringify([...existing,{...req,id:uid(),createdAt:TODAY}]));
    }catch(e){console.error("Request write failed",e.message);}
  };

  const onSiteEquip=trackerSite?allEquip.filter(e=>e.site===trackerSite&&e.status==="checked_out"):[];
  const availableEquip=allEquip.filter(e=>e.status==="available");
  return{allEquip,onSiteEquip,availableEquip,syncReady,hasStorage,writeBack,submitRequest};
};

