// --- PHOTO UPLOAD ------------------------------------------------------------
const PhotoUpload=({photos,onChange})=>{
  const inputRef=useRef();const[lb,setLb]=useState(null);
  const handleFiles=async e=>{
    const files=Array.from(e.target.files);
    const newP=await Promise.all(files.map(async f=>({id:uid(),base64:await readFile(f),mimeType:f.type,caption:""})));
    onChange(p=>[...p,...newP]);e.target.value="";
  };
  const update=(id,k,v)=>onChange(p=>p.map(x=>x.id===id?{...x,[k]:v}:x));
  const remove=id=>onChange(p=>p.filter(x=>x.id!==id));
  return(
    <div>
      {photos.length===0
        ?<div className="photo-upload-zone" onClick={()=>inputRef.current?.click()}>
            <div style={{fontSize:22,opacity:.5,marginBottom:6}}></div>
            <div style={{fontFamily:"'Barlow Condensed'",fontSize:12,letterSpacing:1,color:"var(--accent-bright)"}}>Upload Site Photos</div>
            <div style={{fontSize:11,color:"var(--muted)",marginTop:3}}>JPG, PNG   Multiple files OK</div>
          </div>
        :<div>
            <div className="photo-grid">
              {photos.map(p=>(
                <div key={p.id}>
                  <div className="photo-thumb-wrap">
                    <img src={p.base64} className="photo-thumb" style={{cursor:"pointer"}} onClick={()=>setLb(p.base64)}/>
                    <button className="photo-remove" onClick={()=>remove(p.id)}></button>
                  </div>
                  <input className="finput" style={{fontSize:11,padding:"3px 8px",marginTop:4}} value={p.caption} onChange={e=>update(p.id,"caption",e.target.value)} placeholder="Caption"/>
                </div>
              ))}
              <div style={{aspectRatio:"4/3",display:"flex",alignItems:"center",justifyContent:"center",border:"2px dashed var(--navy-border)",borderRadius:6,cursor:"pointer"}} onClick={()=>inputRef.current?.click()}>
                <div style={{textAlign:"center",color:"var(--muted)"}}><div style={{fontSize:18}}>+</div><div style={{fontSize:11,fontFamily:"'Barlow Condensed'",letterSpacing:1}}>Add More</div></div>
              </div>
            </div>
            <div style={{fontSize:11,color:"rgba(167,139,250,.7)",marginTop:8}}> Photos available for AI analysis after saving</div>
          </div>
      }
      <input ref={inputRef} type="file" accept="image/*" multiple style={{display:"none"}} onChange={handleFiles}/>
      {lb&&<Lightbox src={lb} onClose={()=>setLb(null)}/>}
    </div>
  );
};

