var buildSubcontractEmail = function(sc, dirEntry, job) {
  var pc = getPrimaryContact(dirEntry);
  var lines = [
    "WESTROE CONSTRUCTION | GC License #105268 | Charlotte, NC | 704-962-6507",
    "================================================================",
    "",
    "SUBCONTRACT AGREEMENT",
    "",
    "To: "+(pc?pc.name:"")+(dirEntry?" | "+dirEntry.company:""),
    "Project: "+(job?job.name+" ("+job.id+")":""),
    "Date: "+TODAY,
    "",
    "Please review and execute the attached subcontract agreement for the following scope:",
    "",
    "Trade: "+sc.trade,
    "Contract Value: "+fmt(sc.contractValue||0),
    "Status: "+sc.status,
    "",
    sc.description ? ("SCOPE SUMMARY:\n"+sc.description) : "",
    "",
    sc.scopeNotes ? ("NOTES:\n"+sc.scopeNotes) : "",
    "",
    "Please return an executed copy at your earliest convenience.",
    "If you have any questions, contact us at 704-962-6507.",
    "",
    "================================================================",
    "Westroe Construction | GC License #105268",
    "Charlotte, NC | 704-962-6507",
  ].filter(function(l){return l!==null&&l!==undefined;});
  return lines.join("\n");
};

var buildRfiEmail = function(rfi, job) {
  var lines = [
    "WESTROE CONSTRUCTION | GC License #105268 | Charlotte, NC | 704-962-6507",
    "================================================================",
    "",
    "REQUEST FOR INFORMATION",
    "",
    "RFI No.: "+(rfi.rfiNumber||rfi.id),
    "Project: "+(job?job.name+" ("+job.id+")":""),
    "Date Submitted: "+fmtDate(rfi.submittedDate||TODAY),
    "Response Required By: "+(rfi.requiredBy?fmtDate(rfi.requiredBy):"ASAP"),
    "Priority: "+(rfi.priority||"Normal"),
    "Assigned To: "+(rfi.assignedTo&&rfi.assignedTo.name?rfi.assignedTo.name:(rfi.assignedTo||"")),
    "",
    "QUESTION:",
    (rfi.question||rfi.title||""),
    "",
    rfi.drawingRef ? ("Drawing Reference: "+rfi.drawingRef) : "",
    rfi.specRef    ? ("Spec Section: "+rfi.specRef) : "",
    rfi.scheduleActivity ? ("Schedule Activity: "+rfi.scheduleActivity) : "",
    rfi.notes      ? ("\nNotes:\n"+rfi.notes) : "",
    "",
    "Please respond at your earliest convenience.",
    "Direct responses to 704-962-6507 or reply to this email.",
    "",
    "================================================================",
    "Westroe Construction | GC License #105268",
    "Charlotte, NC | 704-962-6507",
  ].filter(Boolean);
  return lines.join("\n");
};

var buildSubmittalEmail = function(sub, job) {
  var lines = [
    "WESTROE CONSTRUCTION | GC License #105268 | Charlotte, NC | 704-962-6507",
    "================================================================",
    "",
    "SUBMITTAL TRANSMITTAL",
    "",
    "Submittal No.: "+sub.number+" (Rev. "+sub.revision+")",
    "Project: "+(job?job.name+" ("+job.id+")":""),
    "Date: "+TODAY,
    "Submittal Type: "+sub.type,
    sub.specSection ? ("Spec Section: "+sub.specSection) : "",
    "Submitted By: "+(sub.submittedBy||sub.trade||""),
    "",
    "DESCRIPTION:",
    sub.title,
    sub.description ? ("\n"+sub.description) : "",
    "",
    (sub.drawingRefs&&sub.drawingRefs.length>0) ? ("Drawing References: "+sub.drawingRefs.join(", ")) : "",
    sub.requiredOnSite ? ("Required On Site: "+fmtDate(sub.requiredOnSite)) : "",
    "",
    "This submittal is transmitted for your review and approval.",
    "Please return with action noted at your earliest convenience.",
    "",
    sub.aiReviewDraft ? ("GC REVIEW COMMENTS:\n"+sub.aiReviewDraft+"\n") : "",
    "================================================================",
    "Westroe Construction | GC License #105268",
    "Charlotte, NC | 704-962-6507",
  ].filter(Boolean);
  return lines.join("\n");
};

