const TagPill = ({tag}) => {
  const cl = TAG_COLORS[tag] || TAG_COLORS["General"];
  return (
    <span style={{fontSize:10,fontFamily:"'Barlow Condensed'",letterSpacing:1,padding:"2px 7px",borderRadius:4,background:cl.bg,border:"1px solid "+cl.border,color:cl.text}}>
      {tag.toUpperCase()}
    </span>
  );
};

const MasterDocLibrary = ({docs, jobs, onAdd, onUpdate, onDelete, onPushToJob}) => {
  const [showAdd,   setShowAdd]   = useState(false);
  const [tagFilter, setTagFilter] = useState("all");
  const [showPush,  setShowPush]  = useState(null);
  const [f, setF] = useState({name:"",tag:"Contract",description:"",autoPush:false});
  const set = (k,v) => setF(p=>({...p,[k]:v}));
  const inputRefs = useRef({});
  const autoPushCt = docs.filter(d=>d.autoPush).length;
  const uploadedCt = docs.filter(d=>d.base64).length;
  const filtered   = docs.filter(d => tagFilter==="all" || d.tag===tagFilter);
  const grouped    = DOC_TAGS.map(tag=>({tag,items:filtered.filter(d=>d.tag===tag)})).filter(g=>g.items.length>0);

  const handleFileUpload = async (e, docId) => {
    const file = e.target.files[0];
    if(!file) return;
    const b64 = await readFile(file);
    const ext  = file.name.split(".").pop().toLowerCase();
    const ft   = ext==="pdf"?"pdf":ext==="docx"?"docx":"other";
    onUpdate({...docs.find(d=>d.id===docId), base64:b64, fileName:file.name, fileType:ft, uploadDate:TODAY, identifiedFields:null});
    e.target.value="";
  };

  return (
    <div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:16}}>
        {[
          {label:"Total Templates",     val:docs.length,                                    color:"var(--white)"},
          {label:"Files Uploaded",      val:uploadedCt,                                     color:"var(--accent-bright)"},
          {label:"Auto-Push",           val:autoPushCt,                                     color:"var(--green)"},
          {label:"Contract Templates",  val:docs.filter(d=>d.tag==="Contract").length,       color:"var(--accent-bright)"},
        ].map(s=>(
          <div key={s.label} className="stat-card">
            <div className="stat-label">{s.label}</div>
            <div className="stat-value" style={{fontSize:18,color:s.color}}>{s.val}</div>
          </div>
        ))}
      </div>

      <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:"11px 14px",marginBottom:16,fontSize:13,color:"var(--white)"}}>
        Upload templates once here. <strong style={{color:"var(--green)"}}>Auto-push</strong> docs go to every new project. Contract templates appear in the Contracts tab of every job automatically.
      </div>

      <div style={{display:"flex",gap:8,marginBottom:12,alignItems:"flex-end"}}>
        <div>
          <div className="flabel">Tag</div>
          <select className="fselect" value={tagFilter} onChange={e=>setTagFilter(e.target.value)}>
            <option value="all">All Tags</option>
            {DOC_TAGS.map(t=><option key={t}>{t}</option>)}
          </select>
        </div>
        <div style={{marginLeft:"auto"}}>
          <button className="btn btn-primary btn-sm" onClick={()=>setShowAdd(!showAdd)}>+ Add Template</button>
        </div>
      </div>

      {showAdd && (
        <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14,marginBottom:14,display:"flex",flexDirection:"column",gap:10}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 160px",gap:10}}>
            <div><div className="flabel">Template Name</div><input className="finput" value={f.name} onChange={e=>set("name",e.target.value)} placeholder="Document name..."/></div>
            <div><div className="flabel">Tag</div><select className="fselect" value={f.tag} onChange={e=>set("tag",e.target.value)}>{DOC_TAGS.map(t=><option key={t}>{t}</option>)}</select></div>
          </div>
          <div><div className="flabel">Description</div><input className="finput" value={f.description} onChange={e=>set("description",e.target.value)} placeholder="Brief description..."/></div>
          <label style={{display:"flex",alignItems:"center",gap:6,cursor:"pointer",fontSize:13,color:"var(--white)"}}>
            <input type="checkbox" checked={f.autoPush} onChange={e=>set("autoPush",e.target.checked)} style={{accentColor:"var(--accent)"}}/>
            Auto-push to new projects
          </label>
          <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
            <button className="btn btn-ghost btn-sm" onClick={()=>setShowAdd(false)}>Cancel</button>
            <button className="btn btn-primary btn-sm" onClick={()=>{
              if(!f.name.trim()) return;
              onAdd({...f,id:"mdl"+uid(),base64:null,fileName:"",fileType:"",identifiedFields:null,uploadDate:null});
              setShowAdd(false);
              setF({name:"",tag:"Contract",description:"",autoPull:false});
            }}>Add</button>
          </div>
        </div>
      )}

      {grouped.map(({tag,items})=>(
        <div key={tag} style={{marginBottom:18}}>
          <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:8,paddingBottom:4,borderBottom:"1px solid var(--navy-border)"}}>
            <TagPill tag={tag}/>
            <span style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:1.5,color:"var(--muted)"}}>{items.length} TEMPLATE{items.length!==1?"S":""}</span>
          </div>
          {items.map(doc=>(
            <div key={doc.id} style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:6,padding:"11px 14px",marginBottom:6}}>
              <div style={{display:"flex",alignItems:"flex-start",gap:12}}>
                <div style={{flex:1}}>
                  <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:2}}>
                    <span style={{fontSize:13,color:"var(--white)",fontWeight:600}}>{doc.name}</span>
                    {doc.autoPush && (
                      <span style={{fontSize:10,color:"var(--green)",fontFamily:"'Barlow Condensed'",letterSpacing:1,background:"rgba(52,211,153,.1)",border:"1px solid rgba(52,211,153,.2)",borderRadius:3,padding:"1px 6px"}}>AUTO-PUSH</span>
                    )}
                    {doc.base64 && (
                      <span style={{fontSize:10,color:"var(--accent-bright)",fontFamily:"'Barlow Condensed'",letterSpacing:1}}>{doc.fileType.toUpperCase()} UPLOADED</span>
                    )}
                  </div>
                  {doc.description && <div style={{fontSize:11,color:"var(--muted)"}}>{doc.description}</div>}
                  {doc.uploadDate && <div style={{fontSize:10,color:"var(--muted)",fontFamily:"'IBM Plex Mono',monospace",marginTop:2}}>Uploaded {fmtDate(doc.uploadDate)}</div>}
                </div>
                <div style={{display:"flex",gap:6,flexShrink:0,alignItems:"center",flexWrap:"wrap",justifyContent:"flex-end"}}>
                  <label style={{display:"flex",alignItems:"center",gap:4,cursor:"pointer",fontSize:11,color:"var(--muted)"}}>
                    <input type="checkbox" checked={!!doc.autoPush} onChange={e=>onUpdate({...doc,autoPush:e.target.checked})} style={{accentColor:"var(--accent)"}}/>
                    Auto-push
                  </label>
                  <button className="btn btn-ghost btn-sm" style={{fontSize:11}} onClick={()=>inputRefs.current[doc.id]&&inputRefs.current[doc.id].click()}>
                    {doc.base64?"Replace File":"Upload File"}
                  </button>
                  <input ref={el=>inputRefs.current[doc.id]=el} type="file" accept=".pdf,.docx" style={{display:"none"}} onChange={e=>handleFileUpload(e,doc.id)}/>
                  {doc.base64 && jobs.length > 0 && (
                    <button className="btn btn-ghost btn-sm" style={{fontSize:11,color:"var(--accent-bright)"}} onClick={()=>setShowPush(doc)}>
                      Push to Project
                    </button>
                  )}
                  <button className="btn btn-ghost btn-sm" style={{fontSize:11,color:"var(--red)"}} onClick={()=>onDelete(doc.id)}>x</button>
                </div>
              </div>
            </div>
          ))}
        </div>
      ))}

      {showPush && (
        <div className="overlay" onClick={()=>setShowPush(null)}>
          <div className="modal" onClick={e=>e.stopPropagation()} style={{maxWidth:400}}>
            <div className="modal-hdr">
              <div className="modal-title">Push to Project</div>
              <button className="btn btn-ghost btn-sm" onClick={()=>setShowPush(null)}>x</button>
            </div>
            <div className="modal-body">
              <div style={{fontSize:13,color:"var(--white)",marginBottom:12}}>Push <strong>{showPush.name}</strong> to:</div>
              {jobs.map(job=>(
                <button key={job.id} className="btn btn-ghost" style={{width:"100%",textAlign:"left",marginBottom:6,padding:"10px 14px",display:"flex",justifyContent:"space-between"}} onClick={()=>{onPushToJob(showPush,job.id);setShowPush(null);}}>
                  <span>{job.name}</span>
                  <span style={{fontSize:11,color:"var(--muted)"}}>{job.id}</span>
                </button>
              ))}
            </div>
            <div className="modal-ftr">
              <button className="btn btn-ghost" onClick={()=>setShowPush(null)}>Cancel</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};


// --- CONTRACT TOOL DATA -------------------------------------------------------
const CONTRACT_STATUSES = ["Draft","Final","Executed","Void"];

const initContractTemplates = [];
const initContractInstances = {};

// --- FIELD EXTRACTION & MAPPING -----------------------------------------------
const extractContractFields = async (fileBase64, fileType, job, directory) => {
  const content = [
    {type:"text", text:"You are a construction contract analyst for Westroe Construction.\nReview this contract template and identify every fill-in placeholder - blank lines, underscores, bracketed text like [OWNER NAME], ALL CAPS labels, or any field clearly expecting input.\n\nFor each placeholder found, return a JSON array:\n[{placeholder, context, suggestedMapping}]\n\nplaceholder: the exact text or a short label for the blank (e.g. '[OWNER NAME]', 'CONTRACTOR LICENSE #', '_____ days')\ncontext: 1 sentence describing what this field is\nsuggestedMapping: one of: owner_name, owner_address, contractor_name, contractor_address, contractor_license, contractor_phone, project_address, contract_value, start_date, finish_date, permit_number, lien_agent, architect_name, project_name, project_id, effective_date, scope_of_work, OTHER\n\nReturn ONLY valid JSON array. No markdown, no preamble."}
  ];
  if(fileType === "pdf" || fileType === "docx") {
    content.splice(0,0,{
      type:"document",
      source:{type:"base64", media_type: fileType==="pdf"?"application/pdf":"application/vnd.openxmlformats-officedocument.wordprocessingml.document", data:fileBase64}
    });
  }
  const res = await fetch("https://api.anthropic.com/v1/messages",{
    method:"POST",
    headers:{"Content-Type":"application/json"},
    body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:2000,messages:[{role:"user",content}]})
  });
  const data = await res.json();
  if(data.error) throw new Error(data.error.message);
  const raw = data.content.filter(b=>b.type==="text").map(b=>b.text).join("");
  const cleaned = raw.split("```json").join("").split("```").join("").trim();
  return JSON.parse(cleaned);
};

const buildAutoFill = (job, directory) => {
  const ownerEntry = directory.find(d => d.name === job.client || (d.contacts||[]).some(c=>c.name===job.client));
  const ownerAddr  = ownerEntry?.address || "";
  return {
    owner_name:        job.client || "",
    owner_address:     ownerAddr,
    contractor_name:   "Westroe Construction",
    contractor_address:"Charlotte, NC",
    contractor_license:"GC License #105268",
    contractor_phone:  "704-962-6507",
    project_address:   job.address    || "",
    contract_value:    job.originalContract ? "$"+job.originalContract.toLocaleString() : "",
    start_date:        job.startDate  ? fmtDate(job.startDate)  : "",
    finish_date:       job.finishDate ? fmtDate(job.finishDate) : "",
    permit_number:     job.permitNumber  || "",
    lien_agent:        job.lienAgentNumber || "",
    architect_name:    job.architect  || "",
    project_name:      job.name       || "",
    project_id:        job.id         || "",
    effective_date:    TODAY,
    scope_of_work:     "",
  };
};

// --- TEMPLATE MANAGER ---------------------------------------------------------
const TemplateManager = ({templates, onAdd, onDelete}) => {
  const [uploading, setUploading] = useState(false);
  const [uploadErr, setUploadErr] = useState(null);
  const inputRef = useRef();

  const handleUpload = async (e) => {
    const file = e.target.files[0];
    if(!file) return;
    setUploading(true); setUploadErr(null);
    try {
      const b64 = await readFile(file);
      const ext = file.name.split(".").pop().toLowerCase();
      const fileType = ext === "pdf" ? "pdf" : ext === "docx" ? "docx" : "other";
      onAdd({
        id:"ct"+uid(), name:file.name.replace(/\.[^.]+$/,""),
        fileName:file.name, fileType, base64:b64,
        uploadDate:TODAY, identifiedFields:null,
      });
    } catch(err) {
      setUploadErr("Upload failed: "+err.message);
    }
    setUploading(false);
    e.target.value="";
  };

  return (
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
        <div style={{fontSize:12,color:"var(--muted)"}}>Upload your existing contract templates. Westroe will extract and auto-fill fields when you create a contract for a project.</div>
        <button className="btn btn-primary btn-sm" onClick={()=>inputRef.current&&inputRef.current.click()} disabled={uploading}>
          {uploading?"Uploading...":"+ Upload Template"}
        </button>
        <input ref={inputRef} type="file" accept=".pdf,.docx" style={{display:"none"}} onChange={handleUpload}/>
      </div>
      {uploadErr && <div style={{fontSize:12,color:"var(--red)",marginBottom:8}}>{uploadErr}</div>}
      {templates.length===0 ? (
        <div className="empty" style={{padding:40}}>
          <div style={{fontSize:24,opacity:.3,marginBottom:8}}></div>
          <div style={{fontFamily:"'Barlow Condensed'",fontSize:13,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:6}}>No Templates Yet</div>
          <div style={{fontSize:12,color:"var(--muted)"}}>Upload a PDF or DOCX of your existing contract - Westroe will extract the fill-in fields automatically.</div>
        </div>
      ) : templates.map(t=>(
        <div key={t.id} style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:6,padding:"11px 14px",marginBottom:6,display:"flex",alignItems:"center",gap:12}}>
          <div style={{flex:1}}>
            <div style={{fontSize:13,color:"var(--white)",fontWeight:600,marginBottom:2}}>{t.name}</div>
            <div style={{fontSize:11,color:"var(--muted)"}}>
              {t.fileName}   {t.fileType.toUpperCase()}   Uploaded {fmtDate(t.uploadDate)}
              {t.identifiedFields && <span style={{color:"var(--green)",marginLeft:8}}>  {t.identifiedFields.length} fields identified</span>}
            </div>
          </div>
          <button className="btn btn-ghost btn-sm" style={{color:"var(--red)",fontSize:11}} onClick={()=>onDelete(t.id)}></button>
        </div>
      ))}
    </div>
  );
};

// --- CONTRACT FIELD MAPPING UI ------------------------------------------------
const FieldMappingPanel = ({fields, autoFill, overrides, onChange}) => {
  const LABELS = {
    owner_name:"Owner Name", owner_address:"Owner Address",
    contractor_name:"Contractor Name", contractor_address:"Contractor Address",
    contractor_license:"GC License #", contractor_phone:"Contractor Phone",
    project_address:"Project Address", contract_value:"Contract Value",
    start_date:"Start Date", finish_date:"Completion Date",
    permit_number:"Permit Number", lien_agent:"Lien Agent Number",
    architect_name:"Architect", project_name:"Project Name",
    project_id:"Project ID", effective_date:"Effective Date",
    scope_of_work:"Scope of Work", OTHER:"Other",
  };

  return (
    <div style={{display:"flex",flexDirection:"column",gap:8}}>
      {fields.map((f,i)=>{
        const auto = autoFill[f.suggestedMapping] || "";
        const val  = overrides[f.placeholder] !== undefined ? overrides[f.placeholder] : auto;
        const isFilled = !!val;
        return (
          <div key={i} style={{background:"var(--navy)",border:"1px solid "+(isFilled?"rgba(52,211,153,.2)":"rgba(251,191,36,.25)"),borderRadius:6,padding:"10px 12px"}}>
            <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:4}}>
              <span style={{width:8,height:8,borderRadius:"50%",background:isFilled?"var(--green)":"var(--yellow)",flexShrink:0,display:"inline-block"}}/>
              <span style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:11,color:"var(--accent-bright)"}}>{f.placeholder}</span>
              <span style={{fontSize:10,color:"var(--muted)",fontFamily:"'Barlow Condensed'",letterSpacing:.5,marginLeft:"auto"}}>{LABELS[f.suggestedMapping]||f.suggestedMapping}</span>
            </div>
            {f.context && <div style={{fontSize:11,color:"var(--muted)",marginBottom:6,marginLeft:16}}>{f.context}</div>}
            <input className="finput" value={val}
              onChange={e=>onChange({...overrides,[f.placeholder]:e.target.value})}
              placeholder={isFilled?"":"Enter value..."}
              style={{fontSize:12,background:isFilled?"rgba(52,211,153,.04)":"rgba(251,191,36,.04)"}}/>
            {auto && val===auto && (
              <div style={{fontSize:10,color:"var(--green)",marginTop:3,fontFamily:"'Barlow Condensed'",letterSpacing:.5}}> Auto-filled from project data</div>
            )}
          </div>
        );
      })}
    </div>
  );
};

// --- CONTRACT INSTANCE EDITOR -------------------------------------------------
const ContractEditor = ({instance, template, job, directory, onSave, onClose}) => {
  const [step, setStep]           = useState(instance ? "preview" : "fields");
  const [fields, setFields]       = useState(template?.identifiedFields || []);
  const [extracting, setExtracting] = useState(false);
  const [extractErr, setExtractErr] = useState(null);
  const autoFill = useMemo(() => buildAutoFill(job, directory), [job, directory]);
  const [overrides, setOverrides] = useState(instance ? instance.fieldValues : {});
  const [title, setTitle]         = useState(instance ? instance.title : (template?.name || "Contract"));
  const [notes, setNotes]         = useState(instance ? instance.notes : "");
  const [status, setStatus]       = useState(instance ? instance.status : "Draft");
  const [filledText, setFilledText] = useState(instance ? instance.filledText : "");
  const [generating, setGenerating] = useState(false);
  const [genErr, setGenErr]         = useState(null);
  const [copied, setCopied]         = useState(false);

  const unfilledCt = fields.filter(f=>{
    const val = overrides[f.placeholder] !== undefined ? overrides[f.placeholder] : autoFill[f.suggestedMapping] || "";
    return !val;
  }).length;

  const extractFields = async () => {
    if(!template) return;
    setExtracting(true); setExtractErr(null);
    try {
      const identified = await extractContractFields(template.base64, template.fileType, job, directory);
      setFields(identified);
    } catch(err) {
      setExtractErr("Extraction failed: "+err.message);
    }
    setExtracting(false);
  };

  const generatePreview = async () => {
    setGenerating(true); setGenErr(null);
    const fieldList = fields.map(f=>{
      const val = overrides[f.placeholder] !== undefined ? overrides[f.placeholder] : autoFill[f.suggestedMapping] || "[UNFILLED]";
      return f.placeholder+"  "+val;
    }).join("\n");

    const prompt = [
      "You are preparing a construction contract for Westroe Construction.",
      "Template: "+title,
      "Project: "+job.name+" ("+job.id+") - "+job.client,
      "",
      "Using the following field values, generate the complete filled contract text.",
      "Replace every placeholder with its value. Keep all original contract language intact.",
      "Format professionally with clear section breaks.",
      "",
      "FIELD VALUES:",
      fieldList,
      "",
      "If you do not have the original contract text, generate a professional construction contract",
      "for the scope described using these field values. Include all standard sections: parties,",
      "scope, contract sum, schedule, payment terms, change orders, dispute resolution, signatures.",
    ].join("\n");

    try {
      const msgContent = [];
      if(template && template.base64) {
        msgContent.push({
          type:"document",
          source:{
            type:"base64",
            media_type: template.fileType==="pdf"?"application/pdf":"application/vnd.openxmlformats-officedocument.wordprocessingml.document",
            data:template.base64
          }
        });
      }
      msgContent.push({type:"text",text:prompt});
      const res = await fetch("https://api.anthropic.com/v1/messages",{
        method:"POST",
        headers:{"Content-Type":"application/json"},
        body:JSON.stringify({
          model:"claude-sonnet-4-20250514",
          max_tokens:4000,
          system:"You are a construction contract specialist for Westroe Construction (GC License #105268), Charlotte NC. If the template does not already have a Westroe letterhead, begin the document with: WESTROE CONSTRUCTION | GC License #105268 | Charlotte, NC | 704-962-6507. Generate complete, professional contract language.",
          messages:[{role:"user",content:msgContent}]
        })
      });
      const data = await res.json();
      if(data.error) throw new Error(data.error.message);
      const text = data.content.filter(b=>b.type==="text").map(b=>b.text).join("");
      setFilledText(text);
      setStep("preview");
    } catch(err) {
      setGenErr("Generation failed: "+err.message);
    }
    setGenerating(false);
  };

  const copyText = () => {
    navigator.clipboard.writeText(filledText).then(()=>{
      setCopied(true);
      setTimeout(()=>setCopied(false),2000);
    });
  };

  const handleSave = () => {
    const fieldValues = {};
    fields.forEach(f=>{
      fieldValues[f.placeholder] = overrides[f.placeholder] !== undefined
        ? overrides[f.placeholder]
        : autoFill[f.suggestedMapping] || "";
    });
    onSave({
      id: instance ? instance.id : "ci"+uid(),
      jobId: job.id,
      templateId: template?.id || null,
      templateName: title,
      title, notes, status, fieldValues, filledText,
      createdDate: instance ? instance.createdDate : TODAY,
      lastModified: TODAY,
    });
    onClose();
  };

  return (
    <div className="overlay" onClick={onClose}>
      <div className="modal modal-wide" onClick={e=>e.stopPropagation()} style={{maxWidth:760,maxHeight:"90vh",display:"flex",flexDirection:"column"}}>
        <div className="modal-hdr">
          <div>
            <div className="modal-title">
              {step==="fields"?"Map Contract Fields":"Contract Preview"}
            </div>
            <div className="modal-sub">{job.name}   {template ? template.name : "No template"}</div>
          </div>
          <div style={{display:"flex",gap:8,alignItems:"center"}}>
            {step==="preview" && <button className="btn btn-ghost btn-sm" onClick={()=>setStep("fields")}> Fields</button>}
            <button className="btn btn-ghost btn-sm" onClick={onClose}>x</button>
          </div>
        </div>

        <div className="modal-body" style={{flex:1,overflowY:"auto"}}>
          {step==="fields" && (
            <div style={{display:"flex",flexDirection:"column",gap:12}}>
              <div className="frow">
                <div style={{flex:2}}><div className="flabel">Contract Title</div><input className="finput" value={title} onChange={e=>setTitle(e.target.value)}/></div>
                <div><div className="flabel">Status</div><select className="fselect" value={status} onChange={e=>setStatus(e.target.value)}>{CONTRACT_STATUSES.map(s=><option key={s}>{s}</option>)}</select></div>
              </div>
              <div><div className="flabel">Notes</div><input className="finput" value={notes} onChange={e=>setNotes(e.target.value)} placeholder="Version notes, amendments..."/></div>

              {!fields.length && template && (
                <div style={{textAlign:"center",padding:"24px 0"}}>
                  <div style={{fontSize:12,color:"var(--muted)",marginBottom:12}}>
                    Click below to have Claude read your template and identify all fill-in fields automatically.
                  </div>
                  {extractErr && <div style={{fontSize:12,color:"var(--red)",marginBottom:8}}>{extractErr}</div>}
                  <button className="btn btn-ai" onClick={extractFields} disabled={extracting}>
                    {extracting?"Extracting fields...":" Extract Fields from Template"}
                  </button>
                  {extracting && <div style={{marginTop:12}}><div className="spinner" style={{margin:"0 auto 6px"}}/><div style={{fontSize:11,color:"var(--muted)"}}>Reading template...</div></div>}
                </div>
              )}

              {fields.length > 0 && (
                <div>
                  <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}>
                    <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)"}}>
                      {fields.length} Fields   {fields.length-unfilledCt} auto-filled   {unfilledCt} need input
                    </div>
                    {unfilledCt===0 && <span style={{fontSize:12,color:"var(--green)",fontFamily:"'Barlow Condensed'",letterSpacing:1}}> All fields filled</span>}
                  </div>
                  <FieldMappingPanel fields={fields} autoFill={autoFill} overrides={overrides} onChange={setOverrides}/>
                </div>
              )}
            </div>
          )}

          {step==="preview" && (
            <div>
              {!filledText ? (
                <div style={{textAlign:"center",padding:"24px 0"}}>
                  {generating ? (
                    <div><div className="spinner" style={{margin:"0 auto 12px"}}/><div style={{fontSize:12,color:"var(--muted)"}}>Generating filled contract...</div></div>
                  ) : (
                    <div>
                      {genErr && <div style={{fontSize:12,color:"var(--red)",marginBottom:12}}>{genErr}</div>}
                      <button className="btn btn-ai" onClick={generatePreview}> Generate Filled Contract</button>
                    </div>
                  )}
                </div>
              ) : (
                <div>
                  <div style={{display:"flex",gap:8,marginBottom:12,alignItems:"center"}}>
                    <div style={{fontSize:12,color:"var(--muted)"}}>Review and edit below. Copy text to paste into Word, or ask Westroe to export as .docx.</div>
                    <button className="btn btn-ghost btn-sm" style={{marginLeft:"auto"}} onClick={copyText}>{copied?" Copied":"Copy Text"}</button>
                    <button className="btn btn-ghost btn-sm" onClick={generatePreview}>Re-generate</button>
                  </div>
                  <textarea
                    value={filledText}
                    onChange={e=>setFilledText(e.target.value)}
                    style={{
                      width:"100%",minHeight:460,background:"var(--navy)",
                      border:"1px solid var(--navy-border)",borderRadius:8,
                      padding:16,fontSize:12,color:"var(--white)",
                      lineHeight:1.8,fontFamily:"'IBM Plex Mono',monospace",
                      resize:"vertical",boxSizing:"border-box",
                    }}
                  />
                  <div style={{marginTop:10,padding:"10px 14px",background:"rgba(167,139,250,.06)",border:"1px solid rgba(167,139,250,.2)",borderRadius:6,fontSize:12,color:"var(--muted)"}}>
                    <span style={{color:"var(--purple)"}}> To export as a formatted Word document: </span>
                    upload your original contract template in this chat and ask to generate a .docx - Westroe will fill and format it using your exact template layout.
                  </div>
                </div>
              )}
            </div>
          )}
        </div>

        <div className="modal-ftr">
          <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
          {step==="fields" && fields.length > 0 && (
            <button className="btn btn-ghost" onClick={generatePreview} disabled={generating} style={{color:"var(--purple)"}}>
              {generating?"Generating...":" Preview Contract"}
            </button>
          )}
          <button className="btn btn-primary" onClick={handleSave}>Save Contract</button>
        </div>
      </div>
    </div>
  );
};

// --- CONTRACTS TAB ------------------------------------------------------------
const ContractsTab = ({job, directory, contracts, contractTemplates, onAddContract, onUpdateContract}) => {
  const [view, setView]           = useState("contracts");
  const [showEditor,     setShowEditor]     = useState(false);
  const [editInstance,   setEditInstance]   = useState(null);
  const [selTemplate,    setSelTemplate]    = useState(null);
  const [showUpload,     setShowUpload]     = useState(false);
  const [uploadName,     setUploadName]     = useState("");
  const [uploadStatus,   setUploadStatus]   = useState("Final");
  const [uploadFile,     setUploadFile]     = useState(null);
  const uploadRef = useRef();

  const jobContracts = contracts.filter(c=>c.jobId===job.id).sort((a,b)=>b.createdDate.localeCompare(a.createdDate));

  const openNew = () => {
    setEditInstance(null);
    setSelTemplate(contractTemplates[0]||null);
    setShowEditor(true);
  };

  const openEdit = (instance) => {
    setEditInstance(instance);
    setSelTemplate(contractTemplates.find(t=>t.id===instance.templateId)||null);
    setShowEditor(true);
  };

  const handleSave = (data) => {
    if(editInstance) {
      onUpdateContract(data);
    } else {
      onAddContract(data);
    }
    setShowEditor(false);
  };

  const statusColor = {Draft:"var(--muted)",Final:"var(--accent-bright)",Executed:"var(--green)",Void:"var(--red)"};

  const pickUploadFile = () => { if(uploadRef.current) uploadRef.current.click(); };
  const onUploadFileChange = (e) => {
    const file = e.target.files[0];
    if(file) setUploadFile(file);
    e.target.value = "";
  };
  const saveUploadedContract = () => {
    if(!uploadName.trim() || !uploadFile) return;
    readFile(uploadFile).then(b64 => {
      const ext = uploadFile.name.split(".").pop().toLowerCase();
      onAddContract({
        id:"ci"+uid(), jobId:job.id, templateId:null,
        templateName:"Uploaded", title:uploadName,
        notes:uploadFile.name, status:uploadStatus,
        fieldValues:{}, filledText:"", pdfBase64:b64,
        pdfName:uploadFile.name, fileType:ext,
        createdDate:TODAY, lastModified:TODAY,
      });
      setShowUpload(false);
      setUploadName("");
      setUploadFile(null);
      setUploadStatus("Final");
    });
  };

  return (
    <div>
      <div className="drw-tabs">
        {[["contracts","Contracts"],["templates","Templates"]].map(([k,l])=>(
          <button key={k} className={"drw-tab"+(view===k?" active":"")} onClick={()=>setView(k)}>{l}</button>
        ))}
      </div>

      {view==="contracts" && (
        <div style={{paddingTop:12}}>
          <div style={{display:"flex",justifyContent:"flex-end",marginBottom:12,gap:8}}>
            <button className="btn btn-ghost btn-sm" onClick={()=>setShowUpload(true)}>Upload Contract</button>
            <button className="btn btn-primary btn-sm" onClick={openNew} disabled={!contractTemplates.length}>
              {contractTemplates.length?"+ Generate from Template":"No templates yet"}
            </button>
          </div>
          {jobContracts.length===0 ? (
            <div className="empty" style={{padding:40}}>
              <div style={{fontSize:24,opacity:.3,marginBottom:8}}></div>
              <div style={{fontFamily:"'Barlow Condensed'",fontSize:13,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:6}}>No Contracts Yet</div>
              <div style={{fontSize:12,color:"var(--muted)"}}>
                {contractTemplates.length
                  ? "Click + New Contract to create a contract from your templates."
                  : "Go to Templates tab to upload your contract template first."}
              </div>
            </div>
          ) : jobContracts.map(c=>(
            <div key={c.id} onClick={()=>openEdit(c)} style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:6,padding:"12px 14px",marginBottom:8,cursor:"pointer",transition:"background .15s"}}>
              <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between"}}>
                <div>
                  <div style={{fontSize:14,color:"var(--white)",fontWeight:700,marginBottom:3}}>{c.title}</div>
                  <div style={{fontSize:11,color:"var(--muted)"}}>
                    {c.templateName&&<span>{c.templateName}   </span>}
                    Created {fmtDate(c.createdDate)}
                    {c.lastModified!==c.createdDate&&<span>   Updated {fmtDate(c.lastModified)}</span>}
                  </div>
                  {c.notes&&<div style={{fontSize:11,color:"var(--muted)",marginTop:3}}>{c.notes}</div>}
                </div>
                <span style={{fontSize:11,color:statusColor[c.status]||"var(--muted)",fontFamily:"'Barlow Condensed'",letterSpacing:1,flexShrink:0,marginLeft:8}}>{c.status.toUpperCase()}</span>
              </div>
            </div>
          ))}
        </div>
      )}

      {view==="templates" && (
        <div style={{paddingTop:12}}>
          <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:20,textAlign:"center"}}>
            <div style={{fontSize:22,opacity:.4,marginBottom:10}}></div>
            <div style={{fontFamily:"'Barlow Condensed'",fontSize:14,letterSpacing:2,textTransform:"uppercase",color:"var(--white)",marginBottom:8}}>Templates Managed in Documents</div>
            <div style={{fontSize:13,color:"var(--muted)",maxWidth:400,margin:"0 auto 12px"}}>
              Upload and manage all contract templates in the <strong style={{color:"var(--accent-bright)"}}>Documents</strong> nav tab. Templates tagged Contract appear here automatically.
            </div>
            {contractTemplates.length===0 && <div style={{fontSize:12,color:"var(--yellow)"}}>No contract templates uploaded yet.</div>}
            {contractTemplates.length>0 && <div style={{fontSize:12,color:"var(--green)"}}>{contractTemplates.length} contract template{contractTemplates.length!==1?"s":""} available.</div>}
          </div>
        </div>
      )}

      {showUpload && (
        <div className="overlay" onClick={()=>setShowUpload(false)}>
          <div className="modal" onClick={e=>e.stopPropagation()} style={{maxWidth:460}}>
            <div className="modal-hdr">
              <div className="modal-title">Upload Contract</div>
              <div className="modal-sub">AIA, custom, or any executed agreement</div>
              <button className="btn btn-ghost btn-sm" onClick={()=>setShowUpload(false)}>x</button>
            </div>
            <div className="modal-body" style={{display:"flex",flexDirection:"column",gap:12}}>
              <div>
                <div className="flabel">Contract Name</div>
                <input className="finput" value={uploadName} onChange={e=>setUploadName(e.target.value)} placeholder="AIA A101, Owner Agreement, Subcontract..."/>
              </div>
              <div>
                <div className="flabel">Status</div>
                <select className="fselect" value={uploadStatus} onChange={e=>setUploadStatus(e.target.value)}>
                  {CONTRACT_STATUSES.map(s=><option key={s}>{s}</option>)}
                </select>
              </div>
              <div>
                <div className="flabel">File (PDF or DOCX)</div>
                {uploadFile ? (
                  <div style={{display:"flex",alignItems:"center",gap:10,padding:"10px 12px",background:"rgba(52,211,153,.05)",border:"1px solid rgba(52,211,153,.2)",borderRadius:6}}>
                    <span style={{fontSize:13,color:"var(--green)",flex:1}}>{uploadFile.name}</span>
                    <button className="btn btn-ghost btn-sm" style={{color:"var(--red)"}} onClick={()=>setUploadFile(null)}>Remove</button>
                  </div>
                ) : (
                  <div className="drw-upload-zone" onClick={pickUploadFile}>
                    <div style={{fontFamily:"'Barlow Condensed'",fontSize:12,letterSpacing:1,color:"var(--accent-bright)"}}>Click to select PDF or DOCX</div>
                  </div>
                )}
                <input ref={uploadRef} type="file" accept=".pdf,.docx" style={{display:"none"}} onChange={onUploadFileChange}/>
              </div>
            </div>
            <div className="modal-ftr">
              <button className="btn btn-ghost" onClick={()=>setShowUpload(false)}>Cancel</button>
              <button className="btn btn-primary" disabled={!uploadName.trim()||!uploadFile} onClick={saveUploadedContract}>Save Contract</button>
            </div>
          </div>
        </div>
      )}

      {showEditor && (
        <ContractEditor
          instance={editInstance}
          template={selTemplate}
          job={job}
          directory={directory}
          onSave={handleSave}
          onClose={()=>setShowEditor(false)}
        />
      )}
    </div>
  );
};

// --- JOB DASHBOARD COMPONENT -------------------------------------------------
const JobDashboard = ({job, activities, onUpdateJob}) => {
  const [editing, setEditing] = useState(false);
  const [f, setF] = useState({
    architect:     job.architect     || "",
    address:       job.address       || "",
    permitNumber:  job.permitNumber  || "",
    lienAgentNumber: job.lienAgentNumber || "",
    startDate:     job.startDate     || "",
    finishDate:    job.finishDate    || "",
    billingsToDate: job.billingsToDate || 0,
    openInvoices:  job.openInvoices  || 0,
  });
  const set = (k,v) => setF(p=>({...p,[k]:v}));

  const calc = useMemo(() => calcJob(job), [job]);

  // Schedule % complete - weighted by duration, non-milestones only
  const jobActs = activities.filter(a => a.jobId === job.id && !a.isMilestone);
  const schedPct = useMemo(() => {
    if(!jobActs.length) return null;
    const totalDays = jobActs.reduce((s,a) => {
      const dur = Math.max(1, Math.ceil((new Date(a.endDate)-new Date(a.startDate))/86400000));
      return s + dur;
    }, 0);
    const doneDays = jobActs.reduce((s,a) => {
      const dur = Math.max(1, Math.ceil((new Date(a.endDate)-new Date(a.startDate))/86400000));
      return s + dur * ((a.percentComplete||0)/100);
    }, 0);
    return totalDays ? Math.round(doneDays/totalDays*100) : 0;
  }, [jobActs]);

  const billings    = job.billingsToDate || 0;
  const openInv     = job.openInvoices   || 0;
  const costSpent   = job.actualCost     || 0;
  const currentContract = calc.cc;
  const unbilled    = currentContract - billings;
  const approvedCOs = job.ownerCOs.filter(c=>c.status==="Approved").reduce((s,c)=>s+c.amount,0);
  const pendingCOs  = job.ownerCOs.filter(c=>c.status==="Pending").reduce((s,c)=>s+c.amount,0);

  // Days on project
  const daysElapsed = job.startDate ? Math.max(0,Math.floor((new Date(TODAY)-new Date(job.startDate))/86400000)) : null;
  const daysRemain  = job.finishDate ? Math.ceil((new Date(job.finishDate)-new Date(TODAY))/86400000) : null;
  const isLate      = daysRemain !== null && daysRemain < 0;

  const saveInfo = () => {
    onUpdateJob({
      ...job,
      architect:       f.architect,
      address:         f.address,
      permitNumber:    f.permitNumber,
      lienAgentNumber: f.lienAgentNumber,
      startDate:       f.startDate,
      finishDate:      f.finishDate,
      billingsToDate:  parseFloat(f.billingsToDate)||0,
      openInvoices:    parseFloat(f.openInvoices)||0,
    });
    setEditing(false);
  };

  return (
    <div>
      {/* -- FINANCIAL STATS -- */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:16}}>
        {[
          {label:"Current Contract",  val:fmt(currentContract),   sub:"Orig. "+fmt(job.originalContract), color:"var(--white)"},
          {label:"Approved COs",      val:fmt(approvedCOs),       sub:pendingCOs>0?"+ "+fmt(pendingCOs)+" pending":"No pending COs", color:approvedCOs>0?"var(--yellow)":"var(--muted)"},
          {label:"Cost to Date",      val:fmt(costSpent),         sub:(currentContract>0?(costSpent/currentContract*100).toFixed(0):"0")+"% of contract", color:"var(--white)"},
          {label:"Projected Margin",  val:fmt(calc.pm),           sub:calc.pmpct.toFixed(1)+"%", color:calc.pmpct>=15?"var(--green)":calc.pmpct>=8?"var(--yellow)":"var(--red)"},
        ].map(s=>(
          <div key={s.label} className="stat-card">
            <div className="stat-label">{s.label}</div>
            <div className="stat-value" style={{fontSize:16,color:s.color}}>{s.val}</div>
            <div className="stat-sub">{s.sub}</div>
          </div>
        ))}
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:20}}>
        {[
          {label:"Billings to Date",  val:fmt(billings),    sub:(currentContract>0?(billings/currentContract*100).toFixed(0):"0")+"% billed", color:"var(--accent-bright)"},
          {label:"Open Invoices",     val:fmt(openInv),     sub:"Receivable",        color:openInv>0?"var(--yellow)":"var(--muted)"},
          {label:"Unbilled to Date",  val:fmt(unbilled),    sub:"Earned not billed", color:unbilled>5000?"var(--orange)":"var(--muted)"},
          {label:"Cost Variance",     val:fmt(calc.pc-job.originalCost), sub:calc.pc>job.originalCost?"Over estimate":"Under estimate", color:calc.pc>job.originalCost?"var(--red)":"var(--green)"},
        ].map(s=>(
          <div key={s.label} className="stat-card">
            <div className="stat-label">{s.label}</div>
            <div className="stat-value" style={{fontSize:16,color:s.color}}>{s.val}</div>
            <div className="stat-sub">{s.sub}</div>
          </div>
        ))}
      </div>

      {/* -- PROGRESS BARS -- */}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:20}}>
        {/* Schedule % */}
        <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:"14px 16px"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"baseline",marginBottom:8}}>
            <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)"}}>Schedule Complete</div>
            <div style={{fontFamily:"'Barlow Condensed'",fontSize:24,fontWeight:700,color:schedPct===100?"var(--green)":schedPct!==null&&schedPct>=70?"var(--accent-bright)":"var(--yellow)"}}>{schedPct!==null?schedPct+"%":"-"}</div>
          </div>
          <div style={{height:8,background:"rgba(255,255,255,.06)",borderRadius:4,overflow:"hidden",marginBottom:8}}>
            <div style={{height:"100%",width:(schedPct||0)+"%",background:schedPct===100?"var(--green)":schedPct!==null&&schedPct>=70?"var(--accent)":"var(--yellow)",transition:"width .5s",borderRadius:4}}/>
          </div>
          <div style={{display:"flex",justifyContent:"space-between",fontSize:11,color:"var(--muted)"}}>
            <span>{daysElapsed!==null?daysElapsed+" days elapsed":"-"}</span>
            <span style={{color:isLate?"var(--red)":daysRemain!==null&&daysRemain<=14?"var(--orange)":"var(--muted)"}}>
              {daysRemain!==null?(isLate?Math.abs(daysRemain)+" days late":daysRemain+" days left"):"-"}
            </span>
          </div>
        </div>
        {/* Billings vs contract */}
        <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:"14px 16px"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"baseline",marginBottom:8}}>
            <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)"}}>Billings vs Contract</div>
            <div style={{fontFamily:"'Barlow Condensed'",fontSize:24,fontWeight:700,color:"var(--accent-bright)"}}>{currentContract>0?Math.round(billings/currentContract*100)+"%":"-"}</div>
          </div>
          <div style={{height:8,background:"rgba(255,255,255,.06)",borderRadius:4,overflow:"hidden",marginBottom:8}}>
            <div style={{height:"100%",width:currentContract>0?Math.min(billings/currentContract*100,100)+"%":"0%",background:"var(--accent)",transition:"width .5s",borderRadius:4}}/>
          </div>
          <div style={{display:"flex",justifyContent:"space-between",fontSize:11,color:"var(--muted)"}}>
            <span>Billed: {fmt(billings)}</span>
            <span>Contract: {fmt(currentContract)}</span>
          </div>
        </div>
      </div>

      {/* -- PROJECT INFO -- */}
      <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,overflow:"hidden"}}>
        <div style={{padding:"11px 16px",borderBottom:"1px solid var(--navy-border)",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
          <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)"}}>Project Information</div>
          {editing ? (
            <div style={{display:"flex",gap:8}}>
              <button className="btn btn-ghost btn-sm" onClick={()=>setEditing(false)}>Cancel</button>
              <button className="btn btn-primary btn-sm" onClick={saveInfo}>Save</button>
            </div>
          ) : (
            <button className="btn btn-ghost btn-sm" onClick={()=>setEditing(true)}>Edit</button>
          )}
        </div>
        <div style={{padding:16}}>
          {editing ? (
            <div style={{display:"flex",flexDirection:"column",gap:12}}>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                <div><div className="flabel">Client</div><input className="finput" value={job.client} onChange={e=>onUpdateJob({...job,client:e.target.value})} placeholder="Client name..."/></div>
                <div><div className="flabel">Architect / Designer</div><input className="finput" value={f.architect} onChange={e=>set("architect",e.target.value)} placeholder="Firm name..."/></div>
              </div>
              <div><div className="flabel">Project Address</div><input className="finput" value={f.address} onChange={e=>set("address",e.target.value)} placeholder="123 Main St, Charlotte NC 28202"/></div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                <div><div className="flabel">Permit Number</div><input className="finput" value={f.permitNumber} onChange={e=>set("permitNumber",e.target.value)} placeholder="BLD-2025-XXXXX"/></div>
                <div><div className="flabel">Lien Agent Number</div><input className="finput" value={f.lienAgentNumber} onChange={e=>set("lienAgentNumber",e.target.value)} placeholder="LA-2025-XXXX"/></div>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                <div><div className="flabel">Contract Start Date</div><input className="finput" type="date" value={f.startDate} onChange={e=>set("startDate",e.target.value)}/></div>
                <div><div className="flabel">Substantial Completion</div><input className="finput" type="date" value={f.finishDate} onChange={e=>set("finishDate",e.target.value)}/></div>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                <div><div className="flabel">Billings to Date ($)</div><input className="finput" type="number" value={f.billingsToDate} onChange={e=>set("billingsToDate",e.target.value)}/></div>
                <div><div className="flabel">Open Invoices ($)</div><input className="finput" type="number" value={f.openInvoices} onChange={e=>set("openInvoices",e.target.value)}/></div>
              </div>
            </div>
          ) : (
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"10px 24px"}}>
              {[
                ["Client",            job.client||"-"],
                ["Architect",         job.architect||"-"],
                ["Address",           job.address||"-"],
                ["Permit Number",     job.permitNumber||"-"],
                ["Lien Agent Number", job.lienAgentNumber||"-"],
                ["Start Date",        job.startDate?fmtDate(job.startDate):"-"],
                ["Substantial Completion", job.finishDate?fmtDate(job.finishDate)+(isLate?"  PAST DUE":""):"-"],
                ["Project Phase",     job.phase],
              ].map(([label,val])=>(
                <div key={label} style={{padding:"8px 0",borderBottom:"1px solid rgba(42,64,128,.2)"}}>
                  <div style={{fontFamily:"'Barlow Condensed'",fontSize:10,letterSpacing:1.5,textTransform:"uppercase",color:"var(--muted)",marginBottom:2}}>{label}</div>
                  <div style={{fontSize:13,color:label==="Substantial Completion"&&isLate?"var(--red)":"var(--white)",fontWeight:500}}>{val}</div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const JobTabs = ({tab, setTab, photoCt, currentUser}) => {
  var tabs = [
    ["summary","Dashboard",null],
    canView(currentUser,"contract")&&["contracts","Contracts",null],
    canView(currentUser,"subcontract")&&["subcontracts","Subcontracts",null],
    canView(currentUser,"financials")&&["finance","Financials",null],
    canView(currentUser,"co")&&["cos","Change Orders",null],
    canView(currentUser,"rfi")&&["rfis","RFIs",null],
    canView(currentUser,"schedule")&&["schedule","Schedule",null],
    ["photos","Photos",photoCt||null],
    ["logs","Daily Logs",null],
    ["logreport","Log Report",null],
    ["meetings","Meetings",null],["closeout","Closeout",null],
    ["inspections","Inspections",null],
    ["submittals","Submittals",null],
  ];
  return (
    <div className="dtabs" style={{WebkitOverflowScrolling:"touch"}}>
      {tabs.map(function(t) {
        var k=t[0]; var l=t[1]; var b=t[2];
        return (
          <button key={k} className={"dtab"+(tab===k?" active":"")} onClick={function(){setTab(k);}}>
            {l}
            {b ? <span className="nav-badge" style={{background:"var(--accent)",marginLeft:4,fontSize:9}}>{b}</span> : null}
          </button>
        );
      })}
    </div>
  );
};


const JobDetail=({job,jobs,logs,directory,activities,phases,setPhases,setActs,masterDocLib,onBack,onUpdateJob,onAddLog,onUpdateLog,currentUser,onCreatePunch,jobSubmittals,masterSubs,onAddSubmittal,onUpdateSubmittal,onAddSubmittals,jobContracts,contractTemplates,onAddContract,onUpdateContract,costCodes,jobBudgetLines,jobCostEntries,jobSOV,jobDraws,onAddBudgetLine,onUpdateBudgetLine,onDeleteBudgetLine,onAddCostEntry,onUpdateCostEntry,onDeleteCostEntry,onAddSOVLine,onUpdateSOVLine,onDeleteSOVLine,onAddDraw,onUpdateDraw,jobSubcontracts,onAddSubcontract,onUpdateSubcontract,jobRfis,allRfis,onUpdateRfi,onAddRfi,jobCloseout,jobInspections,onUpdateCloseout,onAddInspection,onUpdateInspection,onDeleteInspection,jobMeetings,allMeetings,onAddMeeting,onUpdateMeeting})=>{
  const[tab,setTab]=useState("summary");const[showOCO,setShowOCO]=useState(false);const[showSCO,setShowSCO]=useState(false);
  const jobLogs=logs.filter(l=>l.jobId===job.id);
  const photoCt=jobLogs.reduce(function(s,l){return s+(l.photos||[]).length;},0);
  const calc=useMemo(()=>calcJob(job),[job]);
  const addCO=(type,data)=>{const list=type==="owner"?job.ownerCOs:job.subCOs;const prefix=type==="owner"?"CO":"SCO";const num=prefix+"-"+String(list.length+1).padStart(3,"0");const co={id:uid(),num,...data};onUpdateJob(type==="owner"?{...job,ownerCOs:[...job.ownerCOs,co]}:{...job,subCOs:[...job.subCOs,co]});type==="owner"?setShowOCO(false):setShowSCO(false);};
  const updCO=(type,id,status)=>{if(type==="owner")onUpdateJob({...job,ownerCOs:job.ownerCOs.map(c=>c.id===id?{...c,status}:c)});else onUpdateJob({...job,subCOs:job.subCOs.map(c=>c.id===id?{...c,status}:c)});};
  return (<div>
    {job.isTraining && (
      <div style={{padding:"6px 16px",background:"rgba(251,191,36,.08)",borderBottom:"2px solid rgba(251,191,36,.4)",fontSize:12,color:"var(--yellow)",fontFamily:"'Barlow Condensed'",letterSpacing:1,textAlign:"center"}}>
        TRAINING PROJECT -- Data excluded from company financials and dashboards
      </div>
    )}
    <button className="back-btn" onClick={onBack}> All Jobs</button>
    <div style={{marginBottom:22}}>
      <div style={{display:"flex",alignItems:"center",gap:14,flexWrap:"wrap"}}><div style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:30,fontWeight:700,color:"var(--white)",letterSpacing:1}}>{job.name}</div><Pill s={job.phase}/><span className="live-badge"><span className="live-dot"/>LIVE CALC</span></div>
      <div style={{display:"flex",gap:16,marginTop:4,alignItems:"center"}}><span style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:12,color:"var(--muted)"}}>{job.id}</span><span style={{color:"var(--muted)"}}> </span><span style={{fontSize:13,color:"var(--muted)"}}>{job.client}</span></div>
    </div>
    <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12,marginBottom:20}}>
      {[{l:"Current Contract",v:fmt(calc.cc),s:"Orig. "+fmt(job.originalContract),c:"var(--white)"},{l:"Projected Cost",v:fmt(calc.pc),s:"Actual: "+fmt(job.actualCost),c:"var(--white)"},{l:"Projected Margin",v:fmt(calc.pm),s:calc.pmpct.toFixed(1)+"%",c:mc(calc.pmpct)},{l:"Pending COs",v:job.ownerCOs.filter(c=>c.status==="Pending").length+job.subCOs.filter(c=>c.status==="Pending").length,s:"Awaiting approval",c:"var(--yellow)"}].map(s=><div key={s.l} className="stat-card"><div className="stat-label">{s.l}</div><div className="stat-value" style={{fontSize:18,color:s.c}}>{s.v}</div><div className="stat-sub">{s.s}</div></div>)}
    </div>
    <JobTabs tab={tab} setTab={setTab} photoCt={photoCt} currentUser={currentUser}/>

    {tab==="summary"&&<JobDashboard job={job} activities={activities} onUpdateJob={onUpdateJob}/>}

    {tab==="cos"&&<div>
      <div style={{marginBottom:20}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}><div style={{fontFamily:"'Barlow Condensed'",fontSize:14,letterSpacing:2,textTransform:"uppercase",color:"var(--white)"}}>Owner Change Orders</div><button className="btn btn-primary btn-sm" onClick={()=>setShowOCO(true)}>+ Owner CO</button></div>
        <div className="card"><table className="tbl"><thead><tr><th>#</th><th>Description</th><th>Date</th><th>Amount</th><th>Status</th><th></th></tr></thead><tbody>{job.ownerCOs.length===0&&<tr><td colSpan={6} className="empty">No owner COs</td></tr>}{job.ownerCOs.map(co=><tr key={co.id}><td className="col-id">{co.num}</td><td style={{color:"var(--white)"}}>
                    <div style={{fontWeight:600}}>{co.description}</div>
                    {co.reason&&<div style={{fontSize:11,color:"var(--muted)",marginTop:2}}>{co.reason}</div>}
                    {co.linkedContract&&<div style={{fontSize:10,color:"var(--accent-bright)",marginTop:2}}>Contract: {co.linkedContract.name||co.linkedContract.type||co.linkedContract.id}</div>}
                  </td><td style={{color:"var(--muted)",fontSize:12}}>{co.date}</td><td className="col-mono" style={{color:co.status==="Approved"?"var(--green)":co.status==="Rejected"?"var(--red)":"var(--yellow)"}}>{co.status==="Approved"?"+":""}{fmt(co.amount)}</td><td><Pill s={co.status}/></td><td>{co.status==="Pending"&&<div style={{display:"flex",gap:6}}><button className="btn btn-ghost btn-sm" style={{color:"var(--green)"}} onClick={()=>updCO("owner",co.id,"Approved")}>Approve</button><button className="btn btn-ghost btn-sm" style={{color:"var(--red)"}} onClick={()=>updCO("owner",co.id,"Rejected")}>Reject</button></div>}</td></tr>)}</tbody></table></div>
      </div>
      <div>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}><div style={{fontFamily:"'Barlow Condensed'",fontSize:14,letterSpacing:2,textTransform:"uppercase",color:"var(--white)"}}>Sub / Vendor Change Orders</div><button className="btn btn-ghost btn-sm" onClick={()=>setShowSCO(true)}>+ Sub CO</button></div>
        <div className="card"><table className="tbl"><thead><tr><th>#</th><th>Description</th><th>Sub</th><th>Date</th><th>Amount</th><th>Status</th><th></th></tr></thead><tbody>{job.subCOs.length===0&&<tr><td colSpan={7} className="empty">No sub COs</td></tr>}{job.subCOs.map(co=><tr key={co.id}><td className="col-id">{co.num}</td><td style={{color:"var(--white)"}}>
                    <div style={{fontWeight:600}}>{co.description}</div>
                    {co.reason&&<div style={{fontSize:11,color:"var(--muted)",marginTop:2}}>{co.reason}</div>}
                    {co.linkedSubcontract&&<div style={{fontSize:10,color:"var(--accent-bright)",marginTop:2}}>{co.linkedSubcontract.trade} - {fmt(co.linkedSubcontract.contractValue||0)}</div>}
                  </td><td><span className="tag">{co.sub}</span></td><td style={{color:"var(--muted)",fontSize:12}}>{co.date}</td><td className="col-mono" style={{color:co.status==="Approved"?"var(--orange)":"var(--yellow)"}}>+{fmt(co.amount)}</td><td><Pill s={co.status}/></td><td>{co.status==="Pending"&&<div style={{display:"flex",gap:6}}><button className="btn btn-ghost btn-sm" style={{color:"var(--green)"}} onClick={()=>updCO("sub",co.id,"Approved")}>Approve</button><button className="btn btn-ghost btn-sm" style={{color:"var(--red)"}} onClick={()=>updCO("sub",co.id,"Rejected")}>Reject</button></div>}</td></tr>)}</tbody></table></div>
      </div>
    </div>}

    {tab==="logs"&&<ProjectLogs job={job} jobs={jobs} logs={logs} directory={directory} onAddLog={onAddLog} onUpdateLog={onUpdateLog} onCreatePunch={onCreatePunch}/>}

    {tab==="logreport" && (
      <LogReportTool job={job} logs={logs} directory={directory} onUpdateJob={onUpdateJob}/>
    )}

    {tab==="meetings" && (
      <MeetingsTool job={job} meetings={jobMeetings||[]} onAdd={onAddMeeting} onUpdate={onUpdateMeeting}
        directory={directory} allRfis={allRfis||[]} allSubmittals={jobSubmittals||[]}
        allPunches={punches||[]} allActivities={activities||[]} phases={phases||[]} allLogs={logs}/>
    )}

    {tab==="closeout" && (
      <CloseoutChecklist job={job} checklist={jobCloseout||[]} onUpdate={function(items){onUpdateCloseout(job.id,items);}} onUpdateJob={onUpdateJob}/>
    )}

    {tab==="inspections" && (
      <MunicipalInspections job={job} inspections={jobInspections||[]} onAdd={function(i){onAddInspection(job.id,i);}} onUpdate={function(i){onUpdateInspection(job.id,i);}} onDelete={function(id){onDeleteInspection(job.id,id);}}/>
    )}

    {tab==="submittals"&&<SubmittalLog job={job} directory={directory} subs={jobSubmittals||[]} masterSubs={masterSubs||[]} onAdd={s=>onAddSubmittal(job.id,s)} onUpdate={s=>onUpdateSubmittal(job.id,s)} onAddMultiple={items=>onAddSubmittals(job.id,items)}/>}

    {tab==="contracts"&&<ContractsTab job={job} directory={directory} contracts={jobContracts||[]} contractTemplates={contractTemplates||[]} onAddContract={onAddContract} onUpdateContract={onUpdateContract}/>}

    {tab==="subcontracts" && (
      <SubcontractLog job={job} directory={directory} costCodes={costCodes} contractTemplates={contractTemplates||[]} subcontracts={jobSubcontracts||[]} phases={phases||[]} activities={activities||[]} masterDocLib={masterDocLib||[]} onAdd={sc=>onAddSubcontract(job.id,sc)} onUpdate={sc=>onUpdateSubcontract(job.id,sc)}/>
    )}

    {tab==="rfis" && (
      <div>
        <RfiLog rfis={jobRfis||[]} jobs={jobs} onUpdate={onUpdateRfi} onAdd={onAddRfi} directory={directory}/>
      </div>
    )}

    {tab==="photos" && (
      <PhotoLibrary job={job} logs={logs}/>
    )}

    {tab==="schedule" && (
      <ScheduleTool logs={logs} jobs={jobs} phases={phases} activities={activities} setPhases={setPhases} setActs={setActs} defaultJobId={job.id} lockFilter={true}/>
    )}

    {tab==="finance" && (
      <JobFinance job={job} budgetLines={jobBudgetLines||[]} costEntries={jobCostEntries||[]} costCodes={costCodes} sovLines={jobSOV||[]} drawRequests={jobDraws||[]} jobSubcontracts={jobSubcontracts||[]}
        onAddBudgetLine={bl=>onAddBudgetLine(job.id,bl)} onUpdateBudgetLine={bl=>onUpdateBudgetLine(job.id,bl)} onDeleteBudgetLine={id=>onDeleteBudgetLine(job.id,id)}
        onAddCostEntry={e=>onAddCostEntry(job.id,e)} onUpdateCostEntry={e=>onUpdateCostEntry(job.id,e)} onDeleteCostEntry={id=>onDeleteCostEntry(job.id,id)}
        onAddSOVLine={l=>onAddSOVLine(job.id,l)} onUpdateSOVLine={l=>onUpdateSOVLine(job.id,l)} onDeleteSOVLine={id=>onDeleteSOVLine(job.id,id)}
        onAddDraw={d=>onAddDraw(job.id,d)} onUpdateDraw={d=>onUpdateDraw(job.id,d)}/>
    )}

    {tab==="budget"&&<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>{job.budget.map(b=>{const v=b.budgeted-b.actual,p=b.budgeted>0?(b.actual/b.budgeted)*100:0;return (<div key={b.category} style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:"14px 16px"}}><div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:10}}>{b.category}</div><div style={{display:"flex",gap:20,marginBottom:8}}>{[["Budgeted",fmt(b.budgeted),"var(--white)"],["Actual",fmt(b.actual),b.actual>b.budgeted?"var(--red)":"var(--green)"],["Variance",fmt(v),v>=0?"var(--green)":"var(--red)"]].map(([l,val,c])=><div key={l}><div style={{fontSize:10,color:"var(--muted)",marginBottom:2}}>{l}</div><div style={{fontFamily:"'IBM Plex Mono'",fontSize:15,color:c}}>{val}</div></div>)}</div><div className="mbar-wrap"><div className="mbar" style={{flex:1}}><div className="mbar-fill" style={{width:Math.min(p,100)+"%",background:p>100?"var(--red)":p>85?"var(--yellow)":"var(--green)"}}/></div><span style={{fontFamily:"'IBM Plex Mono'",fontSize:11,minWidth:36,textAlign:"right",color:p>100?"var(--red)":"var(--muted)"}}>{p.toFixed(0)}%</span></div></div>);})}</div>}

    {showOCO&&<COModal type="owner" contracts={jobContracts||[]} subcontracts={jobSubcontracts||[]} directory={directory} onClose={()=>setShowOCO(false)} onSave={d=>addCO("owner",d)}/>}
    {showSCO&&<COModal type="sub" contracts={jobContracts||[]} subcontracts={jobSubcontracts||[]} directory={directory} onClose={()=>setShowSCO(false)} onSave={d=>addCO("sub",d)}/>}
  </div>);
};

// --- JOBS LIST ----------------------------------------------------------------
// --- NEW JOB MODAL ------------------------------------------------------------
const JOB_PHASES = ["Draft","Bid","Active","Punch","Closeout","Complete","On Hold"];

const nextJobId = (jobs) => {
  const years = jobs.map(j => {
    const m = j.id.match(/WC-(\d{4})/);
    return m ? parseInt(m[1]) : 0;
  });
  const max = years.length ? Math.max(...years) : 2400;
  return "WC-"+String(max+1).padStart(4,"0");
};

const NewJobModal = ({jobs, directory, masterDocLib, masterSubs, onSave, onClose}) => {
  const suggestedId = nextJobId(jobs);
  const [f, setF] = useState({
    id:            suggestedId,
    name:          "",
    client:        "",
    architect:     "",
    address:       "",
    permitNumber:  "",
    lienAgentNumber:"",
    phase:         "Draft",
    originalContract: "",
    originalCost:  "",
    startDate:     "",
    finishDate:    "",
    assignedSubIds:[],
    notes:         "",
  });
  const set = (k,v) => setF(p=>({...p,[k]:v}));
  const [step, setStep] = useState(1);
  const [clientSearch, setClientSearch] = useState("");

  const subOptions = directory.filter(d=>d.active&&d.trade);
  const toggleSub = (id) => set("assignedSubIds",
    f.assignedSubIds.includes(id)
      ? f.assignedSubIds.filter(x=>x!==id)
      : [...f.assignedSubIds, id]
  );

  const autoPushDocs = masterDocLib.filter(d=>d.autoPush&&d.base64);
  const autoPullSubs = masterSubs.filter(s=>s.autoPull);

  const handleSave = () => {
    if(!f.name.trim()||!f.client.trim()) return;
    onSave({
      ...f,
      originalContract: parseFloat(f.originalContract)||0,
      originalCost:     parseFloat(f.originalCost)||0,
      actualCost:       0,
      billingsToDate:   0,
      openInvoices:     0,
      ownerCOs:         [],
      subCOs:           [],
      budget:           [],
    });
  };

  return (
    <div className="overlay" onClick={onClose}>
      <div className="modal modal-wide" onClick={e=>e.stopPropagation()} style={{maxWidth:620}}>
        <div className="modal-hdr">
          <div>
            <div className="modal-title">New Project</div>
            <div className="modal-sub">Step {step} of 3 - {["Project Info","Team & Subs","Review"][step-1]}</div>
          </div>
          <button className="btn btn-ghost btn-sm" onClick={onClose}>x</button>
        </div>

        {/* Progress bar */}
        <div style={{height:3,background:"rgba(255,255,255,.06)"}}>
          <div style={{height:"100%",width:(step/3*100)+"%",background:"var(--accent)",transition:"width .3s"}}/>
        </div>

        <div className="modal-body" style={{display:"flex",flexDirection:"column",gap:12}}>

          {/* STEP 1 - Project Info */}
          {step===1 && (
            <div style={{display:"flex",flexDirection:"column",gap:12}}>
              <div style={{display:"grid",gridTemplateColumns:"1fr 120px",gap:10}}>
                <div><div className="flabel">Project Name</div><input className="finput" value={f.name} onChange={e=>set("name",e.target.value)} placeholder="Dilworth Kitchen & Bath Remodel..." autoFocus/></div>
                <div><div className="flabel">Project ID</div><input className="finput" value={f.id} onChange={e=>set("id",e.target.value.toUpperCase())}/></div>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                <div><div className="flabel">Client / Owner</div><input className="finput" value={f.client} onChange={e=>set("client",e.target.value)} placeholder="Client name..."/></div>
                <div><div className="flabel">Architect / Designer</div><input className="finput" value={f.architect} onChange={e=>set("architect",e.target.value)} placeholder="Firm name..."/></div>
              </div>
              <div><div className="flabel">Project Address</div><input className="finput" value={f.address} onChange={e=>set("address",e.target.value)} placeholder="123 Main St, Charlotte NC 28202"/></div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                <div><div className="flabel">Permit Number</div><input className="finput" value={f.permitNumber} onChange={e=>set("permitNumber",e.target.value)} placeholder="BLD-2026-XXXXX"/></div>
                <div><div className="flabel">Lien Agent Number</div><input className="finput" value={f.lienAgentNumber} onChange={e=>set("lienAgentNumber",e.target.value)} placeholder="LA-2026-XXXX"/></div>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"140px 1fr 1fr 1fr",gap:10}}>
                <div><div className="flabel">Phase</div><select className="fselect" value={f.phase} onChange={e=>set("phase",e.target.value)}>{JOB_PHASES.map(p=><option key={p}>{p}</option>)}</select></div>
                <div><div className="flabel">Contract Value</div><input className="finput" type="number" value={f.originalContract} onChange={e=>set("originalContract",e.target.value)} placeholder="0"/></div>
                <div><div className="flabel">Start Date</div><input className="finput" type="date" value={f.startDate} onChange={e=>set("startDate",e.target.value)}/></div>
                <div><div className="flabel">Completion Date</div><input className="finput" type="date" value={f.finishDate} onChange={e=>set("finishDate",e.target.value)}/></div>
              </div>
            </div>
          )}

          {/* STEP 2 - Subs */}
          {step===2 && (
            <div style={{display:"flex",flexDirection:"column",gap:12}}>
              <div style={{fontSize:13,color:"var(--white)",marginBottom:4}}>Select subcontractors for this project. You can add more later.</div>
              <input className="finput" value={clientSearch} onChange={e=>setClientSearch(e.target.value)} placeholder="Search by company or trade..."/>
              <div style={{maxHeight:300,overflowY:"auto",border:"1px solid var(--navy-border)",borderRadius:8}}>
                {subOptions.filter(s=>!clientSearch||s.company.toLowerCase().includes(clientSearch.toLowerCase())||s.trade.toLowerCase().includes(clientSearch.toLowerCase())).map(s => {
                  const selected = f.assignedSubIds.includes(s.id);
                  const coi = checkCOI(s);
                  return (
                    <div key={s.id} onClick={()=>toggleSub(s.id)} style={{display:"flex",alignItems:"center",gap:12,padding:"10px 14px",borderBottom:"1px solid rgba(42,64,128,.2)",cursor:"pointer",background:selected?"rgba(74,124,220,.08)":"transparent"}}>
                      <div style={{width:18,height:18,borderRadius:4,border:"2px solid "+(selected?"var(--accent)":"var(--navy-border)"),background:selected?"var(--accent)":"transparent",flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center"}}>
                        {selected&&<span style={{fontSize:11,color:"var(--white)",fontWeight:700}}>v</span>}
                      </div>
                      <div style={{flex:1}}>
                        <div style={{fontSize:13,color:"var(--white)",fontWeight:600}}>{s.company}</div>
                        <div style={{fontSize:11,color:"var(--muted)"}}>{s.trade}{s.license?"   "+s.license:""}</div>
                      </div>
                      <div style={{fontSize:11,color:coi.ok?(coi.warn?"var(--yellow)":"var(--green)"):"var(--red)",fontFamily:"'Barlow Condensed'",letterSpacing:.5,flexShrink:0}}>
                        {coi.ok?(coi.warn?"COI EXPIRING":"COI OK"):"COI ISSUE"}
                      </div>
                    </div>
                  );
                })}
              </div>
              <div style={{fontSize:12,color:"var(--muted)"}}>{f.assignedSubIds.length} sub{f.assignedSubIds.length!==1?"s":""} selected</div>
            </div>
          )}

          {/* STEP 3 - Review + auto-pull preview */}
          {step===3 && (
            <div style={{display:"flex",flexDirection:"column",gap:14}}>
              <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14}}>
                <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:10}}>Project Summary</div>
                {[
                  ["ID",           f.id],
                  ["Name",         f.name],
                  ["Client",       f.client],
                  ["Architect",    f.architect||"-"],
                  ["Address",      f.address||"-"],
                  ["Phase",        f.phase],
                  ["Contract",     f.originalContract?fmt(parseFloat(f.originalContract)):"-"],
                  ["Start",        f.startDate?fmtDate(f.startDate):"-"],
                  ["Completion",   f.finishDate?fmtDate(f.finishDate):"-"],
                  ["Subs",         f.assignedSubIds.length+" assigned"],
                ].map(([l,v])=>(
                  <div key={l} style={{display:"flex",gap:12,padding:"5px 0",borderBottom:"1px solid rgba(42,64,128,.15)"}}>
                    <span style={{fontSize:11,color:"var(--muted)",width:90,flexShrink:0,fontFamily:"'Barlow Condensed'",letterSpacing:1}}>{l.toUpperCase()}</span>
                    <span style={{fontSize:13,color:"var(--white)"}}>{v}</span>
                  </div>
                ))}
              </div>

              {(autoPushDocs.length>0||autoPullSubs.length>0) && (
                <div style={{background:"rgba(52,211,153,.04)",border:"1px solid rgba(52,211,153,.15)",borderRadius:8,padding:14}}>
                  <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--green)",marginBottom:8}}>Auto-Pulled on Creation</div>
                  {autoPushDocs.length>0 && (
                    <div style={{marginBottom:8}}>
                      <div style={{fontSize:11,color:"var(--muted)",marginBottom:4}}>Safety Documents ({autoPushDocs.length})</div>
                      {autoPushDocs.map(d=><div key={d.id} style={{fontSize:12,color:"var(--white)",padding:"2px 0"}}> {d.name}</div>)}
                    </div>
                  )}
                  {autoPullSubs.length>0 && (
                    <div>
                      <div style={{fontSize:11,color:"var(--muted)",marginBottom:4}}>Submittal Templates ({autoPullSubs.length})</div>
                      {autoPullSubs.map(s=><div key={s.id} style={{fontSize:12,color:"var(--white)",padding:"2px 0"}}> {s.title}</div>)}
                    </div>
                  )}
                </div>
              )}
            </div>
          )}
        </div>

        <div className="modal-ftr">
          {step>1 && <button className="btn btn-ghost" onClick={()=>setStep(s=>s-1)}>Back</button>}
          <div style={{flex:1}}/>
          {step<3 && (
            <button className="btn btn-primary" onClick={()=>{
              if(step===1&&(!f.name.trim()||!f.client.trim())) return;
              setStep(s=>s+1);
            }}>Next</button>
          )}
          {step===3 && (
            <button className="btn btn-primary" onClick={handleSave}>Create Project</button>
          )}
        </div>
      </div>
    </div>
  );
};

const JobsList=({jobs,logs,directory,masterDocLib,masterSubs,onSelect,onAdd})=>{
  const [showNewJob, setShowNewJob] = useState(false);
  const totals=jobs.filter(j=>!j.isTraining).reduce((a,j)=>{const c=calcJob(j);return{rev:a.rev+c.cc,m:a.m+c.pm};},{rev:0,m:0});
  const bm=totals.rev>0?(totals.m/totals.rev)*100:0;
  const noLog=jobs.filter(j=>j.phase==="Active"&&!j.isTraining&&!hasToday(logs,j.id));
  return (<div>
    {noLog.length>0&&<div className="alert-bar alert-orange"><span></span><span>No daily log today: <strong>{noLog.map(j=>j.name).join(", ")}</strong></span></div>}
    <div className="stat-grid">
      <div className="stat-card"><div className="stat-label">Active Jobs</div><div className="stat-value">{jobs.filter(j=>j.phase==="Active"&&!j.isTraining).length}</div><div className="stat-sub">{jobs.filter(j=>!j.isTraining).length} total</div></div>
      <div className="stat-card"><div className="stat-label">Total Contract</div><div className="stat-value" style={{fontSize:18}}>{fmt(totals.rev)}</div></div>
      <div className="stat-card"><div className="stat-label">Blended Margin</div><div className="stat-value" style={{color:mc(bm),fontSize:20}}>{bm.toFixed(1)}%</div></div>
      <div className="stat-card"><div className="stat-label">Pending COs</div><div className="stat-value" style={{fontSize:18,color:"var(--yellow)"}}>{jobs.filter(j=>!j.isTraining).reduce((s,j)=>s+j.ownerCOs.filter(c=>c.status==="Pending").length+j.subCOs.filter(c=>c.status==="Pending").length,0)}</div></div>
    </div>
    <div className="card"><div className="card-hdr"><span className="card-title">Jobs</span><button className="btn btn-primary btn-sm" onClick={()=>setShowNewJob(true)}>+ New Job</button></div>
    <table className="tbl"><thead><tr><th>Job</th><th>Client</th><th>Phase</th><th>Contract Value</th><th>Margin %</th><th>Status</th></tr></thead><tbody>{jobs.map(j=>{const c=calcJob(j);const noLogToday=j.phase==="Active"&&!hasToday(logs,j.id);const saf=logs.filter(l=>l.jobId===j.id&&l.safety?.incident).length>0;const delays=logs.flatMap(l=>l.jobId===j.id?(l.delays||[]):[]).length;const rfis=logs.flatMap(l=>l.jobId===j.id?(l.rfis||[]):[]).length;return (<tr key={j.id} className="clickable" onClick={()=>onSelect(j.id)}><td><div className="col-name">{j.name}</div><div className="col-id">{j.id}</div></td><td style={{color:"var(--muted)"}}>{j.client}</td><td><Pill s={j.phase}/></td><td className="col-mono" style={{color:"var(--accent-bright)"}}>{fmt(c.cc)}</td><td style={{minWidth:130}}><MBar pct={c.pmpct}/></td><td style={{minWidth:160}}>{saf&&<span className="flag flag-red" style={{fontSize:10,marginRight:4}}><span className="flag-dot"/>Safety</span>}{delays>0&&<span className="flag flag-yellow" style={{fontSize:10,marginRight:4}}><span className="flag-dot"/>Delay</span>}{rfis>0&&<span className="flag flag-purple" style={{fontSize:10,marginRight:4}}><span className="flag-dot"/>RFI</span>}{noLogToday&&<span className="flag flag-blue" style={{fontSize:10}}><span className="flag-dot"/>No Log</span>}{!noLogToday&&!saf&&delays===0&&rfis===0&&<span style={{color:"var(--green)",fontSize:13}}></span>}</td></tr>);})}</tbody></table></div>
    {showNewJob && (
      <NewJobModal jobs={jobs} directory={directory||[]} masterDocLib={masterDocLib||[]} masterSubs={masterSubs||[]} onClose={()=>setShowNewJob(false)} onSave={data=>{
        onAdd(data);
        setShowNewJob(false);
      }}/>
    )}
  </div>);
};



