// --- SCHEDULE HELPERS ---------------------------------------------------------
const parseDate  = d => new Date(d+"T12:00:00");
const dateDiff   = (a,b) => Math.round((parseDate(b)-parseDate(a))/86400000);
const dateAdd    = (d,n) => { const dt=parseDate(d); dt.setDate(dt.getDate()+n); return dt.toISOString().split("T")[0]; };
const fmtShort   = d => new Date(d+"T12:00:00").toLocaleDateString("en-US",{month:"short",day:"numeric"});
const weekOf     = d => { const dt=parseDate(d); dt.setDate(dt.getDate()-dt.getDay()); return dt.toISOString().split("T")[0]; };
const isoWeek    = d => weekOf(d);

// Get all weeks between two dates
const getWeeks = (start, end) => {
  const weeks = [];
  let cur = weekOf(start);
  const endW = weekOf(end);
  while(cur <= endW) {
    weeks.push(cur);
    cur = dateAdd(cur, 7);
  }
  return weeks;
};

// Does an activity overlap a given week?
const actOverlapsWeek = (act, weekStart) => {
  const wEnd = dateAdd(weekStart, 6);
  return act.startDate <= wEnd && act.endDate >= weekStart;
};

// Status color
const statusColor = s => ({not_started:"var(--navy-light)",in_progress:"var(--accent)",complete:"var(--green)",delayed:"var(--red)"}[s]||"var(--navy-light)");
const statusLabel = s => ({not_started:"Not Started",in_progress:"In Progress",complete:"Complete",delayed:"Delayed"}[s]||s);



// --- SCHEDULE DASHBOARD -------------------------------------------------------
const ScheduleDashboard = ({activities, phases, jobs, logs}) => {
  const activeJobs = jobs.filter(j => j.phase === "Active" && !j.isTraining);

  // Per-job summaries
  const jobSummaries = activeJobs.map(job => {
    const jobActs = activities.filter(a => a.jobId === job.id);
    const total = jobActs.length;
    const completed = jobActs.filter(a => a.status === "complete").length;
    const delayed = jobActs.filter(a => a.status === "delayed").length;
    const inProgress = jobActs.filter(a => a.status === "in_progress").length;
    const avgPct = total > 0 ? Math.round(jobActs.reduce((s,a) => s + a.percentComplete, 0) / total) : 0;
    const daysAtRisk = logs.filter(l => l.jobId === job.id)
      .flatMap(l => l.delays || [])
      .reduce((s,d) => s + (parseInt(d.impactDays) || 0), 0);
    const starts = jobActs.map(a => a.startDate).sort();
    const ends = jobActs.map(a => a.endDate).sort().reverse();
    const projStart = starts[0] || TODAY;
    const projEnd = ends[0] || TODAY;
    const totalSpan = Math.max(1, dateDiff(projStart, projEnd));
    const elapsed = Math.max(0, Math.min(totalSpan, dateDiff(projStart, TODAY)));
    const todayPct = Math.round((elapsed / totalSpan) * 100);
    const nextMs = jobActs
      .filter(a => a.isMilestone && a.status !== "complete" && a.endDate >= TODAY)
      .sort((a,b) => a.endDate.localeCompare(b.endDate))[0];
    const critDelays = logs.filter(l => l.jobId === job.id)
      .flatMap(l => l.delays || [])
      .filter(d => d.criticalPath).length;
    return {job, total, completed, delayed, inProgress, avgPct, daysAtRisk, projStart, projEnd, todayPct, nextMs, critDelays};
  });

  // Cross-project summary
  const totalDelayed = jobSummaries.reduce((s,j) => s + j.delayed, 0);
  const totalDaysAtRisk = jobSummaries.reduce((s,j) => s + j.daysAtRisk, 0);
  const totalCritical = jobSummaries.reduce((s,j) => s + j.critDelays, 0);

  // Crew conflicts this week
  const startWk = weekOf(TODAY);
  const crewConflicts = TEAM.filter(t => t.field).filter(t => {
    const byJob = {};
    activities.filter(a => a.westroeAssignees.includes(t.id) && actOverlapsWeek(a, startWk))
      .forEach(a => { byJob[a.jobId] = 1; });
    return Object.keys(byJob).length >= 2;
  }).length;

  // Upcoming milestones (all projects, next 30 days)
  const msEnd = dateAdd(TODAY, 30);
  const upcomingMs = activities
    .filter(a => a.isMilestone && a.endDate >= TODAY && a.endDate <= msEnd && a.status !== "complete")
    .sort((a,b) => a.endDate.localeCompare(b.endDate));

  // All delayed activities
  const delayedActs = activities
    .filter(a => a.status === "delayed")
    .sort((a,b) => a.endDate.localeCompare(b.endDate));

  // RFIs from logs that affect schedule
  const schedRFIs = logs.flatMap(l => (l.rfis || [])
    .filter(r => r.scheduleActivity && r.requiredBy)
    .map(r => ({...r, jobId: l.jobId, logDate: l.date})))
    .sort((a,b) => a.requiredBy.localeCompare(b.requiredBy));

  const c = (val, warn, bad) => val >= bad ? "var(--red)" : val >= warn ? "var(--yellow)" : "var(--green)";

  return (
    <div>
      {/* Summary strip */}
      <div className="sdash-summary">
        {[
          {l:"Active Projects",   v:activeJobs.length,   c:"var(--accent-bright)", sub:""},
          {l:"Delayed Activities",v:totalDelayed,         c:c(totalDelayed,1,3),    sub:totalCritical>0?totalCritical+" critical path":""},
          {l:"Days at Risk",      v:totalDaysAtRisk,      c:c(totalDaysAtRisk,5,14),sub:"across all projects"},
          {l:"Crew Conflicts",    v:crewConflicts,        c:crewConflicts>0?"var(--red)":"var(--green)",sub:crewConflicts>0?"this week":"No conflicts this week"},
        ].map(s => (
          <div key={s.l} className="sdash-summary-card">
            <div className="stat-label">{s.l}</div>
            <div style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:24,fontWeight:500,color:s.c,marginBottom:2}}>{s.v}</div>
            {s.sub && <div style={{fontSize:11,color:"var(--muted)"}}>{s.sub}</div>}
          </div>
        ))}
      </div>

      {/* Alerts */}
      {totalCritical > 0 && (
        <div className="alert-bar alert-red" style={{marginBottom:14}}>
          <span></span>
          <span><strong>{totalCritical} critical path delay{totalCritical>1?"s":""}</strong> logged across active projects.</span>
        </div>
      )}
      {crewConflicts > 0 && (
        <div className="alert-bar alert-yellow" style={{marginBottom:14}}>
          <span></span>
          <span><strong>{crewConflicts} crew member{crewConflicts>1?"s":""}</strong> assigned to multiple projects this week. Check Resource Dashboard.</span>
        </div>
      )}

      {/* Per-project cards */}
      <div className="sdash-grid">
        {jobSummaries.map(({job, total, completed, delayed, inProgress, avgPct, daysAtRisk, projStart, projEnd, todayPct, nextMs, critDelays}) => (
          <div key={job.id} className="sdash-card">
            <div className="sdash-card-hdr">
              <div>
                <div className="sdash-job-name">{job.name}</div>
                <div className="sdash-job-meta">{job.id}   {job.client}</div>
              </div>
              <div style={{textAlign:"right"}}>
                <Pill s={job.phase}/>
                {delayed > 0 && (
                  <div style={{marginTop:4}}>
                    <span className="flag flag-yellow" style={{fontSize:10}}>
                      <span className="flag-dot"/>{delayed} delayed
                    </span>
                  </div>
                )}
              </div>
            </div>
            <div className="sdash-body">
              {/* Progress bar */}
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:6}}>
                <span style={{fontSize:12,color:"var(--muted)"}}>Overall Progress</span>
                <span style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:13,color:avgPct>=70?"var(--green)":avgPct>=40?"var(--accent-bright)":"var(--muted)"}}>{avgPct}%</span>
              </div>
              <div style={{height:8,background:"var(--navy-light)",borderRadius:4,overflow:"hidden",marginBottom:4}}>
                <div style={{height:"100%",width:avgPct+"%",background:avgPct>=70?"var(--green)":"var(--accent)",borderRadius:4,transition:"width .4s"}}/>
              </div>

              {/* Timeline */}
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:2}}>
                <span style={{fontSize:10,color:"var(--muted)",fontFamily:"'IBM Plex Mono',monospace"}}>{fmtShort(projStart)}</span>
                <span style={{fontSize:10,color:"var(--muted)",fontFamily:"'IBM Plex Mono',monospace"}}>{fmtShort(projEnd)}</span>
              </div>
              <div className="sdash-timeline">
                <div className="sdash-timeline-done" style={{width:todayPct+"%"}}/>
                <div className="sdash-timeline-today" style={{left:todayPct+"%"}}/>
              </div>

              {/* Stats */}
              <div className="sdash-stats">
                {[
                  {l:"Complete",  v:completed+"/"+total, c:completed===total?"var(--green)":"var(--white)"},
                  {l:"In Progress",v:inProgress,          c:"var(--accent-bright)"},
                  {l:"Delayed",   v:delayed,              c:delayed>0?"var(--yellow)":"var(--green)"},
                  {l:"Days at Risk",v:daysAtRisk,         c:daysAtRisk>0?"var(--red)":"var(--green)"},
                ].map(s => (
                  <div key={s.l} className="sdash-stat">
                    <div className="sdash-stat-val" style={{color:s.c}}>{s.v}</div>
                    <div className="sdash-stat-lbl">{s.l}</div>
                  </div>
                ))}
              </div>

              {/* Next milestone */}
              {nextMs && (
                <div className="sdash-ms-chip">
                   {nextMs.name} - {fmtShort(nextMs.endDate)}
                </div>
              )}
            </div>
          </div>
        ))}
      </div>

      {/* Delayed + Milestones panels */}
      <div className="sdash-panels">
        <div className="sdash-panel">
          <div className="sdash-panel-hdr">
            <span style={{color:"var(--yellow)"}}>Delayed Activities</span>
            <span style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:12,color:"var(--muted)"}}>{delayedActs.length}</span>
          </div>
          {delayedActs.length === 0 ? (
            <div className="empty" style={{padding:20}}>No delayed activities</div>
          ) : delayedActs.map(function(act){
            const job = jobs.find(j => j.id === act.jobId);
            const ph = phases.find(p => p.id === act.phaseId);
            const logDelays = logs.filter(l => l.jobId === act.jobId)
              .flatMap(l => l.delays || [])
              .filter(d => d.scheduleActivity && d.scheduleActivity.trim().toLowerCase() === act.name.trim().toLowerCase());
            const totalImpact = logDelays.reduce((s,d) => s+(parseInt(d.impactDays)||0), 0);
            return (
              <div key={act.id} className="sdash-row">
                <div style={{width:3,background:"var(--yellow)",borderRadius:2,alignSelf:"stretch",flexShrink:0}}/>
                <div className="sdash-row-main">
                  <div className="sdash-row-name">{act.name}</div>
                  <div className="sdash-row-meta">{job ? job.name : ""}{ph ? "   "+ph.name : ""}</div>
                  {totalImpact > 0 && (
                    <div style={{marginTop:3}}>
                      <span className="flag flag-yellow" style={{fontSize:10}}>{totalImpact}d impact from logs</span>
                    </div>
                  )}
                </div>
                <div style={{textAlign:"right",flexShrink:0}}>
                  <div style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:11,color:"var(--muted)"}}>{fmtShort(act.endDate)}</div>
                </div>
              </div>
            );
          })}
        </div>

        <div className="sdash-panel">
          <div className="sdash-panel-hdr">
            <span style={{color:"var(--yellow)"}}>Upcoming Milestones</span>
            <span style={{fontSize:10,color:"var(--muted)"}}>Next 30 days</span>
          </div>
          {upcomingMs.length === 0 ? (
            <div className="empty" style={{padding:20}}>No milestones in next 30 days</div>
          ) : upcomingMs.map(function(act){
            const job = jobs.find(j => j.id === act.jobId);
            const daysLeft = dateDiff(TODAY, act.endDate);
            return (
              <div key={act.id} className="sdash-row">
                <div style={{width:10,height:10,background:"var(--yellow)",transform:"rotate(45deg)",borderRadius:2,flexShrink:0,marginTop:3}}/>
                <div className="sdash-row-main">
                  <div className="sdash-row-name">{act.name}</div>
                  <div className="sdash-row-meta">{job ? job.name : ""}</div>
                </div>
                <div style={{textAlign:"right",flexShrink:0}}>
                  <div style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:11,color:daysLeft<=7?"var(--red)":daysLeft<=14?"var(--yellow)":"var(--muted)"}}>{fmtShort(act.endDate)}</div>
                  <div style={{fontSize:10,color:"var(--muted)",marginTop:1}}>{daysLeft}d</div>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* RFIs affecting schedule */}
      {schedRFIs.length > 0 && (
        <div className="sdash-panel">
          <div className="sdash-panel-hdr">
            <span style={{color:"var(--purple)"}}>RFIs Affecting Schedule</span>
            <span className="schedule-stub" style={{fontSize:9}}> RFI Tool (coming)</span>
          </div>
          {schedRFIs.map(r => {
            const job = jobs.find(j => j.id === r.jobId);
            const daysLeft = dateDiff(TODAY, r.requiredBy);
            return (
              <div key={r.id} className="sdash-row">
                <div className="sdash-row-main">
                  <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:3}}>
                    <span className="rfi-draft">{r.num}</span>
                    <span className="sdash-row-name" style={{fontSize:12}}>{r.title}</span>
                  </div>
                  <div className="sdash-row-meta">{job ? job.name : ""}{r.scheduleActivity ? "   "+r.scheduleActivity : ""}</div>
                </div>
                <div style={{textAlign:"right",flexShrink:0}}>
                  <div style={{fontSize:11,color:daysLeft<=3?"var(--red)":daysLeft<=7?"var(--yellow)":"var(--muted)",fontFamily:"'IBM Plex Mono',monospace"}}>Due {r.requiredBy}</div>
                  {daysLeft < 0 && <div style={{fontSize:10,color:"var(--red)"}}>OVERDUE</div>}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

// --- ACTIVITY MODAL (add / edit) ----------------------------------------------
const ActivityModal = ({phases, jobs, initial, onClose, onSave}) => {
  const blank = {
    jobId: jobs[0]?.id || "",
    phaseId: "",
    name: "",
    startDate: TODAY,
    endDate: dateAdd(TODAY, 7),
    status: "not_started",
    percentComplete: 0,
    isMilestone: false,
    westroeAssignees: [],
    subAssignees: [],
    notes: "",
  };
  const [f, setF] = useState(initial ? {...initial} : blank);
  const set = (k,v) => setF(p => ({...p, [k]:v}));
  const jobPhases = phases.filter(p => p.jobId === f.jobId);
  const fieldTeam = TEAM.filter(t => t.field);

  const toggleCrew = id => set("westroeAssignees",
    f.westroeAssignees.includes(id)
      ? f.westroeAssignees.filter(x => x !== id)
      : [...f.westroeAssignees, id]
  );

  const [subInput, setSubInput] = useState("");
  const addSub = () => {
    if(subInput.trim() && !f.subAssignees.includes(subInput.trim())) {
      set("subAssignees", [...f.subAssignees, subInput.trim()]);
    }
    setSubInput("");
  };
  const removeSub = s => set("subAssignees", f.subAssignees.filter(x => x !== s));

  const canSave = f.name.trim() && f.phaseId && f.startDate && f.endDate;

  return (
    <div className="overlay" onClick={onClose}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <div className="modal-hdr">
          <div>
            <div className="modal-title">{initial ? "Edit Activity" : "Add Activity"}</div>
          </div>
          <button className="btn btn-ghost btn-sm" onClick={onClose}></button>
        </div>
        <div style={{padding:"16px 20px",display:"flex",flexDirection:"column",gap:12,maxHeight:"75vh",overflowY:"auto"}}>
          <div className="frow">
            <div>
              <div className="flabel">Project</div>
              <select className="fselect" value={f.jobId} onChange={e => {set("jobId",e.target.value);set("phaseId","");}}>
                {jobs.map(j => <option key={j.id} value={j.id}>{j.name}</option>)}
              </select>
            </div>
            <div>
              <div className="flabel">Phase</div>
              <select className="fselect" value={f.phaseId} onChange={e => set("phaseId",e.target.value)}>
                <option value="">- Select Phase -</option>
                {jobPhases.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
            </div>
          </div>
          <div>
            <div className="flabel">Activity Name</div>
            <input className="finput" value={f.name} onChange={e => set("name",e.target.value)} placeholder="e.g. Electrical Rough-In"/>
          </div>
          <div className="frow">
            <div>
              <div className="flabel">Start Date</div>
              <input className="finput" type="date" value={f.startDate} onChange={e => set("startDate",e.target.value)}/>
            </div>
            <div>
              <div className="flabel">End Date</div>
              <input className="finput" type="date" value={f.endDate} onChange={e => set("endDate",e.target.value)}/>
            </div>
          </div>
          <div className="frow">
            <div>
              <div className="flabel">Status</div>
              <select className="fselect" value={f.status} onChange={e => set("status",e.target.value)}>
                {STATUS_OPTS.map(s => <option key={s.v} value={s.v}>{s.l}</option>)}
              </select>
            </div>
            <div>
              <div className="flabel">% Complete</div>
              <input className="finput" type="number" min="0" max="100" value={f.percentComplete}
                onChange={e => set("percentComplete", Math.min(100,Math.max(0,parseInt(e.target.value)||0)))}/>
            </div>
          </div>
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            <input type="checkbox" checked={f.isMilestone} onChange={e => set("isMilestone",e.target.checked)} style={{accentColor:"var(--yellow)"}}/>
            <label style={{fontSize:13,color:"var(--white)",cursor:"pointer"}}>Mark as Milestone </label>
          </div>
          <div style={{borderTop:"1px solid var(--navy-border)",paddingTop:12}}>
            <div style={{fontSize:10,color:"var(--muted)",fontFamily:"'Barlow Condensed',sans-serif",letterSpacing:2,textTransform:"uppercase",marginBottom:8}}>Resources <span style={{color:"var(--muted)",fontSize:9,letterSpacing:1}}>OPTIONAL</span></div>
            <div className="flabel" style={{marginBottom:6}}>Westroe Crew</div>
            <div style={{display:"flex",flexWrap:"wrap",gap:4,marginBottom:10}}>
              {fieldTeam.map(t => {
                const sel = f.westroeAssignees.includes(t.id);
                return (
                  <button key={t.id} className={"chip"+(sel?" selected":"")} onClick={() => toggleCrew(t.id)}>
                    {sel?" ":""}{t.name.split(" ")[0]}
                  </button>
                );
              })}
            </div>
            <div className="flabel" style={{marginBottom:6}}>Subcontractors</div>
            <div style={{display:"flex",gap:4,flexWrap:"wrap",marginBottom:8}}>
              {f.subAssignees.map(s => (
                <span key={s} style={{display:"inline-flex",alignItems:"center",gap:4,padding:"2px 8px",borderRadius:4,background:"var(--blue-dim)",color:"var(--muted)",fontSize:12,border:"1px solid rgba(42,64,128,.4)"}}>
                  {s}<button onClick={() => removeSub(s)} style={{background:"none",border:"none",color:"var(--muted)",cursor:"pointer",padding:0,fontSize:12}}></button>
                </span>
              ))}
            </div>
            <div style={{display:"flex",gap:8}}>
              <input className="finput" value={subInput} onChange={e => setSubInput(e.target.value)}
                onKeyDown={e => {if(e.key==="Enter") addSub();}}
                placeholder="Type sub name + Enter"/>
              <button className="btn btn-ghost btn-sm" onClick={addSub}>Add</button>
            </div>
          </div>
          <div>
            <div className="flabel">Notes</div>
            <textarea className="ftextarea" rows={2} value={f.notes} onChange={e => set("notes",e.target.value)} placeholder="Optional notes"/>
          </div>
        </div>
        <div className="modal-ftr">
          {initial && (
            <button className="btn btn-ghost" style={{color:"var(--red)",marginRight:"auto"}}
              onClick={() => { onSave(null, "delete"); }}>
              Delete
            </button>
          )}
          <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" disabled={!canSave} style={{opacity:canSave?1:.5}}
            onClick={() => { if(canSave) onSave({...f, id: initial?.id || uid()}); }}>
            {initial ? "Save Changes" : "Add Activity"}
          </button>
        </div>
      </div>
    </div>
  );
};

// --- PHASE MODAL --------------------------------------------------------------
