// --- COST IMPACT ANALYSIS COMPONENT -----------------------------------------
const IMPACT_STYLES = {
  "Potential Add":    {cls:"cost-impact-add", icon:"+ ADD"},
  "Potential Deduct": {cls:"cost-impact-ded", icon:"- DEDUCT"},
  "Neutral":          {cls:"cost-impact-neu", icon:"NEUTRAL"},
  "Unclear":          {cls:"cost-impact-unc", icon:"? UNCLEAR"},
};

const CostAnalysisPanel = ({analysis, onRerun, loading}) => {
  if(loading) {
    return (
      <div className="cost-panel">
        <div className="cost-panel-hdr">
          <span className="cost-panel-title">Analyzing Cost Impact...</span>
          <span className="spinner" style={{width:14,height:14,borderWidth:2}}/>
        </div>
      </div>
    );
  }
  if(!analysis) return null;

  const style = IMPACT_STYLES[analysis.direction] || IMPACT_STYLES["Unclear"];

  return (
    <div className="cost-panel">
      <div className="cost-panel-hdr">
        <span className="cost-panel-title">Cost Impact Analysis</span>
        <div style={{display:"flex",alignItems:"center",gap:8}}>
          <span className={style.cls}>{style.icon}</span>
          <span style={{fontSize:11,color:"var(--muted)",fontFamily:"'Barlow Condensed'",letterSpacing:1}}>{analysis.magnitude}</span>
          {onRerun && <button className="btn btn-ghost btn-sm" onClick={onRerun} style={{fontSize:10}}>Re-run</button>}
        </div>
      </div>
      <div className="cost-body">
        {analysis.affectedCategories && analysis.affectedCategories.length > 0 && (
          <div style={{marginBottom:10}}>
            <div className="drw-detail-label">Affected Budget Categories</div>
            <div>{analysis.affectedCategories.map(c => <span key={c} className="cost-category-tag">{c}</span>)}</div>
          </div>
        )}
        {analysis.narrative && (
          <div style={{marginBottom:10}}>
            <div className="drw-detail-label">Analysis</div>
            <div style={{fontSize:13,color:"var(--white)",lineHeight:1.6}}>{analysis.narrative}</div>
          </div>
        )}
        {analysis.recommendedAction && (
          <div style={{padding:"8px 12px",background:"rgba(74,124,220,.08)",border:"1px solid rgba(74,124,220,.2)",borderRadius:6}}>
            <div className="drw-detail-label" style={{marginBottom:3}}>Recommended Action</div>
            <div style={{fontSize:13,color:"var(--accent-bright)"}}>{analysis.recommendedAction}</div>
          </div>
        )}
        <div style={{fontSize:10,color:"var(--muted)",marginTop:8,fontFamily:"'IBM Plex Mono',monospace"}}>
          Analyzed {fmtDate(analysis.date)}   Claude Sonnet
        </div>
      </div>
    </div>
  );
};

const runCostAnalysis = async (title, description, jobBudget, extraContext) => {
  const budgetSummary = jobBudget
    ? jobBudget.map(b => b.category+": budgeted $"+b.budgeted.toLocaleString()+", actual $"+b.actual.toLocaleString()).join("; ")
    : "No budget data available";

  const prompt = [
    "You are a construction cost analyst for Westroe Construction (GC).",
    "Analyze the following item and determine its likely cost impact.",
    "",
    "ITEM: "+title,
    "DESCRIPTION: "+(description||"No description provided"),
    extraContext ? "ADDITIONAL CONTEXT: "+extraContext : "",
    "",
    "CURRENT JOB BUDGET CATEGORIES:",
    budgetSummary,
    "",
    "Return ONLY valid JSON:",
    "{",
    "  direction: 'Potential Add' | 'Potential Deduct' | 'Neutral' | 'Unclear',",
    "  magnitude: 'Minor' | 'Moderate' | 'Significant',",
    "  affectedCategories: [array of budget category names likely affected],",
    "  narrative: 'explanation of cost reasoning in 2-3 sentences',",
    "  recommendedAction: 'Issue CO now' | 'Hold pending answer' | 'No action needed' | 'Monitor'",
    "}"
  ].join("\n");

  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: {"Content-Type":"application/json"},
    body: JSON.stringify({
      model: "claude-sonnet-4-20250514",
      max_tokens: 600,
      system: "You are a construction cost analyst. Return ONLY valid JSON, no markdown.",
      messages: [{role:"user", content:prompt}]
    })
  });
  const data = await res.json();
  if(data.error) throw new Error(data.error.message);
  const text = data.content.filter(b => b.type==="text").map(b => b.text).join("");
  const cleaned = text.split("```json").join("").split("```").join("").trim();
  return {...JSON.parse(cleaned), date: TODAY};
};


