// --- SHEET DETAIL PANEL -------------------------------------------------------
const SheetDetailPanel = ({sheet, allRfis, jobs, onUpdate}) => {
  const job = jobs.find(j => j.id === sheet.jobId);
  const currentRev = sheet.revisions.find(r => r.isCurrent) || sheet.revisions[sheet.revisions.length-1];
  const linkedRfis = allRfis.filter(r => sheet.rfiIds.includes(r.id));
  const inputRef = useRef();

  const handleUpload = async (e) => {
    const file = e.target.files[0];
    if(!file) return;
    const b64 = await readFile(file);
    onUpdate({...sheet, pdfBase64: b64, pdfName: file.name});
    e.target.value = "";
  };

  const addRevision = () => {
    const maxRev = sheet.revisions.reduce((m,r) => Math.max(m,parseInt(r.rev)||0), 0);
    const newRev = {rev:String(maxRev+1), date:TODAY, note:"", isCurrent:true};
    const revisions = sheet.revisions.map(r => ({...r, isCurrent:false})).concat(newRev);
    onUpdate({...sheet, revisions});
  };

  const updateRevNote = (rev, note) => {
    onUpdate({...sheet, revisions: sheet.revisions.map(r => r.rev===rev ? {...r,note} : r)});
  };

  return (
    <div className="drw-detail">
      <div className="drw-detail-section">
        <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:8}}>
          <div>
            <div style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:13,color:"var(--accent-bright)",marginBottom:2}}>{sheet.sheetNum}</div>
            <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:20,fontWeight:700,color:"var(--white)"}}>{sheet.title}</div>
            <div style={{fontSize:12,color:"var(--muted)",marginTop:2}}>{job ? job.name : ""}   {sheet.discipline}</div>
          </div>
          <span className="rev-badge rev-badge-current">Rev {currentRev.rev} - Current</span>
        </div>
      </div>

      {/* PDF viewer / upload */}
      <div className="drw-detail-section">
        <div className="drw-detail-label">Drawing File</div>
        {sheet.pdfBase64 ? (
          <div>
            <div style={{fontSize:12,color:"var(--green)",marginBottom:8}}>{sheet.pdfName || "Drawing uploaded"}</div>
            <embed src={sheet.pdfBase64} type="application/pdf" className="drw-pdf-frame"/>
            <div className="markup-placeholder" style={{marginTop:10}}>
              <div style={{fontSize:12,color:"var(--purple)",fontFamily:"'Barlow Condensed'",letterSpacing:1,textTransform:"uppercase",marginBottom:4}}>
                Markup Tools - Web App Phase
              </div>
              <div style={{fontSize:11,color:"var(--muted)"}}>Bluebeam-style annotation, pin placement, and RFI linking on drawing will be available when the platform moves to web.</div>
            </div>
          </div>
        ) : (
          <div className="drw-upload-zone" onClick={() => inputRef.current && inputRef.current.click()}>
            <div style={{fontSize:22,opacity:.5,marginBottom:6}}></div>
            <div style={{fontFamily:"'Barlow Condensed'",fontSize:12,letterSpacing:1,color:"var(--accent-bright)"}}>Upload Drawing PDF</div>
          </div>
        )}
        <input ref={inputRef} type="file" accept=".pdf" style={{display:"none"}} onChange={handleUpload}/>
      </div>

      {/* Revision history */}
      <div className="drw-detail-section">
        <div className="drw-detail-label" style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}>
          <span>Revision History</span>
          <button className="btn btn-ghost btn-sm" onClick={addRevision}>+ Add Rev</button>
        </div>
        {[...sheet.revisions].reverse().map(r => (
          <div key={r.rev} style={{display:"flex",alignItems:"center",gap:10,padding:"7px 0",borderBottom:"1px solid rgba(42,64,128,.2)"}}>
            <span className={"rev-badge"+(r.isCurrent?" rev-badge-current":" rev-badge-superseded")}>Rev {r.rev}</span>
            <span style={{fontSize:11,color:"var(--muted)",fontFamily:"'IBM Plex Mono',monospace"}}>{r.date}</span>
            <input className="finput" value={r.note} onChange={e => updateRevNote(r.rev, e.target.value)}
              placeholder="Revision note..." style={{flex:1,fontSize:12,padding:"4px 8px"}}/>
            {r.isCurrent && <span style={{fontSize:10,color:"var(--green)",fontFamily:"'Barlow Condensed'",letterSpacing:1}}>CURRENT</span>}
          </div>
        ))}
      </div>

      {/* Linked RFIs */}
      <div className="drw-detail-section">
        <div className="drw-detail-label">Linked RFIs ({linkedRfis.length})</div>
        {linkedRfis.length === 0 ? (
          <div style={{fontSize:12,color:"var(--muted)"}}>No RFIs reference this sheet.</div>
        ) : linkedRfis.map(r => (
          <div key={r.id} style={{display:"flex",alignItems:"center",gap:8,padding:"6px 0",borderBottom:"1px solid rgba(42,64,128,.2)"}}>
            <span className="rfi-number">{r.rfiNumber ? "RFI-"+r.rfiNumber : "DRAFT"}</span>
            <span style={{fontSize:13,color:"var(--white)"}}>{r.title}</span>
            <span className={"rfi-status-pill "+rfiStatusCls(r.status)} style={{marginLeft:"auto"}}>{rfiStatusLabel(r.status)}</span>
          </div>
        ))}
      </div>
    </div>
  );
};

// --- ASI / BULLETIN DETAIL ----------------------------------------------------
const AsiDetail = ({item, type, job, allRfis, onUpdate}) => {
  const [analyzing, setAnalyzing] = useState(false);
  const [error, setError]         = useState(null);
  const inputRef = useRef();

  const handleUpload = async (e) => {
    const file = e.target.files[0];
    if(!file) return;
    const b64 = await readFile(file);
    onUpdate({...item, pdfBase64:b64, pdfName:file.name});
    e.target.value = "";
  };

  const analyze = async () => {
    setAnalyzing(true); setError(null);
    try {
      const budget = job ? job.budget : null;
      const context = "Affected sheets: "+(item.affectedSheets||[]).join(", ")+
        ". Issuer: "+(item.issuer||"Unknown")+
        ". Status: "+item.status;
      const result = await runCostAnalysis(item.title, item.description, budget, context);
      onUpdate({...item, costAnalysis:result});
    } catch(err) {
      setError("Analysis failed: "+err.message);
    }
    setAnalyzing(false);
  };

  const linkedRfis = allRfis.filter(r => (item.rfiIds||[]).includes(r.id));
  const statusColor = {
    "Issued":"var(--accent-bright)","Under Review":"var(--yellow)",
    "Incorporated":"var(--green)","CO Pending":"var(--orange)"
  }[item.status] || "var(--muted)";

  return (
    <div className="drw-detail">
      <div className="drw-detail-section">
        <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:8}}>
          <div>
            <div style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:13,color:"var(--accent-bright)",marginBottom:2}}>{item.number}</div>
            <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:18,fontWeight:700,color:"var(--white)"}}>{item.title}</div>
            <div style={{fontSize:12,color:"var(--muted)",marginTop:3}}>{fmtDate(item.date)}   Issued by {item.issuer}</div>
          </div>
          <span style={{fontSize:11,color:statusColor,fontFamily:"'Barlow Condensed'",letterSpacing:1,textTransform:"uppercase",background:statusColor+"22",border:"1px solid "+statusColor+"44",borderRadius:4,padding:"3px 8px"}}>{item.status}</span>
        </div>
        <div style={{fontSize:13,color:"var(--white)",lineHeight:1.6}}>{item.description}</div>
      </div>

      {/* Affected sheets */}
      {(item.affectedSheets||[]).length > 0 && (
        <div className="drw-detail-section">
          <div className="drw-detail-label">Affected Sheets</div>
          <div>{(item.affectedSheets||[]).map(s => <span key={s} className="cost-category-tag">{s}</span>)}</div>
        </div>
      )}

      {/* Status */}
      <div className="drw-detail-section">
        <div className="drw-detail-label">Status</div>
        <select className="fselect" style={{maxWidth:220}} value={item.status}
          onChange={e => onUpdate({...item, status:e.target.value})}>
          {ASI_STATUSES.map(s => <option key={s}>{s}</option>)}
        </select>
      </div>

      {/* Cost analysis */}
      <div className="drw-detail-section">
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8}}>
          <div className="drw-detail-label">Cost Impact</div>
          {!item.costAnalysis && !analyzing && (
            <button className="btn btn-ai btn-sm" onClick={analyze}>Analyze Cost Impact</button>
          )}
        </div>
        {error && <div style={{fontSize:12,color:"var(--red)",marginBottom:8}}>{error}</div>}
        <CostAnalysisPanel
          analysis={item.costAnalysis}
          loading={analyzing}
          onRerun={item.costAnalysis ? analyze : null}
        />
        {!item.costAnalysis && !analyzing && (
          <div style={{fontSize:12,color:"var(--muted)"}}>
            Click "Analyze Cost Impact" to have Claude cross-reference this {type} against the job budget and flag likely cost implications.
          </div>
        )}
      </div>

      {/* PDF */}
      <div className="drw-detail-section">
        <div className="drw-detail-label">Document</div>
        {item.pdfBase64 ? (
          <div>
            <div style={{fontSize:12,color:"var(--green)",marginBottom:8}}>{item.pdfName}</div>
            <embed src={item.pdfBase64} type="application/pdf" className="drw-pdf-frame"/>
          </div>
        ) : (
          <div className="drw-upload-zone" onClick={() => inputRef.current && inputRef.current.click()}>
            <div style={{fontFamily:"'Barlow Condensed'",fontSize:12,letterSpacing:1,color:"var(--accent-bright)"}}>Upload {type} PDF</div>
          </div>
        )}
        <input ref={inputRef} type="file" accept=".pdf" style={{display:"none"}} onChange={handleUpload}/>
      </div>

      {/* Linked RFIs */}
      {linkedRfis.length > 0 && (
        <div className="drw-detail-section">
          <div className="drw-detail-label">Linked RFIs</div>
          {linkedRfis.map(r => (
            <div key={r.id} style={{display:"flex",alignItems:"center",gap:8,padding:"6px 0",borderBottom:"1px solid rgba(42,64,128,.2)"}}>
              <span className="rfi-number">{r.rfiNumber ? "RFI-"+r.rfiNumber : "DRAFT"}</span>
              <span style={{fontSize:13,color:"var(--white)"}}>{r.title}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

// --- PERMIT SET TAB -----------------------------------------------------------
const PermitSetTab = ({sheets, jobs, allRfis, jobFilter, onUpdateSheet, onAddSheet}) => {
  const [selId, setSelId]   = useState(null);
  const [filterDisc, setFilterDisc] = useState("all");
  const [showAdd, setShowAdd] = useState(false);
  const [addForm, setAddForm] = useState({jobId:jobs[0]?.id||"",discipline:"Architectural",sheetNum:"",title:""});
  const inputRef = useRef();

  const filtered = sheets
    .filter(s => {
      if(jobFilter!=="all" && s.jobId!==jobFilter) return false;
      if(filterDisc!=="all" && s.discipline!==filterDisc) return false;
      return true;
    })
    .sort((a,b) => a.sheetNum.localeCompare(b.sheetNum));

  const byDisc = DRW_DISCIPLINES.map(d => ({
    disc:d,
    sheets:filtered.filter(s => s.discipline===d)
  })).filter(g => g.sheets.length > 0);

  const selSheet = sheets.find(s => s.id===selId);

  const handleAdd = () => {
    if(!addForm.sheetNum.trim()||!addForm.title.trim()) return;
    const newSheet = {
      id:"ds"+uid(), jobId:addForm.jobId, discipline:addForm.discipline,
      sheetNum:addForm.sheetNum, title:addForm.title,
      revisions:[{rev:"0",date:TODAY,note:"Permit Issue",isCurrent:true}],
      supersededBy:null, rfiIds:[], linkedPunchIds:[], pdfBase64:null,
    };
    onAddSheet(newSheet);
    setShowAdd(false);
    setAddForm({jobId:jobs[0]?.id||"",discipline:"Architectural",sheetNum:"",title:""});
  };

  return (
    <div>
      <div style={{display:"flex",gap:10,marginBottom:12,alignItems:"flex-end",flexWrap:"wrap"}}>
        <div>
          <div className="flabel">Discipline</div>
          <select className="fselect" value={filterDisc} onChange={e => setFilterDisc(e.target.value)}>
            <option value="all">All Disciplines</option>
            {DRW_DISCIPLINES.map(d => <option key={d}>{d}</option>)}
          </select>
        </div>
        <div style={{marginLeft:"auto"}}>
          <button className="btn btn-primary" onClick={() => setShowAdd(!showAdd)}>+ Add Sheet</button>
        </div>
      </div>

      {showAdd && (
        <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:16,marginBottom:12}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 100px 1fr",gap:10,marginBottom:10}}>
            <div><div className="flabel">Project</div><select className="fselect" value={addForm.jobId} onChange={e => setAddForm(p=>({...p,jobId:e.target.value}))}>{jobs.map(j=><option key={j.id} value={j.id}>{j.name}</option>)}</select></div>
            <div><div className="flabel">Discipline</div><select className="fselect" value={addForm.discipline} onChange={e => setAddForm(p=>({...p,discipline:e.target.value}))}>{DRW_DISCIPLINES.map(d=><option key={d}>{d}</option>)}</select></div>
            <div><div className="flabel">Sheet #</div><input className="finput" value={addForm.sheetNum} onChange={e => setAddForm(p=>({...p,sheetNum:e.target.value}))} placeholder="A-201"/></div>
            <div><div className="flabel">Title</div><input className="finput" value={addForm.title} onChange={e => setAddForm(p=>({...p,title:e.target.value}))} placeholder="Floor Plan..."/></div>
          </div>
          <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
            <button className="btn btn-ghost" onClick={() => setShowAdd(false)}>Cancel</button>
            <button className="btn btn-primary" onClick={handleAdd}>Add Sheet</button>
          </div>
        </div>
      )}

      <div style={{display:"grid",gridTemplateColumns:selSheet?"280px 1fr":"1fr",gap:0,border:"1px solid var(--navy-border)",borderRadius:8,overflow:"hidden",minHeight:400}}>
        <div style={{borderRight:selSheet?"1px solid var(--navy-border)":"none",overflowY:"auto"}}>
          {byDisc.length === 0 ? (
            <div className="empty" style={{padding:40}}>No sheets match filters</div>
          ) : byDisc.map(({disc, sheets:dSheets}) => (
            <div key={disc}>
              <div className="drw-sidebar-hdr">{disc} ({dSheets.length})</div>
              {dSheets.map(s => {
                const curRev = s.revisions.find(r => r.isCurrent) || s.revisions[s.revisions.length-1];
                return (
                  <div key={s.id} className={"drw-sheet-row"+(selId===s.id?" selected":"")} onClick={() => setSelId(selId===s.id?null:s.id)}>
                    <div className="drw-sheet-num">{s.sheetNum}</div>
                    <div className="drw-sheet-title">{s.title}</div>
                    <div style={{display:"flex",alignItems:"center",gap:6,marginTop:3}}>
                      <span className="drw-sheet-rev">Rev {curRev.rev}</span>
                      {s.rfiIds.length>0 && <span className="flag flag-purple" style={{fontSize:9,padding:"1px 5px"}}>RFI</span>}
                      {s.pdfBase64 && <span style={{fontSize:9,color:"var(--green)",fontFamily:"'Barlow Condensed'",letterSpacing:1}}>PDF</span>}
                    </div>
                  </div>
                );
              })}
            </div>
          ))}
        </div>
        {selSheet && (
          <div style={{overflowY:"auto"}}>
            <SheetDetailPanel sheet={selSheet} allRfis={allRfis} jobs={jobs} onUpdate={onUpdateSheet}/>
          </div>
        )}
      </div>
    </div>
  );
};

// --- ASI / BULLETIN TAB -------------------------------------------------------
const AsiBulletinTab = ({items, type, jobs, allRfis, jobFilter, onUpdate, onAdd}) => {
  const [selId, setSelId] = useState(null);
  const [showAdd, setShowAdd] = useState(false);
  const [f, setF] = useState({jobId:jobs[0]?.id||"",number:"",title:"",date:TODAY,issuer:"Architect",description:"",affectedSheets:[],status:"Issued"});
  const set = (k,v) => setF(p=>({...p,[k]:v}));
  const [sheetInput, setSheetInput] = useState("");

  const filtered = items
    .filter(i => jobFilter==="all" || i.jobId===jobFilter)
    .sort((a,b) => b.date.localeCompare(a.date));

  const sel = items.find(i => i.id===selId);
  const selJob = sel ? jobs.find(j=>j.id===sel.jobId) : null;

  const handleAdd = () => {
    if(!f.number.trim()||!f.title.trim()) return;
    onAdd({...f, id:type+uid(), costAnalysis:null, rfiIds:[], pdfBase64:null});
    setShowAdd(false);
    setF({jobId:jobs[0]?.id||"",number:"",title:"",date:TODAY,issuer:"Architect",description:"",affectedSheets:[],status:"Issued"});
  };

  const addSheet = () => {
    if(sheetInput.trim() && !f.affectedSheets.includes(sheetInput.trim())) {
      set("affectedSheets",[...f.affectedSheets,sheetInput.trim()]);
    }
    setSheetInput("");
  };

  return (
    <div>
      <div style={{display:"flex",justifyContent:"flex-end",marginBottom:12}}>
        <button className="btn btn-primary" onClick={() => setShowAdd(!showAdd)}>+ Add {type}</button>
      </div>
      {showAdd && (
        <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:16,marginBottom:12,display:"flex",flexDirection:"column",gap:12}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 100px 1fr 120px",gap:10}}>
            <div><div className="flabel">Project</div><select className="fselect" value={f.jobId} onChange={e=>set("jobId",e.target.value)}>{jobs.map(j=><option key={j.id} value={j.id}>{j.name}</option>)}</select></div>
            <div><div className="flabel">Number</div><input className="finput" value={f.number} onChange={e=>set("number",e.target.value)} placeholder={type==="ASI"?"ASI-001":"BUL-001"}/></div>
            <div><div className="flabel">Title</div><input className="finput" value={f.title} onChange={e=>set("title",e.target.value)} placeholder="Brief title..."/></div>
            <div><div className="flabel">Date</div><input className="finput" type="date" value={f.date} onChange={e=>set("date",e.target.value)}/></div>
          </div>
          <div className="frow">
            <div><div className="flabel">Issuer</div><input className="finput" value={f.issuer} onChange={e=>set("issuer",e.target.value)} placeholder="Architect, Engineer..."/></div>
            <div><div className="flabel">Status</div><select className="fselect" value={f.status} onChange={e=>set("status",e.target.value)}>{ASI_STATUSES.map(s=><option key={s}>{s}</option>)}</select></div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
            <div><div className="flabel">Assigned To (Architect / Engineer) <span style={{fontSize:9,color:"var(--muted)"}}>from directory</span></div>
              <ContactPicker directory={directory} value={f.assignedTo} onChange={function(c){set("assignedTo",c);}} placeholder="Select reviewer..."/>
            </div>
            <div><div className="flabel">Status</div><select className="fselect" value={f.status} onChange={e=>set("status",e.target.value)}>{SUB_STATUSES.map(s=><option key={s}>{s}</option>)}</select></div>
          </div>
          <div><div className="flabel">Description</div><textarea className="ftextarea" rows={2} value={f.description} onChange={e=>set("description",e.target.value)} placeholder="What does this document address..."/></div>
          <div>
            <div className="flabel" style={{marginBottom:6}}>Affected Sheets</div>
            <div style={{display:"flex",gap:4,flexWrap:"wrap",marginBottom:6}}>{f.affectedSheets.map(s=><span key={s} className="cost-category-tag">{s}<button onClick={()=>set("affectedSheets",f.affectedSheets.filter(x=>x!==s))} style={{background:"none",border:"none",color:"var(--muted)",cursor:"pointer",marginLeft:4}}>x</button></span>)}</div>
            <div style={{display:"flex",gap:8}}><input className="finput" value={sheetInput} onChange={e=>setSheetInput(e.target.value)} onKeyDown={e=>{if(e.key==="Enter")addSheet();}} placeholder="Sheet number + Enter..."/><button className="btn btn-ghost btn-sm" onClick={addSheet}>Add</button></div>
          </div>
          <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
            <button className="btn btn-ghost" onClick={()=>setShowAdd(false)}>Cancel</button>
            <button className="btn btn-primary" onClick={handleAdd}>Add {type}</button>
          </div>
        </div>
      )}
      <div style={{display:"grid",gridTemplateColumns:sel?"300px 1fr":"1fr",gap:0,border:"1px solid var(--navy-border)",borderRadius:8,overflow:"hidden",minHeight:400}}>
        <div style={{borderRight:sel?"1px solid var(--navy-border)":"none",overflowY:"auto"}}>
          {filtered.length===0 ? <div className="empty" style={{padding:40}}>No {type}s logged</div>
           : filtered.map(function(item){
            const hasAnalysis = !!item.costAnalysis;
            const impactStyle = hasAnalysis ? IMPACT_STYLES[item.costAnalysis.direction] : null;
            return (
              <div key={item.id} className={"asi-row"+(selId===item.id?" selected":"")} onClick={()=>setSelId(selId===item.id?null:item.id)}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
                  <div>
                    <div className="asi-number">{item.number}</div>
                    <div style={{fontSize:13,color:"var(--white)",fontWeight:600,margin:"2px 0"}}>{item.title}</div>
                    <div style={{fontSize:11,color:"var(--muted)",fontFamily:"'IBM Plex Mono',monospace"}}>{fmtDate(item.date)}   {item.issuer}</div>
                  </div>
                  <div style={{textAlign:"right",flexShrink:0,marginLeft:8}}>
                    {hasAnalysis && <div className={impactStyle.cls} style={{marginBottom:4}}>{impactStyle.icon}</div>}
                    <span style={{fontSize:10,color:({Issued:"var(--accent-bright)",Incorporated:"var(--green)","CO Pending":"var(--orange)","Under Review":"var(--yellow)"})[item.status]||"var(--muted)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>{item.status}</span>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
        {sel && (
          <div style={{overflowY:"auto"}}>
            <AsiDetail item={sel} type={type} job={selJob} allRfis={allRfis}
              onUpdate={updated => onUpdate(updated)}/>
          </div>
        )}
      </div>
    </div>
  );
};

// --- SUB COORDINATION TAB -----------------------------------------------------
const SubCoordTab = ({items, jobs, jobFilter, onUpdate, onAdd}) => {
  const [selId, setSelId] = useState(null);
  const [showAdd, setShowAdd] = useState(false);
  const [f, setF] = useState({jobId:jobs[0]?.id||"",trade:"",description:"",submittedDate:TODAY,approvalStatus:"Submitted",revision:"0",notes:""});
  const set = (k,v) => setF(p=>({...p,[k]:v}));
  const inputRef = useRef();

  const filtered = items.filter(i => jobFilter==="all"||i.jobId===jobFilter).sort((a,b)=>b.submittedDate.localeCompare(a.submittedDate));
  const sel = items.find(i=>i.id===selId);

  const statusColor = {
    "Submitted":"var(--accent-bright)","Approved":"var(--green)",
    "Approved as Noted":"var(--green)","Revise and Resubmit":"var(--yellow)","Rejected":"var(--red)"
  };

  const handleUpload = async (e) => {
    const file = e.target.files[0];
    if(!file||!sel) return;
    const b64 = await readFile(file);
    onUpdate({...sel,pdfBase64:b64,pdfName:file.name});
    e.target.value="";
  };

  return (
    <div>
      <div style={{display:"flex",justifyContent:"flex-end",marginBottom:12}}>
        <button className="btn btn-primary" onClick={()=>setShowAdd(!showAdd)}>+ Add Sub Coord Drawing</button>
      </div>
      {showAdd && (
        <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:16,marginBottom:12,display:"flex",flexDirection:"column",gap:10}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 80px",gap:10}}>
            <div><div className="flabel">Project</div><select className="fselect" value={f.jobId} onChange={e=>set("jobId",e.target.value)}>{jobs.map(j=><option key={j.id} value={j.id}>{j.name}</option>)}</select></div>
            <div><div className="flabel">Trade / Company</div><input className="finput" value={f.trade} onChange={e=>set("trade",e.target.value)} placeholder="Structural Steel, HVAC..."/></div>
            <div><div className="flabel">Rev</div><input className="finput" value={f.revision} onChange={e=>set("revision",e.target.value)} placeholder="0"/></div>
          </div>
          <div><div className="flabel">Description</div><input className="finput" value={f.description} onChange={e=>set("description",e.target.value)} placeholder="What does this drawing cover..."/></div>
          <div className="frow">
            <div><div className="flabel">Submitted Date</div><input className="finput" type="date" value={f.submittedDate} onChange={e=>set("submittedDate",e.target.value)}/></div>
            <div><div className="flabel">Status</div><select className="fselect" value={f.approvalStatus} onChange={e=>set("approvalStatus",e.target.value)}>{SUB_COORD_APPROVAL.map(s=><option key={s}>{s}</option>)}</select></div>
          </div>
          <div><div className="flabel">Notes</div><textarea className="ftextarea" rows={2} value={f.notes} onChange={e=>set("notes",e.target.value)} placeholder="Review notes, conditions..."/></div>
          <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
            <button className="btn btn-ghost" onClick={()=>setShowAdd(false)}>Cancel</button>
            <button className="btn btn-primary" onClick={()=>{if(f.trade.trim()){onAdd({...f,id:"sc"+uid(),approvedDate:null,pdfBase64:null});setShowAdd(false);}}}>Add</button>
          </div>
        </div>
      )}
      <div style={{display:"grid",gridTemplateColumns:sel?"300px 1fr":"1fr",gap:0,border:"1px solid var(--navy-border)",borderRadius:8,overflow:"hidden",minHeight:400}}>
        <div style={{borderRight:sel?"1px solid var(--navy-border)":"none",overflowY:"auto"}}>
          {filtered.length===0 ? <div className="empty" style={{padding:40}}>No sub coordination drawings</div>
           : filtered.map(item=>{
            const job = jobs.find(j=>j.id===item.jobId);
            return (
              <div key={item.id} className={"drw-sheet-row"+(selId===item.id?" selected":"")} onClick={()=>setSelId(selId===item.id?null:item.id)}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
                  <div>
                    <div style={{fontSize:13,color:"var(--white)",fontWeight:600,marginBottom:2}}>{item.trade}</div>
                    <div style={{fontSize:11,color:"var(--muted)",marginBottom:3}}>{item.description}</div>
                    <div style={{fontSize:10,color:"var(--muted)",fontFamily:"'IBM Plex Mono',monospace"}}>{job?job.id:""}   Rev {item.revision}   {fmtDate(item.submittedDate)}</div>
                  </div>
                  <span style={{fontSize:10,color:statusColor[item.approvalStatus]||"var(--muted)",fontFamily:"'Barlow Condensed'",letterSpacing:.5,flexShrink:0,marginLeft:8,textAlign:"right"}}>{item.approvalStatus}</span>
                </div>
              </div>
            );
          })}
        </div>
        {sel && (
          <div style={{overflowY:"auto",padding:16}}>
            <div className="drw-detail-section">
              <div style={{fontFamily:"'Barlow Condensed'",fontSize:18,fontWeight:700,color:"var(--white)",marginBottom:4}}>{sel.trade}</div>
              <div style={{fontSize:13,color:"var(--muted)",marginBottom:8}}>{sel.description}</div>
              <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
                <select className="fselect" style={{maxWidth:220}} value={sel.approvalStatus}
                  onChange={e=>{
                    const approved=["Approved","Approved as Noted"].includes(e.target.value);
                    onUpdate({...sel,approvalStatus:e.target.value,approvedDate:approved?TODAY:sel.approvedDate});
                  }}>
                  {SUB_COORD_APPROVAL.map(s=><option key={s}>{s}</option>)}
                </select>
                {sel.approvedDate && <span style={{fontSize:12,color:"var(--green)",fontFamily:"'IBM Plex Mono',monospace",padding:"8px 0"}}>Approved {fmtDate(sel.approvedDate)}</span>}
              </div>
            </div>
            <div className="drw-detail-section">
              <div className="drw-detail-label">Notes</div>
              <textarea className="ftextarea" rows={3} value={sel.notes} onChange={e=>onUpdate({...sel,notes:e.target.value})} placeholder="Review notes..."/>
            </div>
            <div className="drw-detail-section">
              <div className="drw-detail-label">Document</div>
              {sel.pdfBase64 ? (
                <div><div style={{fontSize:12,color:"var(--green)",marginBottom:8}}>{sel.pdfName}</div><embed src={sel.pdfBase64} type="application/pdf" className="drw-pdf-frame"/></div>
              ) : (
                <div className="drw-upload-zone" onClick={()=>inputRef.current&&inputRef.current.click()}>
                  <div style={{fontFamily:"'Barlow Condensed'",fontSize:12,letterSpacing:1,color:"var(--accent-bright)"}}>Upload Sub Coord Drawing PDF</div>
                </div>
              )}
              <input ref={inputRef} type="file" accept=".pdf" style={{display:"none"}} onChange={handleUpload}/>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

// --- DRAWING TOOL WRAPPER -----------------------------------------------------
const DrawingTool = ({jobs, rfis}) => {
  const [tab, setTab]         = useState("permit");
  const [jobFilter, setJobFilter] = useState("all");
  const [drawings, setDrawings]   = useState(initDrawings);

  const allRfis = rfis || [];

  const updateSheet = (updated) => setDrawings(p=>({...p,permitSheets:p.permitSheets.map(s=>s.id===updated.id?updated:s)}));
  const addSheet    = (s)       => setDrawings(p=>({...p,permitSheets:[...p.permitSheets,s]}));
  const updateAsi   = (updated) => setDrawings(p=>({...p,asis:p.asis.map(a=>a.id===updated.id?updated:a)}));
  const addAsi      = (a)       => setDrawings(p=>({...p,asis:[...p.asis,a]}));
  const updateBul   = (updated) => setDrawings(p=>({...p,bulletins:p.bulletins.map(b=>b.id===updated.id?updated:b)}));
  const addBul      = (b)       => setDrawings(p=>({...p,bulletins:[...p.bulletins,b]}));
  const updateSC    = (updated) => setDrawings(p=>({...p,subCoord:p.subCoord.map(s=>s.id===updated.id?updated:s)}));
  const addSC       = (s)       => setDrawings(p=>({...p,subCoord:[...p.subCoord,s]}));

  const pendingBuls = drawings.bulletins.filter(b=>["Issued","Under Review"].includes(b.status)).length;
  const pendingAsis = drawings.asis.filter(a=>["Issued","Under Review"].includes(a.status)).length;

  return (
    <div>
      <div style={{display:"flex",alignItems:"center",gap:0,marginBottom:16,borderBottom:"1px solid var(--navy-border)"}}>
        <div style={{display:"flex",flex:1}}>
          {[
            ["permit","Permit Set",null],
            ["asi","ASIs",pendingAsis||null],
            ["bulletin","Bulletins",pendingBuls||null],
            ["subcoord","Sub Coordination",null],
          ].map(([k,l,b])=>(
            <button key={k} className={"dtab"+(tab===k?" active":"")} onClick={()=>setTab(k)}>
              {l}
              {b?<span className="nav-badge" style={{background:"var(--orange)"}}>{b}</span>:null}
            </button>
          ))}
        </div>
        <div style={{padding:"0 0 8px 0"}}>
          <select className="fselect" style={{minWidth:180,fontSize:12}} value={jobFilter} onChange={e=>setJobFilter(e.target.value)}>
            <option value="all">All Projects</option>
            {jobs.map(j=><option key={j.id} value={j.id}>{j.name}</option>)}
          </select>
        </div>
      </div>
      {tab==="permit"   && <PermitSetTab sheets={drawings.permitSheets} jobs={jobs} allRfis={allRfis} jobFilter={jobFilter} onUpdateSheet={updateSheet} onAddSheet={addSheet}/>}
      {tab==="asi"      && <AsiBulletinTab items={drawings.asis}     type="ASI"     jobs={jobs} allRfis={allRfis} jobFilter={jobFilter} onUpdate={updateAsi} onAdd={addAsi}/>}
      {tab==="bulletin" && <AsiBulletinTab items={drawings.bulletins} type="Bulletin" jobs={jobs} allRfis={allRfis} jobFilter={jobFilter} onUpdate={updateBul} onAdd={addBul}/>}
      {tab==="subcoord" && <SubCoordTab items={drawings.subCoord} jobs={jobs} jobFilter={jobFilter} onUpdate={updateSC} onAdd={addSC}/>}
    </div>
  );
};

// --- RFI HELPERS -------------------------------------------------------------
const RFI_STATUSES = [
  {v:"draft",     l:"Draft",     cls:"rfi-draft"},
  {v:"submitted", l:"Submitted", cls:"rfi-submitted"},
  {v:"answered",  l:"Answered",  cls:"rfi-answered"},
  {v:"closed",    l:"Closed",    cls:"rfi-closed"},
];
// --- CONTACT PICKER -----------------------------------------------------------
// Replaces generic assignee selects with real directory contacts.
// Stores: {id, name, company, role, email} on the parent record.
const ContactPicker = ({directory, value, onChange, placeholder, roleLabel}) => {
  var [open, setOpen] = useState(false);
  var [search, setSearch] = useState("");

  // Flatten all contacts
  var allContacts = [];
  (directory||[]).forEach(function(company){
    (company.contacts||[]).forEach(function(c){
      allContacts.push({
        key: company.id+"_"+c.id,
        name: c.name,
        company: company.company,
        role: c.role||"",
        email: c.email||"",
        primary: !!c.primary,
      });
    });
  });

  var filtered = search
    ? allContacts.filter(function(c){
        var q = search.toLowerCase();
        return c.name.toLowerCase().includes(q) || c.company.toLowerCase().includes(q) || c.role.toLowerCase().includes(q);
      })
    : allContacts;

  var displayName = value && value.name
    ? value.name + (value.company ? " - " + value.company : "")
    : (placeholder || "Select contact...");

  var select = function(c) {
    onChange({id:c.key, name:c.name, company:c.company, role:c.role, email:c.email});
    setOpen(false);
    setSearch("");
  };

  var clear = function(e) {
    e.stopPropagation();
    onChange(null);
  };

  return (
    <div style={{position:"relative"}}>
      <div className="finput" onClick={function(){setOpen(!open);}}
        style={{cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"space-between",minHeight:36}}>
        <div style={{flex:1,minWidth:0}}>
          {value && value.name ? (
            <div>
              <div style={{fontSize:13,color:"var(--white)",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{value.name}</div>
              <div style={{fontSize:10,color:"var(--muted)",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{value.company}{value.role?" - "+value.role:""}</div>
            </div>
          ) : (
            <span style={{color:"var(--muted)",fontSize:12}}>{placeholder||"Select contact..."}</span>
          )}
        </div>
        <div style={{display:"flex",gap:4,flexShrink:0,marginLeft:6}}>
          {value && <button style={{background:"none",border:"none",color:"var(--muted)",cursor:"pointer",fontSize:12,padding:"0 2px"}} onClick={clear}>x</button>}
          <span style={{color:"var(--muted)",fontSize:10}}></span>
        </div>
      </div>
      {open && (
        <div style={{position:"absolute",top:"100%",left:0,right:0,zIndex:200,background:"var(--navy-dark)",border:"1px solid var(--navy-border)",borderRadius:6,boxShadow:"0 8px 24px rgba(0,0,0,.4)",maxHeight:260,display:"flex",flexDirection:"column"}}>
          <div style={{padding:6,borderBottom:"1px solid var(--navy-border)"}}>
            <input className="finput" autoFocus value={search}
              onChange={function(e){setSearch(e.target.value);}}
              onClick={function(e){e.stopPropagation();}}
              placeholder="Search name or company..." style={{fontSize:12,padding:"4px 8px"}}/>
          </div>
          <div style={{overflowY:"auto",flex:1}}>
            {filtered.length===0 && <div style={{padding:12,fontSize:12,color:"var(--muted)"}}>No contacts found. Add contacts in the Directory.</div>}
            {filtered.map(function(c){
              var isSel = value && value.id===c.key;
              return (
                <div key={c.key} onClick={function(){select(c);}}
                  style={{padding:"8px 12px",cursor:"pointer",background:isSel?"rgba(74,124,220,.12)":"transparent",borderBottom:"1px solid rgba(42,64,128,.1)"}}>
                  <div style={{display:"flex",alignItems:"center",gap:6}}>
                    <span style={{fontSize:12,color:"var(--white)",fontWeight:isSel?600:400}}>{c.name}</span>
                    {c.primary && <span style={{fontSize:9,color:"var(--accent-bright)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>PRIMARY</span>}
                  </div>
                  <div style={{fontSize:10,color:"var(--muted)"}}>{c.company}{c.role?" - "+c.role:""}</div>
                  {c.email && <div style={{fontSize:9,color:"var(--accent-bright)",fontFamily:"'IBM Plex Mono',monospace"}}>{c.email}</div>}
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
};


const RFI_ASSIGNEES_LIST = [
  "Architect","Structural Engineer","MEP Engineer","Civil Engineer",
  "Owner","Specialty Consultant","GC  Internal"
];

const rfiStatusCls = s => {
  const found = RFI_STATUSES.find(r => r.v === s);
  return found ? found.cls : "rfi-draft";
};
const rfiStatusLabel = s => {
  const found = RFI_STATUSES.find(r => r.v === s);
  return found ? found.l : s;
};
const isOverdue = rfi => {
  if(!rfi.requiredBy || rfi.status === "answered" || rfi.status === "closed") return false;
  if(rfi.status !== "submitted") return false;
  return rfi.requiredBy < TODAY;
};
const getNextRfiNum = (allRfis, jobId) => {
  const submitted = allRfis.filter(r => r.jobId === jobId && r.rfiNumber);
  const maxNum = submitted.reduce((m, r) => {
    const n = parseInt(r.rfiNumber.replace(/[^0-9]/g,"")) || 0;
    return n > m ? n : m;
  }, 0);
  return String(maxNum + 1).padStart(3, "0");
};

