// --- ROUND MANAGER -----------------------------------------------------------
const RoundCard = ({r, jobs, punches}) => {
  var job      = jobs.find(function(j){return j.id===r.jobId;});
  var rPunches = punches.filter(function(p){return p.roundId===r.id;});
  var openCt   = rPunches.filter(function(p){return ["Open","In Progress"].includes(p.status);}).length;
  var doneCt   = rPunches.filter(function(p){return ["Verified","Complete"].includes(p.status);}).length;
  var pct      = rPunches.length ? Math.round(doneCt/rPunches.length*100) : 0;
  return (
    <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14,marginBottom:10}}>
      <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:8}}>
        <div>
          <div style={{fontFamily:"'Barlow Condensed'",fontSize:17,fontWeight:700,color:"var(--white)"}}>
            {job ? job.name+" - " : ""} Round {r.number}
          </div>
          <div style={{fontSize:12,color:"var(--muted)",marginTop:2}}>{fmtDate(r.date)} - {r.conductedBy}</div>
          {r.notes && <div style={{fontSize:12,color:"var(--white)",marginTop:4}}>{r.notes}</div>}
        </div>
        <div style={{textAlign:"right",flexShrink:0}}>
          <div style={{fontFamily:"'Barlow Condensed'",fontSize:22,fontWeight:700,color:pct===100?"var(--green)":"var(--accent-bright)"}}>{pct}%</div>
          <div style={{fontSize:11,color:"var(--muted)"}}>complete</div>
        </div>
      </div>
      <div style={{display:"flex",gap:12,alignItems:"center"}}>
        <div style={{height:4,flex:1,background:"rgba(255,255,255,.06)",borderRadius:2,overflow:"hidden"}}>
          <div style={{height:"100%",width:pct+"%",background:pct===100?"var(--green)":"var(--accent)",transition:"width .3s"}}/>
        </div>
        <div style={{fontSize:11,color:"var(--muted)",whiteSpace:"nowrap"}}>
          {rPunches.length} items - {openCt} open - {doneCt} verified
        </div>
      </div>
    </div>
  );
};


