// --- SUBMITTAL HELPERS --------------------------------------------------------
const subNextNum = (jobSubs) => {
  const max = jobSubs.reduce((m,s)=>{const n=parseInt((s.number||"").replace("S-",""))||0;return Math.max(m,n);},0);
  return "S-"+(String(max+1).padStart(3,"0"));
};

const subIsOverdue = (sub) => {
  if(["Approved","Approved as Noted","Void","Rejected"].includes(sub.status)) return false;
  if(sub.gcReviewDue && sub.gcReviewDue < TODAY) return true;
  if(sub.architectReviewDue && sub.architectReviewDue < TODAY) return true;
  return false;
};

const subDaysToSite = (sub) => {
  if(!sub.requiredOnSite) return null;
  const d = new Date(sub.requiredOnSite);
  const n = new Date(TODAY);
  return Math.ceil((d-n)/86400000);
};

