// --- AI SPEC PARSER -----------------------------------------------------------
const SpecParserModal = ({job, existingSubs, onAddMultiple, onClose}) => {
  const [input, setInput]       = useState("");
  const [loading, setLoading]   = useState(false);
  const [results, setResults]   = useState(null);
  const [selected, setSelected] = useState([]);
  const [error, setError]       = useState(null);

  const parse = async () => {
    if(!input.trim()) return;
    setLoading(true); setError(null); setResults(null);
    const prompt = [
      "You are a construction submittal coordinator for Westroe Construction.",
      "Extract all required submittals from the following specification text or description.",
      "Project: "+job.name+" ("+job.id+")",
      "",
      "SPEC INPUT:",
      input,
      "",
      "For each submittal required, return a JSON array:",
      "[{type, specSection, title, description, trade, requiredOnSite}]",
      "type must be one of: Shop Drawing, Product Data, Sample, Mix Design, Test Report, O&M Manual, Other",
      "specSection: the spec section number and name if identifiable, else ''",
      "title: concise submittal name",
      "description: what the submittal should contain",
      "trade: likely responsible trade",
      "requiredOnSite: leave as ''",
      "Return ONLY valid JSON array. No markdown."
    ].join("\n");

    try {
      const res = await fetch("https://api.anthropic.com/v1/messages",{
        method:"POST",
        headers:{"Content-Type":"application/json"},
        body:JSON.stringify({
          model:"claude-sonnet-4-20250514",
          max_tokens:2000,
          system:"You are a construction submittal coordinator. Return ONLY valid JSON array.",
          messages:[{role:"user",content:prompt}]
        })
      });
      const data = await res.json();
      if(data.error) throw new Error(data.error.message);
      const raw = data.content.filter(b=>b.type==="text").map(b=>b.text).join("");
      const cleaned = raw.split("```json").join("").split("```").join("").trim();
      const parsed = JSON.parse(cleaned);
      setResults(parsed);
      setSelected(parsed.map((_,i)=>i));
    } catch(err) {
      setError("Parse failed: "+err.message);
    }
    setLoading(false);
  };

  const toggleSel = (i) => setSelected(p=>p.includes(i)?p.filter(x=>x!==i):[...p,i]);

  const addSelected = () => {
    const toAdd = results.filter((_,i)=>selected.includes(i));
    const startMax = existingSubs.reduce((m,s)=>{const n=parseInt((s.number||"").replace("S-",""))||0;return Math.max(m,n);},0);
    const newItems = toAdd.map((s,i)=>({
      id:"sub"+uid(),jobId:job.id,
      number:"S-"+(String(startMax+i+1).padStart(3,"0")),
      type:s.type,specSection:s.specSection,title:s.title,
      description:s.description,trade:s.trade,submittedBy:"",
      submittedDate:"",gcReviewDue:"",architectReviewDue:"",
      requiredOnSite:s.requiredOnSite||"",
      status:"Draft",revision:0,gcNotes:"",architectResponse:"",
      revisionHistory:[],rfiIds:[],drawingRefs:[],pdfBase64:null,aiReviewDraft:null,
    }));
    onAddMultiple(newItems);
    onClose();
  };

  return (
    <div className="overlay" onClick={onClose}>
      <div className="modal modal-wide" onClick={e=>e.stopPropagation()}>
        <div className="modal-hdr" style={{background:"linear-gradient(135deg,rgba(74,45,142,.3),#162550)"}}>
          <div>
            <div className="modal-title" style={{color:"var(--purple)"}}> Spec Parser</div>
            <div className="modal-sub">Paste spec section text - Claude extracts required submittals</div>
          </div>
          <button className="btn btn-ghost btn-sm" onClick={onClose}>x</button>
        </div>
        <div className="modal-body">
          {!results && (
            <div style={{display:"flex",flexDirection:"column",gap:12}}>
              <div>
                <div className="flabel">Spec Section Text or Description</div>
                <textarea className="ftextarea" rows={8} value={input} onChange={e=>setInput(e.target.value)}
                  placeholder={"Paste specification text here, or describe the scope - e.g.:\n\n'Section 09 30 00 - Tiling: Contractor shall submit shop drawings showing tile layout, pattern, grout joint size, transition details, and setting material data sheets prior to installation. Submit samples of each tile type and finish...'\n\nOr just describe: 'Structural steel, HM doors, HVAC equipment, tile, plumbing fixtures'"}/>
              </div>
              {error && <div style={{fontSize:12,color:"var(--red)"}}>{error}</div>}
              <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
                <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
                <button className="btn btn-ai" onClick={parse} disabled={loading||!input.trim()}>
                  {loading?"Parsing...":" Extract Submittals"}
                </button>
              </div>
              {loading && <div style={{textAlign:"center",padding:16}}><div className="spinner" style={{margin:"0 auto 8px"}}/><div style={{fontSize:12,color:"var(--muted)"}}>Extracting submittals from spec...</div></div>}
            </div>
          )}
          {results && (
            <div>
              <div style={{fontSize:13,color:"var(--muted)",marginBottom:12}}>
                {results.length} submittal{results.length!==1?"s":""} found. Select items to add as Draft entries.
              </div>
              {results.map((s,i)=>{
                const isSel = selected.includes(i);
                return (
                  <div key={i} onClick={()=>toggleSel(i)} style={{
                    display:"flex",gap:12,alignItems:"flex-start",
                    padding:"11px 14px",marginBottom:6,borderRadius:6,cursor:"pointer",
                    background:isSel?"rgba(74,124,220,.08)":"var(--navy)",
                    border:"1px solid "+(isSel?"rgba(74,124,220,.35)":"var(--navy-border)"),
                  }}>
                    <div style={{marginTop:2,flexShrink:0}}>
                      <div style={{width:16,height:16,borderRadius:3,border:"2px solid "+(isSel?"var(--accent)":"var(--navy-border)"),background:isSel?"var(--accent)":"transparent",display:"flex",alignItems:"center",justifyContent:"center"}}>
                        {isSel&&<span style={{fontSize:10,color:"var(--white)",fontWeight:700}}></span>}
                      </div>
                    </div>
                    <div style={{flex:1}}>
                      <div style={{display:"flex",gap:8,alignItems:"center",marginBottom:3}}>
                        <span style={{fontSize:11,fontFamily:"'Barlow Condensed'",letterSpacing:1,color:"var(--accent-bright)",background:"var(--blue-dim)",border:"1px solid rgba(74,124,220,.2)",borderRadius:3,padding:"1px 6px"}}>{s.type}</span>
                        {s.specSection&&<span style={{fontSize:11,color:"var(--muted)",fontFamily:"'IBM Plex Mono',monospace"}}>{s.specSection}</span>}
                        {s.trade&&<span style={{fontSize:11,color:"var(--muted)"}}>{s.trade}</span>}
                      </div>
                      <div style={{fontSize:13,color:"var(--white)",fontWeight:600,marginBottom:2}}>{s.title}</div>
                      <div style={{fontSize:11,color:"var(--muted)"}}>{s.description}</div>
                    </div>
                  </div>
                );
              })}
              <div style={{display:"flex",gap:8,justifyContent:"space-between",marginTop:12}}>
                <button className="btn btn-ghost btn-sm" onClick={()=>setResults(null)}> Re-parse</button>
                <div style={{display:"flex",gap:8}}>
                  <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
                  <button className="btn btn-primary" onClick={addSelected} disabled={!selected.length}>
                    Add {selected.length} Submittal{selected.length!==1?"s":""}
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

// --- SUBMITTAL DETAIL PANEL ---------------------------------------------------
const SubmittalDetail = ({sub, job, onUpdate, onEdit, onClose, directory}) => {
  const [genReview, setGenReview]   = useState(false);
  const [reviewLoad, setReviewLoad] = useState(false);
  const [reviewErr, setReviewErr]   = useState(null);
  const [showSendSub, setShowSendSub] = useState(false);
  const [showReview, setShowReview]   = useState(false);
  const [showRecord, setShowRecord]   = useState(false);
  const inputRef = useRef();

  const handleUpload = async (e) => {
    const file = e.target.files[0];
    if(!file) return;
    const b64 = await readFile(file);
    onUpdate({...sub,pdfBase64:b64,pdfName:file.name});
    e.target.value="";
  };

  const generateReview = async () => {
    setReviewLoad(true); setReviewErr(null);
    const prompt = [
      "You are reviewing a construction submittal as the GC for Westroe Construction.",
      "Project: "+job.name+" ("+job.id+")",
      "Submittal: "+sub.number+" - "+sub.title,
      "Type: "+sub.type,
      "Spec Section: "+(sub.specSection||"Not specified"),
      "Trade: "+(sub.submittedBy||sub.trade||"Not specified"),
      "Description: "+(sub.description||"Not provided"),
      "Drawing References: "+(sub.drawingRefs||[]).join(", ")||"None",
      "",
      "Draft a professional GC review comment for this submittal.",
      "Include:",
      "- Whether it appears complete based on the description",
      "- Key coordination items to verify before forwarding to the Architect",
      "- Any spec section compliance items to confirm",
      "- Recommended action: Approve / Approve as Noted / Revise and Resubmit / Reject",
      "Keep it concise and professional - 3-5 sentences plus a recommendation.",
    ].join("\n");
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages",{
        method:"POST",
        headers:{"Content-Type":"application/json"},
        body:JSON.stringify({
          model:"claude-sonnet-4-20250514",
          max_tokens:600,
          system:"You are a GC project manager writing professional submittal review comments. Be concise and practical.",
          messages:[{role:"user",content:prompt}]
        })
      });
      const data = await res.json();
      if(data.error) throw new Error(data.error.message);
      const text = data.content.filter(b=>b.type==="text").map(b=>b.text).join("");
      onUpdate({...sub,aiReviewDraft:text});
      setGenReview(false);
    } catch(err) {
      setReviewErr("Failed: "+err.message);
    }
    setReviewLoad(false);
  };

  const statusColor = SUB_STAT_COLOR[sub.status]||"var(--muted)";
  const daysToSite  = subDaysToSite(sub);
  const overdue     = subIsOverdue(sub);

  return (
    <div style={{padding:16,overflowY:"auto",height:"100%"}}>
      {/* Header */}
      <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:12,gap:8}}>
        <div>
          <div style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:12,color:"var(--accent-bright)",marginBottom:1}}>{sub.number}   Rev {sub.revision}</div>
          <div style={{fontFamily:"'Barlow Condensed'",fontSize:17,fontWeight:700,color:"var(--white)",lineHeight:1.2,marginBottom:3}}>{sub.title}</div>
          <div style={{fontSize:11,color:"var(--muted)"}}>
            <span style={{fontSize:11,fontFamily:"'Barlow Condensed'",letterSpacing:1,color:"var(--accent-bright)",background:"var(--blue-dim)",border:"1px solid rgba(74,124,220,.2)",borderRadius:3,padding:"1px 5px",marginRight:6}}>{sub.type}</span>
            {sub.specSection&&<span style={{fontFamily:"'IBM Plex Mono',monospace",marginRight:6}}>{sub.specSection}</span>}
            {sub.submittedBy||sub.trade}
          </div>
        </div>
        <div style={{display:"flex",gap:6,flexShrink:0}}>
          <button className="btn btn-ghost btn-sm" onClick={onEdit}>Edit</button>
          <button className="btn btn-ghost btn-sm" style={{color:"var(--accent-bright)"}} onClick={function(){setShowSendSub(true);}}>Send</button>
          <button className="btn btn-ghost btn-sm" style={{color:"var(--purple)"}} onClick={function(){setShowReview(true);}}>Share Review</button>
          <button className="btn btn-ghost btn-sm" style={{color:"var(--green)"}} onClick={function(){setShowRecord(true);}}>Record Response</button>
          <button className="btn btn-ghost btn-sm" onClick={onClose}>x</button>
        </div>
      </div>

      {/* Status + dates */}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:12}}>
        <div>
          <div className="flabel">Status</div>
          <select className="fselect" value={sub.status} onChange={e=>onUpdate({...sub,status:e.target.value})}>
            {SUB_STATUSES.map(s=><option key={s}>{s}</option>)}
          </select>
        </div>
        <div style={{padding:"8px 10px",background:"rgba(255,255,255,.03)",borderRadius:6,border:"1px solid var(--navy-border)"}}>
          <div className="flabel">Required On Site</div>
          <div style={{fontSize:13,color:daysToSite!==null&&daysToSite<=14?"var(--orange)":"var(--white)",fontFamily:"'IBM Plex Mono',monospace"}}>
            {sub.requiredOnSite?fmtDate(sub.requiredOnSite):"Not set"}
            {daysToSite!==null&&<span style={{fontSize:11,color:daysToSite<=7?"var(--red)":daysToSite<=14?"var(--orange)":"var(--muted)",marginLeft:8}}>{daysToSite<0?"OVERDUE":(daysToSite+" days")}</span>}
          </div>
        </div>
      </div>

      {overdue && (
        <div style={{padding:"8px 12px",background:"rgba(248,113,113,.07)",border:"1px solid rgba(248,113,113,.2)",borderRadius:6,fontSize:12,color:"var(--red)",marginBottom:12}}>
           Review deadline overdue - follow up required
        </div>
      )}

      {sub.description && (
        <div style={{marginBottom:12}}>
          <div className="flabel">Description</div>
          <div style={{fontSize:13,color:"var(--white)",lineHeight:1.6}}>{sub.description}</div>
        </div>
      )}

      {/* Drawing refs */}
      {(sub.drawingRefs||[]).length>0 && (
        <div style={{marginBottom:12}}>
          <div className="flabel">Drawing References</div>
          <div>{(sub.drawingRefs||[]).map(r=><span key={r} className="cost-category-tag">{r}</span>)}</div>
        </div>
      )}

      {/* GC Review Notes */}
      <div style={{marginBottom:12}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:6}}>
          <div className="flabel">GC Review Notes</div>
          {!sub.aiReviewDraft && !reviewLoad && (
            <button className="btn btn-ai btn-sm" onClick={()=>setGenReview(true)} style={{fontSize:10}}> Draft Review</button>
          )}
        </div>
        {sub.aiReviewDraft && !genReview && (
          <div style={{background:"rgba(167,139,250,.07)",border:"1px solid rgba(167,139,250,.2)",borderRadius:6,padding:"10px 12px",marginBottom:8,fontSize:12,color:"var(--white)",lineHeight:1.6}}>
            <div style={{fontSize:10,color:"var(--purple)",fontFamily:"'Barlow Condensed'",letterSpacing:1,marginBottom:4}}> AI DRAFT - Review and edit before sending</div>
            <textarea className="ftextarea" rows={4} value={sub.aiReviewDraft} onChange={e=>onUpdate({...sub,aiReviewDraft:e.target.value})} style={{background:"transparent",border:"none",padding:0,fontSize:12,color:"var(--white)"}}/>
            <div style={{display:"flex",gap:6,marginTop:6}}>
              <button className="btn btn-primary btn-sm" onClick={()=>onUpdate({...sub,gcNotes:sub.aiReviewDraft,aiReviewDraft:null})}>Use as GC Notes</button>
              <button className="btn btn-ghost btn-sm" style={{fontSize:10}} onClick={()=>setGenReview(true)}>Re-draft</button>
            </div>
          </div>
        )}
        {genReview && (
          <div style={{marginBottom:8}}>
            {reviewLoad ? (
              <div style={{display:"flex",alignItems:"center",gap:8,padding:"10px 0"}}>
                <div className="spinner" style={{width:14,height:14,borderWidth:2}}/>
                <span style={{fontSize:12,color:"var(--muted)"}}>Drafting GC review...</span>
              </div>
            ) : (
              <div style={{display:"flex",gap:8}}>
                <button className="btn btn-ai btn-sm" onClick={generateReview}> Generate Draft</button>
                <button className="btn btn-ghost btn-sm" onClick={()=>setGenReview(false)}>Cancel</button>
              </div>
            )}
            {reviewErr && <div style={{fontSize:11,color:"var(--red)",marginTop:4}}>{reviewErr}</div>}
          </div>
        )}
        <textarea className="ftextarea" rows={3} value={sub.gcNotes||""} onChange={e=>onUpdate({...sub,gcNotes:e.target.value})} placeholder="GC review comments, coordination items, conditions..."/>
      </div>

      {/* Architect Response */}
      <div style={{marginBottom:12}}>
        <div className="flabel">Architect / Engineer Response</div>
        <textarea className="ftextarea" rows={2} value={sub.architectResponse||""} onChange={e=>onUpdate({...sub,architectResponse:e.target.value})} placeholder="Architect or engineer response notes..."/>
      </div>

      {/* Revision History */}
      {(sub.revisionHistory||[]).length>0 && (
        <div style={{marginBottom:12}}>
          <div className="flabel">Revision History</div>
          {[...(sub.revisionHistory||[])].reverse().map((r,i)=>(
            <div key={i} style={{display:"flex",gap:10,alignItems:"flex-start",padding:"7px 0",borderBottom:"1px solid rgba(42,64,128,.2)"}}>
              <span style={{fontSize:11,fontFamily:"'IBM Plex Mono',monospace",color:"var(--accent-bright)",flexShrink:0}}>Rev {r.rev}</span>
              <span style={{fontSize:11,color:"var(--muted)",fontFamily:"'IBM Plex Mono',monospace",flexShrink:0}}>{fmtDate(r.date)}</span>
              <span style={{fontSize:11,color:SUB_STAT_COLOR[r.status]||"var(--muted)",flexShrink:0}}>{r.status}</span>
              <span style={{fontSize:11,color:"var(--muted)",flex:1}}>{r.note}</span>
            </div>
          ))}
        </div>
      )}

      {/* PDF */}
      <div>
        <div className="flabel" style={{marginBottom:6}}>Document</div>
        {sub.pdfBase64 ? (
          <div>
            <div style={{fontSize:12,color:"var(--green)",marginBottom:8}}>{sub.pdfName}</div>
            <embed src={sub.pdfBase64} type="application/pdf" className="drw-pdf-frame"/>
          </div>
        ) : (
          <div className="drw-upload-zone" onClick={()=>inputRef.current&&inputRef.current.click()}>
            <div style={{fontFamily:"'Barlow Condensed'",fontSize:12,letterSpacing:1,color:"var(--accent-bright)"}}>Upload Submittal PDF</div>
          </div>
        )}
        <input ref={inputRef} type="file" accept=".pdf" style={{display:"none"}} onChange={handleUpload}/>
      </div>
    </div>
  );
};

// --- SUBMITTAL DASHBOARD ------------------------------------------------------
const SubmittalDashboard = ({subs}) => {
  const open     = subs.filter(s=>!["Approved","Approved as Noted","Void","Rejected"].includes(s.status));
  const overdue  = subs.filter(subIsOverdue);
  const approved = subs.filter(s=>["Approved","Approved as Noted"].includes(s.status));
  const upcoming = subs.filter(s=>s.requiredOnSite&&!["Void"].includes(s.status)).sort((a,b)=>a.requiredOnSite.localeCompare(b.requiredOnSite)).slice(0,8);

  const byType = SUB_TYPES.map(t=>({type:t,count:subs.filter(s=>s.type===t).length})).filter(t=>t.count>0);
  const byStatus = SUB_STATUSES.map(s=>({status:s,count:subs.filter(x=>x.status===s).length})).filter(s=>s.count>0);

  return (
    <div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12,marginBottom:20}}>
        {[
          {label:"Total Submittals",val:subs.length,color:"var(--accent-bright)"},
          {label:"In Progress",val:open.length,color:"var(--yellow)"},
          {label:"Overdue",val:overdue.length,color:overdue.length?"var(--red)":"var(--muted)"},
          {label:"Approved",val:approved.length,color:"var(--green)"},
        ].map(s=><div key={s.label} className="stat-card"><div className="stat-label">{s.label}</div><div className="stat-value" style={{color:s.color}}>{s.val}</div></div>)}
      </div>
      {upcoming.length>0 && (
        <div style={{marginBottom:20}}>
          <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:10}}>Upcoming Required On Site</div>
          {upcoming.map(s=>{
            const d = subDaysToSite(s);
            return (
              <div key={s.id} style={{display:"flex",alignItems:"center",gap:12,padding:"8px 0",borderBottom:"1px solid rgba(42,64,128,.2)"}}>
                <span style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:11,color:"var(--accent-bright)",width:50,flexShrink:0}}>{s.number}</span>
                <span style={{fontSize:13,color:"var(--white)",flex:1}}>{s.title}</span>
                <span style={{fontSize:11,color:SUB_STAT_COLOR[s.status]||"var(--muted)",fontFamily:"'Barlow Condensed'",flexShrink:0}}>{s.status}</span>
                <span style={{fontSize:11,fontFamily:"'IBM Plex Mono',monospace",color:d!==null&&d<=7?"var(--red)":d!==null&&d<=14?"var(--orange)":"var(--muted)",flexShrink:0,minWidth:70,textAlign:"right"}}>{fmtDate(s.requiredOnSite)}</span>
              </div>
            );
          })}
        </div>
      )}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
        <div>
          <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:10}}>By Type</div>
          {byType.map(t=>(
            <div key={t.type} style={{display:"flex",alignItems:"center",gap:10,marginBottom:7}}>
              <div style={{fontSize:12,color:"var(--white)",width:120,flexShrink:0}}>{t.type}</div>
              <div style={{flex:1,height:5,background:"rgba(255,255,255,.06)",borderRadius:3,overflow:"hidden"}}>
                <div style={{height:"100%",width:(t.count/subs.length*100)+"%",background:"var(--accent)",transition:"width .4s"}}/>
              </div>
              <div style={{fontSize:12,color:"var(--muted)",width:20,textAlign:"right"}}>{t.count}</div>
            </div>
          ))}
        </div>
        <div>
          <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:10}}>By Status</div>
          {byStatus.map(s=>(
            <div key={s.status} style={{display:"flex",alignItems:"center",gap:8,marginBottom:6}}>
              <div style={{width:8,height:8,borderRadius:"50%",background:SUB_STAT_COLOR[s.status]||"var(--muted)",flexShrink:0}}/>
              <div style={{fontSize:12,color:"var(--white)",flex:1}}>{s.status}</div>
              <div style={{fontSize:12,color:"var(--muted)"}}>{s.count}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
      {showSendSub && (
        <DistributeModal title={"Send Submittal - "+sub.number}
          subject={"Submittal "+sub.number+" - "+sub.title+" - "+job.name}
          body={buildSubmittalEmail(sub, job)}
          directory={directory||[]}
          priorityDirId={sub.assignedTo&&sub.assignedTo.id?(sub.assignedTo.id.split("_")[0]):null}
          preselect={sub.assignedTo&&sub.assignedTo.id?[sub.assignedTo.id]:[]}
          onClose={function(){setShowSendSub(false);}}/>
      )}
      {showReview && (function(){
        var html=buildReviewHtml(sub,"submittal",job,"shane@westroeconstruction.com");
        var blob=new Blob([html],{type:"text/html"});
        window.open(URL.createObjectURL(blob),"_blank");
        setShowReview(false); return null;
      })()}
      {showRecord && (
        <RecordResponseModal item={sub} itemType="submittal"
          onSave={function(upd){onUpdate(upd);setShowRecord(false);}}
          onClose={function(){setShowRecord(false);}}/>
      )}
};

// --- SUBMITTAL LOG (PROJECT-LEVEL) --------------------------------------------
const SubmittalLog = ({job, directory, subs, masterSubs, onAdd, onUpdate, onAddMultiple}) => {
  const [tab, setTab]         = useState("log");
  const [selId, setSelId]     = useState(null);
  const [showAdd, setShowAdd] = useState(false);
  const [editSub, setEditSub] = useState(null);
  const [showParse, setShowParse] = useState(false);
  const [showPullMaster, setShowPullMaster] = useState(false);
  const [statusF, setStatusF] = useState("active");
  const [typeF, setTypeF]     = useState("all");

  const sel = subs.find(s=>s.id===selId);

  const filtered = subs.filter(s=>{
    if(statusF==="active" && ["Approved","Approved as Noted","Void","Rejected"].includes(s.status)) return false;
    if(statusF!=="all" && statusF!=="active" && s.status!==statusF) return false;
    if(typeF!=="all" && s.type!==typeF) return false;
    return true;
  }).sort((a,b)=>a.number.localeCompare(b.number));

  const overdueCt = subs.filter(subIsOverdue).length;
  const pendingCt = subs.filter(s=>!["Approved","Approved as Noted","Void","Rejected","Draft"].includes(s.status)).length;

  const handleSave = (data) => {
    if(editSub) {
      onUpdate(data);
    } else {
      const num = data.number || subNextNum(subs);
      const revEntry = {rev:data.revision||0,date:data.submittedDate||TODAY,status:data.status,note:"Initial submission."};
      onAdd({...data,id:"sub"+uid(),number:num,revisionHistory:[revEntry]});
    }
    setShowAdd(false);
    setEditSub(null);
  };

  return (
    <div>
      <div style={{display:"flex",alignItems:"center",gap:0,marginBottom:0,borderBottom:"1px solid var(--navy-border)"}}>
        <div style={{display:"flex",flex:1}}>
          {[["log","Submittal Log",pendingCt||null],["dashboard","Dashboard",null]].map(([k,l,b])=>(
            <button key={k} className={"drw-tab"+(tab===k?" active":"")} onClick={()=>setTab(k)}>
              {l}{b?<span className="nav-badge" style={{background:"var(--yellow)",marginLeft:4,color:"var(--navy)"}}>{b}</span>:null}
            </button>
          ))}
        </div>
        <div style={{padding:"0 0 8px 0",display:"flex",gap:8}}>
          {overdueCt>0&&<span style={{fontSize:12,color:"var(--red)",fontFamily:"'Barlow Condensed'",letterSpacing:1,padding:"8px 0"}}> {overdueCt} OVERDUE</span>}
          <button className="btn btn-ghost btn-sm" onClick={()=>setShowPullMaster(true)}> Master Library</button>
          <button className="btn btn-ai btn-sm" onClick={()=>setShowParse(true)}> Spec Parser</button>
          <button className="btn btn-primary btn-sm" onClick={()=>{setEditSub(null);setShowAdd(true);}}>+ Submittal</button>
        </div>
      </div>

      {tab==="log" && (
        <div style={{paddingTop:12}}>
          <div style={{display:"flex",gap:8,marginBottom:12,flexWrap:"wrap"}}>
            <select className="fselect" value={statusF} onChange={e=>setStatusF(e.target.value)} style={{fontSize:12}}>
              <option value="active">Active Only</option>
              <option value="all">All Statuses</option>
              {SUB_STATUSES.map(s=><option key={s} value={s}>{s}</option>)}
            </select>
            <select className="fselect" value={typeF} onChange={e=>setTypeF(e.target.value)} style={{fontSize:12}}>
              <option value="all">All Types</option>
              {SUB_TYPES.map(t=><option key={t}>{t}</option>)}
            </select>
            <div style={{marginLeft:"auto",fontSize:12,color:"var(--muted)",padding:"8px 0"}}>{filtered.length} items</div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:sel?"1fr 400px":"1fr",gap:0,border:"1px solid var(--navy-border)",borderRadius:8,overflow:"hidden",minHeight:400}}>
            <div style={{overflowY:"auto",borderRight:sel?"1px solid var(--navy-border)":"none"}}>
              {filtered.length===0 ? (
                <div className="empty" style={{padding:40}}>
                  {subs.length===0?"No submittals yet - add one or use the Spec Parser to extract from a spec section.":"No submittals match filters."}
                </div>
              ) : filtered.map(s=>{
                const overdue = subIsOverdue(s);
                const d = subDaysToSite(s);
                return (
                  <div key={s.id} onClick={()=>setSelId(selId===s.id?null:s.id)} style={{
                    padding:"11px 14px",borderBottom:"1px solid rgba(42,64,128,.2)",cursor:"pointer",
                    background:selId===s.id?"rgba(74,124,220,.08)":"transparent",
                    borderLeft:selId===s.id?"3px solid var(--accent)":"3px solid transparent",
                    transition:"background .15s",
                  }}>
                    <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",gap:8}}>
                      <div style={{flex:1,minWidth:0}}>
                        <div style={{display:"flex",gap:6,alignItems:"center",marginBottom:3}}>
                          <span style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:11,color:"var(--accent-bright)"}}>{s.number}</span>
                          <span style={{fontSize:10,fontFamily:"'Barlow Condensed'",letterSpacing:.5,color:"var(--accent-bright)",background:"var(--blue-dim)",border:"1px solid rgba(74,124,220,.2)",borderRadius:3,padding:"1px 5px"}}>{s.type}</span>
                          {s.specSection&&<span style={{fontSize:10,color:"var(--muted)",fontFamily:"'IBM Plex Mono',monospace"}}>{s.specSection}</span>}
                          {overdue&&<span style={{fontSize:10,color:"var(--red)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>OVERDUE</span>}
                        </div>
                        <div style={{fontSize:13,color:"var(--white)",fontWeight:600,marginBottom:2,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{s.title}</div>
                        <div style={{fontSize:11,color:"var(--muted)"}}>
                          {s.submittedBy&&<span>{s.submittedBy}</span>}
                          {d!==null&&<span style={{color:d<=7?"var(--red)":d<=14?"var(--orange)":"var(--muted)",marginLeft:8}}>Site: {d<0?"OVERDUE":d+" days"}</span>}
                        </div>
                      </div>
                      <div style={{textAlign:"right",flexShrink:0}}>
                        <div style={{fontSize:11,color:SUB_STAT_COLOR[s.status]||"var(--muted)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>{s.status}</div>
                        <div style={{fontSize:10,color:"var(--muted)",fontFamily:"'IBM Plex Mono',monospace",marginTop:2}}>Rev {s.revision}</div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
            {sel && (
              <div style={{borderLeft:"1px solid var(--navy-border)",overflow:"hidden",display:"flex",flexDirection:"column"}}>
                <SubmittalDetail sub={sel} job={job}
                  onUpdate={onUpdate}
                  onEdit={()=>{setEditSub(sel);setShowAdd(true);}}
                  onClose={()=>setSelId(null)}/>
              </div>
            )}
          </div>
        </div>
      )}

      {tab==="dashboard" && (
        <div style={{paddingTop:12}}>
          <SubmittalDashboard subs={subs}/>
        </div>
      )}

      {showAdd && (
        <SubmittalModal
          job={job} directory={directory}
          existingSub={editSub}
          onSave={handleSave}
          onClose={()=>{setShowAdd(false);setEditSub(null);}}
        />
      )}
      {showParse && (
        <SpecParserModal job={job} existingSubs={subs} onAddMultiple={onAddMultiple} onClose={()=>setShowParse(false)}/>
      )}
      {showPullMaster && masterSubs && (
        <PullFromMasterModal masterSubs={masterSubs} existingSubs={subs} job={job} onPull={onAddMultiple} onClose={()=>setShowPullMaster(false)}/>
      )}
    </div>
  );
};


