const CostCodeLibrary = ({codes, onAdd, onUpdate, onDelete}) => {
  const [showAdd,   setShowAdd]   = useState(false);
  const [divFilter, setDivFilter] = useState("all");
  const [f, setF] = useState({division:CC_DIVISIONS[0], code:"", name:"", type:"Subcontractor"});
  const set = (k,v) => setF(p=>({...p,[k]:v}));

  const filtered = codes.filter(c => divFilter === "all" || c.division === divFilter);
  const grouped  = CC_DIVISIONS.map(d => ({div:d, items:filtered.filter(c=>c.division===d)})).filter(g=>g.items.length>0);

  return (
    <div>
      <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:"11px 14px",marginBottom:14,fontSize:13,color:"var(--white)"}}>
        Cost codes are organized by division and type. When entering a bill or cost, you pick the code that best matches - the description tells you exactly what belongs there. Add or edit codes to match how you track costs.
      </div>
      <div style={{display:"flex",gap:8,marginBottom:12,alignItems:"flex-end"}}>
        <div>
          <div className="flabel">Division</div>
          <select className="fselect" value={divFilter} onChange={e=>setDivFilter(e.target.value)}>
            <option value="all">All Divisions</option>
            {CC_DIVISIONS.map(d=><option key={d}>{d}</option>)}
          </select>
        </div>
        <div style={{marginLeft:"auto"}}>
          <button className="btn btn-primary btn-sm" onClick={()=>setShowAdd(!showAdd)}>+ Add Code</button>
        </div>
      </div>

      {showAdd && (
        <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14,marginBottom:12,display:"flex",flexDirection:"column",gap:10}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 100px 1fr 140px",gap:10}}>
            <div><div className="flabel">Division</div><select className="fselect" value={f.division} onChange={e=>set("division",e.target.value)}>{CC_DIVISIONS.map(d=><option key={d}>{d}</option>)}</select></div>
            <div><div className="flabel">Code #</div><input className="finput" value={f.code} onChange={e=>set("code",e.target.value)} placeholder="06-500"/></div>
            <div><div className="flabel">Description</div><input className="finput" value={f.name} onChange={e=>set("name",e.target.value)} placeholder="What goes here..."/></div>
            <div><div className="flabel">Type</div><select className="fselect" value={f.type} onChange={e=>set("type",e.target.value)}>{CC_TYPES.map(t=><option key={t}>{t}</option>)}</select></div>
          </div>
          <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
            <button className="btn btn-ghost btn-sm" onClick={()=>setShowAdd(false)}>Cancel</button>
            <button className="btn btn-primary btn-sm" onClick={()=>{
              if(!f.code.trim()||!f.name.trim()) return;
              onAdd({...f, id:"cc"+uid()});
              setShowAdd(false);
              setF({division:CC_DIVISIONS[0],code:"",name:"",type:"Subcontractor"});
            }}>Add Code</button>
          </div>
        </div>
      )}

      {grouped.map(({div, items}) => (
        <div key={div} style={{marginBottom:14}}>
          <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:8,paddingBottom:4,borderBottom:"1px solid var(--navy-border)"}}>{div}</div>
          {items.map(code => (
            <div key={code.id} style={{display:"flex",alignItems:"center",gap:12,padding:"8px 12px",background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:5,marginBottom:5}}>
              <span style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:12,color:"var(--accent-bright)",width:60,flexShrink:0}}>{code.code}</span>
              <span style={{fontSize:13,color:"var(--white)",flex:1}}>{code.name}</span>
              <span style={{fontSize:11,fontFamily:"'Barlow Condensed'",letterSpacing:.5,color:"var(--muted)",width:100}}>{code.type}</span>
              <button className="btn btn-ghost btn-sm" style={{fontSize:11,color:"var(--red)"}} onClick={()=>onDelete(code.id)}>x</button>
            </div>
          ))}
        </div>
      ))}
    </div>
  );
};

// --- BUDGET BUILDER -----------------------------------------------------------
const BudgetBuilder = ({job, budgetLines, costCodes, costEntries, jobSubcontracts, onAdd, onUpdate, onDelete}) => {
  const [showAdd, setShowAdd] = useState(false);
  const [f, setF] = useState({costCodeId:"", budgeted:"", notes:""});
  const set = (k,v) => setF(p=>({...p,[k]:v}));

  const enriched = budgetLines.map(bl => {
    const base = calcBudgetLine(bl, costEntries);
    const committed = calcCommittedForCode(bl.costCodeId, jobSubcontracts||[]);
    return {...base, committed};
  });
  const totalBudget = enriched.reduce((s,b)=>s+b.budgeted,0);
  const totalActual = enriched.reduce((s,b)=>s+b.actual,0);
  const totalVariance = totalBudget - totalActual;

  const grouped = CC_DIVISIONS.map(div => ({
    div,
    lines: enriched.filter(bl => {
      const code = costCodes.find(c=>c.id===bl.costCodeId);
      return code && code.division === div;
    })
  })).filter(g=>g.lines.length>0);

  const usedCodeIds = new Set(budgetLines.map(b=>b.costCodeId));
  const availCodes  = costCodes.filter(c=>!usedCodeIds.has(c.id));

  return (
    <div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:16}}>
        {[
          {label:"Total Budget",    val:fmt(totalBudget),    color:"var(--white)"},
          {label:"Actual to Date",  val:fmt(totalActual),    color:totalActual>totalBudget?"var(--red)":"var(--white)"},
          {label:"Remaining",       val:fmt(totalVariance),  color:totalVariance<0?"var(--red)":"var(--green)"},
          {label:"% Used",          val:fmtPct(totalBudget>0?totalActual/totalBudget*100:0), color:totalActual/totalBudget>0.9?"var(--red)":totalActual/totalBudget>0.75?"var(--yellow)":"var(--green)"},
        ].map(s=>(
          <div key={s.label} className="stat-card">
            <div className="stat-label">{s.label}</div>
            <div className="stat-value" style={{fontSize:16,color:s.color}}>{s.val}</div>
          </div>
        ))}
      </div>

      <div style={{display:"flex",justifyContent:"flex-end",marginBottom:10}}>
        <button className="btn btn-primary btn-sm" onClick={()=>setShowAdd(!showAdd)}>+ Add Budget Line</button>
      </div>

      {showAdd && (
        <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14,marginBottom:12,display:"flex",flexDirection:"column",gap:10}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 140px 1fr",gap:10}}>
            <div>
              <div className="flabel">Cost Code</div>
              <select className="fselect" value={f.costCodeId} onChange={e=>set("costCodeId",e.target.value)}>
                <option value="">Select code...</option>
                {CC_DIVISIONS.map(div => {
                  const divCodes = availCodes.filter(c=>c.division===div);
                  if(!divCodes.length) return null;
                  return (
                    <optgroup key={div} label={div}>
                      {divCodes.map(c=><option key={c.id} value={c.id}>{c.code} - {c.name}</option>)}
                    </optgroup>
                  );
                })}
              </select>
            </div>
            <div><div className="flabel">Budgeted Amount</div><input className="finput" type="number" value={f.budgeted} onChange={e=>set("budgeted",e.target.value)} placeholder="0"/></div>
            <div><div className="flabel">Notes</div><input className="finput" value={f.notes} onChange={e=>set("notes",e.target.value)} placeholder="Brief note..."/></div>
          </div>
          <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
            <button className="btn btn-ghost btn-sm" onClick={()=>setShowAdd(false)}>Cancel</button>
            <button className="btn btn-primary btn-sm" onClick={()=>{
              if(!f.costCodeId||!f.budgeted) return;
              onAdd({id:"bl"+uid(),jobId:job.id,costCodeId:f.costCodeId,budgeted:parseFloat(f.budgeted)||0,notes:f.notes});
              setShowAdd(false);
              setF({costCodeId:"",budgeted:"",notes:""});
            }}>Add Line</button>
          </div>
        </div>
      )}

      {grouped.map(({div, lines}) => {
        const divBudget = lines.reduce((s,l)=>s+l.budgeted,0);
        const divActual = lines.reduce((s,l)=>s+l.actual,0);
        return (
          <div key={div} style={{marginBottom:16}}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:6,paddingBottom:4,borderBottom:"1px solid var(--navy-border)"}}>
              <span style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)"}}>{div}</span>
              <span style={{fontSize:11,color:"var(--muted)"}}>Budget {fmt(divBudget)} / Actual {fmt(divActual)}</span>
            </div>
            <table className="tbl">
              <thead>
                <tr><th>Code</th><th>Description</th><th>Budgeted</th><th>Actual</th><th>Variance</th><th>% Used</th><th>Notes</th><th></th></tr>
              </thead>
              <tbody>
                {lines.map(bl => {
                  const code = costCodes.find(c=>c.id===bl.costCodeId);
                  const over = bl.variance < 0;
                  return (
                    <tr key={bl.id}>
                      <td className="col-mono" style={{color:"var(--accent-bright)"}}>{code?code.code:""}</td>
                      <td style={{color:"var(--white)"}}>{code?code.name:""}</td>
                      <td className="col-mono">{fmt(bl.budgeted)}</td>
                      <td className="col-mono" style={{color:bl.committed>bl.budgeted?"var(--orange)":"var(--yellow)"}}>{fmt(bl.committed)}</td>
                      <td className="col-mono" style={{color:over?"var(--red)":"var(--white)"}}>{fmt(bl.actual)}</td>
                      <td className="col-mono" style={{color:over?"var(--red)":"var(--green)"}}>{over?"-":""}{fmt(Math.abs(bl.variance))}</td>
                      <td>
                        <div style={{display:"flex",alignItems:"center",gap:6}}>
                          <div style={{width:60,height:5,background:"rgba(255,255,255,.06)",borderRadius:3,overflow:"hidden"}}>
                            <div style={{height:"100%",width:Math.min(bl.pct,100)+"%",background:bl.pct>100?"var(--red)":bl.pct>85?"var(--yellow)":"var(--green)"}}/>
                          </div>
                          <span style={{fontSize:11,color:bl.pct>100?"var(--red)":bl.pct>85?"var(--yellow)":"var(--muted)"}}>{bl.pct.toFixed(0)}%</span>
                        </div>
                      </td>
                      <td style={{fontSize:11,color:"var(--muted)"}}>{bl.notes}</td>
                      <td>
                        <button className="btn btn-ghost btn-sm" style={{fontSize:11,color:"var(--red)"}} onClick={()=>onDelete(bl.id)}>x</button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        );
      })}
    </div>
  );
};

// --- COST ENTRY LOG -------------------------------------------------------------
const CE_STATUSES = ["Draft","Approved","Paid"];
const CE_STATUS_COLOR = {Draft:"var(--muted)",Approved:"var(--yellow)",Paid:"var(--green)"};

const CostEntryModal = ({jobId, costCodes, existingEntry, onSave, onClose}) => {
  const blank = {jobId, costCodeId:"", vendor:"", description:"", amount:"", date:TODAY, invoiceNum:"", status:"Draft", pdfBase64:null, pdfName:""};
  const [f, setF]           = useState(existingEntry || blank);
  const [extracting, setEx] = useState(false);
  const [extractErr, setExtErr] = useState(null);
  const set = (k,v) => setF(p=>({...p,[k]:v}));
  const fileRef = useRef();

  const handleFile = (e) => {
    const file = e.target.files[0];
    if(!file) return;
    readFile(file).then(b64 => setF(p=>({...p, pdfBase64:b64, pdfName:file.name})));
    e.target.value="";
  };

  const extractFromDoc = () => {
    if(!f.pdfBase64) return;
    setEx(true); setExtErr(null);
    const msgContent = [
      {type:"document", source:{type:"base64", media_type:"application/pdf", data:f.pdfBase64}},
      {type:"text", text:"Extract the following fields from this invoice or receipt and return ONLY valid JSON:\n{vendor, description, amount, date, invoiceNum, suggestedCostType}\nvendor: company name\ndescription: what was purchased or performed\namount: numeric dollar amount only (no $ sign)\ndate: YYYY-MM-DD format\ninvoiceNum: invoice or receipt number if visible, else ''\nsuggestedCostType: one of Labor, Subcontractor, Material, Overhead, Equipment\nIf a field is not found, use empty string. Return ONLY the JSON object, no markdown."}
    ];
    fetch("https://api.anthropic.com/v1/messages",{
      method:"POST",
      headers:{"Content-Type":"application/json"},
      body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:400,system:"Extract invoice data. Return only valid JSON.",messages:[{role:"user",content:msgContent}]})
    }).then(r=>r.json()).then(data=>{
      if(data.error) throw new Error(data.error.message);
      const raw = data.content.filter(b=>b.type==="text").map(b=>b.text).join("");
      const cleaned = raw.split("```json").join("").split("```").join("").trim();
      const parsed = JSON.parse(cleaned);
      setF(p=>({
        ...p,
        vendor:      parsed.vendor      || p.vendor,
        description: parsed.description || p.description,
        amount:      parsed.amount      || p.amount,
        date:        parsed.date        || p.date,
        invoiceNum:  parsed.invoiceNum  || p.invoiceNum,
      }));
    }).catch(err=>{
      setExtErr("Extraction failed: "+err.message);
    }).finally(()=>setEx(false));
  };

  return (
    <div className="overlay" onClick={onClose}>
      <div className="modal modal-wide" onClick={e=>e.stopPropagation()} style={{maxWidth:580}}>
        <div className="modal-hdr">
          <div className="modal-title">{existingEntry?"Edit Cost Entry":"New Cost Entry"}</div>
          <button className="btn btn-ghost btn-sm" onClick={onClose}>x</button>
        </div>
        <div className="modal-body" style={{display:"flex",flexDirection:"column",gap:12}}>
          <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:12}}>
            <div className="flabel" style={{marginBottom:6}}>Upload Invoice / Receipt (optional)</div>
            {f.pdfBase64 ? (
              <div style={{display:"flex",alignItems:"center",gap:10}}>
                <span style={{fontSize:13,color:"var(--green)",flex:1}}>{f.pdfName}</span>
                <button className="btn btn-ai btn-sm" onClick={extractFromDoc} disabled={extracting}>{extracting?"Extracting...":"Extract Data"}</button>
                <button className="btn btn-ghost btn-sm" style={{color:"var(--red)"}} onClick={()=>setF(p=>({...p,pdfBase64:null,pdfName:""}))}>Remove</button>
              </div>
            ) : (
              <div className="drw-upload-zone" onClick={()=>fileRef.current&&fileRef.current.click()}>
                <div style={{fontFamily:"'Barlow Condensed'",fontSize:12,letterSpacing:1,color:"var(--accent-bright)"}}>Upload PDF or image - Claude will extract vendor, amount, and date</div>
              </div>
            )}
            <input ref={fileRef} type="file" accept=".pdf,image/*" style={{display:"none"}} onChange={handleFile}/>
            {extractErr && <div style={{fontSize:11,color:"var(--red)",marginTop:6}}>{extractErr}</div>}
          </div>

          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
            <div><div className="flabel">Vendor / Payee</div><input className="finput" value={f.vendor} onChange={e=>set("vendor",e.target.value)} placeholder="Company name..."/></div>
            <div><div className="flabel">Invoice / Receipt #</div><input className="finput" value={f.invoiceNum} onChange={e=>set("invoiceNum",e.target.value)} placeholder="INV-001"/></div>
          </div>
          <div><div className="flabel">Description</div><input className="finput" value={f.description} onChange={e=>set("description",e.target.value)} placeholder="What was this for..."/></div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10}}>
            <div>
              <div className="flabel">Cost Code</div>
              <select className="fselect" value={f.costCodeId} onChange={e=>set("costCodeId",e.target.value)}>
                <option value="">Select code...</option>
                {CC_DIVISIONS.map(div => {
                  const divCodes = costCodes.filter(c=>c.division===div);
                  if(!divCodes.length) return null;
                  return (
                    <optgroup key={div} label={div}>
                      {divCodes.map(c=><option key={c.id} value={c.id}>{c.code} - {c.name}</option>)}
                    </optgroup>
                  );
                })}
              </select>
            </div>
            <div><div className="flabel">Amount</div><input className="finput" type="number" value={f.amount} onChange={e=>set("amount",e.target.value)} placeholder="0.00"/></div>
            <div><div className="flabel">Date</div><input className="finput" type="date" value={f.date} onChange={e=>set("date",e.target.value)}/></div>
          </div>
          <div>
            <div className="flabel">Status</div>
            <select className="fselect" style={{maxWidth:200}} value={f.status} onChange={e=>set("status",e.target.value)}>
              {CE_STATUSES.map(s=><option key={s}>{s}</option>)}
            </select>
          </div>
        </div>
        <div className="modal-ftr">
          <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" onClick={()=>{
            if(!f.vendor.trim()||!f.amount) return;
            onSave({...f, id:existingEntry?f.id:"ce"+uid(), amount:parseFloat(f.amount)||0});
          }}>Save Entry</button>
        </div>
      </div>
    </div>
  );
};

const CostEntryLog = ({job, costEntries, costCodes, onAdd, onUpdate, onDelete}) => {
  const [showModal,setShowModal] = useState(false);
  const [editEntry,setEditEntry] = useState(null);
  const [statusF,  setStatusF]   = useState("all");
  const [codeF,    setCodeF]     = useState("all");

  const filtered = costEntries
    .filter(e => statusF==="all" || e.status===statusF)
    .filter(e => codeF==="all"   || e.costCodeId===codeF)
    .sort((a,b)=>b.date.localeCompare(a.date));

  const totalApproved = costEntries.filter(e=>e.status!=="Draft").reduce((s,e)=>s+e.amount,0);
  const totalPaid     = costEntries.filter(e=>e.status==="Paid").reduce((s,e)=>s+e.amount,0);
  const totalDraft    = costEntries.filter(e=>e.status==="Draft").reduce((s,e)=>s+e.amount,0);

  const openModal  = () => { setEditEntry(null); setShowModal(true); };
  const editModal  = (entry) => { setEditEntry(entry); setShowModal(true); };
  const closeModal = () => { setShowModal(false); setEditEntry(null); };
  const handleSave = (entry) => {
    if(editEntry) { onUpdate(entry); } else { onAdd(entry); }
    closeModal();
  };

  return (
    <div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10,marginBottom:16}}>
        {[
          {label:"Total Costs (Approved+Paid)", val:fmt(totalApproved), color:"var(--white)"},
          {label:"Paid",                         val:fmt(totalPaid),     color:"var(--green)"},
          {label:"Pending Approval",             val:fmt(totalDraft),    color:totalDraft>0?"var(--yellow)":"var(--muted)"},
        ].map(s=>(
          <div key={s.label} className="stat-card">
            <div className="stat-label">{s.label}</div>
            <div className="stat-value" style={{fontSize:16,color:s.color}}>{s.val}</div>
          </div>
        ))}
      </div>

      <div style={{display:"flex",gap:8,marginBottom:12,alignItems:"flex-end",flexWrap:"wrap"}}>
        <div>
          <div className="flabel">Status</div>
          <select className="fselect" value={statusF} onChange={e=>setStatusF(e.target.value)} style={{fontSize:12}}>
            <option value="all">All Statuses</option>
            {CE_STATUSES.map(s=><option key={s}>{s}</option>)}
          </select>
        </div>
        <div>
          <div className="flabel">Cost Code</div>
          <select className="fselect" value={codeF} onChange={e=>setCodeF(e.target.value)} style={{fontSize:12}}>
            <option value="all">All Codes</option>
            {costCodes.map(c=><option key={c.id} value={c.id}>{c.code} - {c.name}</option>)}
          </select>
        </div>
        <div style={{marginLeft:"auto"}}>
          <button className="btn btn-primary btn-sm" onClick={openModal}>+ Add Cost Entry</button>
        </div>
      </div>

      {filtered.length===0 ? (
        <div className="empty" style={{padding:40}}>No cost entries yet. Click + Add Cost Entry or upload an invoice to get started.</div>
      ) : (
        <table className="tbl">
          <thead>
            <tr><th>Date</th><th>Vendor</th><th>Description</th><th>Code</th><th>Amount</th><th>Invoice #</th><th>Status</th><th></th></tr>
          </thead>
          <tbody>
            {filtered.map(e => {
              const code = costCodes.find(c=>c.id===e.costCodeId);
              return (
                <tr key={e.id} onClick={()=>editModal(e)} style={{cursor:"pointer"}}>
                  <td className="col-mono">{fmtDate(e.date)}</td>
                  <td style={{color:"var(--white)",fontWeight:600}}>{e.vendor}</td>
                  <td style={{color:"var(--muted)",fontSize:11}}>{e.description}</td>
                  <td className="col-mono" style={{color:"var(--accent-bright)",fontSize:11}}>{code?code.code:""}</td>
                  <td className="col-mono">{fmt(e.amount)}</td>
                  <td className="col-mono" style={{fontSize:11,color:"var(--muted)"}}>{e.invoiceNum}</td>
                  <td><span style={{fontSize:11,color:CE_STATUS_COLOR[e.status]||"var(--muted)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>{e.status}</span></td>
                  <td>
                    <button className="btn btn-ghost btn-sm" style={{fontSize:11,color:"var(--red)"}} onClick={ev=>{ev.stopPropagation();onDelete(e.id);}}>x</button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      )}

      {showModal && (
        <CostEntryModal jobId={job.id} costCodes={costCodes} existingEntry={editEntry} onSave={handleSave} onClose={closeModal}/>
      )}
    </div>
  );
};

// --- SOV & DRAWS -----------------------------------------------------------------
const ScheduleOfValues = ({job, sovLines, drawRequests, onAddLine, onUpdateLine, onDeleteLine}) => {
  const [showAdd,setShowAdd] = useState(false);
  const [f, setF] = useState({description:"", scheduledValue:""});
  const set = (k,v) => setF(p=>({...p,[k]:v}));

  const totalScheduled  = sovLines.reduce((s,l)=>s+l.scheduledValue,0);
  const totalPrevBilled = sovLines.reduce((s,l)=>s+(l.previousPct/100)*l.scheduledValue,0);
  const totalBalance    = totalScheduled - totalPrevBilled;
  const contractTotal   = job.originalContract + (job.ownerCOs||[]).filter(c=>c.status==="Approved").reduce((s,c)=>s+c.amount,0);

  return (
    <div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:16}}>
        {[
          {label:"Scheduled Value",  val:fmt(totalScheduled),  color:"var(--white)"},
          {label:"Contract Total",   val:fmt(contractTotal),   color:Math.abs(totalScheduled-contractTotal)>100?"var(--yellow)":"var(--green)"},
          {label:"Billed to Date",   val:fmt(totalPrevBilled), color:"var(--accent-bright)"},
          {label:"Balance to Bill",  val:fmt(totalBalance),    color:"var(--muted)"},
        ].map(s=>(
          <div key={s.label} className="stat-card">
            <div className="stat-label">{s.label}</div>
            <div className="stat-value" style={{fontSize:16,color:s.color}}>{s.val}</div>
          </div>
        ))}
      </div>

      {Math.abs(totalScheduled-contractTotal)>100 && (
        <div style={{padding:"8px 12px",background:"rgba(251,191,36,.06)",border:"1px solid rgba(251,191,36,.2)",borderRadius:6,fontSize:12,color:"var(--yellow)",marginBottom:12}}>
          SOV total ({fmt(totalScheduled)}) does not match current contract ({fmt(contractTotal)}). Update line items to match.
        </div>
      )}

      <div style={{display:"flex",justifyContent:"flex-end",marginBottom:10}}>
        <button className="btn btn-primary btn-sm" onClick={()=>setShowAdd(!showAdd)}>+ Add SOV Line</button>
      </div>

      {showAdd && (
        <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14,marginBottom:12,display:"flex",flexDirection:"column",gap:10}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 160px",gap:10}}>
            <div><div className="flabel">Description</div><input className="finput" value={f.description} onChange={e=>set("description",e.target.value)} placeholder="Line item description..."/></div>
            <div><div className="flabel">Scheduled Value</div><input className="finput" type="number" value={f.scheduledValue} onChange={e=>set("scheduledValue",e.target.value)} placeholder="0.00"/></div>
          </div>
          <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
            <button className="btn btn-ghost btn-sm" onClick={()=>setShowAdd(false)}>Cancel</button>
            <button className="btn btn-primary btn-sm" onClick={()=>{
              if(!f.description.trim()||!f.scheduledValue) return;
              const nextNum = sovLines.length ? Math.max(...sovLines.map(l=>l.lineNum))+1 : 1;
              onAddLine({id:"sov"+uid(),jobId:job.id,lineNum:nextNum,description:f.description,scheduledValue:parseFloat(f.scheduledValue)||0,previousPct:0,thisPct:0});
              setShowAdd(false);
              setF({description:"",scheduledValue:""});
            }}>Add Line</button>
          </div>
        </div>
      )}

      <table className="tbl">
        <thead>
          <tr><th>#</th><th>Description</th><th>Scheduled Value</th><th>% Complete</th><th>Billed to Date</th><th>Balance</th><th></th></tr>
        </thead>
        <tbody>
          {sovLines.sort((a,b)=>a.lineNum-b.lineNum).map(line => {
            const billed  = (line.previousPct/100) * line.scheduledValue;
            const balance = line.scheduledValue - billed;
            return (
              <tr key={line.id}>
                <td className="col-mono" style={{color:"var(--muted)"}}>{line.lineNum}</td>
                <td style={{color:"var(--white)"}}>{line.description}</td>
                <td className="col-mono">{fmt(line.scheduledValue)}</td>
                <td>
                  <div style={{display:"flex",alignItems:"center",gap:8}}>
                    <input type="number" min="0" max="100" value={line.previousPct}
                      onChange={e=>onUpdateLine({...line,previousPct:Math.min(100,Math.max(0,parseInt(e.target.value)||0))})}
                      style={{width:60,background:"transparent",border:"1px solid var(--navy-border)",borderRadius:4,color:"var(--white)",padding:"3px 6px",fontSize:12,fontFamily:"'IBM Plex Mono',monospace"}}/>
                    <span style={{fontSize:11,color:"var(--muted)"}}>%</span>
                  </div>
                </td>
                <td className="col-mono" style={{color:"var(--accent-bright)"}}>{fmt(billed)}</td>
                <td className="col-mono" style={{color:"var(--muted)"}}>{fmt(balance)}</td>
                <td><button className="btn btn-ghost btn-sm" style={{fontSize:11,color:"var(--red)"}} onClick={()=>onDeleteLine(line.id)}>x</button></td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
};

// --- DRAW REQUEST MANAGER -----------------------------------------------------
const DR_STATUS_COLOR = {Draft:"var(--muted)",Submitted:"var(--accent-bright)",Approved:"var(--green)",Paid:"var(--green)",Void:"var(--red)"};
const DR_STATUSES = ["Draft","Submitted","Approved","Paid","Void"];

const DrawManager = ({job, drawRequests, sovLines, onAdd, onUpdate}) => {
  const [selId, setSelId] = useState(null);
  const [showAdd, setShowAdd] = useState(false);
  const [editLines, setEditLines] = useState({});

  const sel = drawRequests.find(d=>d.id===selId);

  const createDraw = () => {
    const nextNum = drawRequests.length ? Math.max(...drawRequests.map(d=>d.drawNum))+1 : 1;
    onAdd({id:"dr"+uid(),jobId:job.id,drawNum:nextNum,periodEnd:TODAY,retainagePct:10,status:"Draft",submittedDate:"",approvedDate:"",paidDate:"",lines:{}});
  };

  const selLines = sel ? {...sel.lines, ...editLines} : {};

  const amounts = sel ? calcDrawAmounts(sovLines, {...sel,lines:selLines}, sel.retainagePct) : null;

  const saveDrawLines = () => {
    if(!sel) return;
    onUpdate({...sel, lines:{...sel.lines,...editLines}});
    setEditLines({});
  };

  return (
    <div>
      <div style={{display:"flex",justifyContent:"flex-end",marginBottom:12}}>
        <button className="btn btn-primary btn-sm" onClick={createDraw}>+ New Draw Request</button>
      </div>

      <div style={{display:"grid",gridTemplateColumns:sel?"300px 1fr":"1fr",gap:0,border:"1px solid var(--navy-border)",borderRadius:8,overflow:"hidden",minHeight:300}}>
        <div style={{borderRight:sel?"1px solid var(--navy-border)":"none",overflowY:"auto"}}>
          {drawRequests.length===0 ? (
            <div className="empty" style={{padding:40}}>No draw requests yet.</div>
          ) : drawRequests.sort((a,b)=>a.drawNum-b.drawNum).map(dr => {
            const ams = calcDrawAmounts(sovLines, dr, dr.retainagePct);
            return (
              <div key={dr.id} onClick={()=>setSelId(selId===dr.id?null:dr.id)} style={{padding:"12px 14px",borderBottom:"1px solid rgba(42,64,128,.2)",cursor:"pointer",background:selId===dr.id?"rgba(74,124,220,.08)":"transparent",borderLeft:selId===dr.id?"3px solid var(--accent)":"3px solid transparent"}}>
                <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:3}}>
                  <div style={{fontFamily:"'Barlow Condensed'",fontSize:16,fontWeight:700,color:"var(--white)"}}>Draw #{dr.drawNum}</div>
                  <span style={{fontSize:11,color:DR_STATUS_COLOR[dr.status]||"var(--muted)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>{dr.status.toUpperCase()}</span>
                </div>
                <div style={{fontSize:12,color:"var(--accent-bright)",fontFamily:"'IBM Plex Mono',monospace"}}>{fmt(ams.netDue)} net due</div>
                <div style={{fontSize:11,color:"var(--muted)",marginTop:2}}>Period ending {fmtDate(dr.periodEnd)}</div>
              </div>
            );
          })}
        </div>

        {sel && (
          <div style={{overflowY:"auto",padding:16}}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:14}}>
              <div style={{fontFamily:"'Barlow Condensed'",fontSize:18,fontWeight:700,color:"var(--white)"}}>Draw Request #{sel.drawNum}</div>
              <select className="fselect" style={{maxWidth:160,fontSize:12}} value={sel.status} onChange={e=>onUpdate({...sel,status:e.target.value})}>
                {DR_STATUSES.map(s=><option key={s}>{s}</option>)}
              </select>
            </div>

            <div style={{display:"grid",gridTemplateColumns:"repeat(2,1fr)",gap:8,marginBottom:14}}>
              <div><div className="flabel">Period End Date</div><input className="finput" type="date" value={sel.periodEnd} onChange={e=>onUpdate({...sel,periodEnd:e.target.value})}/></div>
              <div><div className="flabel">Retainage %</div><input className="finput" type="number" value={sel.retainagePct} onChange={e=>onUpdate({...sel,retainagePct:parseFloat(e.target.value)||0})}/></div>
            </div>

            <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:8}}>SOV % Complete This Draw</div>
            {sovLines.sort((a,b)=>a.lineNum-b.lineNum).map(line => {
              const current = selLines[line.id] !== undefined ? selLines[line.id] : (sel.lines[line.id]||0);
              const prevAmt = (line.previousPct/100)*line.scheduledValue;
              const thisAmt = ((current-line.previousPct)/100)*line.scheduledValue;
              return (
                <div key={line.id} style={{display:"flex",alignItems:"center",gap:10,padding:"7px 0",borderBottom:"1px solid rgba(42,64,128,.2)"}}>
                  <span style={{fontSize:12,color:"var(--white)",flex:1}}>{line.description}</span>
                  <span style={{fontSize:11,color:"var(--muted)",fontFamily:"'IBM Plex Mono',monospace",width:60,textAlign:"right"}}>{fmt(line.scheduledValue)}</span>
                  <input type="number" min={line.previousPct} max="100" value={current}
                    onChange={e=>setEditLines(p=>({...p,[line.id]:Math.min(100,Math.max(line.previousPct,parseInt(e.target.value)||0))}))}
                    style={{width:55,background:"transparent",border:"1px solid var(--navy-border)",borderRadius:4,color:"var(--white)",padding:"3px 6px",fontSize:12,fontFamily:"'IBM Plex Mono',monospace"}}/>
                  <span style={{fontSize:11,color:"var(--muted)"}}>%</span>
                  <span style={{fontSize:11,color:thisAmt>0?"var(--accent-bright)":"var(--muted)",fontFamily:"'IBM Plex Mono',monospace",width:70,textAlign:"right"}}>{fmt(thisAmt)}</span>
                </div>
              );
            })}

            {Object.keys(editLines).length>0 && (
              <button className="btn btn-primary btn-sm" style={{marginTop:10}} onClick={saveDrawLines}>Save Changes</button>
            )}

            {amounts && (
              <div style={{marginTop:16,background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14}}>
                <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:10}}>Draw Summary</div>
                {[
                  ["Previous Billings",      fmt(amounts.previousBilled), "var(--muted)"],
                  ["This Period",             fmt(amounts.thisPeriod),     "var(--white)"],
                  ["Total Billed to Date",    fmt(amounts.totalBilled),    "var(--accent-bright)"],
                  ["Less Retainage ("+sel.retainagePct+"%)", "-"+fmt(amounts.retainage), "var(--yellow)"],
                  ["Net Amount Due",          fmt(amounts.netDue),         "var(--green)"],
                ].map(([l,v,c])=>(
                  <div key={l} style={{display:"flex",justifyContent:"space-between",padding:"5px 0",borderBottom:"1px solid rgba(42,64,128,.2)"}}>
                    <span style={{fontSize:13,color:"var(--muted)"}}>{l}</span>
                    <span style={{fontSize:13,fontFamily:"'IBM Plex Mono',monospace",color:c,fontWeight:600}}>{v}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

// --- JOB FINANCE DASHBOARD ----------------------------------------------------
const JobFinanceDashboard = ({job, budgetLines, costEntries, costCodes, sovLines, drawRequests}) => {
  const calc       = useMemo(()=>calcJob(job),[job]);
  const enriched   = budgetLines.map(bl=>calcBudgetLine(bl,costEntries));
  const totalBudget= enriched.reduce((s,b)=>s+b.budgeted,0);
  const totalActual= enriched.reduce((s,b)=>s+b.actual,0);
  const totalBilled= sovLines.reduce((s,l)=>s+(l.previousPct/100)*l.scheduledValue,0);
  const retainageHeld = drawRequests
    .filter(d=>["Approved","Paid"].includes(d.status))
    .reduce((s,d)=>s+calcDrawAmounts(sovLines,d,d.retainagePct).retainage,0);
  const collected  = drawRequests.filter(d=>d.status==="Paid")
    .reduce((s,d)=>s+calcDrawAmounts(sovLines,d,d.retainagePct).netDue,0);
  const earned     = totalBilled; // simplified WIP: earned = billed %
  const wipPosition = earned - totalBilled; // over/under billed
  const projMargin  = calc.cc - totalActual;
  const projMarginPct = calc.cc > 0 ? projMargin/calc.cc*100 : 0;

  const byDiv = CC_DIVISIONS.map(div => {
    const lines = enriched.filter(bl=>{const c=costCodes.find(x=>x.id===bl.costCodeId);return c&&c.division===div;});
    if(!lines.length) return null;
    return {div:div.split(" - ")[1]||div, budget:lines.reduce((s,l)=>s+l.budgeted,0), actual:lines.reduce((s,l)=>s+l.actual,0)};
  }).filter(Boolean);
  const maxBarVal = Math.max(...byDiv.map(d=>Math.max(d.budget,d.actual)),1);

  return (
    <div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:10}}>
        {[
          {label:"Current Contract",  val:fmt(calc.cc),         color:"var(--white)"},
          {label:"Total Billed",      val:fmt(totalBilled),     color:"var(--accent-bright)"},
          {label:"Collected",         val:fmt(collected),       color:"var(--green)"},
          {label:"Outstanding",       val:fmt(totalBilled-collected), color:totalBilled-collected>0?"var(--yellow)":"var(--muted)"},
        ].map(s=>(
          <div key={s.label} className="stat-card">
            <div className="stat-label">{s.label}</div>
            <div className="stat-value" style={{fontSize:15,color:s.color}}>{s.val}</div>
          </div>
        ))}
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:18}}>
        {[
          {label:"Total Budget",      val:fmt(totalBudget),     color:"var(--white)"},
          {label:"Cost to Date",      val:fmt(totalActual),     color:totalActual>totalBudget?"var(--red)":"var(--white)"},
          {label:"Projected Margin",  val:fmt(projMargin),      color:projMarginPct>=15?"var(--green)":projMarginPct>=8?"var(--yellow)":"var(--red)"},
          {label:"Retainage Held",    val:fmt(retainageHeld),   color:"var(--muted)"},
        ].map(s=>(
          <div key={s.label} className="stat-card">
            <div className="stat-label">{s.label}</div>
            <div className="stat-value" style={{fontSize:15,color:s.color}}>{s.val}</div>
            {s.label==="Projected Margin"&&<div className="stat-sub">{projMarginPct.toFixed(1)}% margin</div>}
          </div>
        ))}
      </div>

      <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:10}}>Budget vs Actual by Division</div>
      {byDiv.map(d=>(
        <div key={d.div} style={{marginBottom:10}}>
          <div style={{display:"flex",justifyContent:"space-between",fontSize:11,color:"var(--white)",marginBottom:4}}>
            <span>{d.div}</span>
            <span style={{fontFamily:"'IBM Plex Mono',monospace",color:d.actual>d.budget?"var(--red)":"var(--muted)"}}>{fmt(d.actual)} / {fmt(d.budget)}</span>
          </div>
          <div style={{position:"relative",height:14,background:"rgba(255,255,255,.04)",borderRadius:3,overflow:"hidden"}}>
            <div style={{position:"absolute",top:0,left:0,height:"100%",width:(d.budget/maxBarVal*100)+"%",background:"rgba(74,124,220,.25)",borderRadius:3}}/>
            <div style={{position:"absolute",top:2,left:0,height:"calc(100% - 4px)",width:(d.actual/maxBarVal*100)+"%",background:d.actual>d.budget?"var(--red)":"var(--accent)",borderRadius:3,margin:"0 0 0 0"}}/>
          </div>
        </div>
      ))}
    </div>
  );
};

// --- JOB FINANCE TAB WRAPPER --------------------------------------------------
const JobFinance = ({job, budgetLines, costEntries, costCodes, sovLines, drawRequests, jobSubcontracts,
  onAddBudgetLine, onUpdateBudgetLine, onDeleteBudgetLine,
  onAddCostEntry, onUpdateCostEntry, onDeleteCostEntry,
  onAddSOVLine, onUpdateSOVLine, onDeleteSOVLine,
  onAddDraw, onUpdateDraw}) => {

  const [tab, setTab] = useState("dashboard");
  const draftCosts = costEntries.filter(e=>e.status==="Draft").length;
  const draftDraws = drawRequests.filter(d=>d.status==="Draft").length;

  return (
    <div>
      <div className="drw-tabs">
        {[
          ["dashboard","Overview",null],
          ["budget","Budget",null],
          ["costs","Cost Entries",draftCosts||null],
          ["sov","Schedule of Values",null],
          ["draws","Draw Requests",draftDraws||null],
        ].map(([k,l,b])=>(
          <button key={k} className={"drw-tab"+(tab===k?" active":"")} onClick={()=>setTab(k)}>
            {l}{b?<span className="nav-badge" style={{background:"var(--yellow)",color:"var(--navy)",marginLeft:4}}>{b}</span>:null}
          </button>
        ))}
      </div>
      <div style={{paddingTop:14}}>
        {tab==="dashboard" && (
          <JobFinanceDashboard job={job} budgetLines={budgetLines} costEntries={costEntries} costCodes={costCodes} sovLines={sovLines} drawRequests={drawRequests}/>
        )}
        {tab==="budget" && (
          <BudgetBuilder job={job} budgetLines={budgetLines} costCodes={costCodes} costEntries={costEntries} jobSubcontracts={jobSubcontracts||[]} onAdd={onAddBudgetLine} onUpdate={onUpdateBudgetLine} onDelete={onDeleteBudgetLine}/>
        )}
        {tab==="costs" && (
          <CostEntryLog job={job} costEntries={costEntries} costCodes={costCodes} onAdd={onAddCostEntry} onUpdate={onUpdateCostEntry} onDelete={onDeleteCostEntry}/>
        )}
        {tab==="sov" && (
          <ScheduleOfValues job={job} sovLines={sovLines} drawRequests={drawRequests} onAddLine={onAddSOVLine} onUpdateLine={onUpdateSOVLine} onDeleteLine={onDeleteSOVLine}/>
        )}
        {tab==="draws" && (
          <DrawManager job={job} drawRequests={drawRequests} sovLines={sovLines} onAdd={onAddDraw} onUpdate={onUpdateDraw}/>
        )}
      </div>
    </div>
  );
};

// --- COMPANY FINANCE DASHBOARD ------------------------------------------------
// --- PROFIT FADE REPORT -------------------------------------------------------
const ProfitFadeReport = ({jobStats, costCodes}) => {
  var [selJobId, setSelJobId] = useState(null);

  // For each job, compute: estimated margin vs projected margin vs current margin
  // Profit fade = erosion from original estimate to current projection
  var rows = jobStats.map(function(js) {
    var job = js.job;
    var calc = js.calc;

    // Original margin
    var origContract = job.originalContract || 0;
    var origCost     = job.originalCost     || 0;
    var origMargin   = origContract > 0 ? (origContract - origCost) / origContract * 100 : 0;
    var origMarginAmt = origContract - origCost;

    // Current projected (includes approved COs)
    var currContract = calc.cc;
    var currCost     = calc.pc;
    var currMargin   = calc.pmpct;
    var currMarginAmt = calc.pm;

    // Actual cost to date
    var actualCost   = js.totalActual || 0;
    // Projected final = actual cost so far + remaining budget
    var budgetTotal  = js.totalBudget || currCost;
    var spentPct     = budgetTotal > 0 ? actualCost / budgetTotal : 0;
    var impliedFinal = spentPct > 0.05 ? actualCost / Math.max(spentPct, 0.01) : currCost;
    var projectedMargin    = currContract > 0 ? (currContract - impliedFinal) / currContract * 100 : 0;
    var projectedMarginAmt = currContract - impliedFinal;

    // Fade calculation
    var fadeFromEst    = origMargin - currMargin;        // estimate vs current projected
    var fadeFromProj   = currMargin - projectedMargin;   // current proj vs implied final
    var totalFade      = origMargin - projectedMargin;   // total fade estimate to implied

    var fadeAmt        = origMarginAmt - projectedMarginAmt;

    // Risk flags
    var flags = [];
    if(fadeFromEst > 5)  flags.push({label:"CO Fade",    color:"var(--yellow)", desc:"Change orders eroded "+fadeFromEst.toFixed(1)+"% margin"});
    if(fadeFromProj > 5) flags.push({label:"Cost Creep",  color:"var(--orange)", desc:"Actual costs tracking "+fadeFromProj.toFixed(1)+"% above budget"});
    if(totalFade > 10)   flags.push({label:"High Risk",   color:"var(--red)",    desc:"Total margin fade exceeds 10%"});
    if(projectedMargin < 10) flags.push({label:"Thin Margin",color:"var(--red)", desc:"Projected margin below 10%"});
    if((calc.pO) > origContract * 0.05) flags.push({label:"Pending COs",color:"var(--purple)",desc:"Pending COs could further affect margin"});

    return {
      job, origMargin, origMarginAmt, currMargin, currMarginAmt,
      projectedMargin, projectedMarginAmt, fadeFromEst, fadeFromProj,
      totalFade, fadeAmt, flags, actualCost, budgetTotal, spentPct,
      pendingCOs: calc.pO,
    };
  });

  var selRow = rows.find(function(r){return r.job.id===selJobId;});
  var mc = function(pct){ return pct>=18?"var(--green)":pct>=12?"var(--accent-bright)":pct>=8?"var(--yellow)":"var(--red)"; };
  var fadeColor = function(f){ return f<0?"var(--green)":f<3?"var(--muted)":f<7?"var(--yellow)":"var(--red)"; };

  return (
    <div>
      <div style={{padding:"10px 14px",background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,marginBottom:16,fontSize:12,color:"var(--white)",lineHeight:1.6}}>
        <span style={{color:"var(--accent-bright)",fontFamily:"'Barlow Condensed'",letterSpacing:1}}>PROFIT FADE</span> tracks margin erosion from original estimate through projected final cost.
        Fade occurs from change orders (sub markups without owner recovery), cost overruns, and scope creep.
        Click any job row to see a breakdown.
      </div>

      {/* Summary table */}
      <div className="card" style={{marginBottom:16}}>
        <table className="tbl">
          <thead>
            <tr>
              <th>Project</th>
              <th style={{textAlign:"right"}}>Est Margin</th>
              <th style={{textAlign:"right"}}>Current Proj</th>
              <th style={{textAlign:"right"}}>Implied Final</th>
              <th style={{textAlign:"right"}}>Total Fade</th>
              <th style={{textAlign:"right"}}>Fade $</th>
              <th>Flags</th>
            </tr>
          </thead>
          <tbody>
            {rows.map(function(r){
              return (
                <tr key={r.job.id} className="clickable" onClick={function(){setSelJobId(selJobId===r.job.id?null:r.job.id);}}
                  style={{background:selJobId===r.job.id?"rgba(74,124,220,.08)":"transparent"}}>
                  <td>
                    <div style={{color:"var(--white)",fontWeight:600}}>{r.job.name}</div>
                    <div style={{fontSize:10,color:"var(--muted)"}}>{r.job.id} - {r.job.phase}</div>
                  </td>
                  <td style={{textAlign:"right",fontFamily:"'IBM Plex Mono',monospace",color:mc(r.origMargin)}}>{r.origMargin.toFixed(1)}%</td>
                  <td style={{textAlign:"right",fontFamily:"'IBM Plex Mono',monospace",color:mc(r.currMargin)}}>{r.currMargin.toFixed(1)}%</td>
                  <td style={{textAlign:"right",fontFamily:"'IBM Plex Mono',monospace",color:mc(r.projectedMargin)}}>{r.projectedMargin.toFixed(1)}%</td>
                  <td style={{textAlign:"right",fontFamily:"'IBM Plex Mono',monospace",color:fadeColor(r.totalFade),fontWeight:r.totalFade>5?700:400}}>
                    {r.totalFade>0?"+":""}{r.totalFade.toFixed(1)}%
                  </td>
                  <td style={{textAlign:"right",fontFamily:"'IBM Plex Mono',monospace",color:r.fadeAmt>0?"var(--red)":"var(--green)",fontWeight:r.fadeAmt>0?700:400}}>
                    {r.fadeAmt>0?"-":"+$"}{r.fadeAmt>0?fmt(r.fadeAmt).replace("$",""):fmt(Math.abs(r.fadeAmt)).replace("$","")}
                  </td>
                  <td>
                    <div style={{display:"flex",gap:4,flexWrap:"wrap"}}>
                      {r.flags.map(function(f,i){
                        return <span key={i} style={{fontSize:9,fontFamily:"'Barlow Condensed'",letterSpacing:.5,color:f.color,border:"1px solid "+f.color+"44",borderRadius:3,padding:"1px 5px"}}>{f.label}</span>;
                      })}
                      {r.flags.length===0 && <span style={{fontSize:10,color:"var(--green)"}}>On Track</span>}
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Detail panel */}
      {selRow && (
        <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:16}}>
          <div style={{fontFamily:"'Barlow Condensed'",fontSize:16,fontWeight:700,color:"var(--white)",marginBottom:12}}>
            {selRow.job.name} - Fade Detail
          </div>

          {/* Waterfall cards */}
          <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:16}}>
            {[
              {label:"Original Estimate",   val:selRow.origMarginAmt,    pct:selRow.origMargin,    note:"At bid/award"},
              {label:"Current Contract",    val:selRow.currMarginAmt,    pct:selRow.currMargin,    note:"After approved COs"},
              {label:"Implied Final",       val:selRow.projectedMarginAmt,pct:selRow.projectedMargin,note:"Based on actual vs budget"},
              {label:"Total $ at Risk",     val:selRow.fadeAmt,           pct:selRow.totalFade,     note:"Estimate vs implied final", invert:true},
            ].map(function(s){
              var color = s.invert ? (s.val>0?"var(--red)":"var(--green)") : mc(s.pct);
              return (
                <div key={s.label} className="stat-card">
                  <div className="stat-label">{s.label}</div>
                  <div className="stat-value" style={{fontSize:15,color:color}}>{s.invert?(s.val>0?"-$":"+$"):""}{fmt(Math.abs(s.val)).replace("$","")}</div>
                  <div className="stat-sub">{s.pct.toFixed(1)}% margin   {s.note}</div>
                </div>
              );
            })}
          </div>

          {/* Fade waterfall bars */}
          <div style={{marginBottom:16}}>
            <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:10}}>Margin Waterfall</div>
            {[
              {label:"Original Estimate",  val:selRow.origMargin,       color:"var(--accent-bright)"},
              {label:"After Owner COs",    val:selRow.currMargin,       color:mc(selRow.currMargin)},
              {label:"Implied Final",      val:selRow.projectedMargin,  color:mc(selRow.projectedMargin)},
            ].map(function(bar){
              var w = Math.max(0,Math.min(100,bar.val)) + "%";
              return (
                <div key={bar.label} style={{marginBottom:8}}>
                  <div style={{display:"flex",justifyContent:"space-between",fontSize:11,marginBottom:3}}>
                    <span style={{color:"var(--muted)"}}>{bar.label}</span>
                    <span style={{fontFamily:"'IBM Plex Mono',monospace",color:bar.color,fontWeight:600}}>{bar.val.toFixed(1)}%</span>
                  </div>
                  <div style={{height:6,background:"rgba(255,255,255,.06)",borderRadius:3,overflow:"hidden"}}>
                    <div style={{height:"100%",width:w,background:bar.color,borderRadius:3,transition:"width .4s"}}/>
                  </div>
                </div>
              );
            })}
          </div>

          {/* Cost tracking */}
          <div style={{marginBottom:16}}>
            <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:8}}>Cost Tracking</div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10}}>
              <div className="stat-card">
                <div className="stat-label">Budget</div>
                <div className="stat-value" style={{fontSize:14}}>{fmt(selRow.budgetTotal)}</div>
                <div className="stat-sub">Total projected cost</div>
              </div>
              <div className="stat-card">
                <div className="stat-label">Actual to Date</div>
                <div className="stat-value" style={{fontSize:14,color:selRow.actualCost>selRow.budgetTotal?"var(--red)":"var(--accent-bright)"}}>{fmt(selRow.actualCost)}</div>
                <div className="stat-sub">{(selRow.spentPct*100).toFixed(0)}% of budget spent</div>
              </div>
              <div className="stat-card">
                <div className="stat-label">Remaining Budget</div>
                <div className="stat-value" style={{fontSize:14,color:selRow.budgetTotal-selRow.actualCost<0?"var(--red)":"var(--green)"}}>{fmt(Math.max(0,selRow.budgetTotal-selRow.actualCost))}</div>
                <div className="stat-sub">{selRow.budgetTotal-selRow.actualCost<0?"OVER BUDGET":"Available"}</div>
              </div>
            </div>
          </div>

          {/* Flags / risk items */}
          {selRow.flags.length>0 && (
            <div>
              <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:8}}>Risk Items</div>
              {selRow.flags.map(function(f,i){
                return (
                  <div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 12px",background:"rgba(255,255,255,.03)",border:"1px solid "+f.color+"33",borderRadius:6,marginBottom:6}}>
                    <div style={{width:8,height:8,borderRadius:"50%",background:f.color,flexShrink:0}}/>
                    <div>
                      <div style={{fontSize:12,color:f.color,fontFamily:"'Barlow Condensed'",letterSpacing:.5,fontWeight:700}}>{f.label}</div>
                      <div style={{fontSize:11,color:"var(--muted)"}}>{f.desc}</div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
          {selRow.flags.length===0 && (
            <div style={{padding:"10px 14px",background:"rgba(52,211,153,.05)",border:"1px solid rgba(52,211,153,.2)",borderRadius:6,fontSize:12,color:"var(--green)"}}>
              No margin risk flags. This job is tracking well against estimate.
            </div>
          )}
        </div>
      )}
    </div>
  );
};

const CompanyFinance = ({jobs, budgetLines, costEntries, costCodes, sovLines, drawRequests}) => {
  const [tab, setTab] = useState("overview");

  const jobStats = jobs.filter(j=>j.phase!=="Closed"&&!j.isTraining).map(job => {
    const jBudget  = budgetLines[job.id]||[];
    const jCosts   = costEntries[job.id]||[];
    const jSOV     = sovLines[job.id]||[];
    const jDraws   = drawRequests[job.id]||[];
    const calc     = calcJob(job);
    const enriched = jBudget.map(bl=>calcBudgetLine(bl,jCosts));
    const totalBudget = enriched.reduce((s,b)=>s+b.budgeted,0);
    const totalActual = enriched.reduce((s,b)=>s+b.actual,0);
    const totalBilled = jSOV.reduce((s,l)=>s+(l.previousPct/100)*l.scheduledValue,0);
    const collected   = jDraws.filter(d=>d.status==="Paid").reduce((s,d)=>s+calcDrawAmounts(jSOV,d,d.retainagePct).netDue,0);
    const outstanding = totalBilled - collected;
    const retainage   = jDraws.filter(d=>["Approved","Paid"].includes(d.status)).reduce((s,d)=>s+calcDrawAmounts(jSOV,d,d.retainagePct).retainage,0);
    const projMargin  = calc.cc > 0 ? (calc.cc - totalActual)/calc.cc*100 : 0;
    const wipPos      = totalBilled - totalActual; // simplified WIP: earned - cost
    return {job,calc,totalBudget,totalActual,totalBilled,collected,outstanding,retainage,projMargin,wipPos};
  });

  const totals = {
    contract:    jobStats.reduce((s,j)=>s+j.calc.cc,0),
    billed:      jobStats.reduce((s,j)=>s+j.totalBilled,0),
    collected:   jobStats.reduce((s,j)=>s+j.collected,0),
    outstanding: jobStats.reduce((s,j)=>s+j.outstanding,0),
    costs:       jobStats.reduce((s,j)=>s+j.totalActual,0),
    retainage:   jobStats.reduce((s,j)=>s+j.retainage,0),
  };
  const totalMargin    = totals.contract > 0 ? (totals.contract-totals.costs)/totals.contract*100 : 0;

  return (
    <div>
      <div className="drw-tabs">
        {[["overview","Overview"],["wip","WIP Report"],["receivables","Receivables"]].map(([k,l])=>(
          <button key={k} className={"drw-tab"+(tab===k?" active":"")} onClick={()=>setTab(k)}>{l}</button>
        ))}
      </div>
      <div style={{paddingTop:14}}>
        {tab==="overview" && (
          <div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:16}}>
              {[
                {label:"Total Contract Value",  val:fmt(totals.contract),    color:"var(--white)"},
                {label:"Billed to Date",         val:fmt(totals.billed),      color:"var(--accent-bright)"},
                {label:"Collected",              val:fmt(totals.collected),   color:"var(--green)"},
                {label:"Open Receivables",       val:fmt(totals.outstanding), color:totals.outstanding>0?"var(--yellow)":"var(--muted)"},
              ].map(s=>(
                <div key={s.label} className="stat-card">
                  <div className="stat-label">{s.label}</div>
                  <div className="stat-value" style={{fontSize:16,color:s.color}}>{s.val}</div>
                </div>
              ))}
            </div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:20}}>
              {[
                {label:"Total Costs to Date",   val:fmt(totals.costs),       color:"var(--white)"},
                {label:"Retainage Held",         val:fmt(totals.retainage),   color:"var(--muted)"},
                {label:"Gross Margin (Projected)",val:fmt(totals.contract-totals.costs), color:totalMargin>=15?"var(--green)":totalMargin>=8?"var(--yellow)":"var(--red)"},
                {label:"Margin %",               val:fmtPct(totalMargin),     color:totalMargin>=15?"var(--green)":totalMargin>=8?"var(--yellow)":"var(--red)"},
              ].map(s=>(
                <div key={s.label} className="stat-card">
                  <div className="stat-label">{s.label}</div>
                  <div className="stat-value" style={{fontSize:16,color:s.color}}>{s.val}</div>
                </div>
              ))}
            </div>

            <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:10}}>By Project</div>
            <table className="tbl">
              <thead><tr><th>Project</th><th>Contract</th><th>Billed</th><th>Costs</th><th>Proj Margin</th><th>Outstanding</th></tr></thead>
              <tbody>
                {jobStats.map(({job,calc,totalBilled,totalActual,outstanding,projMargin})=>(
                  <tr key={job.id}>
                    <td><div style={{color:"var(--white)",fontWeight:600}}>{job.name}</div><div style={{fontSize:11,color:"var(--muted)"}}>{job.id}</div></td>
                    <td className="col-mono">{fmt(calc.cc)}</td>
                    <td className="col-mono">{fmt(totalBilled)}</td>
                    <td className="col-mono">{fmt(totalActual)}</td>
                    <td><span style={{fontSize:12,fontFamily:"'Barlow Condensed'",color:projMargin>=15?"var(--green)":projMargin>=8?"var(--yellow)":"var(--red)"}}>{fmtPct(projMargin)}</span></td>
                    <td className="col-mono" style={{color:outstanding>0?"var(--yellow)":"var(--muted)"}}>{fmt(outstanding)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {tab==="wip" && (
          <div>
            <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:"11px 14px",marginBottom:14,fontSize:13,color:"var(--white)"}}>
              The WIP report shows whether each job is <strong style={{color:"var(--green)"}}>over-billed</strong> (you have billed more than you have earned - you owe work) or <strong style={{color:"var(--red)"}}>under-billed</strong> (you have done more work than you have billed - the client owes you money). Ideally you want to be slightly over-billed on every job.
            </div>
            <table className="tbl">
              <thead><tr><th>Project</th><th>Contract</th><th>% Complete</th><th>Earned Revenue</th><th>Billed to Date</th><th>WIP Position</th><th>Status</th></tr></thead>
              <tbody>
                {jobStats.map(({job,calc,totalBilled,totalActual,wipPos})=>{
                  const jSOV = sovLines[job.id]||[];
                  const totalSched = jSOV.reduce((s,l)=>s+l.scheduledValue,0);
                  const pctComplete = totalSched>0 ? totalBilled/totalSched*100 : 0;
                  const earned = pctComplete/100*calc.cc;
                  const wip = totalBilled - earned;
                  const isOverBilled = wip > 0;
                  return (
                    <tr key={job.id}>
                      <td><div style={{color:"var(--white)",fontWeight:600}}>{job.name}</div><div style={{fontSize:11,color:"var(--muted)"}}>{job.id}</div></td>
                      <td className="col-mono">{fmt(calc.cc)}</td>
                      <td className="col-mono">{fmtPct(pctComplete)}</td>
                      <td className="col-mono">{fmt(earned)}</td>
                      <td className="col-mono">{fmt(totalBilled)}</td>
                      <td className="col-mono" style={{color:isOverBilled?"var(--green)":"var(--red)",fontWeight:600}}>{isOverBilled?"+":""}{fmt(wip)}</td>
                      <td><span style={{fontSize:11,fontFamily:"'Barlow Condensed'",letterSpacing:.5,color:isOverBilled?"var(--green)":"var(--red)"}}>{isOverBilled?"OVER-BILLED":"UNDER-BILLED"}</span></td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}

        {tab==="receivables" && (
          <div>
            <table className="tbl">
              <thead><tr><th>Project</th><th>Client</th><th>Billed</th><th>Collected</th><th>Outstanding</th><th>Retainage</th></tr></thead>
              <tbody>
                {jobStats.map(({job,totalBilled,collected,outstanding,retainage})=>(
                  <tr key={job.id}>
                    <td><div style={{color:"var(--white)",fontWeight:600}}>{job.name}</div><div style={{fontSize:11,color:"var(--muted)"}}>{job.id}</div></td>
                    <td style={{color:"var(--muted)"}}>{job.client}</td>
                    <td className="col-mono">{fmt(totalBilled)}</td>
                    <td className="col-mono" style={{color:"var(--green)"}}>{fmt(collected)}</td>
                    <td className="col-mono" style={{color:outstanding>0?"var(--yellow)":"var(--muted)",fontWeight:outstanding>0?600:400}}>{fmt(outstanding)}</td>
                    <td className="col-mono" style={{color:"var(--muted)"}}>{fmt(retainage)}</td>
                  </tr>
                ))}
                <tr style={{borderTop:"2px solid var(--navy-border)"}}>
                  <td colSpan="2" style={{color:"var(--white)",fontWeight:700,fontFamily:"'Barlow Condensed'",letterSpacing:1}}>TOTALS</td>
                  <td className="col-mono" style={{fontWeight:700}}>{fmt(totals.billed)}</td>
                  <td className="col-mono" style={{color:"var(--green)",fontWeight:700}}>{fmt(totals.collected)}</td>
                  <td className="col-mono" style={{color:totals.outstanding>0?"var(--yellow)":"var(--muted)",fontWeight:700}}>{fmt(totals.outstanding)}</td>
                  <td className="col-mono" style={{fontWeight:700}}>{fmt(totals.retainage)}</td>
                </tr>
              </tbody>
            </table>
          </div>
        )}
        {tab==="fade" && (
          <ProfitFadeReport jobStats={jobStats} costCodes={costCodes}/>
        )}
      </div>
    </div>
  );
};

