// --- SUBCONTRACT HELPERS ------------------------------------------------------
const calcCommittedForCode = (costCodeId, jobSubcontracts) => {
  return (jobSubcontracts||[])
    .filter(sc => sc.costCodeId === costCodeId && ["Issued","Executed","Complete"].includes(sc.status))
    .reduce((s, sc) => {
      const scoAmt = (sc.subCOs||[])
        .filter(sco => ["Issued","Executed"].includes(sco.status))
        .reduce((ss, sco) => ss + (sco.amount||0), 0);
      return s + (sc.contractValue||0) + scoAmt;
    }, 0);
};

const checkCOI = (dirEntry) => {
  if(!dirEntry) return {ok:false, message:"Sub not found in directory"};
  if(!dirEntry.insExp) return {ok:false, message:"No COI on file for "+dirEntry.company};
  const expDate = new Date(dirEntry.insExp);
  const now     = new Date(TODAY);
  if(expDate < now) {
    return {ok:false, message:"COI expired "+fmtDate(dirEntry.insExp)+" for "+dirEntry.company};
  }
  const days = Math.ceil((expDate-now)/86400000);
  if(days <= 60) {
    return {ok:true, warn:true, message:"COI expiring in "+days+" days ("+fmtDate(dirEntry.insExp)+")"};
  }
  return {ok:true, warn:false, message:"COI current through "+fmtDate(dirEntry.insExp)};
};

// --- COI WARNING MODAL --------------------------------------------------------
const COIWarningModal = ({sub, dirEntry, onConfirm, onCancel}) => {
  const [confirmText, setConfirmText] = useState("");
  const coi = checkCOI(dirEntry);
  const canProceed = confirmText.trim().toUpperCase() === "CONFIRM";

  return (
    <div className="overlay" onClick={onCancel}>
      <div className="modal" onClick={e=>e.stopPropagation()} style={{maxWidth:480}}>
        <div className="modal-hdr" style={{background:"rgba(248,113,113,.1)"}}>
          <div>
            <div className="modal-title" style={{color:"var(--red)"}}>COI Warning</div>
            <div className="modal-sub">Insurance issue detected</div>
          </div>
          <button className="btn btn-ghost btn-sm" onClick={onCancel}>x</button>
        </div>
        <div className="modal-body">
          <div style={{padding:"12px 14px",background:"rgba(248,113,113,.06)",border:"1px solid rgba(248,113,113,.25)",borderRadius:8,marginBottom:14}}>
            <div style={{fontSize:14,color:"var(--red)",fontWeight:600,marginBottom:4}}>Issue: {coi.message}</div>
            <div style={{fontSize:12,color:"var(--muted)"}}>Issuing a subcontract to an uninsured or underinsured party exposes Westroe Construction to liability. An updated COI should be obtained before proceeding.</div>
          </div>
          <div style={{fontSize:13,color:"var(--white)",marginBottom:10}}>
            To proceed anyway, type <strong style={{color:"var(--red)"}}>CONFIRM</strong> below and acknowledge you are overriding this safeguard.
          </div>
          <input className="finput" value={confirmText} onChange={e=>setConfirmText(e.target.value)} placeholder="Type CONFIRM to override..."/>
          <div style={{fontSize:11,color:"var(--muted)",marginTop:8}}>Recommended: Update the COI in the Master Directory first, then re-issue this subcontract.</div>
        </div>
        <div className="modal-ftr">
          <button className="btn btn-primary" onClick={onCancel}>Cancel - Update COI First</button>
          <button className="btn btn-ghost" style={{color:"var(--red)",opacity:canProceed?1:.4}} disabled={!canProceed} onClick={onConfirm}>Override &amp; Proceed</button>
        </div>
      </div>
    </div>
  );
};

// --- SUB CO MODAL -------------------------------------------------------------
const SubCOModal = ({subcontract, existingSCO, onSave, onClose, directory}) => {
  const nextNum = (subcontract.subCOs||[]).length
    ? "SCO-"+(String(Math.max(...(subcontract.subCOs||[]).map(s=>parseInt(s.num.replace("SCO-",""))||0))+1)).padStart("3","0")
    : "SCO-001";
  const blank = {num:nextNum, description:"", amount:"", status:"Draft", date:TODAY, reason:""};
  const [f, setF] = useState(existingSCO || blank);
  const set = (k,v) => setF(p=>({...p,[k]:v}));

  return (
    <div className="overlay" onClick={onClose}>
      <div className="modal" onClick={e=>e.stopPropagation()} style={{maxWidth:480}}>
        <div className="modal-hdr">
          <div className="modal-title">{existingSCO?"Edit Sub Change Order":"New Sub Change Order"}</div>
          <button className="btn btn-ghost btn-sm" onClick={onClose}>x</button>
        </div>
        <div className="modal-body" style={{display:"flex",flexDirection:"column",gap:10}}>
          <div style={{display:"grid",gridTemplateColumns:"100px 1fr",gap:10}}>
            <div><div className="flabel">Number</div><input className="finput" value={f.num} onChange={e=>set("num",e.target.value)}/></div>
            <div><div className="flabel">Description</div><input className="finput" value={f.description} onChange={e=>set("description",e.target.value)} placeholder="What changed..."/></div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 140px",gap:10}}>
            <div><div className="flabel">Amount</div><input className="finput" type="number" value={f.amount} onChange={e=>set("amount",e.target.value)} placeholder="0.00"/></div>
            <div><div className="flabel">Date</div><input className="finput" type="date" value={f.date} onChange={e=>set("date",e.target.value)}/></div>
            <div><div className="flabel">Status</div><select className="fselect" value={f.status} onChange={e=>set("status",e.target.value)}>{SCO_STATUSES.map(s=><option key={s}>{s}</option>)}</select></div>
          </div>
          <div><div className="flabel">Reason / Justification</div><input className="finput" value={f.reason} onChange={e=>set("reason",e.target.value)} placeholder="Owner-directed, unforeseen condition, design change..."/></div>
        </div>
        <div className="modal-ftr">
          <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" onClick={()=>{
            if(!f.description.trim()||!f.amount) return;
            onSave({...f, id:existingSCO?f.id:"sco"+uid(), amount:parseFloat(f.amount)||0});
          }}>Save</button>
        </div>
      </div>
    </div>
  );
};

