// Full-screen document viewer for generated subcontract with section nav,
// formatted display, inline editing, copy, and print.

const SubcontractFormModal = function(props) {
  var job=props.job,directory=props.directory,costCodes=props.costCodes;
  var contractTemplates=props.contractTemplates,existingSC=props.existingSC;
  var phases=props.phases,activities=props.activities,masterDocLib=props.masterDocLib;
  var onSave=props.onSave,onClose=props.onClose;
  const subs = directory.filter(d=>d.active);
  const blank = {jobId:job.id,dirId:"",trade:"",costCodeId:"",description:"",contractValue:"",status:"Draft",scopeNotes:"",templateDocId:null,generatedDoc:"",pdfBase64:null,scopeOfWork:"",executedDate:"",subCOs:[],lienWaivers:[],invoices:[],requireCondWaiver:false};
  const [f, setF] = useState(existingSC ? {...existingSC, contractValue:String(existingSC.contractValue)} : blank);
  const set = (k,v) => setF(p=>({...p,[k]:v}));
  const [genLoading, setGenLoading]     = useState(false);
  const [genError, setGenError]         = useState(null);
  const [draftingScope, setDraftingScope] = useState(false);
  const [showViewer, setShowViewer]     = useState(false);
  const [exhibits, setExhibits] = useState({schedB:true,lienC:true,safetyD:true});
  const setEx = (k,v) => setExhibits(p=>({...p,[k]:v}));
  const linkedScope = null;

  const selectedSub = directory.find(d=>d.id===f.dirId);
  const coi = selectedSub ? checkCOI(selectedSub) : null;

  const draftScopeInline = () => {
    if(!f.trade&&!f.description) return;
    setDraftingScope(true);
    const prompt = [
      "Draft a formal Exhibit A - Scope of Work for a subcontract agreement.",
      "GC: Westroe Construction | GC License #105268 | Charlotte, NC | 704-962-6507",
      "Project: "+job.name,
      "Trade / Subcontractor Work: "+f.trade,
      "Description: "+f.description,
      "Scope Notes: "+(f.scopeNotes||"None"),
      "Contract Value: $"+(parseFloat(f.contractValue)||0).toLocaleString(),
      "",
      "Draft a comprehensive Exhibit A with sections: General Scope, Specific Inclusions, Specific Exclusions, Performance Standards, Coordination Obligations, Schedule Requirements, Submittals Required, Warranties.",
      "Use formal subcontract language. Reference GC License #105268 and OSHA compliance.",
    ].join("\n");
    fetch("https://api.anthropic.com/v1/messages",{
      method:"POST",headers:{"Content-Type":"application/json"},
      body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:3000,system:"You are drafting a formal subcontract Exhibit A scope of work for Westroe Construction (GC #105268), Charlotte NC.",messages:[{role:"user",content:prompt}]})
    }).then(r=>r.json()).then(data=>{
      if(data.error) throw new Error(data.error.message);
      const text = data.content.filter(b=>b.type==="text").map(b=>b.text).join("");
      set("scopeOfWork",text);
    }).catch(err=>console.error("Scope draft failed:",err.message))
    .finally(()=>setDraftingScope(false));
  };

  const generateDoc = () => {
    const template = contractTemplates.find(t=>t.id===f.templateDocId);
    if(!template) return;
    setGenLoading(true); setGenError(null);
    const subInfo = selectedSub ? selectedSub.company+" - "+selectedSub.trade+(selectedSub.license?" - Lic: "+selectedSub.license:"")+(selectedSub.phone?" | "+selectedSub.phone:"") : "Unknown";
    const code = costCodes.find(c=>c.id===f.costCodeId);
    const prompt = [
      "Generate a subcontract agreement for Westroe Construction based on this template.",
      "Fill in all placeholders and blanks with the project data provided.",
      "Keep all original contract language intact.",
      "",
      "CONTRACTOR: Westroe Construction | GC License #105268 | Charlotte, NC | 704-962-6507",
      "SUBCONTRACTOR: "+subInfo,
      "PROJECT: "+job.name+" ("+job.id+")",
      "ADDRESS: "+(job.address||""),
      "TRADE: "+f.trade,
      "COST CODE: "+(code?code.code+" - "+code.name:""),
      "CONTRACT VALUE: $"+(parseFloat(f.contractValue)||0).toLocaleString(),
      "SCOPE: "+f.description+(f.scopeNotes?" | "+f.scopeNotes:""),
      "START DATE: "+(job.startDate||""),
      "COMPLETION DATE: "+(job.finishDate||""),
      "RETAINAGE: 10%",
      "",
      f.scopeOfWork?"EXHIBIT A - SCOPE OF WORK (include verbatim):":"",
      f.scopeOfWork||"",
      "",
      exhibits.schedB?"EXHIBIT B - PROJECT SCHEDULE: Generate a project schedule exhibit showing key milestones and phases for this subcontractor. Use the following job dates: Start: "+(job.startDate||"TBD")+", Completion: "+(job.finishDate||"TBD")+". Include relevant phases for the "+f.trade+" scope. Format as a milestone table.":"",
      "",
      exhibits.lienC?"EXHIBIT C - LIEN WAIVER FORMS: Include four North Carolina lien waiver forms: (1) Conditional Waiver and Release on Progress Payment, (2) Unconditional Waiver and Release on Progress Payment, (3) Conditional Waiver and Release on Final Payment, (4) Unconditional Waiver and Release on Final Payment. Use standard NC statutory form language. Leave claimant name, project name, and amounts as blanks to fill in.":"",
      "",
      exhibits.safetyD?"EXHIBIT D - SUBCONTRACTOR SAFETY REQUIREMENTS: Generate a Westroe Construction subcontractor safety requirements exhibit covering: required insurance and COI submission, competent person designation, PPE requirements, toolbox talk requirements, incident reporting, OSHA compliance, site-specific safety plan submission, and right of GC to stop work for safety violations.":"",
      "",
      "IMPORTANT: Generate the complete contract document with all selected exhibits clearly labeled as separate sections (EXHIBIT A, EXHIBIT B, etc.) at the end of the base agreement.",
    ].join("\n");
    const msgContent = [];
    if(template.base64) {
      msgContent.push({type:"document",source:{type:"base64",media_type:template.fileType==="pdf"?"application/pdf":"application/vnd.openxmlformats-officedocument.wordprocessingml.document",data:template.base64}});
    }
    msgContent.push({type:"text",text:prompt});
    fetch("https://api.anthropic.com/v1/messages",{
      method:"POST",
      headers:{"Content-Type":"application/json"},
      body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:4000,system:"You are generating a construction subcontract for Westroe Construction (GC License #105268), Charlotte NC. If the template does not already have a Westroe letterhead, add at the very top: WESTROE CONSTRUCTION | GC License #105268 | Charlotte, NC | 704-962-6507. Fill all blanks with provided project data. Preserve all original contract language.",messages:[{role:"user",content:msgContent}]})
    }).then(r=>r.json()).then(data=>{
      if(data.error) throw new Error(data.error.message);
      const text = data.content.filter(b=>b.type==="text").map(b=>b.text).join("");
      setF(p=>({...p,generatedDoc:text}));
    }).catch(err=>{
      setGenError("Generation failed: "+err.message);
    }).finally(()=>setGenLoading(false));
  };

  return (
    <div className="overlay" onClick={onClose}>
      <div className="modal modal-wide" onClick={e=>e.stopPropagation()} style={{maxWidth:640,maxHeight:"90vh",display:"flex",flexDirection:"column"}}>
        <div className="modal-hdr">
          <div className="modal-title">{existingSC?"Edit Subcontract":"New Subcontract"}</div>
          <button className="btn btn-ghost btn-sm" onClick={onClose}>x</button>
        </div>
        <div className="modal-body" style={{flex:1,overflowY:"auto",display:"flex",flexDirection:"column",gap:12}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
            <div>
              <div className="flabel">Subcontractor</div>
              <select className="fselect" value={f.dirId} onChange={e=>set("dirId",e.target.value)}>
                <option value="">Select from directory...</option>
                {subs.map(d=><option key={d.id} value={d.id}>{d.company} - {d.trade}</option>)}
              </select>
              {coi && (
                <div style={{fontSize:11,marginTop:4,color:coi.ok?(coi.warn?"var(--yellow)":"var(--green)"):"var(--red)"}}>
                  {coi.ok?(coi.warn?"Warning: ":""):"Issue: "}{coi.message}
                </div>
              )}
            </div>
            <div><div className="flabel">Trade</div><input className="finput" value={f.trade} onChange={e=>set("trade",e.target.value)} placeholder="Plumbing, Electrical..."/></div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 140px 140px",gap:10}}>
            <div>
              <div className="flabel">Cost Code (ties to budget)</div>
              <select className="fselect" value={f.costCodeId} onChange={e=>set("costCodeId",e.target.value)}>
                <option value="">Select code...</option>
                {CC_DIVISIONS.map(div=>{
                  const divCodes = costCodes.filter(c=>c.division===div&&["Subcontractor","Labor"].includes(c.type));
                  if(!divCodes.length) return null;
                  return (
                    <optgroup key={div} label={div}>
                      {divCodes.map(c=><option key={c.id} value={c.id}>{c.code} - {c.name}</option>)}
                    </optgroup>
                  );
                })}
              </select>
            </div>
            <div><div className="flabel">Contract Value</div><input className="finput" type="number" value={f.contractValue} onChange={e=>set("contractValue",e.target.value)} placeholder="0.00"/></div>
            <div><div className="flabel">Status</div><select className="fselect" value={f.status} onChange={e=>set("status",e.target.value)}>{SC_STATUSES.map(s=><option key={s}>{s}</option>)}</select></div>
          </div>
          <div><div className="flabel">Scope of Work</div><textarea className="ftextarea" rows={2} value={f.description} onChange={e=>set("description",e.target.value)} placeholder="What is this subcontractor responsible for..."/></div>
          <div><div className="flabel">Scope Notes / Exclusions</div><input className="finput" value={f.scopeNotes} onChange={e=>set("scopeNotes",e.target.value)} placeholder="Key inclusions, exclusions, coordination requirements..."/></div>

          <div>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:6}}>
              <div className="flabel">Exhibit A - Scope of Work</div>
              <div style={{display:"flex",gap:6}}>
                {linkedScope && !f.scopeOfWork && (
                  <button className="btn btn-ghost btn-sm" style={{fontSize:11,color:"var(--green)"}} onClick={()=>set("scopeOfWork",linkedScope)}>
                    Pull from PreCon Estimate
                  </button>
                )}
                <button className="btn btn-ai btn-sm" style={{fontSize:10}} onClick={draftScopeInline} disabled={draftingScope}>
                  {draftingScope?"Drafting...":"Draft Scope with AI"}
                </button>
              </div>
            </div>
            {linkedScope && !f.scopeOfWork && (
              <div style={{fontSize:11,color:"var(--green)",marginBottom:6}}>Exhibit A scope available from PreCon estimate</div>
            )}
            <textarea className="ftextarea" rows={6} value={f.scopeOfWork||""} onChange={e=>set("scopeOfWork",e.target.value)} placeholder="Exhibit A scope of work will be embedded in the generated subcontract document..."/>
          </div>

          {/* Exhibit selection */}
          <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:12}}>
            <div className="flabel" style={{marginBottom:8}}>Exhibits to Include</div>
            <div style={{display:"flex",gap:16,flexWrap:"wrap"}}>
              <label style={{display:"flex",alignItems:"center",gap:6,cursor:"pointer",fontSize:12,color:"var(--white)"}}>
                <input type="checkbox" checked disabled style={{accentColor:"var(--accent)"}}/>
                <span>Exhibit A - Scope of Work <span style={{fontSize:10,color:"var(--green)"}}>always</span></span>
              </label>
              <label style={{display:"flex",alignItems:"center",gap:6,cursor:"pointer",fontSize:12,color:"var(--white)"}}>
                <input type="checkbox" checked={exhibits.schedB} onChange={e=>setEx("schedB",e.target.checked)} style={{accentColor:"var(--accent)"}}/>
                Exhibit B - Project Schedule
              </label>
              <label style={{display:"flex",alignItems:"center",gap:6,cursor:"pointer",fontSize:12,color:"var(--white)"}}>
                <input type="checkbox" checked={exhibits.lienC} onChange={e=>setEx("lienC",e.target.checked)} style={{accentColor:"var(--accent)"}}/>
                Exhibit C - Lien Waiver Forms
              </label>
              <label style={{display:"flex",alignItems:"center",gap:6,cursor:"pointer",fontSize:12,color:"var(--white)"}}>
                <input type="checkbox" checked={exhibits.safetyD} onChange={e=>setEx("safetyD",e.target.checked)} style={{accentColor:"var(--accent)"}}/>
                Exhibit D - Safety Requirements
              </label>
            </div>
            <div style={{fontSize:11,color:"var(--muted)",marginTop:8}}>Selected exhibits are embedded in the generated contract document.</div>
          </div>

          {contractTemplates.length > 0 && (
            <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:12}}>
              <div className="flabel" style={{marginBottom:6}}>Generate from Template (optional)</div>
              <div style={{display:"flex",gap:8,alignItems:"center"}}>
                <select className="fselect" value={f.templateDocId||""} onChange={e=>set("templateDocId",e.target.value||null)} style={{flex:1}}>
                  <option value="">Select contract template...</option>
                  {contractTemplates.map(t=><option key={t.id} value={t.id}>{t.name}</option>)}
                </select>
                <button className="btn btn-ai btn-sm" onClick={generateDoc} disabled={!f.templateDocId||genLoading}>{genLoading?"Generating...":"Generate Doc"}</button>
              </div>
              {genError && <div style={{fontSize:11,color:"var(--red)",marginTop:6}}>{genError}</div>}
              {f.generatedDoc && (
                <div style={{marginTop:10}}>
                  <div style={{padding:"10px 12px",background:"rgba(52,211,153,.05)",border:"1px solid rgba(52,211,153,.2)",borderRadius:6,display:"flex",alignItems:"center",gap:12}}>
                    <div style={{flex:1}}>
                      <div style={{fontSize:12,color:"var(--green)",fontWeight:600}}>Document generated</div>
                      <div style={{fontSize:10,color:"var(--muted)"}}>{f.generatedDoc.length.toLocaleString()} chars</div>
                    </div>
                    <button className="btn btn-ghost btn-sm" style={{fontSize:11,color:"var(--accent-bright)"}} onClick={function(){setShowViewer(!showViewer);}}>{showViewer?"Hide":"View / Edit"}</button>
                  </div>
                  {showViewer && (
                    <textarea value={f.generatedDoc} onChange={function(e){set("generatedDoc",e.target.value);}}
                      style={{width:"100%",height:240,marginTop:6,padding:10,background:"rgba(255,255,255,.03)",border:"1px solid var(--navy-border)",borderRadius:6,fontSize:11,color:"var(--white)",lineHeight:1.6,resize:"vertical",boxSizing:"border-box",fontFamily:"monospace"}}/>
                  )}
                </div>
              )}
            </div>
          )}
        </div>
        <div className="modal-ftr">
          <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" onClick={()=>{
            if(!f.dirId||!f.description.trim()) return;
            onSave({...f,id:existingSC?f.id:"subsc"+uid(),contractValue:parseFloat(f.contractValue)||0,scopeOfWork:f.scopeOfWork||"",exhibits:{...exhibits}});
          }}>Save Subcontract</button>
        </div>
      </div>
    </div>
  );
};

// --- LIEN WAIVER TRACKER -----------------------------------------------------
// --- SUB INVOICE + LIEN WAIVER PORTAL ----------------------------------------

// ─── NC Lien Waiver text generators ──────────────────────────────────────────
var buildNCWaiver = function(type, sc, dirEntry, job, invoice) {
  var pc      = getPrimaryContact(dirEntry)||{};
  var company = dirEntry ? dirEntry.company : "";
  var amount  = fmt(invoice.amount);
  var period  = invoice.periodEnd || TODAY;
  var isFinal = type.indexOf("Final") > -1;
  var isUncond= type.indexOf("Unconditional") > -1;

  var header = isUncond
    ? (isFinal ? "UNCONDITIONAL WAIVER AND RELEASE ON FINAL PAYMENT"
               : "UNCONDITIONAL WAIVER AND RELEASE ON PROGRESS PAYMENT")
    : (isFinal ? "CONDITIONAL WAIVER AND RELEASE ON FINAL PAYMENT"
               : "CONDITIONAL WAIVER AND RELEASE ON PROGRESS PAYMENT");

  var recital = isUncond
    ? (isFinal
        ? "The undersigned has been paid and has received a final payment of "+amount+" for all labor, services, equipment, or materials furnished to the property or to "+company+" on the job described below and does hereby waive and release any mechanic's lien, materialman's lien, or any other claim or right against the described property arising under Chapter 44A of the North Carolina General Statutes."
        : "The undersigned has been paid the sum of "+amount+" for all labor, services, equipment, or materials furnished to the property or to "+company+" through "+fmtDate(period)+" and does hereby waive and release any mechanic's lien, materialman's lien, or any other claim or right against the described property arising under Chapter 44A of the North Carolina General Statutes through "+fmtDate(period)+".")
    : (isFinal
        ? "The undersigned has been promised payment in the sum of "+amount+" for all labor, services, equipment, or materials furnished to the property or to "+company+" and upon receipt of such payment, does hereby waive and release any mechanic's lien, materialman's lien, or any other claim or right against the described property arising under Chapter 44A of the North Carolina General Statutes."
        : "The undersigned has been promised payment in the sum of "+amount+" for all labor, services, equipment, or materials furnished to the property or to "+company+" through "+fmtDate(period)+" and upon receipt of such payment, does hereby waive and release any mechanic's lien, materialman's lien, or any other claim or right against the described property arising under Chapter 44A of the North Carolina General Statutes through "+fmtDate(period)+".");

  var lines = [
    "WESTROE CONSTRUCTION | GC LICENSE #105268 | CHARLOTTE, NC | 704-962-6507",
    "================================================================================",
    "",
    header,
    "North Carolina General Statutes Section 44A-24.1",
    "",
    "Project:         "+(job ? job.name+" ("+job.id+")" : ""),
    "Project Address: "+(job ? job.address||"Charlotte, NC" : ""),
    "Owner:           "+(job ? job.client||"" : ""),
    "GC:              Westroe Construction | GC License #105268",
    "Claimant:        "+company,
    "Trade:           "+sc.trade,
    "Through Date:    "+fmtDate(period),
    "Payment Amount:  "+amount,
    "",
    recital,
    "",
    "EXCEPTION: This waiver and release does not apply to the following:",
    "___ Disputed claims for extras in the amount of $__________",
    "___ Other: _________________________________________________",
    "",
    "================================================================================",
    "Claimant (Company): "+company,
    "Signed By:          _____________________________",
    "Title:              _____________________________",
    "Date:               _____________________________",
    "",
    "================================================================================",
    "Westroe Construction | GC License #105268 | Charlotte, NC | 704-962-6507",
  ];
  return lines.join("\n");
};

// --- Sub invoice portal HTML (no-login) --------------------------------------
var buildInvoicePortalHtml = function(sc, dirEntry, job, replyEmail) {
  var pc      = getPrimaryContact(dirEntry)||{name:"",email:""};
  var company = dirEntry ? dirEntry.company : "";
  var ref     = "INV:"+sc.id;

  return "<!DOCTYPE html><html lang=\"en\"><head><meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"><title>Submit Invoice - Westroe Construction</title>"
    +"<link href=\"https://fonts.googleapis.com/css2?family=Barlow+Condensed:wght@600;700;800&family=Barlow:wght@400;500;600&display=swap\" rel=\"stylesheet\">"
    +"<style>*{box-sizing:border-box;margin:0;padding:0}body{background:#0a1228;color:#e8ecf5;font-family:'Barlow',sans-serif;min-height:100vh;padding:20px}"
    +".wrap{max-width:620px;margin:0 auto}.card{background:#0f1f44;border:1px solid rgba(42,64,128,.4);border-radius:10px;padding:20px;margin-bottom:16px}"
    +".lbl{font-size:10px;color:#8a99bb;text-transform:uppercase;letter-spacing:.1em;font-weight:700;display:block;margin-bottom:4px}"
    +".inp{width:100%;background:rgba(255,255,255,.05);border:1px solid rgba(42,64,128,.4);border-radius:6px;padding:9px 12px;color:#e8ecf5;font-size:13px;outline:none;margin-bottom:12px}"
    +".row{display:grid;grid-template-columns:1fr 1fr;gap:12px}"
    +".btn{display:inline-flex;align-items:center;justify-content:center;padding:12px 24px;border-radius:6px;font-family:'Barlow Condensed',sans-serif;font-size:14px;font-weight:700;letter-spacing:1px;cursor:pointer;border:none;background:#4a7cdc;color:#fff;width:100%}"
    +".hdr{display:flex;justify-content:space-between;align-items:center;padding-bottom:16px;margin-bottom:20px;border-bottom:1px solid rgba(42,64,128,.3)}"
    +".co{font-family:'Barlow Condensed',sans-serif;font-weight:800;font-size:22px;letter-spacing:.05em;color:#fff}"
    +"</style></head><body><div class=\"wrap\">"
    +"<div class=\"hdr\"><div><div class=\"co\">WESTROE CONSTRUCTION</div><div style=\"font-size:10px;color:#8a99bb;letter-spacing:.1em;margin-top:3px\">GC LICENSE #105268 | CHARLOTTE, NC</div></div>"
    +"<div style=\"text-align:right;font-size:11px;color:#8a99bb\">Invoice Submission Portal</div></div>"
    +"<div class=\"card\"><div style=\"font-size:11px;color:#4a7cdc;letter-spacing:.1em;text-transform:uppercase;margin-bottom:6px\">Subcontract Details</div>"
    +"<div style=\"font-size:16px;font-weight:700;font-family:'Barlow Condensed',sans-serif;color:#fff;margin-bottom:8px\">"+company+" - "+sc.trade+"</div>"
    +"<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:8px;font-size:12px;color:#8a99bb\">"
    +"<div>Project: <span style=\"color:#e8ecf5\">"+(job?job.name:"")+"</span></div>"
    +"<div>Contract Value: <span style=\"color:#e8ecf5\">$"+(sc.contractValue?Number(sc.contractValue).toLocaleString():"TBD")+"</span></div>"
    +"<div>Trade: <span style=\"color:#e8ecf5\">"+sc.trade+"</span></div>"
    +"<div>Status: <span style=\"color:#e8ecf5\">"+sc.status+"</span></div>"
    +"</div></div>"
    +"<div class=\"card\"><div style=\"font-size:14px;font-weight:700;font-family:'Barlow Condensed',sans-serif;color:#fff;margin-bottom:14px\">Submit Invoice</div>"
    +"<label class=\"lbl\">Invoice Number</label><input class=\"inp\" id=\"invNum\" placeholder=\"Your invoice number...\"/>"
    +"<div class=\"row\"><div><label class=\"lbl\">Invoice Date</label><input class=\"inp\" id=\"invDate\" type=\"date\" value=\""+TODAY+"\"/></div>"
    +"<div><label class=\"lbl\">Period End Date</label><input class=\"inp\" id=\"perEnd\" type=\"date\" value=\""+TODAY+"\"/></div></div>"
    +"<label class=\"lbl\">Amount Requested ($)</label><input class=\"inp\" id=\"amount\" type=\"number\" placeholder=\"0.00\" min=\"0\" step=\"0.01\"/>"
    +"<label class=\"lbl\">Percent Complete</label><input class=\"inp\" id=\"pct\" type=\"number\" placeholder=\"0\" min=\"0\" max=\"100\" step=\"1\"/>"
    +"<label class=\"lbl\">Is this a final invoice?</label>"
    +"<select class=\"inp\" id=\"isFinal\"><option value=\"no\">No - Progress Payment</option><option value=\"yes\">Yes - Final Payment</option></select>"
    +"<label class=\"lbl\">Description of Work Completed</label>"
    +"<textarea class=\"inp\" id=\"desc\" rows=\"3\" placeholder=\"Describe work completed this period...\"></textarea>"
    +"<label class=\"lbl\">Your Name (Authorized Signatory)</label><input class=\"inp\" id=\"sigName\" placeholder=\"Full name and title...\"/>"
    +"<div id=\"err\" style=\"color:#f87171;font-size:12px;margin-bottom:10px;display:none\"></div>"
    +"<button class=\"btn\" onclick=\"submitInvoice()\">Submit Invoice to Westroe Construction</button>"
    +"<div id=\"msg\" style=\"margin-top:10px;font-size:12px;color:#8a99bb;display:none\"></div></div>"
    +"<div style=\"text-align:center;font-size:11px;color:#4a7a9a;padding-top:10px\">Questions? Contact Westroe Construction at 704-962-6507</div>"
    +"</div><script>function submitInvoice(){"
    +"var num=document.getElementById('invNum').value.trim();"
    +"var dt=document.getElementById('invDate').value;"
    +"var pe=document.getElementById('perEnd').value;"
    +"var amt=document.getElementById('amount').value;"
    +"var pct=document.getElementById('pct').value;"
    +"var fin=document.getElementById('isFinal').value;"
    +"var desc=document.getElementById('desc').value.trim();"
    +"var sig=document.getElementById('sigName').value.trim();"
    +"var err=document.getElementById('err');"
    +"if(!amt||!sig){err.style.display='block';err.textContent='Invoice amount and your name are required.';return;}"
    +"err.style.display='none';"
    +"var body='INVOICE SUBMISSION\\n================================================================================\\n"
    +"Ref: "+ref+"\\nProject: "+(job?job.name+"("+job.id+")":"")+"\\nSubcontractor: "+company+"\\nTrade: "+sc.trade+"\\n\\n"
    +"Invoice Number: '+num+'\\nInvoice Date: '+dt+'\\nPeriod End: '+pe+'\\nAmount Requested: $'+parseFloat(amt).toLocaleString('en-US',{minimumFractionDigits:2})+'\\n"
    +"Percent Complete: '+pct+'%\\nFinal Payment: '+(fin==='yes'?'YES - FINAL':'No - Progress')+'\\n\\nWork Description:\\n'+desc+'\\n\\n"
    +"Submitted By: '+sig+'\\n================================================================================\\nSubmitted via Westroe Construction Invoice Portal';"
    +"var subj=encodeURIComponent('INVOICE: "+company+" - "+sc.trade+" - '+dt);"
    +"window.location.href='mailto:"+replyEmail+"?subject='+subj+'&body='+encodeURIComponent(body);"
    +"document.getElementById('msg').style.display='block';"
    +"document.getElementById('msg').textContent='Your email client should open with the invoice pre-filled. Send it to complete your submission.';}"
    +"</script></body></html>";
};

// --- Lien waiver signing portal HTML (no-login) -------------------------------
var buildWaiverSignPortalHtml = function(waiver, sc, dirEntry, job, replyEmail) {
  var company = dirEntry ? dirEntry.company : "";
  var ref     = "WAIVER:"+waiver.id;

  return "<!DOCTYPE html><html lang=\"en\"><head><meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"><title>Sign Lien Waiver - Westroe Construction</title>"
    +"<link href=\"https://fonts.googleapis.com/css2?family=Barlow+Condensed:wght@600;700;800&family=Barlow:wght@400;500;600&display=swap\" rel=\"stylesheet\">"
    +"<style>*{box-sizing:border-box;margin:0;padding:0}body{background:#0a1228;color:#e8ecf5;font-family:'Barlow',sans-serif;min-height:100vh;padding:20px}"
    +".wrap{max-width:620px;margin:0 auto}.card{background:#0f1f44;border:1px solid rgba(42,64,128,.4);border-radius:10px;padding:20px;margin-bottom:16px}"
    +".lbl{font-size:10px;color:#8a99bb;text-transform:uppercase;letter-spacing:.1em;font-weight:700;display:block;margin-bottom:4px}"
    +".inp{width:100%;background:rgba(255,255,255,.05);border:1px solid rgba(42,64,128,.4);border-radius:6px;padding:9px 12px;color:#e8ecf5;font-size:13px;outline:none;margin-bottom:12px}"
    +".btn{display:inline-flex;align-items:center;justify-content:center;padding:12px 24px;border-radius:6px;font-family:'Barlow Condensed',sans-serif;font-size:14px;font-weight:700;letter-spacing:1px;cursor:pointer;border:none;background:#14532d;color:#4ade80;width:100%}"
    +".hdr{display:flex;justify-content:space-between;align-items:center;padding-bottom:16px;margin-bottom:20px;border-bottom:1px solid rgba(42,64,128,.3)}"
    +".co{font-family:'Barlow Condensed',sans-serif;font-weight:800;font-size:22px;letter-spacing:.05em;color:#fff}"
    +".doc{background:rgba(255,255,255,.02);border:1px solid rgba(42,64,128,.3);border-radius:6px;padding:14px;font-family:monospace;font-size:11px;color:#c8d8f0;line-height:1.7;white-space:pre-wrap;max-height:320px;overflow-y:auto;margin-bottom:14px}"
    +"</style></head><body><div class=\"wrap\">"
    +"<div class=\"hdr\"><div><div class=\"co\">WESTROE CONSTRUCTION</div><div style=\"font-size:10px;color:#8a99bb;letter-spacing:.1em;margin-top:3px\">GC LICENSE #105268 | CHARLOTTE, NC</div></div>"
    +"<div style=\"text-align:right;font-size:11px;color:#8a99bb\">Lien Waiver Signing</div></div>"
    +"<div class=\"card\">"
    +"<div style=\"font-size:11px;color:#4ade80;letter-spacing:.1em;text-transform:uppercase;margin-bottom:6px\">"+waiver.type+"</div>"
    +"<div style=\"font-size:16px;font-weight:700;font-family:'Barlow Condensed',sans-serif;color:#fff;margin-bottom:4px\">"+company+" - "+sc.trade+"</div>"
    +"<div style=\"font-size:12px;color:#8a99bb;margin-bottom:10px\">"+(job?job.name:"")+(" | Amount: $"+(waiver.paymentAmount?Number(waiver.paymentAmount).toLocaleString():""))+"</div>"
    +"<div class=\"doc\" id=\"waiverDoc\">"+waiver.waiverText.replace(/</g,"&lt;").replace(/>/g,"&gt;")+"</div>"
    +"<div style=\"font-size:12px;color:#8a99bb;margin-bottom:14px;padding:10px;background:rgba(74,124,220,.06);border:1px solid rgba(74,124,220,.2);border-radius:5px\">"
    +"Please read the waiver above carefully. By entering your name and signing below, you agree to the terms stated."
    +"</div>"
    +"<label class=\"lbl\">Full Name (Authorized Signatory)</label><input class=\"inp\" id=\"sigName\" placeholder=\"Full name...\"/>"
    +"<label class=\"lbl\">Title</label><input class=\"inp\" id=\"sigTitle\" placeholder=\"Owner, President, PM...\"/>"
    +"<div id=\"err\" style=\"color:#f87171;font-size:12px;margin-bottom:10px;display:none\"></div>"
    +"<button class=\"btn\" onclick=\"signWaiver()\">Sign and Return Waiver</button>"
    +"<div id=\"msg\" style=\"margin-top:10px;font-size:12px;color:#8a99bb;display:none\"></div></div>"
    +"<div style=\"text-align:center;font-size:11px;color:#4a7a9a;padding-top:10px\">Questions? Contact Westroe Construction at 704-962-6507</div>"
    +"</div><script>function signWaiver(){"
    +"var name=document.getElementById('sigName').value.trim();"
    +"var title=document.getElementById('sigTitle').value.trim();"
    +"var err=document.getElementById('err');"
    +"if(!name){err.style.display='block';err.textContent='Your full name is required to sign.';return;}"
    +"err.style.display='none';"
    +"var body='SIGNED LIEN WAIVER\\n================================================================================\\n"
    +"Ref: "+ref+"\\nWaiver Type: "+waiver.type+"\\nProject: "+(job?job.name+"("+job.id+")":"")+"\\n"
    +"Subcontractor: "+company+"\\nAmount: $"+(waiver.paymentAmount?Number(waiver.paymentAmount).toLocaleString():"")+"\\n\\n"
    +"SIGNED BY: '+name+'\\nTITLE: '+title+'\\nDATE: '+new Date().toLocaleDateString()+'\\nTIMESTAMP: '+new Date().toISOString()+'\\n\\n"
    +"================================================================================\\nSigned via Westroe Construction Lien Waiver Portal';"
    +"var subj=encodeURIComponent('SIGNED WAIVER: "+waiver.type+" - "+company+"');"
    +"window.location.href='mailto:"+replyEmail+"?subject='+subj+'&body='+encodeURIComponent(body);"
    +"document.getElementById('msg').style.display='block';"
    +"document.getElementById('msg').textContent='Your email client should open with the signed waiver. Send it to complete your signature.';}"
    +"</script></body></html>";
};

// --- Record Invoice Modal (GC side - paste email to parse) --------------------
const RecordInvoiceModal = ({sc, dirEntry, job, onSave, onClose}) => {
  var [pasted, setPasted] = useState("");
  var [parsed, setParsed] = useState(null);
  var [err,    setErr]    = useState("");

  var parseInv = function(text) {
    setErr("");
    var amtM  = text.match(/Amount Requested:\s*\$([0-9,\.]+)/i);
    var numM  = text.match(/Invoice Number:\s*(.+)/i);
    var dateM = text.match(/Invoice Date:\s*(.+)/i);
    var perM  = text.match(/Period End:\s*(.+)/i);
    var pctM  = text.match(/Percent Complete:\s*(\d+)/i);
    var finM  = text.match(/Final Payment:\s*(YES|No)/i);
    var sigM  = text.match(/Submitted By:\s*(.+)/i);
    var descM = text.match(/Work Description:\n([\s\S]+?)(?=\n={10,}|Submitted By)/i);
    if(!amtM) { setErr("Could not find amount in pasted text."); return; }
    setParsed({
      amount:    parseFloat((amtM[1]||"0").replace(/,/g,"")),
      invNum:    numM  ? numM[1].trim()  : "",
      invDate:   dateM ? dateM[1].trim() : TODAY,
      periodEnd: perM  ? perM[1].trim()  : TODAY,
      pctComplete: pctM ? parseInt(pctM[1]) : 0,
      isFinal:   finM  ? finM[1].toUpperCase().startsWith("YES") : false,
      submittedBy: sigM  ? sigM[1].trim() : "",
      description: descM ? descM[1].trim() : "",
    });
  };

  var handleSave = function(status) {
    if(!parsed) return;
    var newInv = {
      id:           "inv"+uid(),
      invNum:       parsed.invNum,
      invDate:      parsed.invDate,
      periodEnd:    parsed.periodEnd,
      amount:       parsed.amount,
      pctComplete:  parsed.pctComplete,
      isFinal:      parsed.isFinal,
      description:  parsed.description,
      submittedBy:  parsed.submittedBy,
      status:       status,
      receivedDate: TODAY,
      approvedDate: status==="Approved" ? TODAY : null,
      waiverGenerated: false,
    };
    var updated = [...(sc.invoices||[]), newInv];
    onSave({...sc, invoices:updated});
  };

  return (
    <div className="overlay" onClick={function(e){if(e.target===e.currentTarget)onClose();}}>
      <div className="modal" style={{maxWidth:520}}>
        <div className="modal-hdr">
          <span className="modal-title">Record Invoice</span>
          <button className="btn btn-ghost btn-sm" onClick={onClose}>x</button>
        </div>
        <div style={{padding:16}}>
          <div style={{fontSize:12,color:"var(--muted)",marginBottom:12,lineHeight:1.6}}>
            Paste the invoice submission email body from the subcontractor below.
          </div>
          <div className="flabel">Paste Invoice Email Body</div>
          <textarea className="ftextarea" rows={8} value={pasted}
            onChange={function(e){setPasted(e.target.value);setParsed(null);setErr("");}}
            placeholder="Paste the full email body here..."/>
          {err && <div style={{fontSize:12,color:"var(--red)",marginTop:6,padding:"5px 8px",background:"rgba(248,113,113,.08)",border:"1px solid rgba(248,113,113,.25)",borderRadius:4}}>{err}</div>}
          {!parsed && (
            <button className="btn btn-ghost btn-sm" style={{marginTop:10,width:"100%"}} onClick={function(){parseInv(pasted);}}>Parse Invoice</button>
          )}
          {parsed && (
            <div style={{marginTop:12,padding:12,background:"rgba(52,211,153,.05)",border:"1px solid rgba(52,211,153,.2)",borderRadius:6}}>
              <div style={{fontSize:11,color:"var(--green)",fontFamily:"'Barlow Condensed'",letterSpacing:1,marginBottom:8}}>PARSED INVOICE</div>
              {[
                ["Invoice #",  parsed.invNum||"-"],
                ["Amount",     fmt(parsed.amount)],
                ["Period End", parsed.periodEnd],
                ["% Complete", parsed.pctComplete+"%"],
                ["Final Pay",  parsed.isFinal?"YES":"No"],
                ["Submitted By", parsed.submittedBy],
              ].map(function(r){
                return (
                  <div key={r[0]} style={{display:"flex",gap:8,marginBottom:4}}>
                    <span style={{fontSize:11,color:"var(--muted)",minWidth:100}}>{r[0]}:</span>
                    <span style={{fontSize:11,color:"var(--white)",fontWeight:600}}>{r[1]}</span>
                  </div>
                );
              })}
              {parsed.description && <div style={{fontSize:11,color:"var(--muted)",marginTop:6,lineHeight:1.5}}>{parsed.description}</div>}
            </div>
          )}
        </div>
        <div className="modal-ftr" style={{justifyContent:"space-between"}}>
          <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
          <div style={{display:"flex",gap:8}}>
            <button className="btn btn-ghost btn-sm" style={{color:"var(--red)"}} disabled={!parsed} style2={{opacity:parsed?1:0.4}}
              onClick={function(){handleSave("Rejected");onClose();}}>Reject</button>
            <button className="btn btn-primary" disabled={!parsed} style={{opacity:parsed?1:0.4}}
              onClick={function(){handleSave("Approved");onClose();}}>Approve</button>
          </div>
        </div>
      </div>
    </div>
  );
};

// --- Record Signed Waiver Modal -----------------------------------------------
const RecordSignedWaiverModal = ({waiver, sc, onSave, onClose}) => {
  var [pasted, setPasted] = useState("");
  var [parsed, setParsed] = useState(null);
  var [err,    setErr]    = useState("");

  var parse = function(text) {
    setErr("");
    var nameM = text.match(/SIGNED BY:\s*(.+)/i);
    var titleM= text.match(/TITLE:\s*(.+)/i);
    var dateM = text.match(/DATE:\s*(.+)/i);
    var tsM   = text.match(/TIMESTAMP:\s*(.+)/i);
    if(!nameM) { setErr("Could not find signature in pasted text."); return; }
    setParsed({
      signerName:  nameM[1].trim(),
      signerTitle: titleM ? titleM[1].trim() : "",
      signedDate:  TODAY,
      signedAt:    tsM ? tsM[1].trim() : new Date().toISOString(),
    });
  };

  var handleSave = function() {
    if(!parsed) return;
    var updated = {...waiver, status:"Received", receivedDate:TODAY, signature:parsed};
    var newWaivers = (sc.lienWaivers||[]).map(function(w){return w.id===waiver.id?updated:w;});
    onSave({...sc, lienWaivers:newWaivers});
  };

  return (
    <div className="overlay" onClick={function(e){if(e.target===e.currentTarget)onClose();}}>
      <div className="modal" style={{maxWidth:480}}>
        <div className="modal-hdr">
          <span className="modal-title">Record Signed Waiver</span>
          <button className="btn btn-ghost btn-sm" onClick={onClose}>x</button>
        </div>
        <div style={{padding:16}}>
          <div style={{fontSize:12,color:"var(--muted)",marginBottom:12}}>
            Paste the signed waiver email body from the subcontractor.
          </div>
          <div className="flabel">Paste Signed Waiver Email</div>
          <textarea className="ftextarea" rows={6} value={pasted}
            onChange={function(e){setPasted(e.target.value);setParsed(null);setErr("");}}
            placeholder="Paste the full email body here..."/>
          {err && <div style={{fontSize:12,color:"var(--red)",marginTop:6}}>{err}</div>}
          {!parsed && <button className="btn btn-ghost btn-sm" style={{marginTop:10,width:"100%"}} onClick={function(){parse(pasted);}}>Parse Signature</button>}
          {parsed && (
            <div style={{marginTop:12,padding:12,background:"rgba(52,211,153,.05)",border:"1px solid rgba(52,211,153,.2)",borderRadius:6}}>
              <div style={{fontSize:11,color:"var(--green)",fontFamily:"'Barlow Condensed'",letterSpacing:1,marginBottom:6}}>SIGNATURE PARSED</div>
              <div style={{fontSize:12,color:"var(--white)"}}>{parsed.signerName}{parsed.signerTitle?" - "+parsed.signerTitle:""}</div>
              <div style={{fontSize:11,color:"var(--muted)"}}>{parsed.signedDate}</div>
            </div>
          )}
        </div>
        <div className="modal-ftr">
          <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" disabled={!parsed} style={{opacity:parsed?1:0.4}} onClick={function(){handleSave();onClose();}}>Record as Received</button>
        </div>
      </div>
    </div>
  );
};

// --- Invoice Log (inside SubcontractDetail) -----------------------------------
const InvoiceLog = ({sc, dirEntry, job, onUpdate}) => {
  var [showRecord, setShowRecord] = useState(false);
  var [showWaiver, setShowWaiver] = useState(null);
  var [showSignWaiver, setShowSignWaiver] = useState(null);

  var invoices = sc.invoices || [];

  var openInvoicePortal = function() {
    var html = buildInvoicePortalHtml(sc, dirEntry, job, "shane@westroeconstruction.com");
    var blob = new Blob([html],{type:"text/html"});
    window.open(URL.createObjectURL(blob),"_blank");
  };

  var generateWaiver = function(inv) {
    var waiverType = inv.isFinal
      ? "Conditional - Final Payment"
      : "Conditional - Progress Payment";
    var waiverText = buildNCWaiver(waiverType, sc, dirEntry, job, inv);
    var newWaiver = {
      id:           "lw"+uid(),
      type:         waiverType,
      paymentAmount: inv.amount,
      paymentPeriod: inv.periodEnd,
      status:       "Requested",
      requestedDate: TODAY,
      receivedDate:  "",
      notes:        "Auto-generated from invoice "+inv.invNum,
      pdfBase64:    null,
      pdfName:      "",
      waiverText:   waiverText,
      invoiceId:    inv.id,
    };
    var updated = {...sc,
      invoices: invoices.map(function(i){return i.id===inv.id?{...i,waiverGenerated:true}:i;}),
      lienWaivers: [...(sc.lienWaivers||[]), newWaiver],
    };
    onUpdate(updated);
    setShowWaiver(newWaiver);
  };

  var openWaiverPortal = function(waiver) {
    var html = buildWaiverSignPortalHtml(waiver, sc, dirEntry, job, "shane@westroeconstruction.com");
    var blob = new Blob([html],{type:"text/html"});
    window.open(URL.createObjectURL(blob),"_blank");
  };

  return (
    <div>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
        <div style={{fontFamily:"'Barlow Condensed'",fontSize:13,fontWeight:700,color:"var(--white)",letterSpacing:.5}}>
          Invoices ({invoices.length})
        </div>
        <div style={{display:"flex",gap:8}}>
          <button className="btn btn-ghost btn-sm" style={{fontSize:11,color:"var(--accent-bright)"}}
            onClick={openInvoicePortal}>Sub Invoice Portal</button>
          <button className="btn btn-ghost btn-sm" style={{fontSize:11}}
            onClick={function(){setShowRecord(true);}}>Record Invoice</button>
        </div>
      </div>

      {invoices.length===0 && (
        <div style={{padding:"20px",textAlign:"center",color:"var(--muted)",fontSize:12,background:"rgba(255,255,255,.02)",borderRadius:6,border:"1px dashed var(--navy-border)"}}>
          No invoices yet. Click "Sub Invoice Portal" to generate a link for the subcontractor to submit.
        </div>
      )}

      {invoices.map(function(inv){
        var statusColor = inv.status==="Approved"?"var(--green)":inv.status==="Rejected"?"var(--red)":"var(--yellow)";
        var relatedWaiver = (sc.lienWaivers||[]).find(function(w){return w.invoiceId===inv.id;});
        return (
          <div key={inv.id} style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:6,padding:"10px 14px",marginBottom:8}}>
            <div style={{display:"flex",alignItems:"flex-start",gap:12}}>
              <div style={{flex:1}}>
                <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:4}}>
                  <span style={{fontFamily:"'Barlow Condensed'",fontSize:14,fontWeight:700,color:"var(--white)"}}>
                    {inv.invNum||"Invoice"} - {fmt(inv.amount)}
                  </span>
                  <span style={{fontSize:10,color:statusColor,fontFamily:"'Barlow Condensed'",letterSpacing:.5,border:"1px solid "+statusColor+"44",borderRadius:3,padding:"0 5px"}}>{inv.status}</span>
                  {inv.isFinal && <span style={{fontSize:10,color:"var(--purple)",fontFamily:"'Barlow Condensed'",letterSpacing:.5,border:"1px solid rgba(167,139,250,.3)",borderRadius:3,padding:"0 5px"}}>FINAL</span>}
                </div>
                <div style={{fontSize:11,color:"var(--muted)"}}>
                  Period: {fmtDate(inv.periodEnd)} - {inv.pctComplete}% complete - Received: {fmtDate(inv.receivedDate)}
                </div>
                {inv.description && <div style={{fontSize:11,color:"var(--muted)",marginTop:4,lineHeight:1.5}}>{inv.description}</div>}
              </div>
              <div style={{display:"flex",flexDirection:"column",gap:4,flexShrink:0}}>
                {inv.status==="Approved" && !inv.waiverGenerated && (
                  <button className="btn btn-ghost btn-sm" style={{fontSize:10,color:"var(--green)",padding:"3px 8px"}}
                    onClick={function(){generateWaiver(inv);}}>Generate Waiver</button>
                )}
                {relatedWaiver && (
                  <button className="btn btn-ghost btn-sm" style={{fontSize:10,color:"var(--accent-bright)",padding:"3px 8px"}}
                    onClick={function(){openWaiverPortal(relatedWaiver);}}>Send Waiver</button>
                )}
                {relatedWaiver && relatedWaiver.status==="Requested" && (
                  <button className="btn btn-ghost btn-sm" style={{fontSize:10,padding:"3px 8px"}}
                    onClick={function(){setShowSignWaiver(relatedWaiver);}}>Record Signed</button>
                )}
                {relatedWaiver && relatedWaiver.status==="Received" && (
                  <span style={{fontSize:10,color:"var(--green)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>WAIVER SIGNED</span>
                )}
              </div>
            </div>
          </div>
        );
      })}

      {showRecord && (
        <RecordInvoiceModal sc={sc} dirEntry={dirEntry} job={job}
          onSave={function(updated){onUpdate(updated);}} onClose={function(){setShowRecord(false);}}/>
      )}
      {showSignWaiver && (
        <RecordSignedWaiverModal waiver={showSignWaiver} sc={sc}
          onSave={function(updated){onUpdate(updated);setShowSignWaiver(null);}} onClose={function(){setShowSignWaiver(null);}}/>
      )}
    </div>
  );
};

// --- LIEN WAIVER EXPORT ------------------------------------------------------
var buildWaiverExportHtml = function(waiverRows, job, dateFrom, dateTo) {
  var header = [
    "<!DOCTYPE html><html lang=\"en\"><head><meta charset=\"UTF-8\">",
    "<title>Lien Waiver Summary - Westroe Construction</title>",
    "<style>",
    "body{font-family:Arial,sans-serif;font-size:11pt;color:#111;margin:0;padding:0}",
    ".page-hdr{background:#0a1228;color:#fff;padding:18px 24px;display:flex;justify-content:space-between;align-items:center}",
    ".co{font-size:18pt;font-weight:900;letter-spacing:.05em}",
    ".lic{font-size:9pt;letter-spacing:.1em;margin-top:3px;color:#8ab0d0}",
    ".summary{padding:16px 24px;border-bottom:1px solid #ddd;background:#f8fafc}",
    ".summary h2{font-size:13pt;margin:0 0 6px;color:#0a1228}",
    ".summary p{margin:2px 0;font-size:10pt;color:#444}",
    ".tbl{width:100%;border-collapse:collapse;font-size:10pt}",
    ".tbl th{background:#0a1228;color:#fff;padding:8px 12px;text-align:left;font-size:9pt;letter-spacing:.05em;text-transform:uppercase}",
    ".tbl td{padding:8px 12px;border-bottom:1px solid #e8ecf0;vertical-align:top}",
    ".tbl tr:nth-child(even) td{background:#f8fafc}",
    ".badge{display:inline-block;padding:2px 8px;border-radius:3px;font-size:8pt;font-weight:700;text-transform:uppercase;letter-spacing:.05em}",
    ".rec{background:#d1fae5;color:#065f46}",
    ".req{background:#fef3c7;color:#92400e}",
    ".miss{background:#fee2e2;color:#991b1b}",
    ".waiver-text{background:#f8fafc;border:1px solid #ddd;border-radius:4px;padding:14px;font-family:monospace;font-size:9pt;line-height:1.6;white-space:pre-wrap;margin:8px 0;page-break-inside:avoid}",
    ".sig-block{margin-top:8px;padding:10px;background:#f0f9ff;border:1px solid #bae6fd;border-radius:4px;font-size:9pt}",
    ".section-hdr{background:#e8f0fe;padding:8px 12px;font-weight:700;font-size:10pt;color:#0a1228;margin-top:16px;border-left:4px solid #0a1228}",
    "@media print{.page-hdr{-webkit-print-color-adjust:exact;print-color-adjust:exact}.tbl th{-webkit-print-color-adjust:exact;print-color-adjust:exact}}",
    "@page{margin:.75in}",
    "</style></head><body>",
  ].join("\n");

  var today = new Date().toLocaleDateString("en-US",{month:"long",day:"numeric",year:"numeric"});
  var fromLabel = dateFrom ? new Date(dateFrom+"T12:00:00").toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"}) : "All dates";
  var toLabel   = dateTo   ? new Date(dateTo+"T12:00:00").toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"}) : "Present";

  var received = waiverRows.filter(function(r){return r.waiver.status==="Received";}).length;
  var pending  = waiverRows.filter(function(r){return r.waiver.status==="Requested";}).length;
  var missing  = waiverRows.filter(function(r){return r.waiver.status==="Required";}).length;

  var summaryBlock = [
    "<div class=\"summary\">",
    "<h2>Lien Waiver Summary Package</h2>",
    "<p><strong>Project:</strong> "+(job?job.name+" ("+job.id+")":"")+"</p>",
    "<p><strong>Client:</strong> "+(job?job.client||"":"")+"</p>",
    "<p><strong>Period:</strong> "+fromLabel+" through "+toLabel+"</p>",
    "<p><strong>Prepared By:</strong> Westroe Construction | GC License #105268 | "+today+"</p>",
    "<p style=\"margin-top:8px\"><strong>Total Waivers in Period:</strong> "+waiverRows.length+
      " &nbsp;&nbsp; <span style=\"color:#065f46\">Received: "+received+"</span>"+
      " &nbsp;&nbsp; <span style=\"color:#92400e\">Pending: "+pending+"</span>"+
      (missing>0?" &nbsp;&nbsp; <span style=\"color:#991b1b\">Missing: "+missing+"</span>":"")+"</p>",
    "</div>",
    "<div style=\"padding:0 24px 24px\">",
  ].join("\n");

  // Group by subcontractor
  var byCompany = {};
  waiverRows.forEach(function(r){
    var key = r.company;
    if(!byCompany[key]) byCompany[key] = {trade:r.trade, rows:[]};
    byCompany[key].rows.push(r);
  });

  var bodyRows = Object.keys(byCompany).map(function(company){
    var group = byCompany[company];
    var rows  = group.rows;
    var subSection = [
      "<div class=\"section-hdr\">"+company+" &mdash; "+group.trade+"</div>",
      "<table class=\"tbl\"><thead><tr>",
      "<th>Waiver Type</th><th>Payment Amount</th><th>Period / Through</th>",
      "<th>Requested</th><th>Received</th><th>Status</th>",
      "</tr></thead><tbody>",
    ].join("");

    var rowHtml = rows.map(function(r){
      var w = r.waiver;
      var statusClass = w.status==="Received"?"rec":w.status==="Requested"?"req":"miss";
      return [
        "<tr>",
        "<td>"+w.type+"</td>",
        "<td>"+(w.paymentAmount?"$"+Number(w.paymentAmount).toLocaleString():"&mdash;")+"</td>",
        "<td>"+(w.paymentPeriod?new Date(w.paymentPeriod+"T12:00:00").toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"}):"&mdash;")+"</td>",
        "<td>"+(w.requestedDate?new Date(w.requestedDate+"T12:00:00").toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"}):"&mdash;")+"</td>",
        "<td>"+(w.receivedDate?new Date(w.receivedDate+"T12:00:00").toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"}):"&mdash;")+"</td>",
        "<td><span class=\"badge "+statusClass+"\">"+w.status+"</span></td>",
        "</tr>",
        // Include waiver text if received and has waiverText
        (w.waiverText && w.status==="Received") ? [
          "<tr><td colspan=\"6\">",
          "<div class=\"waiver-text\">"+w.waiverText.replace(/</g,"&lt;").replace(/>/g,"&gt;")+"</div>",
          w.signature ? "<div class=\"sig-block\"><strong>Signed:</strong> "+w.signature.signerName+(w.signature.signerTitle?" &mdash; "+w.signature.signerTitle:"")+" &nbsp;|&nbsp; <strong>Date:</strong> "+w.signature.signedDate+"</div>" : "",
          "</td></tr>",
        ].join("") : "",
      ].join("");
    }).join("");

    return subSection + rowHtml + "</tbody></table>";
  }).join("\n");

  var footer = [
    "</div>",
    "<div style=\"padding:12px 24px;border-top:1px solid #ddd;font-size:9pt;color:#666;text-align:center\">",
    "Westroe Construction | GC License #105268 | Charlotte, NC | 704-962-6507 | Prepared "+today,
    "</div>",
    "</body></html>",
  ].join("\n");

  return header + summaryBlock + bodyRows + footer;
};

//  Waiver Export Modal 
const WaiverExportModal = ({job, subcontracts, directory, onClose}) => {
  var [dateFrom, setDateFrom] = useState("");
  var [dateTo,   setDateTo]   = useState(TODAY);
  var [inclText, setInclText] = useState(true);

  // Flatten all waivers across all subcontracts, join with company info
  var allWaivers = [];
  (subcontracts||[]).forEach(function(sc){
    var de = (directory||[]).find(function(d){return d.id===sc.dirId;});
    var company = de ? de.company : "Unknown";
    (sc.lienWaivers||[]).forEach(function(w){
      var dateRef = w.receivedDate || w.requestedDate || "";
      allWaivers.push({waiver:w, sc:sc, company:company, trade:sc.trade, dateRef:dateRef});
    });
  });

  // Filter by date range
  var filtered = allWaivers.filter(function(r){
    if(!r.dateRef) return !dateFrom; // no date -- only include if no from filter
    if(dateFrom && r.dateRef < dateFrom) return false;
    if(dateTo   && r.dateRef > dateTo)   return false;
    return true;
  });

  var received = filtered.filter(function(r){return r.waiver.status==="Received";}).length;
  var pending  = filtered.filter(function(r){return r.waiver.status==="Requested";}).length;

  var doExport = function() {
    var html = buildWaiverExportHtml(filtered, job, dateFrom, dateTo);
    var w = window.open("","_blank");
    if(!w) { alert("Please allow popups for this page to export."); return; }
    w.document.write(html);
    w.document.close();
    w.focus();
    setTimeout(function(){w.print();}, 600);
    onClose();
  };

  return (
    <div className="overlay" onClick={function(e){if(e.target===e.currentTarget)onClose();}}>
      <div className="modal" style={{maxWidth:500}}>
        <div className="modal-hdr">
          <span className="modal-title">Export Lien Waivers</span>
          <button className="btn btn-ghost btn-sm" onClick={onClose}>x</button>
        </div>
        <div style={{padding:16}}>

          <div style={{marginBottom:14,padding:"10px 14px",background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:6}}>
            <div style={{fontSize:12,color:"var(--muted)",marginBottom:2}}>{job&&job.name}</div>
            <div style={{fontSize:13,color:"var(--white)",fontWeight:600}}>{allWaivers.length} total waivers across {(subcontracts||[]).length} subcontracts</div>
          </div>

          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:12}}>
            <div>
              <div className="flabel">From Date <span style={{fontSize:9,color:"var(--muted)"}}>optional</span></div>
              <input className="finput" type="date" value={dateFrom} onChange={function(e){setDateFrom(e.target.value);}}/>
            </div>
            <div>
              <div className="flabel">To Date</div>
              <input className="finput" type="date" value={dateTo} onChange={function(e){setDateTo(e.target.value);}}/>
            </div>
          </div>

          <label style={{display:"flex",alignItems:"center",gap:8,fontSize:12,color:"var(--white)",cursor:"pointer",marginBottom:14}}>
            <input type="checkbox" checked={inclText} onChange={function(e){setInclText(e.target.checked);}} style={{accentColor:"var(--accent)"}}/>
            Include full waiver text for received waivers
          </label>

          <div style={{padding:"10px 14px",background:"rgba(74,124,220,.06)",border:"1px solid rgba(74,124,220,.2)",borderRadius:6}}>
            <div style={{fontSize:12,color:"var(--white)",fontWeight:600,marginBottom:4}}>
              {filtered.length} waiver{filtered.length!==1?"s":""}  in selected range
            </div>
            <div style={{fontSize:11,color:"var(--muted)"}}>
              <span style={{color:"var(--green)"}}>{received} received</span>
              {" | "}
              <span style={{color:"var(--yellow)"}}>{pending} pending</span>
              {filtered.length!==allWaivers.length && " | "+( allWaivers.length-filtered.length)+" excluded by date filter"}
            </div>
          </div>

          {filtered.length===0 && (
            <div style={{marginTop:10,fontSize:12,color:"var(--yellow)"}}>No waivers found in the selected date range.</div>
          )}
        </div>
        <div className="modal-ftr">
          <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" disabled={filtered.length===0} style={{opacity:filtered.length>0?1:0.4}} onClick={doExport}>
            Export to HTML
          </button>
        </div>
      </div>
    </div>
  );
};

const LW_TYPES = [
  "Conditional - Progress Payment",
  "Unconditional - Progress Payment",
  "Conditional - Final Payment",
  "Unconditional - Final Payment",
];
const LW_STATUSES = ["Requested","Received","Filed"];
const LW_STATUS_COLOR = {
  Requested:"var(--yellow)",
  Received:"var(--accent-bright)",
  Filed:"var(--green)",
};

const LienWaiverTracker = ({sc, onUpdate}) => {
  const [showAdd,  setShowAdd]  = useState(false);
  const [selId,    setSelId]    = useState(null);
  const [newType,  setNewType]  = useState(LW_TYPES[0]);
  const [newAmt,   setNewAmt]   = useState("");
  const [newPer,   setNewPer]   = useState("");
  const [newDate,  setNewDate]  = useState(TODAY);
  const [newStat,  setNewStat]  = useState("Requested");
  const [newNotes, setNewNotes] = useState("");

  const waivers = sc.lienWaivers || [];
  const sel     = waivers.find(w=>w.id===selId);

  const condReceived = waivers
    .filter(w=>w.type.startsWith("Conditional") && w.status!=="Requested")
    .map(w=>w.paymentAmount);

  const hasWarning = !!sc.requireCondWaiver &&
    waivers.filter(w=>w.type.startsWith("Unconditional"))
           .some(w=>!condReceived.includes(w.paymentAmount));

  const totWaived = waivers
    .filter(w=>w.type.startsWith("Unconditional") && w.status!=="Requested")
    .reduce((s,w)=>s+(parseFloat(w.paymentAmount)||0), 0);

  const addWaiver = () => {
    if(!newAmt) return;
    var newW = {id:"lw"+uid(), type:newType,
      paymentAmount:parseFloat(newAmt)||0, paymentPeriod:newPer,
      status:newStat, requestedDate:newDate, receivedDate:"",
      notes:newNotes, pdfBase64:null, pdfName:""};
    onUpdate({...sc, lienWaivers:[...waivers, newW]});
    setShowAdd(false);
    setNewType(LW_TYPES[0]); setNewAmt(""); setNewPer("");
    setNewDate(TODAY); setNewStat("Requested"); setNewNotes("");
  };

  const updateWaiver = (id, field, val) => {
    onUpdate({...sc, lienWaivers:waivers.map(w=>w.id===id ? {...w,[field]:val} : w)});
  };

  const deleteWaiver = (id) => {
    onUpdate({...sc, lienWaivers:waivers.filter(w=>w.id!==id)});
    if(selId===id) setSelId(null);
  };

  var pendingCt  = waivers.filter(w=>w.status==="Requested").length;
  var receivedCt = waivers.filter(w=>w.status!=="Requested").length;

  return (
    <div>
      <div style={{padding:"10px 14px",background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,marginBottom:12}}>
        <label style={{display:"flex",alignItems:"center",gap:8,cursor:"pointer",fontSize:13,color:"var(--white)"}}>
          <input type="checkbox" checked={!!sc.requireCondWaiver}
            onChange={function(e){onUpdate({...sc,requireCondWaiver:e.target.checked});}}
            style={{accentColor:"var(--accent)"}}/>
          Require conditional waiver before payment release
        </label>
      </div>

      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:14}}>
        <div className="stat-card"><div className="stat-label">Total Waivers</div><div className="stat-value" style={{fontSize:15}}>{waivers.length}</div></div>
        <div className="stat-card"><div className="stat-label">Received / Filed</div><div className="stat-value" style={{fontSize:15,color:"var(--green)"}}>{receivedCt}</div></div>
        <div className="stat-card"><div className="stat-label">Pending</div><div className="stat-value" style={{fontSize:15,color:pendingCt>0?"var(--yellow)":"var(--muted)"}}>{pendingCt}</div></div>
        <div className="stat-card"><div className="stat-label">Released</div><div className="stat-value" style={{fontSize:15,color:"var(--accent-bright)"}}>{fmt(totWaived)}</div></div>
      </div>

      {hasWarning && (
        <div style={{padding:"10px 14px",background:"rgba(251,191,36,.06)",border:"1px solid rgba(251,191,36,.25)",borderRadius:8,fontSize:12,color:"var(--yellow)",marginBottom:12}}>
          Warning: unconditional waivers exist without a matching received conditional waiver.
        </div>
      )}

      <div style={{display:"flex",justifyContent:"flex-end",marginBottom:10}}>
        <button className="btn btn-primary btn-sm" onClick={()=>setShowAdd(!showAdd)}>+ Request Waiver</button>
      </div>

      {showAdd && (
        <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14,marginBottom:12}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:10}}>
            <div>
              <div className="flabel">Type</div>
              <select className="fselect" value={newType} onChange={function(e){setNewType(e.target.value);}}>
                {LW_TYPES.map(function(t){return <option key={t}>{t}</option>;})}
              </select>
            </div>
            <div>
              <div className="flabel">Payment Amount</div>
              <input className="finput" type="number" value={newAmt} onChange={function(e){setNewAmt(e.target.value);}} placeholder="0.00"/>
            </div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 140px",gap:10,marginBottom:10}}>
            <div>
              <div className="flabel">Payment Period / Draw</div>
              <input className="finput" value={newPer} onChange={function(e){setNewPer(e.target.value);}} placeholder="Draw #2 / Mar 1 to Mar 31"/>
            </div>
            <div>
              <div className="flabel">Date Requested</div>
              <input className="finput" type="date" value={newDate} onChange={function(e){setNewDate(e.target.value);}}/>
            </div>
            <div>
              <div className="flabel">Status</div>
              <select className="fselect" value={newStat} onChange={function(e){setNewStat(e.target.value);}}>
                {LW_STATUSES.map(function(s){return <option key={s}>{s}</option>;})}
              </select>
            </div>
          </div>
          <div style={{marginBottom:10}}>
            <div className="flabel">Notes</div>
            <input className="finput" value={newNotes} onChange={function(e){setNewNotes(e.target.value);}} placeholder="Additional notes..."/>
          </div>
          <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
            <button className="btn btn-ghost btn-sm" onClick={()=>setShowAdd(false)}>Cancel</button>
            <button className="btn btn-primary btn-sm" onClick={addWaiver}>Add Waiver</button>
          </div>
        </div>
      )}

      {waivers.length===0 && (
        <div className="empty" style={{padding:32}}>No lien waivers yet. Request the first waiver before releasing payment.</div>
      )}

      {waivers.length>0 && (
        <div style={{border:"1px solid var(--navy-border)",borderRadius:8,overflow:"hidden"}}>
          {waivers.slice().sort(function(a,b){return b.requestedDate.localeCompare(a.requestedDate);}).map(function(w){
            var isCond  = w.type.startsWith("Conditional");
            var isFinal = w.type.includes("Final");
            var hasCond = !isCond && condReceived.includes(w.paymentAmount);
            var warnRow = !!sc.requireCondWaiver && !isCond && !hasCond;
            var stColor = LW_STATUS_COLOR[w.status] || "var(--muted)";
            var badgeBg = isCond ? "rgba(251,191,36,.1)" : "rgba(74,124,220,.1)";
            var badgeColor = isCond ? "var(--yellow)" : "var(--accent-bright)";
            return (
              <div key={w.id} onClick={()=>setSelId(selId===w.id ? null : w.id)}
                style={{padding:"11px 14px",borderBottom:"1px solid rgba(42,64,128,.2)",cursor:"pointer",
                  background:selId===w.id ? "rgba(74,124,220,.08)" : "transparent"}}>
                <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",gap:8}}>
                  <div style={{flex:1}}>
                    <div style={{display:"flex",gap:8,alignItems:"center",marginBottom:3}}>
                      <span style={{fontSize:11,fontFamily:"'Barlow Condensed'",letterSpacing:.5,
                        color:badgeColor,background:badgeBg,borderRadius:3,padding:"1px 6px"}}>
                        {isCond?"CONDITIONAL":"UNCONDITIONAL"}
                      </span>
                      <span style={{fontSize:10,fontFamily:"'Barlow Condensed'",letterSpacing:.5,color:"var(--muted)"}}>
                        {isFinal?"FINAL":"PROGRESS"}
                      </span>
                      {warnRow && <span style={{fontSize:10,color:"var(--yellow)",fontFamily:"'Barlow Condensed'"}}>NO COND</span>}
                      {w.pdfBase64 && <span style={{fontSize:10,color:"var(--green)",fontFamily:"'Barlow Condensed'"}}>SIGNED</span>}
                    </div>
                    <div style={{fontSize:14,fontFamily:"'IBM Plex Mono',monospace",color:"var(--white)",fontWeight:600}}>{fmt(w.paymentAmount)}</div>
                    <div style={{fontSize:11,color:"var(--muted)",marginTop:2}}>
                      {w.paymentPeriod ? w.paymentPeriod+"   " : ""}Requested {fmtDate(w.requestedDate)}
                      {w.receivedDate ? "   Received "+fmtDate(w.receivedDate) : ""}
                    </div>
                  </div>
                  <span style={{fontSize:11,color:stColor,fontFamily:"'Barlow Condensed'",letterSpacing:.5,flexShrink:0}}>{w.status.toUpperCase()}</span>
                </div>
                {selId===w.id && (
                  <div style={{marginTop:12,paddingTop:12,borderTop:"1px solid rgba(42,64,128,.2)"}}>
                    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:10}}>
                      <div>
                        <div className="flabel">Status</div>
                        <select className="fselect" value={w.status}
                          onChange={function(e){updateWaiver(w.id,"status",e.target.value);}}>
                          {LW_STATUSES.map(function(s){return <option key={s}>{s}</option>;})}
                        </select>
                      </div>
                      <div>
                        <div className="flabel">Date Received</div>
                        <input className="finput" type="date" value={w.receivedDate||""}
                          onChange={function(e){updateWaiver(w.id,"receivedDate",e.target.value);}}/>
                      </div>
                    </div>
                    <div style={{marginBottom:10}}>
                      <div className="flabel">Notes</div>
                      <input className="finput" value={w.notes||""}
                        onChange={function(e){updateWaiver(w.id,"notes",e.target.value);}}
                        placeholder="Notes..."/>
                    </div>
                    <button className="btn btn-ghost btn-sm" style={{color:"var(--red)",fontSize:11}}
                      onClick={function(){deleteWaiver(w.id);}}>Delete Waiver</button>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

const SubcontractDetail = ({sc, directory, costCodes, onUpdate, onClose}) => {
  const [detailTab, setDetailTab]       = useState("info");
  const [showSCOModal, setShowSCOModal] = useState(false);
  const [editSCO, setEditSCO]           = useState(null);
  const [pendingStatus, setPending]     = useState(null);
  const [showSend, setShowSend]         = useState(false);
  const [showDocViewer, setShowDocViewer] = useState(false);
  const dirEntry = directory.find(d=>d.id===sc.dirId);
  const code     = costCodes.find(c=>c.id===sc.costCodeId);
  const coi      = checkCOI(dirEntry);
  const scoCt    = (sc.subCOs||[]).length;
  const scoTotal = (sc.subCOs||[]).filter(s=>["Issued","Executed"].includes(s.status)).reduce((s,c)=>s+c.amount,0);

  const handleStatusChange = (newStatus) => {
    const needsCOICheck = ["Issued","Executed"].includes(newStatus);
    if(needsCOICheck && !coi.ok) {
      setPending(newStatus);
    } else {
      const update = {status:newStatus};
      if(newStatus==="Executed" && !sc.executedDate) update.executedDate = TODAY;
      onUpdate({...sc,...update});
    }
  };

  const confirmCOIOverride = () => {
    const update = {status:pendingStatus};
    if(pendingStatus==="Executed" && !sc.executedDate) update.executedDate = TODAY;
    onUpdate({...sc,...update});
    setPending(null);
  };

  const saveSCO = (sco) => {
    const subCOs = editSCO
      ? (sc.subCOs||[]).map(x=>x.id===sco.id?sco:x)
      : [...(sc.subCOs||[]),sco];
    onUpdate({...sc,subCOs});
    setShowSCOModal(false); setEditSCO(null);
  };

  const deleteSCO = (id) => onUpdate({...sc,subCOs:(sc.subCOs||[]).filter(x=>x.id!==id)});

  const pendingWaivers = (sc.lienWaivers||[]).filter(w=>w.status==="Requested").length;

  return (
    <div style={{height:"100%",display:"flex",flexDirection:"column"}}>
      <div style={{padding:"14px 16px 0",borderBottom:"1px solid var(--navy-border)",flexShrink:0}}>
        <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:10}}>
          <div>
            <div style={{fontFamily:"'Barlow Condensed'",fontSize:18,fontWeight:700,color:"var(--white)",marginBottom:2}}>{dirEntry?dirEntry.company:"Unknown Sub"}</div>
            <div style={{fontSize:12,color:"var(--muted)"}}>{sc.trade}{code?"   "+code.code+" - "+code.name:""}</div>
          </div>
          <div style={{display:"flex",gap:6}}>
            <button className="btn btn-ghost btn-sm" style={{fontSize:11,color:"var(--accent-bright)"}} onClick={function(){setShowSend(true);}}>Send to Sub</button>
            <button className="btn btn-ghost btn-sm" onClick={onClose}>x</button>
          </div>
        </div>
        <div style={{display:"flex",gap:0}}>
          {[["info","Info",null],["invoices","Invoices",(sc.invoices||[]).length||null],["waivers","Lien Waivers",pendingWaivers||null]].map(function(item){
            var k=item[0],l=item[1],b=item[2];
            return (
              <button key={k} className={"drw-tab"+(detailTab===k?" active":"")} onClick={()=>setDetailTab(k)} style={{fontSize:11,padding:"6px 12px"}}>
                {l}{b?<span className="nav-badge" style={{background:"var(--yellow)",color:"var(--navy)",marginLeft:4,fontSize:9}}>{b}</span>:null}
              </button>
            );
          })}
        </div>
      </div>
      <div style={{flex:1,overflowY:"auto",padding:16}}>

      {detailTab==="info" && (
      <div>
      {/* COI status */}
      <div style={{padding:"8px 12px",background:coi.ok?"rgba(52,211,153,.05)":"rgba(248,113,113,.06)",border:"1px solid "+(coi.ok?(coi.warn?"rgba(251,191,36,.25)":"rgba(52,211,153,.2)"):"rgba(248,113,113,.25)"),borderRadius:6,fontSize:12,color:coi.ok?(coi.warn?"var(--yellow)":"var(--green)"):"var(--red)",marginBottom:12}}>
        {coi.ok ? "" : "COI Issue: "}{coi.message}
      </div>

      {/* Status */}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:12}}>
        <div>
          <div className="flabel">Status</div>
          <select className="fselect" value={sc.status} onChange={e=>handleStatusChange(e.target.value)}>
            {SC_STATUSES.map(s=><option key={s}>{s}</option>)}
          </select>
        </div>
        <div>
          <div className="flabel">Contract Value</div>
          <div style={{fontSize:16,fontFamily:"'IBM Plex Mono',monospace",color:"var(--accent-bright)",padding:"8px 0"}}>{fmt(sc.contractValue)}</div>
        </div>
      </div>

      {/* Committed total */}
      {scoTotal > 0 && (
        <div style={{padding:"8px 12px",background:"var(--blue-dim)",border:"1px solid rgba(74,124,220,.2)",borderRadius:6,fontSize:12,marginBottom:12}}>
          <span style={{color:"var(--muted)"}}>Base contract: {fmt(sc.contractValue)}</span>
          <span style={{color:"var(--muted)",margin:"0 8px"}}>+</span>
          <span style={{color:"var(--yellow)"}}>Approved SCOs: {fmt(scoTotal)}</span>
          <span style={{color:"var(--muted)",margin:"0 8px"}}>=</span>
          <span style={{color:"var(--white)",fontWeight:700}}>Total committed: {fmt(sc.contractValue+scoTotal)}</span>
        </div>
      )}

      {/* Scope */}
      <div style={{marginBottom:12}}>
        <div className="flabel">Scope of Work</div>
        <div style={{fontSize:13,color:"var(--white)",lineHeight:1.6}}>{sc.description}</div>
        {sc.scopeNotes && <div style={{fontSize:11,color:"var(--muted)",marginTop:4}}>{sc.scopeNotes}</div>}
      </div>

      {/* Executed date */}
      {["Executed","Complete"].includes(sc.status) && (
        <div style={{marginBottom:12}}>
          <div className="flabel">Executed Date</div>
          <input className="finput" type="date" value={sc.executedDate||""} onChange={e=>onUpdate({...sc,executedDate:e.target.value})} style={{maxWidth:180}}/>
        </div>
      )}

      {/* Sub Change Orders */}
      <div>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8}}>
          <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)"}}>Sub Change Orders ({scoCt})</div>
          <button className="btn btn-primary btn-sm" onClick={()=>{setEditSCO(null);setShowSCOModal(true);}}>+ SCO</button>
        </div>
        {(sc.subCOs||[]).length===0 ? (
          <div style={{fontSize:12,color:"var(--muted)"}}>No change orders on this subcontract.</div>
        ) : (sc.subCOs||[]).map(sco=>(
          <div key={sco.id} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 0",borderBottom:"1px solid rgba(42,64,128,.2)"}}>
            <span style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:11,color:"var(--accent-bright)",width:65,flexShrink:0}}>{sco.num}</span>
            <span style={{fontSize:12,color:"var(--white)",flex:1}}>{sco.description}</span>
            <span style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:12,color:"var(--yellow)",flexShrink:0}}>{fmt(sco.amount)}</span>
            <span style={{fontSize:11,color:SC_STATUS_COLOR[sco.status]||"var(--muted)",fontFamily:"'Barlow Condensed'",flexShrink:0}}>{sco.status}</span>
            <button className="btn btn-ghost btn-sm" style={{fontSize:11}} onClick={()=>{setEditSCO(sco);setShowSCOModal(true);}}>Edit</button>
            <button className="btn btn-ghost btn-sm" style={{fontSize:11,color:"var(--red)"}} onClick={()=>deleteSCO(sco.id)}>x</button>
          </div>
        ))}
      </div>

      {/* Exhibit A scope */}
      {sc.exhibits && Object.values(sc.exhibits).some(Boolean) && (
        <div style={{marginTop:12,display:"flex",gap:8,flexWrap:"wrap"}}>
          <span style={{fontSize:10,color:"var(--muted)",fontFamily:"'Barlow Condensed'",letterSpacing:1}}>EXHIBITS:</span>
          <span style={{fontSize:10,color:"var(--green)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>A - Scope</span>
          {sc.exhibits.schedB&&<span style={{fontSize:10,color:"var(--accent-bright)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>B - Schedule</span>}
          {sc.exhibits.lienC&&<span style={{fontSize:10,color:"var(--accent-bright)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>C - Lien Waivers</span>}
          {sc.exhibits.safetyD&&<span style={{fontSize:10,color:"var(--accent-bright)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>D - Safety Reqs</span>}
        </div>
      )}

      {sc.scopeOfWork && (
        <div style={{marginTop:14}}>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:6}}>
            <div className="flabel">Exhibit A - Scope of Work</div>
          </div>
          <div style={{background:"rgba(255,255,255,.03)",border:"1px solid var(--navy-border)",borderRadius:6,padding:12,fontSize:11,color:"var(--white)",lineHeight:1.7,maxHeight:200,overflowY:"auto",whiteSpace:"pre-wrap"}}>{sc.scopeOfWork}</div>
        </div>
      )}

      {/* Generated doc preview */}
      {sc.generatedDoc && (
        <div style={{marginTop:14,padding:"10px 12px",background:"rgba(52,211,153,.05)",border:"1px solid rgba(52,211,153,.2)",borderRadius:6,display:"flex",alignItems:"center",gap:12}}>
          <div style={{flex:1}}>
            <div style={{fontSize:12,color:"var(--green)",fontWeight:600}}>Subcontract Generated</div>
            <div style={{fontSize:10,color:"var(--muted)"}}>{sc.generatedDoc.length.toLocaleString()} chars   {sc.generatedDoc.split("\n").length} lines</div>
          </div>
          <button className="btn btn-ghost btn-sm" style={{fontSize:11,color:"var(--accent-bright)"}} onClick={function(){setShowDocViewer(!showDocViewer);}}>{showDocViewer?"Hide Doc":"View Doc"}</button>
        </div>
      )}
      </div>
      )}

      {detailTab==="invoices" && (
        <InvoiceLog sc={sc} dirEntry={dirEntry} job={null} onUpdate={onUpdate}/>
      )}
      {detailTab==="waivers" && (
        <LienWaiverTracker sc={sc} onUpdate={onUpdate}/>
      )}

      {pendingStatus && (
        <COIWarningModal sub={sc} dirEntry={dirEntry} onConfirm={confirmCOIOverride} onCancel={()=>setPending(null)}/>
      )}
      {showSCOModal && (
        <SubCOModal subcontract={sc} existingSCO={editSCO} onSave={saveSCO} directory={directory} onClose={()=>{setShowSCOModal(false);setEditSCO(null);}}/>
      )}
      {showSend && dirEntry && (
        <DistributeModal title={"Send Subcontract - "+dirEntry.company} subject={"Subcontract - "+sc.trade} body={buildSubcontractEmail(sc,dirEntry,null)} directory={directory} filterDirId={sc.dirId} preselect={dirEntry&&getPrimaryContact(dirEntry)?[dirEntry.id+"_"+getPrimaryContact(dirEntry).id]:[]} onClose={function(){setShowSend(false);}}/>
      )}
      </div>
    </div>
  );
};

// --- SUBCONTRACT LOG MAIN -----------------------------------------------------
const SubcontractLog = ({job, directory, costCodes, contractTemplates, subcontracts, phases, activities, masterDocLib, onAdd, onUpdate}) => {
  const [selId, setSelId]   = useState(null);
  const [showForm, setShowForm] = useState(false);
  const [editSC, setEditSC] = useState(null);
  const [statusF, setStatusF] = useState("all");

  const sel = subcontracts.find(s=>s.id===selId);

  const filtered = subcontracts
    .filter(s => statusF==="all" || s.status===statusF)
    .sort((a,b) => a.status.localeCompare(b.status));

  const totalCommitted = subcontracts
    .filter(s => ["Issued","Executed","Complete"].includes(s.status))
    .reduce((sum, sc) => {
      const scoAmt = (sc.subCOs||[]).filter(s=>["Issued","Executed"].includes(s.status)).reduce((ss,s)=>ss+s.amount,0);
      return sum + sc.contractValue + scoAmt;
    }, 0);

  const handleSave = (data) => {
    if(editSC) { onUpdate(data); } else { onAdd(data); }
    setShowForm(false); setEditSC(null);
  };

  const expiredCOIs = subcontracts
    .filter(s=>s.status!=="Void")
    .filter(s => {
      const d = directory.find(x=>x.id===s.dirId);
      return d && !checkCOI(d).ok;
    }).length;

  return (
    <div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:16}}>
        {[
          {label:"Subcontracts",    val:subcontracts.filter(s=>s.status!=="Void").length, color:"var(--white)"},
          {label:"Total Committed", val:fmt(totalCommitted), color:"var(--accent-bright)"},
          {label:"Executed",        val:subcontracts.filter(s=>s.status==="Executed").length, color:"var(--green)"},
          {label:"COI Issues",      val:expiredCOIs, color:expiredCOIs>0?"var(--red)":"var(--muted)"},
        ].map(s=>(
          <div key={s.label} className="stat-card">
            <div className="stat-label">{s.label}</div>
            <div className="stat-value" style={{fontSize:16,color:s.color}}>{s.val}</div>
          </div>
        ))}
      </div>

      <div style={{display:"flex",gap:8,marginBottom:12,alignItems:"flex-end"}}>
        <div>
          <div className="flabel">Status</div>
          <select className="fselect" value={statusF} onChange={e=>setStatusF(e.target.value)} style={{fontSize:12}}>
            <option value="all">All Statuses</option>
            {SC_STATUSES.map(s=><option key={s}>{s}</option>)}
          </select>
        </div>
        <div style={{marginLeft:"auto",display:"flex",gap:8}}>
          <button className="btn btn-ghost btn-sm" style={{fontSize:11,color:"var(--green)"}} onClick={function(){setShowWaiverExport(true);}}>Export Waivers</button>
          <button className="btn btn-primary btn-sm" onClick={()=>{setEditSC(null);setShowForm(true);}}>+ New Subcontract</button>
        </div>
      </div>

      <div style={{display:"grid",gridTemplateColumns:sel?"1fr 420px":"1fr",gap:0,border:"1px solid var(--navy-border)",borderRadius:8,overflow:"hidden",minHeight:400}}>
        <div style={{borderRight:sel?"1px solid var(--navy-border)":"none",overflowY:"auto"}}>
          {filtered.length===0 ? (
            <div className="empty" style={{padding:40}}>No subcontracts on this project yet.</div>
          ) : filtered.map(function(sc){
            const dirEntry = directory.find(d=>d.id===sc.dirId);
            const code     = costCodes.find(c=>c.id===sc.costCodeId);
            const coi      = checkCOI(dirEntry);
            const scoTotal = (sc.subCOs||[]).filter(s=>["Issued","Executed"].includes(s.status)).reduce((s,c)=>s+c.amount,0);
            return (
              <div key={sc.id} onClick={()=>setSelId(selId===sc.id?null:sc.id)} style={{padding:"12px 14px",borderBottom:"1px solid rgba(42,64,128,.2)",cursor:"pointer",background:selId===sc.id?"rgba(74,124,220,.08)":"transparent",borderLeft:selId===sc.id?"3px solid var(--accent)":"3px solid transparent",transition:"background .15s"}}>
                <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",gap:8}}>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:2}}>
                      <span style={{fontSize:13,color:"var(--white)",fontWeight:700}}>{dirEntry?dirEntry.company:"Unknown"}</span>
                      {!coi.ok && <span style={{fontSize:10,color:"var(--red)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>COI ISSUE</span>}
                      {(sc.lienWaivers||[]).filter(w=>w.status==="Requested").length>0 && <span style={{fontSize:10,color:"var(--yellow)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>WAIVER PENDING</span>}
                      {coi.ok&&coi.warn && <span style={{fontSize:10,color:"var(--yellow)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>COI EXPIRING</span>}
                    </div>
                    <div style={{fontSize:11,color:"var(--muted)"}}>{sc.trade}{code?"   "+code.code:""}</div>
                    <div style={{fontSize:11,color:"var(--muted)",marginTop:2,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{sc.description}</div>
                  </div>
                  <div style={{textAlign:"right",flexShrink:0}}>
                    <div style={{fontSize:14,fontFamily:"'IBM Plex Mono',monospace",color:"var(--accent-bright)",fontWeight:600}}>{fmt(sc.contractValue+scoTotal)}</div>
                    {scoTotal>0 && <div style={{fontSize:10,color:"var(--yellow)",fontFamily:"'IBM Plex Mono',monospace"}}>+{fmt(scoTotal)} SCOs</div>}
                    <div style={{fontSize:11,color:SC_STATUS_COLOR[sc.status]||"var(--muted)",fontFamily:"'Barlow Condensed'",letterSpacing:.5,marginTop:2}}>{sc.status.toUpperCase()}</div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
        {sel && (
          <div style={{borderLeft:"1px solid var(--navy-border)",overflow:"hidden",display:"flex",flexDirection:"column"}}>
            <SubcontractDetail sc={sel} directory={directory} costCodes={costCodes} onUpdate={onUpdate} onClose={()=>setSelId(null)}/>
          </div>
        )}
      </div>

      {showForm && (
        <SubcontractFormModal job={job} directory={directory} costCodes={costCodes} contractTemplates={contractTemplates} existingSC={editSC} onSave={handleSave} onClose={()=>{setShowForm(false);setEditSC(null);}}/>
      )}
    </div>
  );
      {showWaiverExport && (
        <WaiverExportModal
          job={job}
          subcontracts={subcontracts||[]}
          directory={directory||[]}
          onClose={function(){setShowWaiverExport(false);}}/>
      )}

};

// --- TIMECARD DATA ------------------------------------------------------------
const PAY_TYPES = ["Regular","Holiday","PTO","Unpaid Off"];

const COMPANY_HOLIDAYS_2026 = [
  {date:"2026-01-01", name:"New Year's Day"},
  {date:"2026-04-03", name:"Good Friday"},
  {date:"2026-05-25", name:"Memorial Day"},
  {date:"2026-07-03", name:"Independence Day (observed)"},
  {date:"2026-09-07", name:"Labor Day"},
  {date:"2026-11-26", name:"Thanksgiving"},
  {date:"2026-11-27", name:"Day after Thanksgiving"},
  {date:"2026-12-24", name:"Christmas Eve"},
  {date:"2026-12-25", name:"Christmas Day"},
];

const PTO_HOURS = 40;    // 5 days per year after 6 months
const PTO_ELIGIBILITY_MONTHS = 6;

const isHoliday = (date) => COMPANY_HOLIDAYS_2026.find(h=>h.date===date)||null;

const ptoEligible = (hireDate) => {
  if(!hireDate) return false;
  const hire = new Date(hireDate+"T12:00:00");
  const now  = new Date(TODAY+"T12:00:00");
  const months = (now.getFullYear()-hire.getFullYear())*12+(now.getMonth()-hire.getMonth());
  return months >= PTO_ELIGIBILITY_MONTHS;
};

const HOURLY_TEAM = [
  {id:"kevin", name:"Kevin Holloway", role:"Carpenter", costCodeId:"cc29", regularRate:28.00, otMultiplier:1.5, phone:"704-555-0101", email:"kevin.holloway@email.com", hireDate:"2025-09-15", ptoHoursTotal:PTO_HOURS},
  {id:"kael",  name:"Kael Roberts",   role:"Laborer",   costCodeId:"cc30", regularRate:22.00, otMultiplier:1.5, phone:"704-555-0102", email:"kael.roberts@email.com",   hireDate:"2025-10-01", ptoHoursTotal:PTO_HOURS},
];

const PP_STATUSES = ["Open","Submitted","Signed","Payroll Sent"];

const initPayPeriods = [];

const initTimecards = {};


// --- TIMECARD HELPERS ---------------------------------------------------------
const tcCalc = (tc) => {
  const emp = HOURLY_TEAM.find(e=>e.id===tc.employeeId);
  if(!emp) return {regHrs:0,otHrs:0,holHrs:0,ptoHrs:0,regPay:0,otPay:0,holPay:0,ptoPay:0,totalPay:0,totalHrs:0};
  const billable = tc.entries.filter(e=>!e.payType||e.payType==="Regular");
  const regHrs   = billable.reduce((s,e)=>s+(e.regularHours||0),0);
  const otHrs    = billable.reduce((s,e)=>s+(e.otHours||0),0);
  const holHrs   = tc.entries.filter(e=>e.payType==="Holiday").reduce((s,e)=>s+(e.regularHours||0),0);
  const ptoHrs   = tc.entries.filter(e=>e.payType==="PTO").reduce((s,e)=>s+(e.regularHours||0),0);
  const regPay   = regHrs * emp.regularRate;
  const otPay    = otHrs  * emp.regularRate * emp.otMultiplier;
  const holPay   = holHrs * emp.regularRate;
  const ptoPay   = ptoHrs * emp.regularRate;
  const totalPay = regPay + otPay + holPay + ptoPay;
  return {regHrs,otHrs,holHrs,ptoHrs,regPay,otPay,holPay,ptoPay,totalPay,totalHrs:regHrs+otHrs+holHrs+ptoHrs};
};

const ptoUsed = (employeeId, allTimecards) => {
  return Object.values(allTimecards).flat()
    .filter(tc=>tc.employeeId===employeeId)
    .reduce((s,tc)=>s+tc.entries.filter(e=>e.payType==="PTO").reduce((ss,e)=>ss+(e.regularHours||0),0),0);
};

const getPPDates = (pp) => {
  const dates = [];
  const start = new Date(pp.startDate+"T12:00:00");
  for(let i=0;i<7;i++){
    const d = new Date(start);
    d.setDate(d.getDate()+i);
    dates.push(d.toISOString().slice(0,10));
  }
  return dates; // SunSat
};

const DAY_NAMES = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];

// --- TIMECARD ENTRY GRID ------------------------------------------------------
const TimecardGrid = ({tc, pp, jobs, onUpdate}) => {
  const emp     = HOURLY_TEAM.find(e=>e.id===tc.employeeId);
  const ppDates = getPPDates(pp);
  const calc    = tcCalc(tc);
  const isLocked = ["Signed","Payroll Sent"].includes(tc.status);
  const allJobs = [{id:"overhead",name:"Overhead / Shop / Non-Billable"},...jobs.filter(j=>j.phase==="Active"&&!j.isTraining)];

  const getEntry = (date) => tc.entries.find(e=>e.date===date) || null;

  const updateEntry = (date, field, value) => {
    const existing = tc.entries.find(e=>e.date===date);
    let base = existing || {id:"te"+uid(),date,jobId:jobs[0]?.id||"",regularHours:0,otHours:0,notes:"",payType:"Regular"};
    let updated = {...base,[field]:value};
    // Auto-set hours to 8 and job to overhead for Holiday/PTO
    if(field==="payType" && (value==="Holiday"||value==="PTO")) {
      updated.regularHours = 8;
      updated.otHours = 0;
      updated.jobId = "overhead";
    }
    if(field==="payType" && value==="Unpaid Off") {
      updated.regularHours = 0;
      updated.otHours = 0;
      updated.jobId = "";
    }
    if(existing) {
      onUpdate({...tc, entries:tc.entries.map(e=>e.date===date?updated:e)});
    } else {
      if(!value && field!=="jobId" && field!=="payType") return;
      onUpdate({...tc, entries:[...tc.entries,updated]});
    }
  };

  return (
    <div>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
        <div>
          <div style={{fontFamily:"'Barlow Condensed'",fontSize:18,fontWeight:700,color:"var(--white)"}}>{emp?emp.name:"Unknown"}</div>
          <div style={{fontSize:12,color:"var(--muted)"}}>{emp?emp.role:""} - ${emp?emp.regularRate.toFixed(2):0}/hr regular, ${emp?(emp.regularRate*emp.otMultiplier).toFixed(2):0}/hr OT</div>
          {emp&&ptoEligible(emp.hireDate)&&(
            <div style={{fontSize:11,color:"var(--green)",marginTop:2}}>PTO: {emp.ptoHoursTotal}h available</div>
          )}
          {emp&&!ptoEligible(emp.hireDate)&&(
            <div style={{fontSize:11,color:"var(--muted)",marginTop:2}}>PTO eligible after 6 months (hired {fmtDate(emp.hireDate)})</div>
          )}
        </div>
        <div style={{textAlign:"right"}}>
          <div style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:18,color:"var(--accent-bright)",fontWeight:600}}>{fmt(calc.totalPay)}</div>
          <div style={{fontSize:11,color:"var(--muted)"}}>{calc.regHrs}h reg + {calc.otHrs}h OT = {calc.totalHrs}h total</div>
        </div>
      </div>

      <table className="tbl" style={{tableLayout:"fixed"}}>
        <thead>
          <tr>
            <th style={{width:90}}>Day</th>
            <th style={{width:200}}>Pay Type / Job</th>
            <th style={{width:70}}>Reg Hrs</th>
            <th style={{width:70}}>OT Hrs</th>
            <th>Notes</th>
          </tr>
        </thead>
        <tbody>
          {ppDates.map(date=>{
            const entry  = getEntry(date);
            const dayIdx = new Date(date+"T12:00:00").getDay();
            const isWknd = dayIdx===0||dayIdx===6;
            const regHrs = entry?.regularHours||0;
            const otHrs  = entry?.otHours||0;
            const holiday   = isHoliday(date);
            const payType   = entry?.payType||"Regular";
            const isSpecial = payType==="Holiday"||payType==="PTO"||payType==="Unpaid Off";
            return (
              <tr key={date} style={{background:holiday?"rgba(251,191,36,.04)":isWknd?"rgba(138,153,187,.04)":undefined,opacity:isWknd&&!entry?.regularHours?.7:1}}>
                <td className="col-mono" style={{fontSize:11}}>
                  <div style={{color:holiday?"var(--yellow)":isWknd?"var(--muted)":"var(--white)"}}>{DAY_NAMES[dayIdx]}</div>
                  <div style={{color:"var(--muted)",fontSize:10}}>{fmtDate(date).replace(/^\w+, /,"")}</div>
                  {holiday&&<div style={{fontSize:9,color:"var(--yellow)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>{holiday.name}</div>}
                </td>
                <td>
                  {isLocked ? (
                    <div>
                      <div style={{fontSize:10,color:payType==="Holiday"?"var(--yellow)":payType==="PTO"?"var(--green)":"var(--muted)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>{payType!=="Regular"?payType:""}</div>
                      <div style={{fontSize:12,color:"var(--muted)"}}>{isSpecial?payType:entry?jobs.find(j=>j.id===entry.jobId)?.name||entry.jobId:"-"}</div>
                    </div>
                  ) : (
                    <div style={{display:"flex",gap:4,flexDirection:"column"}}>
                      <select className="fselect" style={{fontSize:10,padding:"3px 5px",color:payType==="Holiday"?"var(--yellow)":payType==="PTO"?"var(--green)":"var(--white)"}} value={payType} onChange={e=>updateEntry(date,"payType",e.target.value)}>
                        {PAY_TYPES.map(pt=><option key={pt}>{pt}</option>)}
                      </select>
                      {!isSpecial && (
                        <select className="fselect" style={{fontSize:10,padding:"3px 5px"}} value={entry?.jobId||""} onChange={e=>updateEntry(date,"jobId",e.target.value)}>
                          <option value="">- Not worked -</option>
                          {allJobs.map(j=><option key={j.id} value={j.id}>{j.name}</option>)}
                        </select>
                      )}
                    </div>
                  )}
                </td>
                <td>
                  {isLocked ? (
                    <span className="col-mono" style={{color:regHrs>0?"var(--white)":"var(--muted)"}}>{regHrs||"-"}</span>
                  ) : (
                    <input type="number" min="0" max="24" step="0.5" value={regHrs||""}
                      onChange={e=>updateEntry(date,"regularHours",parseFloat(e.target.value)||0)}
                      placeholder="0"
                      style={{width:"100%",background:"transparent",border:"1px solid var(--navy-border)",borderRadius:4,color:"var(--white)",padding:"4px 6px",fontSize:12,fontFamily:"'IBM Plex Mono',monospace"}}/>
                  )}
                </td>
                <td>
                  {isLocked ? (
                    <span className="col-mono" style={{color:otHrs>0?"var(--orange)":"var(--muted)"}}>{otHrs||"-"}</span>
                  ) : (
                    <input type="number" min="0" max="24" step="0.5" value={otHrs||""}
                      onChange={e=>updateEntry(date,"otHours",parseFloat(e.target.value)||0)}
                      placeholder="0"
                      style={{width:"100%",background:"transparent",border:"1px solid var(--navy-border)",borderRadius:4,color:"var(--orange)",padding:"4px 6px",fontSize:12,fontFamily:"'IBM Plex Mono',monospace"}}/>
                  )}
                </td>
                <td>
                  {isLocked ? (
                    <span style={{fontSize:11,color:"var(--muted)"}}>{entry?.notes||""}</span>
                  ) : (
                    <input className="finput" style={{fontSize:11,padding:"4px 8px"}} value={entry?.notes||""} onChange={e=>updateEntry(date,"notes",e.target.value)} placeholder="Work performed..."/>
                  )}
                </td>
              </tr>
            );
          })}
        </tbody>
        <tfoot>
          <tr style={{borderTop:"2px solid var(--navy-border)"}}>
            <td style={{padding:"8px 10px",fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:1,color:"var(--muted)"}}>TOTALS</td>
            <td style={{padding:"8px 10px",fontSize:11,color:"var(--muted)"}}>
              {calc.holHrs>0&&<span style={{color:"var(--yellow)",marginRight:8}}>{calc.holHrs}h Holiday</span>}
              {calc.ptoHrs>0&&<span style={{color:"var(--green)"}}>{calc.ptoHrs}h PTO</span>}
            </td>
            <td className="col-mono" style={{fontWeight:700,color:"var(--white)"}}>{calc.regHrs}h</td>
            <td className="col-mono" style={{fontWeight:700,color:calc.otHrs>0?"var(--orange)":"var(--muted)"}}>{calc.otHrs}h</td>
            <td className="col-mono" style={{color:"var(--accent-bright)",fontWeight:700}}>{fmt(calc.totalPay)}</td>
          </tr>
        </tfoot>
      </table>

      {tc.status==="Signed" && (
        <div style={{marginTop:12,padding:"10px 14px",background:"rgba(52,211,153,.05)",border:"1px solid rgba(52,211,153,.2)",borderRadius:6,display:"flex",alignItems:"center",gap:12}}>
          <span style={{fontSize:16,color:"var(--green)"}}></span>
          <div>
            <div style={{fontSize:13,color:"var(--green)",fontWeight:600}}>Signed by {tc.signedName}</div>
            <div style={{fontSize:11,color:"var(--muted)"}}>Digitally approved {fmtDate(tc.signedDate)}</div>
          </div>
        </div>
      )}
    </div>
  );
};

// --- APPROVAL MODAL (worker signs) -------------------------------------------
const TimecardApprovalModal = ({tc, pp, jobs, onSign, onClose}) => {
  const emp       = HOURLY_TEAM.find(e=>e.id===tc.employeeId);
  const calc      = tcCalc(tc);
  const ppDates   = getPPDates(pp);
  const [showWaiverExport, setShowWaiverExport] = useState(false);
  const [sigName, setSigName] = useState("");
  const canSign   = sigName.trim().toLowerCase() === (emp?emp.name.toLowerCase():"");

  return (
    <div className="overlay" onClick={onClose}>
      <div className="modal modal-wide" onClick={e=>e.stopPropagation()} style={{maxWidth:560}}>
        <div className="modal-hdr">
          <div>
            <div className="modal-title">Timecard Approval</div>
            <div className="modal-sub">Review and sign your timecard for {fmtDate(pp.startDate)}  {fmtDate(pp.endDate)}</div>
          </div>
          <button className="btn btn-ghost btn-sm" onClick={onClose}>x</button>
        </div>
        <div className="modal-body">
          <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14,marginBottom:14}}>
            <div style={{display:"flex",justifyContent:"space-between",marginBottom:10}}>
              <div>
                <div style={{fontSize:14,color:"var(--white)",fontWeight:700}}>{emp?emp.name:""}</div>
                <div style={{fontSize:11,color:"var(--muted)"}}>{emp?emp.role:""}</div>
              </div>
              <div style={{textAlign:"right"}}>
                <div style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:18,color:"var(--accent-bright)",fontWeight:700}}>{fmt(calc.totalPay)}</div>
                <div style={{fontSize:11,color:"var(--muted)"}}>{calc.regHrs}h @ ${emp?emp.regularRate.toFixed(2):0} + {calc.otHrs}h OT @ ${emp?(emp.regularRate*emp.otMultiplier).toFixed(2):0}</div>
              </div>
            </div>
            {tc.entries.filter(e=>(e.regularHours||0)+(e.otHours||0)>0).map(e=>{
              const job = jobs.find(j=>j.id===e.jobId);
              const dayIdx = new Date(e.date+"T12:00:00").getDay();
              return (
                <div key={e.id} style={{display:"flex",gap:10,padding:"6px 0",borderBottom:"1px solid rgba(42,64,128,.2)",fontSize:12}}>
                  <span style={{color:"var(--muted)",width:80,flexShrink:0}}>{DAY_NAMES[dayIdx]} {fmtDate(e.date).replace(/^\w+, /,"")}</span>
                  <span style={{color:"var(--white)",flex:1}}>{job?job.name:e.jobId}</span>
                  <span style={{color:"var(--white)",fontFamily:"'IBM Plex Mono',monospace",width:50,flexShrink:0}}>{(e.regularHours||0)+(e.otHours||0)}h</span>
                  {e.notes&&<span style={{color:"var(--muted)",fontSize:10,flex:1}}>{e.notes}</span>}
                </div>
              );
            })}
          </div>

          <div style={{padding:"12px 14px",background:"rgba(74,124,220,.06)",border:"1px solid rgba(74,124,220,.2)",borderRadius:8,marginBottom:14,fontSize:12,color:"var(--white)"}}>
            By signing below, I confirm that the hours listed above are accurate and complete for the pay period ending {fmtDate(pp.endDate)}.
          </div>

          <div>
            <div className="flabel">Type your full name to sign: <strong style={{color:"var(--accent-bright)"}}>{emp?emp.name:""}</strong></div>
            <input className="finput" value={sigName} onChange={e=>setSigName(e.target.value)} placeholder="Type your full name exactly..."/>
            {sigName.length>3 && !canSign && <div style={{fontSize:11,color:"var(--red)",marginTop:4}}>Name must match exactly: {emp?emp.name:""}</div>}
            {canSign && (
              <div style={{marginTop:8,padding:"12px 16px",background:"rgba(52,211,153,.05)",border:"1px solid rgba(52,211,153,.2)",borderRadius:6,fontFamily:"Georgia, serif",fontSize:20,color:"var(--green)",fontStyle:"italic"}}>
                {sigName}
              </div>
            )}
          </div>
        </div>
        <div className="modal-ftr">
          <button className="btn btn-ghost" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" disabled={!canSign} onClick={()=>onSign(sigName)}>Sign &amp; Approve Timecard</button>
        </div>
      </div>
    </div>
  );
};

// --- NOTIFICATION PREVIEW MODAL -----------------------------------------------
const NotificationPreviewModal = ({tc, pp, onClose, onMarkSent}) => {
  const emp = HOURLY_TEAM.find(e=>e.id===tc.employeeId);
  const calc = tcCalc(tc);
  const [copied, setCopied] = useState(false);

  const msgText = [
    "Hi "+( emp?emp.name:"" )+" - your Westroe Construction timecard for the pay period "+fmtDate(pp.startDate)+" through "+fmtDate(pp.endDate)+" is ready for review.",
    "",
    "Total hours: "+calc.totalHrs+"h",
    "Regular: "+calc.regHrs+"h | OT: "+calc.otHrs+"h",
    "Gross pay: "+fmt(calc.totalPay),
    "",
    "Please review your timecard and confirm your hours are correct. Reply YES to approve or contact the office with any questions.",
    "",
    "Westroe Construction | 704-962-6507",
  ].join("\n");

  const handleCopy = () => {
    navigator.clipboard.writeText(msgText);
    setCopied(true);
    setTimeout(()=>setCopied(false),2000);
  };

  return (
    <div className="overlay" onClick={onClose}>
      <div className="modal" onClick={e=>e.stopPropagation()} style={{maxWidth:500}}>
        <div className="modal-hdr">
          <div>
            <div className="modal-title">Send Approval Request</div>
            <div className="modal-sub">{emp?emp.name:""} - {emp?emp.phone:""} / {emp?emp.email:""}</div>
          </div>
          <button className="btn btn-ghost btn-sm" onClick={onClose}>x</button>
        </div>
        <div className="modal-body">
          <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14,marginBottom:12}}>
            <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:8}}>Message Preview</div>
            <div style={{fontSize:13,color:"var(--white)",lineHeight:1.8,whiteSpace:"pre-wrap"}}>{msgText}</div>
          </div>
          <div style={{fontSize:12,color:"var(--muted)"}}>
            In production, this message is sent automatically via SMS and email at the end of each pay period. Copy the message below to send manually.
          </div>
        </div>
        <div className="modal-ftr">
          <button className="btn btn-ghost" onClick={handleCopy}>{copied?"Copied!":"Copy Message"}</button>
          <button className="btn btn-primary" onClick={()=>{onMarkSent();onClose();}}>Mark as Sent</button>
        </div>
      </div>
    </div>
  );
};

// --- TIMECARD DASHBOARD -------------------------------------------------------
const TimecardDashboard = ({timecards, payPeriod, jobs}) => {
  if(!payPeriod) return <div className="empty">No pay period selected.</div>;
  const pTCs = timecards[payPeriod.id]||[];

  const byJob = jobs.filter(j=>j.phase==="Active"&&!j.isTraining).map(job=>{
    const hrs = pTCs.reduce((s,tc)=>s+tc.entries.filter(e=>e.jobId===job.id).reduce((ss,e)=>ss+(e.regularHours||0)+(e.otHours||0),0),0);
    const cost = pTCs.reduce((s,tc)=>{
      const emp = HOURLY_TEAM.find(e=>e.id===tc.employeeId);
      if(!emp) return s;
      const regHrs = tc.entries.filter(e=>e.jobId===job.id).reduce((ss,e)=>ss+(e.regularHours||0),0);
      const otHrs  = tc.entries.filter(e=>e.jobId===job.id).reduce((ss,e)=>ss+(e.otHours||0),0);
      return s + regHrs*emp.regularRate + otHrs*emp.regularRate*emp.otMultiplier;
    },0);
    return {job,hrs,cost};
  }).filter(j=>j.hrs>0);

  const totalHrs  = pTCs.reduce((s,tc)=>s+tcCalc(tc).totalHrs,0);
  const totalPay  = pTCs.reduce((s,tc)=>s+tcCalc(tc).totalPay,0);
  const totalOT   = pTCs.reduce((s,tc)=>s+tcCalc(tc).otHrs,0);
  const allSigned = pTCs.length>0&&pTCs.every(tc=>["Signed","Payroll Sent"].includes(tc.status));

  return (
    <div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:20}}>
        {[
          {label:"Total Hours",      val:totalHrs+"h",      color:"var(--white)"},
          {label:"OT Hours",         val:totalOT+"h",        color:totalOT>0?"var(--orange)":"var(--muted)"},
          {label:"Gross Payroll",    val:fmt(totalPay),      color:"var(--accent-bright)"},
          {label:"Timecards",        val:pTCs.filter(tc=>tc.status==="Signed").length+"/"+pTCs.length+" signed", color:allSigned?"var(--green)":"var(--yellow)"},
        ].map(s=>(
          <div key={s.label} className="stat-card">
            <div className="stat-label">{s.label}</div>
            <div className="stat-value" style={{fontSize:16,color:s.color}}>{s.val}</div>
          </div>
        ))}
      </div>

      <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:10}}>Hours by Project</div>
      {byJob.length===0 ? <div className="empty">No hours entered this period.</div>
       : byJob.map(({job,hrs,cost})=>(
        <div key={job.id} style={{display:"flex",alignItems:"center",gap:12,padding:"8px 0",borderBottom:"1px solid rgba(42,64,128,.2)"}}>
          <div style={{flex:1}}>
            <div style={{fontSize:13,color:"var(--white)",fontWeight:600}}>{job.name}</div>
            <div style={{fontSize:11,color:"var(--muted)"}}>{job.id}</div>
          </div>
          <span style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:12,color:"var(--white)",width:40,textAlign:"right"}}>{hrs}h</span>
          <span style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:12,color:"var(--accent-bright)",width:80,textAlign:"right"}}>{fmt(cost)}</span>
        </div>
      ))}

      <div style={{marginTop:20}}>
        <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:10}}>Per Employee</div>
        {pTCs.map(tc=>{
          const emp = HOURLY_TEAM.find(e=>e.id===tc.employeeId);
          const c   = tcCalc(tc);
          return (
            <div key={tc.id} style={{display:"flex",alignItems:"center",gap:12,padding:"8px 0",borderBottom:"1px solid rgba(42,64,128,.2)"}}>
              <div style={{flex:1}}>
                <div style={{fontSize:13,color:"var(--white)",fontWeight:600}}>{emp?emp.name:tc.employeeId}</div>
                <div style={{fontSize:11,color:"var(--muted)"}}>{emp?emp.role:""} - {c.regHrs}h reg + {c.otHrs}h OT</div>
              </div>
              <span style={{fontSize:11,color:tc.status==="Signed"?"var(--green)":"var(--yellow)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>{tc.status.toUpperCase()}</span>
              <span style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:13,color:"var(--accent-bright)",fontWeight:600,width:80,textAlign:"right"}}>{fmt(c.totalPay)}</span>
            </div>
          );
        })}
      </div>
    </div>
  );
};

// --- TIMECARD TOOL MAIN -------------------------------------------------------
const TimecardTool = ({jobs, timecards, payPeriods, onUpdateTC, onAddPP, onUpdatePP, onAddCostEntries}) => {
  const [tab,       setTab]       = useState("timecards");
  const [selPP,     setSelPP]     = useState(payPeriods[payPeriods.length-1]?.id||null);
  const [selEmp,    setSelEmp]    = useState(HOURLY_TEAM[0]?.id||null);
  const [showApproval,  setShowApproval]  = useState(null);
  const [showNotify,    setShowNotify]    = useState(null);

  const currentPP = payPeriods.find(p=>p.id===selPP);
  const ppTCs     = timecards[selPP]||[];
  const selTC     = ppTCs.find(tc=>tc.employeeId===selEmp);

  const createNextPP = () => {
    const last = payPeriods[payPeriods.length-1];
    if(!last) return;
    const nextStart = new Date(last.endDate+"T12:00:00");
    nextStart.setDate(nextStart.getDate()+1);
    // Snap to Sunday if needed
    while(nextStart.getDay()!==0) nextStart.setDate(nextStart.getDate()+1);
    const nextEnd   = new Date(nextStart);
    nextEnd.setDate(nextEnd.getDate()+6); // Saturday
    const newPP = {id:"pp"+uid(),startDate:nextStart.toISOString().slice(0,10),endDate:nextEnd.toISOString().slice(0,10),status:"Open"};
    onAddPP(newPP, HOURLY_TEAM.map(emp=>({
      id:"tc"+uid(),employeeId:emp.id,payPeriodId:newPP.id,
      status:"Open",signedName:"",signedDate:"",notificationSent:false,costEntriesCreated:false,entries:[],
    })));
  };

  const handleSign = (sigName) => {
    if(!selTC) return;
    onUpdateTC(selPP, {...selTC, status:"Signed", signedName:sigName, signedDate:TODAY});
    setShowApproval(null);
  };

  const handleMarkSent = () => {
    if(!showNotify) return;
    onUpdateTC(selPP, {...showNotify, notificationSent:true});
  };

  const handlePostToCosts = () => {
    if(!currentPP) return;
    const signedTCs = ppTCs.filter(tc=>tc.status==="Signed"&&!tc.costEntriesCreated);
    signedTCs.forEach(tc=>{
      const emp = HOURLY_TEAM.find(e=>e.id===tc.employeeId);
      if(!emp) return;
      tc.entries.filter(e=>(!e.payType||e.payType==="Regular")&&e.jobId&&e.jobId!=="overhead"&&((e.regularHours||0)+(e.otHours||0)>0)).forEach(entry=>{
        const regPay = (entry.regularHours||0)*emp.regularRate;
        const otPay  = (entry.otHours||0)*emp.regularRate*emp.otMultiplier;
        const total  = regPay+otPay;
        if(total<=0) return;
        onAddCostEntries(entry.jobId,{
          id:"ce"+uid(), jobId:entry.jobId, costCodeId:emp.costCodeId,
          vendor:emp.name, description:"Labor - "+emp.role+" ("+fmtDate(entry.date)+")",
          amount:total, date:entry.date, invoiceNum:"TC-"+tc.payPeriodId+"-"+tc.employeeId,
          status:"Approved", pdfBase64:null, pdfName:"", sourceTimecardId:tc.id,
        });
      });
      onUpdateTC(selPP, {...tc, costEntriesCreated:true, status:"Payroll Sent"});
    });
  };

  const allSigned  = ppTCs.length>0&&ppTCs.every(tc=>["Signed","Payroll Sent"].includes(tc.status));
  const anyUnsent  = ppTCs.some(tc=>!tc.notificationSent&&tc.status==="Open");
  const anySignedUnposted = ppTCs.some(tc=>tc.status==="Signed"&&!tc.costEntriesCreated);

  return (
    <div>
      {/* Top bar */}
      <div style={{display:"flex",alignItems:"center",gap:0,marginBottom:0,borderBottom:"1px solid var(--navy-border)"}}>
        <div style={{display:"flex",flex:1}}>
          {[["timecards","Timecards",null],["dashboard","Dashboard",null]].map(([k,l,b])=>(
            <button key={k} className={"dtab"+(tab===k?" active":"")} onClick={()=>setTab(k)}>{l}</button>
          ))}
        </div>
        <div style={{padding:"0 0 8px 0",display:"flex",gap:8,alignItems:"center"}}>
          {/* Pay period selector */}
          <select className="fselect" style={{fontSize:12}} value={selPP||""} onChange={e=>setSelPP(e.target.value)}>
            {payPeriods.map(pp=><option key={pp.id} value={pp.id}>{fmtDate(pp.startDate)}  {fmtDate(pp.endDate)} ({pp.status})</option>)}
          </select>
          <button className="btn btn-ghost btn-sm" onClick={createNextPP}>+ New Period</button>
        </div>
      </div>

      {tab==="dashboard" && (
        <div style={{paddingTop:14}}>
          <TimecardDashboard timecards={timecards} payPeriod={currentPP} jobs={jobs}/>
        </div>
      )}

      {tab==="timecards" && currentPP && (
        <div style={{paddingTop:12}}>
          {/* Action bar */}
          <div style={{display:"flex",gap:8,marginBottom:12,alignItems:"center",flexWrap:"wrap"}}>
            <div style={{display:"flex",gap:6}}>
              {HOURLY_TEAM.map(emp=>(
                <button key={emp.id} className={"btn "+(selEmp===emp.id?"btn-primary":"btn-ghost")+" btn-sm"} onClick={()=>setSelEmp(emp.id)}>
                  {emp.name.split(" ")[0]}
                  {ppTCs.find(tc=>tc.employeeId===emp.id)?.status==="Signed"&&<span style={{marginLeft:4,color:"var(--green)"}}></span>}
                </button>
              ))}
            </div>
            <div style={{marginLeft:"auto",display:"flex",gap:8,alignItems:"center"}}>
              {anyUnsent && (
                <button className="btn btn-ghost btn-sm" onClick={()=>setShowNotify(ppTCs.find(tc=>!tc.notificationSent&&tc.status==="Open"))}>
                  Send Approval Request
                </button>
              )}
              {selTC&&selTC.status==="Open" && (
                <button className="btn btn-primary btn-sm" onClick={()=>setShowApproval(selTC)}>
                  Sign Timecard
                </button>
              )}
              {anySignedUnposted && (
                <button className="btn btn-ai btn-sm" onClick={handlePostToCosts}>
                  Post to Job Costs
                </button>
              )}
            </div>
          </div>

          {/* Period status banner */}
          <div style={{display:"flex",gap:8,marginBottom:12,flexWrap:"wrap"}}>
            {ppTCs.map(tc=>{
              const emp = HOURLY_TEAM.find(e=>e.id===tc.employeeId);
              const c   = tcCalc(tc);
              const statusCol = {Open:"var(--muted)",Signed:"var(--green)","Payroll Sent":"var(--accent-bright)"}[tc.status]||"var(--muted)";
              return (
                <div key={tc.id} style={{padding:"8px 12px",background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:6,display:"flex",gap:10,alignItems:"center"}}>
                  <div>
                    <div style={{fontSize:12,color:"var(--white)",fontWeight:600}}>{emp?emp.name:tc.employeeId}</div>
                    <div style={{fontSize:11,color:"var(--muted)"}}>{c.totalHrs}h - {fmt(c.totalPay)}</div>
                  </div>
                  <div style={{display:"flex",flexDirection:"column",gap:3,alignItems:"flex-end"}}>
                    <span style={{fontSize:10,color:statusCol,fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>{tc.status.toUpperCase()}</span>
                    {!tc.notificationSent&&tc.status==="Open"&&(
                      <button className="btn btn-ghost btn-sm" style={{fontSize:9,padding:"2px 6px"}} onClick={()=>setShowNotify(tc)}>Send</button>
                    )}
                    {tc.notificationSent&&tc.status==="Open"&&(
                      <span style={{fontSize:9,color:"var(--accent-bright)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>NOTIFIED</span>
                    )}
                  </div>
                </div>
              );
            })}
          </div>

          {/* Timecard grid */}
          {selTC ? (
            <TimecardGrid tc={selTC} pp={currentPP} jobs={jobs} onUpdate={tc=>onUpdateTC(selPP,tc)}/>
          ) : (
            <div className="empty" style={{padding:40}}>Select an employee above.</div>
          )}
        </div>
      )}

      {showApproval && currentPP && (
        <TimecardApprovalModal tc={showApproval} pp={currentPP} jobs={jobs} onSign={handleSign} onClose={()=>setShowApproval(null)}/>
      )}
      {showNotify && currentPP && (
        <NotificationPreviewModal tc={showNotify} pp={currentPP} onMarkSent={handleMarkSent} onClose={()=>setShowNotify(null)}/>
      )}
    </div>
  );
};

