// --- PRECON HELPERS -----------------------------------------------------------
const calcEstLine = (line) => {
  const mat  = (line.matUnit||0) * (line.qty||0);
  const lab  = (line.labUnit||0) * (line.qty||0);
  return {mat, lab, total:mat+lab};
};

const calcEstTotals = (est) => {
  const lines   = est.lines.map(calcEstLine);
  const dirMat  = lines.reduce((s,l)=>s+l.mat,0);
  const dirLab  = lines.reduce((s,l)=>s+l.lab,0);
  const dirCost = dirMat + dirLab;
  const overhead= dirCost * ((est.overheadPct||0)/100);
  const subtotal= dirCost + overhead;
  const profit  = subtotal * ((est.profitPct||0)/100);
  const bidTotal= subtotal + profit;
  const marginPct = bidTotal>0 ? profit/bidTotal*100 : 0;
  return {dirMat,dirLab,dirCost,overhead,subtotal,profit,bidTotal,marginPct};
};

