const CSVImportModal = ({onImport, onClose}) => {
  const [raw,      setRaw]      = useState("");
  const [preview,  setPreview]  = useState(null);
  const [mapping,  setMapping]  = useState({desc:-1,unit:-1,mat:-1,lab:-1,code:-1,cat:-1});
  const [step,     setStep]     = useState(1);
  const [imported, setImported] = useState(0);
  const fileRef = useRef();
  const setMap = (k,v) => setMapping(p=>({...p,[k]:v}));

  const parseCSV = (text) => {
    const rows = text.trim().split("\n").map(r=>{
      const cols = []; let cur=""; let inQ=false;
      for(let i=0;i<r.length;i++){
        if(r[i]==='"'){inQ=!inQ;}
        else if(r[i]===","&&!inQ){cols.push(cur.trim());cur="";}
        else cur+=r[i];
      }
      cols.push(cur.trim());
      return cols;
    });
    return rows;
  };

  const handleFile = (e) => {
    const file = e.target.files[0];
    if(!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      const text = ev.target.result;
      setRaw(text);
      const rows = parseCSV(text);
      setPreview(rows.slice(0,6));
      // Auto-detect common Xactimate column names
      const hdr = (rows[0]||[]).map(h=>h.toLowerCase());
      const find = (keys) => { for(const k of keys){ const i=hdr.findIndex(h=>h.includes(k)); if(i>=0)return i; } return -1; };
      setMapping({
        code: find(["code","item","line"]),
        desc: find(["description","desc","name","activity"]),
        unit: find(["unit","uom","um"]),
        mat:  find(["material","mat","rcv material","unit material"]),
        lab:  find(["labor","labour","rcv labor","unit labor"]),
        cat:  find(["category","cat","trade","division"]),
      });
      setStep(2);
    };
    reader.readAsText(file);
    e.target.value="";
  };

  const doImport = () => {
    const rows = parseCSV(raw);
    const data = rows.slice(1).filter(r=>r.length>2);
    const items = data.map((r,i)=>({
      id:"pb_imp"+uid(),
      category:  mapping.cat>=0  ? r[mapping.cat]||"Imported"  : "Imported",
      code:      mapping.code>=0 ? r[mapping.code]||""         : "",
      description:mapping.desc>=0? r[mapping.desc]||""         : "",
      unit:      mapping.unit>=0 ? r[mapping.unit]||"EA"       : "EA",
      matCost:   mapping.mat>=0  ? parseFloat(r[mapping.mat])||0  : 0,
      labCost:   mapping.lab>=0  ? parseFloat(r[mapping.lab])||0  : 0,
      notes:"Imported",
    })).filter(i=>i.description);
    onImport(items);
    setImported(items.length);
    setStep(3);
  };

  const headers = preview ? preview[0]||[] : [];

  return (
    <div className="overlay" onClick={onClose}>
      <div className="modal modal-wide" onClick={e=>e.stopPropagation()} style={{maxWidth:640}}>
        <div className="modal-hdr">
          <div>
            <div className="modal-title">Import Price Book from CSV</div>
            <div className="modal-sub">Xactimate export or custom CSV - Step {step} of 3</div>
          </div>
          <button className="btn btn-ghost btn-sm" onClick={onClose}>x</button>
        </div>
        <div className="modal-body">
          {step===1 && (
            <div style={{textAlign:"center",padding:"24px 0"}}>
              <div style={{fontSize:13,color:"var(--white)",marginBottom:16}}>
                Export your Xactimate price list as CSV, or prepare any CSV with columns for description, unit, and unit costs. Claude will auto-detect the column mapping.
              </div>
              <button className="btn btn-primary" onClick={()=>fileRef.current&&fileRef.current.click()}>Select CSV File</button>
              <input ref={fileRef} type="file" accept=".csv,.txt" style={{display:"none"}} onChange={handleFile}/>
            </div>
          )}
          {step===2 && preview && (
            <div>
              <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:8}}>Column Mapping - auto-detected, adjust as needed</div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10,marginBottom:14}}>
                {[["desc","Description (required)"],["unit","Unit"],["mat","Material Cost"],["lab","Labor Cost"],["code","Item Code"],["cat","Category"]].map(([k,l])=>(
                  <div key={k}>
                    <div className="flabel">{l}</div>
                    <select className="fselect" value={mapping[k]} onChange={e=>setMap(k,parseInt(e.target.value))}>
                      <option value={-1}>- Skip -</option>
                      {headers.map((h,i)=><option key={i} value={i}>{h||"Col "+(i+1)}</option>)}
                    </select>
                  </div>
                ))}
              </div>
              <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:6}}>Preview (first 5 data rows)</div>
              <div style={{overflowX:"auto",border:"1px solid var(--navy-border)",borderRadius:6}}>
                <table className="tbl" style={{minWidth:500}}>
                  <thead><tr>{headers.map((h,i)=><th key={i} style={{fontSize:10}}>{h||"Col "+(i+1)}</th>)}</tr></thead>
                  <tbody>{preview.slice(1,6).map((r,i)=><tr key={i}>{r.map((c,j)=><td key={j} style={{fontSize:11,maxWidth:140,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{c}</td>)}</tr>)}</tbody>
                </table>
              </div>
            </div>
          )}
          {step===3 && (
            <div style={{textAlign:"center",padding:"24px 0"}}>
              <div style={{fontSize:28,marginBottom:12}}></div>
              <div style={{fontFamily:"'Barlow Condensed'",fontSize:16,letterSpacing:1,color:"var(--green)",marginBottom:8}}>Import Complete</div>
              <div style={{fontSize:13,color:"var(--white)"}}>{imported} line items imported to your price book.</div>
            </div>
          )}
        </div>
        <div className="modal-ftr">
          {step===2&&<button className="btn btn-ghost" onClick={()=>setStep(1)}>Back</button>}
          {step===2&&mapping.desc>=0&&<button className="btn btn-primary" onClick={doImport}>Import {raw?parseCSV(raw).length-1:0} Items</button>}
          {step===3&&<button className="btn btn-primary" onClick={onClose}>Done</button>}
        </div>
      </div>
    </div>
  );
};

const PriceBook = ({priceBook, onAdd, onUpdate, onDelete, onImport}) => {
  const [showAdd,    setShowAdd]    = useState(false);
  const [showImport, setShowImport] = useState(false);
  const [search,     setSearch]     = useState("");
  const [catFilter,  setCatFilter]  = useState("all");
  const [f, setF] = useState({category:PB_CATEGORIES[0]||"General",code:"",description:"",unit:"SF",matCost:"",labCost:"",notes:""});
  const set = (k,v) => setF(p=>({...p,[k]:v}));

  const cats = [...new Set(priceBook.map(p=>p.category))].sort();
  const filtered = priceBook.filter(p=>{
    if(catFilter!=="all"&&p.category!==catFilter) return false;
    if(search&&!p.description.toLowerCase().includes(search.toLowerCase())&&!p.code.toLowerCase().includes(search.toLowerCase())) return false;
    return true;
  });
  const grouped = cats.map(cat=>({cat,items:filtered.filter(p=>p.category===cat)})).filter(g=>g.items.length>0);

  return (
    <div>
      <div style={{display:"flex",gap:8,marginBottom:12,alignItems:"flex-end",flexWrap:"wrap"}}>
        <div style={{flex:1}}><div className="flabel">Search</div><input className="finput" value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search descriptions or codes..."/></div>
        <div><div className="flabel">Category</div><select className="fselect" value={catFilter} onChange={e=>setCatFilter(e.target.value)}><option value="all">All Categories</option>{cats.map(c=><option key={c}>{c}</option>)}</select></div>
        <div style={{display:"flex",gap:6,paddingTop:18}}>
          <button className="btn btn-ghost btn-sm" onClick={()=>setShowImport(true)}>Import CSV</button>
          <button className="btn btn-primary btn-sm" onClick={()=>setShowAdd(!showAdd)}>+ Add Item</button>
        </div>
      </div>

      {showAdd && (
        <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14,marginBottom:12,display:"flex",flexDirection:"column",gap:10}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 100px 1fr",gap:10}}>
            <div><div className="flabel">Category</div><input className="finput" list="pb-cats" value={f.category} onChange={e=>set("category",e.target.value)}/><datalist id="pb-cats">{cats.map(c=><option key={c} value={c}/>)}</datalist></div>
            <div><div className="flabel">Code</div><input className="finput" value={f.code} onChange={e=>set("code",e.target.value)} placeholder="FRM001"/></div>
            <div><div className="flabel">Description</div><input className="finput" value={f.description} onChange={e=>set("description",e.target.value)} placeholder="What this covers..."/></div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"80px 1fr 1fr 1fr",gap:10}}>
            <div><div className="flabel">Unit</div><select className="fselect" value={f.unit} onChange={e=>set("unit",e.target.value)}>{PC_UNITS.map(u=><option key={u}>{u}</option>)}</select></div>
            <div><div className="flabel">Material $/unit</div><input className="finput" type="number" value={f.matCost} onChange={e=>set("matCost",e.target.value)} placeholder="0.00"/></div>
            <div><div className="flabel">Labor $/unit</div><input className="finput" type="number" value={f.labCost} onChange={e=>set("labCost",e.target.value)} placeholder="0.00"/></div>
            <div><div className="flabel">Total $/unit</div><div style={{padding:"8px 10px",background:"rgba(255,255,255,.03)",border:"1px solid var(--navy-border)",borderRadius:4,fontFamily:"'IBM Plex Mono',monospace",fontSize:13,color:"var(--accent-bright)"}}>${((parseFloat(f.matCost)||0)+(parseFloat(f.labCost)||0)).toFixed(2)}</div></div>
          </div>
          <div style={{display:"flex",gap:16,alignItems:"center"}}>
            <div style={{flex:1}}><div className="flabel">Notes</div><input className="finput" value={f.notes} onChange={e=>set("notes",e.target.value)} placeholder="Scope notes, assumptions..."/></div>
            <label style={{display:"flex",alignItems:"center",gap:6,cursor:"pointer",fontSize:13,color:"var(--white)",flexShrink:0,paddingTop:16}}>
              <input type="checkbox" checked={!!f.selfPerform} onChange={e=>set("selfPerform",e.target.checked)} style={{accentColor:"var(--accent)"}}/>
              Westroe Self-Perform
            </label>
          </div>
          <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
            <button className="btn btn-ghost btn-sm" onClick={()=>setShowAdd(false)}>Cancel</button>
            <button className="btn btn-primary btn-sm" onClick={()=>{
              if(!f.description.trim()) return;
              onAdd({...f,id:"pb"+uid(),matCost:parseFloat(f.matCost)||0,labCost:parseFloat(f.labCost)||0,selfPerform:f.selfPerform||false,laborCostCode:f.laborCostCode||"cc30",matCostCode:f.matCostCode||"cc32"});
              setShowAdd(false);
              setF({category:f.category,code:"",description:"",unit:"SF",matCost:"",labCost:"",notes:""});
            }}>Add to Price Book</button>
          </div>
        </div>
      )}

      <div style={{fontSize:12,color:"var(--muted)",marginBottom:8}}>{filtered.length} items{search?" matching '"+search+"'":""}</div>

      {grouped.map(({cat,items})=>(
        <div key={cat} style={{marginBottom:14}}>
          <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:6,paddingBottom:4,borderBottom:"1px solid var(--navy-border)"}}>{cat} ({items.length})</div>
          <table className="tbl">
            <thead><tr><th style={{width:80}}>Code</th><th>Description</th><th style={{width:50}}>Unit</th><th style={{width:90}}>Material</th><th style={{width:90}}>Labor</th><th style={{width:90}}>Total/Unit</th><th style={{width:50}}>SP</th><th style={{width:40}}></th></tr></thead>
            <tbody>
              {items.map(pb=>(
                <tr key={pb.id}>
                  <td className="col-mono" style={{fontSize:11,color:"var(--muted)"}}>{pb.code}</td>
                  <td style={{color:"var(--white)"}}>{pb.description}{pb.notes&&<div style={{fontSize:10,color:"var(--muted)"}}>{pb.notes}</div>}</td>
                  <td className="col-mono" style={{fontSize:11}}>{pb.unit}</td>
                  <td className="col-mono">${(pb.matCost||0).toFixed(2)}</td>
                  <td className="col-mono">${(pb.labCost||0).toFixed(2)}</td>
                  <td className="col-mono" style={{color:"var(--accent-bright)",fontWeight:600}}>${((pb.matCost||0)+(pb.labCost||0)).toFixed(2)}</td>
                  <td style={{textAlign:"center"}}>{pb.selfPerform&&<span style={{fontSize:10,color:"var(--accent-bright)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>SP</span>}</td>
                  <td><button className="btn btn-ghost btn-sm" style={{fontSize:11,color:"var(--red)"}} onClick={()=>onDelete(pb.id)}>x</button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ))}

      {showImport && <CSVImportModal onImport={onImport} onClose={()=>setShowImport(false)}/>}
    </div>
  );
};

