// --- ESTIMATE DOCUMENTS TAB ---------------------------------------------------
const EstimateDocuments = ({estimate, onUpdate}) => {
  const [uploading, setUploading] = useState(false);
  const fileRef = useRef();

  const docs = estimate.documents||[];

  const handleUpload = (e) => {
    const files = Array.from(e.target.files);
    if(!files.length) return;
    setUploading(true);
    Promise.all(files.map(file => readFile(file).then(b64=>({
      id:"doc"+uid(), name:file.name,
      type:file.name.toLowerCase().endsWith(".pdf")?"pdf":"other",
      base64:b64, uploadDate:TODAY,
    })))).then(newDocs=>{
      onUpdate({...estimate, documents:[...docs,...newDocs]});
      setUploading(false);
    });
    e.target.value="";
  };

  const removeDoc = (id) => onUpdate({...estimate, documents:docs.filter(d=>d.id!==id)});

  return (
    <div>
      <div style={{fontSize:13,color:"var(--muted)",marginBottom:12}}>
        Upload drawings and specification sections here. Claude will read these when generating takeoffs and suggesting bid RFIs.
      </div>
      <div style={{display:"flex",gap:8,marginBottom:14}}>
        <button className="btn btn-primary btn-sm" onClick={()=>fileRef.current&&fileRef.current.click()} disabled={uploading}>
          {uploading?"Uploading...":"+ Upload Drawings / Specs"}
        </button>
        <input ref={fileRef} type="file" accept=".pdf" multiple style={{display:"none"}} onChange={handleUpload}/>
      </div>
      {docs.length===0 ? (
        <div className="drw-upload-zone" onClick={()=>fileRef.current&&fileRef.current.click()}>
          <div style={{fontSize:20,opacity:.4,marginBottom:8}}></div>
          <div style={{fontFamily:"'Barlow Condensed'",fontSize:12,letterSpacing:1,color:"var(--accent-bright)"}}>Upload drawings or spec sections (PDF)</div>
          <div style={{fontSize:11,color:"var(--muted)",marginTop:4}}>Claude will use these for takeoffs and bid RFI suggestions</div>
        </div>
      ) : (
        <div>
          {docs.map(doc=>(
            <div key={doc.id} style={{display:"flex",alignItems:"center",gap:12,padding:"10px 14px",background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:6,marginBottom:6}}>
              <span style={{fontSize:20,opacity:.6}}></span>
              <div style={{flex:1}}>
                <div style={{fontSize:13,color:"var(--white)",fontWeight:600}}>{doc.name}</div>
                <div style={{fontSize:11,color:"var(--muted)"}}>{doc.type.toUpperCase()}   Uploaded {fmtDate(doc.uploadDate)}</div>
              </div>
              <button className="btn btn-ghost btn-sm" style={{color:"var(--red)",fontSize:11}} onClick={()=>removeDoc(doc.id)}>Remove</button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

// --- AI TAKEOFF TAB -----------------------------------------------------------
const AITakeoff = ({estimate, priceBook, onUpdate}) => {
  const [scope,    setScope]    = useState("");
  const [dims,     setDims]     = useState("");
  const [loading,  setLoading]  = useState(false);
  const [error,    setError]    = useState(null);
  const [results,  setResults]  = useState(null);
  const [selected, setSelected] = useState([]);
  const docs = estimate.documents||[];

  const PB_CATS = [...new Set(priceBook.map(p=>p.category))].sort();

  const runTakeoff = () => {
    setLoading(true); setError(null); setResults(null);
    const pbItems = priceBook.filter(p=>!scope||p.category===scope)
      .map(p=>p.code+" | "+p.description+" | "+p.unit+" | $"+((p.matCost+p.labCost).toFixed(2))+"/"+p.unit).join("\n");

    const msgContent = [];
    docs.forEach(doc=>{
      if(doc.base64&&doc.type==="pdf"){
        msgContent.push({type:"document",source:{type:"base64",media_type:"application/pdf",data:doc.base64}});
      }
    });
    msgContent.push({type:"text",text:[
      "You are a construction estimator performing a quantity takeoff for Westroe Construction.",
      "Project: "+estimate.name,
      docs.length>0?"The drawings/specs above are provided for this estimate.":"No drawings uploaded - use the dimensions provided.",
      "",
      "SCOPE: "+(scope||"All scopes"),
      "DIMENSIONS / NOTES: "+(dims||"See drawings"),
      "",
      "Available price book items for this scope:",
      pbItems,
      "",
      "Perform a quantity takeoff and return ONLY a JSON array:",
      '[{priceBookCode, description, qty, unit, notes}]',
      "priceBookCode: match exactly to a code above (e.g. FRM001)",
      "description: match the price book description",
      "qty: numeric quantity extracted from drawings or calculated from dimensions",
      "unit: must match the price book unit",
      "notes: brief takeoff note (e.g. 'N wall 48LF x 9H = 432SF')",
      "Return 5-15 line items. No markdown.",
    ].join("\n")});

    fetch("https://api.anthropic.com/v1/messages",{
      method:"POST",headers:{"Content-Type":"application/json"},
      body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:2000,system:"You are a construction quantity takeoff specialist. Return ONLY valid JSON array.",messages:[{role:"user",content:msgContent}]})
    }).then(r=>r.json()).then(data=>{
      if(data.error) throw new Error(data.error.message);
      const raw = data.content.filter(b=>b.type==="text").map(b=>b.text).join("");
      const cleaned = raw.split("```json").join("").split("```").join("").trim();
      const parsed = JSON.parse(cleaned);
      setResults(parsed);
      setSelected(parsed.map((_,i)=>i));
    }).catch(err=>setError("Takeoff failed: "+err.message))
    .finally(()=>setLoading(false));
  };

  const addSelected = () => {
    const toAdd = results.filter((_,i)=>selected.includes(i));
    const newLines = toAdd.map(r=>{
      const pb = priceBook.find(p=>p.code===r.priceBookCode)||priceBook.find(p=>p.description.toLowerCase().includes((r.description||"").toLowerCase().slice(0,12)));
      return {id:"el"+uid(),priceBookId:pb?pb.id:null,description:r.description||"",qty:r.qty||1,unit:r.unit||"EA",matUnit:pb?pb.matCost:0,labUnit:pb?pb.labCost:0,override:!pb,notes:r.notes||"",selfPerform:pb?!!pb.selfPerform:false,laborCostCode:pb?pb.laborCostCode||"cc30":"cc30",matCostCode:pb?pb.matCostCode||"cc32":"cc32"};
    });
    onUpdate({...estimate,lines:[...estimate.lines,...newLines]});
    setResults(null); setSelected([]);
  };

  return (
    <div>
      <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14,marginBottom:14}}>
        <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:10}}>
          {docs.length>0?"Reading "+docs.length+" uploaded document"+(docs.length!==1?"s":""):"No documents uploaded - Claude will use dimensions below"}
        </div>
        <div style={{display:"grid",gridTemplateColumns:"200px 1fr",gap:10,marginBottom:10}}>
          <div>
            <div className="flabel">Scope / Trade</div>
            <select className="fselect" value={scope} onChange={e=>setScope(e.target.value)}>
              <option value="">All Scopes</option>
              {PB_CATS.map(c=><option key={c}>{c}</option>)}
            </select>
          </div>
          <div>
            <div className="flabel">Dimensions / Notes {docs.length===0?"(required)":"(optional override)"}</div>
            <input className="finput" value={dims} onChange={e=>setDims(e.target.value)} placeholder="e.g. 2,400 SF single-story, 8ft ceilings, 4 baths, 180 LF exterior walls..."/>
          </div>
        </div>
        {error&&<div style={{fontSize:12,color:"var(--red)",marginBottom:8}}>{error}</div>}
        <div style={{display:"flex",gap:8}}>
          <button className="btn btn-ai" onClick={runTakeoff} disabled={loading||(!scope&&!dims&&docs.length===0)}>
            {loading?"Running Takeoff...":" Run AI Takeoff"}
          </button>
          {loading&&<div className="spinner" style={{width:18,height:18,borderWidth:2}}/>}
        </div>
      </div>

      {results && (
        <div>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}>
            <div style={{fontSize:13,color:"var(--muted)"}}>{results.length} quantities extracted - select items to add to estimate</div>
            <div style={{display:"flex",gap:8}}>
              <button className="btn btn-ghost btn-sm" onClick={()=>setSelected(results.map((_,i)=>i))}>Select All</button>
              <button className="btn btn-primary btn-sm" onClick={addSelected} disabled={!selected.length}>Add {selected.length} Lines to Estimate</button>
            </div>
          </div>
          <table className="tbl">
            <thead><tr><th style={{width:30}}></th><th style={{width:80}}>Code</th><th>Description</th><th style={{width:70}}>Qty</th><th style={{width:60}}>Unit</th><th style={{width:90}}>Unit Cost</th><th style={{width:90}}>Total</th><th>Takeoff Note</th></tr></thead>
            <tbody>
              {results.map((r,i)=>{
                const pb = priceBook.find(p=>p.code===r.priceBookCode)||priceBook.find(p=>p.description.toLowerCase().includes((r.description||"").toLowerCase().slice(0,12)));
                const unitCost = pb?(pb.matCost+pb.labCost):0;
                const total = (r.qty||0)*unitCost;
                const isSel = selected.includes(i);
                return (
                  <tr key={i} onClick={()=>setSelected(p=>p.includes(i)?p.filter(x=>x!==i):[...p,i])} style={{cursor:"pointer",background:isSel?"rgba(74,124,220,.06)":"transparent"}}>
                    <td><div style={{width:14,height:14,borderRadius:3,border:"2px solid "+(isSel?"var(--accent)":"var(--navy-border)"),background:isSel?"var(--accent)":"transparent",margin:"0 auto",display:"flex",alignItems:"center",justifyContent:"center"}}>{isSel&&<span style={{fontSize:9,color:"var(--white)",fontWeight:700}}>v</span>}</div></td>
                    <td className="col-mono" style={{fontSize:11,color:pb?"var(--accent-bright)":"var(--red)"}}>{r.priceBookCode}</td>
                    <td style={{color:"var(--white)"}}>{r.description}{!pb&&<span style={{fontSize:10,color:"var(--red)",marginLeft:6}}>not in PB</span>}</td>
                    <td className="col-mono">{r.qty}</td>
                    <td className="col-mono" style={{fontSize:11}}>{r.unit}</td>
                    <td className="col-mono">${unitCost.toFixed(2)}</td>
                    <td className="col-mono" style={{color:"var(--accent-bright)"}}>{fmt(total)}</td>
                    <td style={{fontSize:10,color:"var(--muted)"}}>{r.notes}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

// --- BID RFI TAB --------------------------------------------------------------
const BidRFIs = ({estimate, onUpdate}) => {
  const [loading, setLoading] = useState(false);
  const [error,   setError]   = useState(null);
  const [newQ,    setNewQ]    = useState("");
  const docs  = estimate.documents||[];
  const bRfis = estimate.bidRfis||[];

  const addManual = () => {
    if(!newQ.trim()) return;
    onUpdate({...estimate,bidRfis:[...bRfis,{id:"brfi"+uid(),question:newQ,status:"Open",answer:"",date:TODAY}]});
    setNewQ("");
  };

  const updateRfi = (id,field,val) => onUpdate({...estimate,bidRfis:bRfis.map(r=>r.id===id?{...r,[field]:val}:r)});
  const deleteRfi = (id) => onUpdate({...estimate,bidRfis:bRfis.filter(r=>r.id!==id)});

  const suggest = () => {
    setLoading(true); setError(null);
    const msgContent = [];
    docs.forEach(doc=>{
      if(doc.base64&&doc.type==="pdf") msgContent.push({type:"document",source:{type:"base64",media_type:"application/pdf",data:doc.base64}});
    });
    msgContent.push({type:"text",text:[
      "You are reviewing bid documents for Westroe Construction, a general contractor in Charlotte NC.",
      "Project: "+estimate.name,
      docs.length>0?"Review the uploaded drawings and specs.":"No documents uploaded - suggest common bid clarification questions for a general contractor.",
      "Estimate lines already included: "+estimate.lines.map(l=>l.description).join(", "),
      "",
      "Identify items that need clarification before submitting a bid. Common issues: scope gaps, spec conflicts, unclear responsibilities, allowance vs. specified items, phasing, existing conditions.",
      "",
      "Return ONLY a JSON array:",
      '[{question, category}]',
      "category: one of Scope, Specifications, Site Conditions, Schedule, Allowances, Coordination",
      "Return 6-12 specific, actionable questions. No markdown.",
    ].join("\n")});
    fetch("https://api.anthropic.com/v1/messages",{
      method:"POST",headers:{"Content-Type":"application/json"},
      body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1500,system:"You are a construction bid coordinator. Return ONLY valid JSON array.",messages:[{role:"user",content:msgContent}]})
    }).then(r=>r.json()).then(data=>{
      if(data.error) throw new Error(data.error.message);
      const raw = data.content.filter(b=>b.type==="text").map(b=>b.text).join("");
      const cleaned = raw.split("```json").join("").split("```").join("").trim();
      const parsed = JSON.parse(cleaned);
      const newRfis = parsed.map(r=>({id:"brfi"+uid(),question:r.question,category:r.category,status:"Open",answer:"",date:TODAY}));
      onUpdate({...estimate,bidRfis:[...bRfis,...newRfis]});
    }).catch(err=>setError("Suggestion failed: "+err.message))
    .finally(()=>setLoading(false));
  };

  const copyAll = () => {
    const text = bRfis.filter(r=>r.status==="Open").map((r,i)=>(i+1)+". "+r.question).join("\n");
    navigator.clipboard.writeText(text);
  };

  const BRFI_STATUS_COLOR = {Open:"var(--yellow)",Submitted:"var(--accent-bright)",Answered:"var(--green)"};

  return (
    <div>
      <div style={{display:"flex",gap:8,marginBottom:14,alignItems:"center",flexWrap:"wrap"}}>
        <button className="btn btn-ai btn-sm" onClick={suggest} disabled={loading}>{loading?"Generating...":"Suggest Bid RFIs"}</button>
        {bRfis.filter(r=>r.status==="Open").length>0&&<button className="btn btn-ghost btn-sm" onClick={copyAll}>Copy Open RFIs</button>}
        <div style={{flex:1}}/>
        <div style={{display:"flex",gap:8,flex:2}}>
          <input className="finput" value={newQ} onChange={e=>setNewQ(e.target.value)} onKeyDown={e=>{if(e.key==="Enter")addManual();}} placeholder="Add a bid clarification question..."/>
          <button className="btn btn-ghost btn-sm" onClick={addManual}>Add</button>
        </div>
      </div>
      {error&&<div style={{fontSize:12,color:"var(--red)",marginBottom:8}}>{error}</div>}
      {loading&&<div style={{display:"flex",alignItems:"center",gap:8,padding:"12px 0"}}><div className="spinner" style={{width:16,height:16,borderWidth:2}}/><span style={{fontSize:12,color:"var(--muted)"}}>Analyzing documents for bid RFIs...</span></div>}
      {bRfis.length===0 ? (
        <div className="empty" style={{padding:32}}>No bid RFIs yet. Click "Suggest Bid RFIs" to have Claude review your documents, or add questions manually.</div>
      ) : bRfis.map((r,i)=>(
        <div key={r.id} style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:6,padding:"11px 14px",marginBottom:8}}>
          <div style={{display:"flex",gap:10,alignItems:"flex-start"}}>
            <span style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:11,color:"var(--muted)",flexShrink:0,marginTop:2}}>{i+1}.</span>
            <div style={{flex:1}}>
              <div style={{display:"flex",gap:8,alignItems:"flex-start",marginBottom:6}}>
                <div style={{fontSize:13,color:"var(--white)",flex:1}}>{r.question}</div>
                {r.category&&<span style={{fontSize:10,fontFamily:"'Barlow Condensed'",letterSpacing:.5,color:"var(--muted)",background:"rgba(138,153,187,.1)",border:"1px solid rgba(138,153,187,.2)",borderRadius:3,padding:"1px 6px",flexShrink:0}}>{r.category}</span>}
              </div>
              {r.status==="Answered"&&r.answer&&(
                <div style={{padding:"8px 10px",background:"rgba(52,211,153,.05)",border:"1px solid rgba(52,211,153,.15)",borderRadius:4,fontSize:12,color:"var(--white)",marginBottom:6}}>
                  <span style={{fontSize:10,color:"var(--green)",fontFamily:"'Barlow Condensed'",letterSpacing:1,marginRight:6}}>ANSWER:</span>{r.answer}
                </div>
              )}
              {r.status==="Answered"&&!r.answer&&(
                <input className="finput" style={{fontSize:12,padding:"4px 8px",marginBottom:6}} placeholder="Enter answer received..." onChange={e=>updateRfi(r.id,"answer",e.target.value)}/>
              )}
            </div>
            <div style={{display:"flex",gap:6,flexShrink:0,alignItems:"center"}}>
              <select className="fselect" style={{fontSize:11,padding:"3px 6px",color:BRFI_STATUS_COLOR[r.status]||"var(--muted)"}} value={r.status} onChange={e=>updateRfi(r.id,"status",e.target.value)}>
                {["Open","Submitted","Answered"].map(s=><option key={s}>{s}</option>)}
              </select>
              <button className="btn btn-ghost btn-sm" style={{fontSize:11,color:"var(--red)"}} onClick={()=>deleteRfi(r.id)}>x</button>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

// --- MATERIAL TAKEOFF FOR SUPPLIER PRICING ------------------------------------
const MaterialTakeoff = ({estimate, priceBook}) => {
  const [selLines,  setSelLines]  = useState([]);
  const [loading,   setLoading]   = useState(false);
  const [error,     setError]     = useState(null);
  const [matList,   setMatList]   = useState(null);
  const [copied,    setCopied]    = useState(false);

  const toggle = (id) => setSelLines(p=>p.includes(id)?p.filter(x=>x!==id):[...p,id]);
  const toggleAll = () => setSelLines(p=>p.length===estimate.lines.length?[]:estimate.lines.map(l=>l.id));

  const generate = () => {
    setLoading(true); setError(null); setMatList(null);
    const selectedItems = estimate.lines.filter(l=>selLines.includes(l.id));
    const itemDesc = selectedItems.map(l=>{
      const pb = priceBook.find(p=>p.id===l.priceBookId);
      return (pb?pb.code+" - ":"")+l.description+" | Qty: "+l.qty+" "+l.unit+(l.notes?" ("+l.notes+")":"");
    }).join("\n");
    const prompt = [
      "You are preparing a material takeoff list for Westroe Construction to send to suppliers for pricing.",
      "Project: "+estimate.name,
      "",
      "ESTIMATE LINE ITEMS TO BREAK OUT:",
      itemDesc,
      "",
      "For each line item, expand into the individual materials needed to order from a supplier.",
      "Be specific with dimensions, grades, and quantities.",
      "Group by material type/supplier category.",
      "Format as a clean, professional list that can be copied and sent directly to a supplier.",
      "",
      "Return as formatted text (not JSON) - use clear headings and bullet points.",
      "Include: item description, quantity needed, unit, and any spec notes.",
      "Add a note at the bottom: 'Please provide pricing for the above materials for '+"+JSON.stringify(estimate.name)+"+'.'",
    ].join("\n");
    fetch("https://api.anthropic.com/v1/messages",{
      method:"POST",headers:{"Content-Type":"application/json"},
      body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:2000,system:"You are a construction materials coordinator for Westroe Construction (GC License #105268), Charlotte NC. Begin every RFQ: WESTROE CONSTRUCTION | GC License #105268 | Charlotte, NC | 704-962-6507 | MATERIAL REQUEST FOR QUOTATION | ==============================.",messages:[{role:"user",content:prompt}]})
    }).then(r=>r.json()).then(data=>{
      if(data.error) throw new Error(data.error.message);
      const text = data.content.filter(b=>b.type==="text").map(b=>b.text).join("");
      setMatList(text);
    }).catch(err=>setError("Generation failed: "+err.message))
    .finally(()=>setLoading(false));
  };

  const copyList = () => {
    if(!matList) return;
    navigator.clipboard.writeText(matList);
    setCopied(true);
    setTimeout(()=>setCopied(false),2000);
  };

  return (
    <div>
      <div style={{fontSize:13,color:"var(--muted)",marginBottom:12}}>
        Select estimate line items to expand into a material list for supplier pricing. Claude will break each line into individual materials with quantities ready to send as an RFQ.
      </div>
      <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,marginBottom:14,overflow:"hidden"}}>
        <div style={{padding:"9px 14px",borderBottom:"1px solid var(--navy-border)",display:"flex",alignItems:"center",gap:10}}>
          <label style={{display:"flex",alignItems:"center",gap:6,cursor:"pointer",fontSize:12,color:"var(--muted)"}}>
            <input type="checkbox" checked={selLines.length===estimate.lines.length&&estimate.lines.length>0} onChange={toggleAll} style={{accentColor:"var(--accent)"}}/>
            Select All ({estimate.lines.length} lines)
          </label>
          <div style={{marginLeft:"auto",fontSize:12,color:"var(--muted)"}}>{selLines.length} selected</div>
        </div>
        {estimate.lines.map(line=>{
          const pb = priceBook.find(p=>p.id===line.priceBookId);
          const isSel = selLines.includes(line.id);
          return (
            <div key={line.id} onClick={()=>toggle(line.id)} style={{display:"flex",alignItems:"center",gap:12,padding:"9px 14px",borderBottom:"1px solid rgba(42,64,128,.2)",cursor:"pointer",background:isSel?"rgba(74,124,220,.06)":"transparent"}}>
              <div style={{width:14,height:14,borderRadius:3,border:"2px solid "+(isSel?"var(--accent)":"var(--navy-border)"),background:isSel?"var(--accent)":"transparent",flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center"}}>
                {isSel&&<span style={{fontSize:9,color:"var(--white)",fontWeight:700}}>v</span>}
              </div>
              {pb&&<span style={{fontSize:11,fontFamily:"'IBM Plex Mono',monospace",color:"var(--muted)",width:60,flexShrink:0}}>{pb.code}</span>}
              <span style={{fontSize:13,color:"var(--white)",flex:1}}>{line.description}</span>
              <span style={{fontSize:12,fontFamily:"'IBM Plex Mono',monospace",color:"var(--muted)",flexShrink:0}}>{line.qty} {line.unit}</span>
            </div>
          );
        })}
      </div>
      <div style={{display:"flex",gap:8,marginBottom:14}}>
        <button className="btn btn-ai" onClick={generate} disabled={loading||!selLines.length}>{loading?"Generating...":"Generate Material List"}</button>
        {loading&&<div className="spinner" style={{width:18,height:18,borderWidth:2}}/>}
      </div>
      {error&&<div style={{fontSize:12,color:"var(--red)",marginBottom:8}}>{error}</div>}
      {matList && (
        <div>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
            <div style={{fontSize:12,color:"var(--green)"}}>Material list ready - review and copy to send to suppliers</div>
            <button className="btn btn-primary btn-sm" onClick={copyList}>{copied?"Copied!":"Copy List"}</button>
          </div>
          <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:16,fontSize:13,color:"var(--white)",lineHeight:1.8,whiteSpace:"pre-wrap",maxHeight:500,overflowY:"auto",fontFamily:"'IBM Plex Mono',monospace"}}>
            {matList}
          </div>
        </div>
      )}
    </div>
  );
};

// --- SCOPE OF WORK TAB -------------------------------------------------------
const ScopeOfWork = ({estimate, priceBook, opportunity, onUpdate}) => {
  const [selTrade,   setSelTrade]   = useState("");
  const [bidScope,   setBidScope]   = useState("");
  const [subExhibit, setSubExhibit] = useState("");
  const [bidLoading, setBidLoad]    = useState(false);
  const [subLoading, setSubLoad]    = useState(false);
  const [bidErr,     setBidErr]     = useState(null);
  const [subErr,     setSubErr]     = useState(null);
  const [bidCopied,  setBidCopied]  = useState(false);
  const [subCopied,  setSubCopied]  = useState(false);
  const docs = estimate.documents||[];

  // Group estimate lines by price book category
  const tradeGroups = {};
  estimate.lines.forEach(line=>{
    const pb = priceBook.find(p=>p.id===line.priceBookId);
    const cat = pb?pb.category:"Other";
    if(!tradeGroups[cat]) tradeGroups[cat]=[];
    tradeGroups[cat].push(line);
  });
  const trades = Object.keys(tradeGroups).sort();

  const tradeLines = selTrade ? (tradeGroups[selTrade]||[]) : [];
  const tradeSummary = tradeLines.map(l=>{
    const pb = priceBook.find(p=>p.id===l.priceBookId);
    return (pb?pb.code+" - ":"")+l.description+" | "+l.qty+" "+l.unit+(l.notes?" ("+l.notes+")":"");
  }).join("\n");

  const buildMsgContent = (prompt) => {
    const content = [];
    docs.forEach(doc=>{
      if(doc.base64&&doc.type==="pdf") content.push({type:"document",source:{type:"base64",media_type:"application/pdf",data:doc.base64}});
    });
    content.push({type:"text",text:prompt});
    return content;
  };

  const draftBidScope = () => {
    if(!selTrade) return;
    setBidLoad(true); setBidErr(null);
    const prompt = [
      "Draft a Scope of Work for subcontractor bidding for Westroe Construction.",
      "GC: Westroe Construction | GC License #105268 | Charlotte, NC | 704-962-6507",
      "Project: "+estimate.name,
      "Client: "+(opportunity?opportunity.client:""),
      "Trade: "+selTrade,
      "",
      "ESTIMATE LINE ITEMS FOR THIS TRADE:",
      tradeSummary,
      "",
      docs.length>0?"The drawings and specifications are attached above. Reference specific drawing sheets and spec sections where applicable.":"No drawings uploaded.",
      "",
      "Draft a concise bid scope of work document for the "+selTrade+" subcontractor.",
      "Format:",
      "1. PROJECT OVERVIEW - brief project description",
      "2. SCOPE OF WORK - detailed list of what is included",
      "3. SPECIFICALLY EXCLUDED - what is NOT included (to avoid pricing ambiguity)",
      "4. COORDINATION REQUIREMENTS - what the sub must coordinate with other trades",
      "5. DRAWINGS & SPECIFICATIONS - relevant references",
      "6. BIDDING REQUIREMENTS - what Westroe needs in the bid (bond, insurance, schedule, sub breakdown)",
      "",
      "Keep language clear and direct - this goes to multiple bidders.",
      "Use bullet points throughout. Be specific.",
    ].join("\n");

    fetch("https://api.anthropic.com/v1/messages",{
      method:"POST",headers:{"Content-Type":"application/json"},
      body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:3000,system:"You are a construction project manager at Westroe Construction (GC License #105268) drafting bid scopes. Begin every document: WESTROE CONSTRUCTION | GC License #105268 | Charlotte, NC | 704-962-6507 | BID SCOPE OF WORK | ==============================. Be specific, clear, and professional.",messages:[{role:"user",content:buildMsgContent(prompt)}]})
    }).then(r=>r.json()).then(data=>{
      if(data.error) throw new Error(data.error.message);
      const text = data.content.filter(b=>b.type==="text").map(b=>b.text).join("");
      setBidScope(text);
    }).catch(err=>setBidErr("Draft failed: "+err.message))
    .finally(()=>setBidLoad(false));
  };

  const draftSubExhibit = () => {
    if(!selTrade) return;
    setSubLoad(true); setSubErr(null);
    const prompt = [
      "Draft a formal Subcontract Exhibit A - Scope of Work for Westroe Construction.",
      "This will be attached to an executed subcontract agreement as a legally binding exhibit.",
      "",
      "GC: Westroe Construction | GC License #105268 | Charlotte, NC | 704-962-6507",
      "Project: "+estimate.name,
      "Client: "+(opportunity?opportunity.client:""),
      "Trade: "+selTrade,
      "",
      "CONTRACTED LINE ITEMS:",
      tradeSummary,
      "",
      docs.length>0?"The project drawings and specifications are attached. Reference specific drawing numbers, sheet numbers, and spec section numbers throughout.":"No drawings uploaded - use general references.",
      "",
      "Draft a formal Subcontract Exhibit A for the "+selTrade+" subcontractor.",
      "Format as a formal legal exhibit with:",
      "",
      "EXHIBIT A - SCOPE OF WORK",
      "Project / Subcontractor header block",
      "",
      "1. GENERAL SCOPE - comprehensive description of all work included",
      "2. SPECIFIC INCLUSIONS - detailed list with drawing/spec references",
      "3. SPECIFIC EXCLUSIONS - what is expressly excluded from this subcontract",
      "4. PERFORMANCE STANDARDS - quality, workmanship, and code compliance requirements",
      "5. COORDINATION OBLIGATIONS - coordination with GC and other trades",
      "6. SCHEDULE REQUIREMENTS - sequencing and milestone obligations",
      "7. SUBMITTALS REQUIRED - shop drawings, product data, samples required prior to work",
      "8. WARRANTIES - warranty period and obligations",
      "",
      "Use formal contract language throughout. Be comprehensive - this is the document that governs the sub's performance.",
      "Reference GC License #105268 and OSHA compliance requirements.",
    ].join("\n");

    fetch("https://api.anthropic.com/v1/messages",{
      method:"POST",headers:{"Content-Type":"application/json"},
      body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:4000,system:"You are a construction attorney and project manager drafting formal subcontract scope of work exhibits for Westroe Construction (GC License #105268), Charlotte NC. Use formal, comprehensive legal language appropriate for an executed subcontract exhibit.",messages:[{role:"user",content:buildMsgContent(prompt)}]})
    }).then(r=>r.json()).then(data=>{
      if(data.error) throw new Error(data.error.message);
      const text = data.content.filter(b=>b.type==="text").map(b=>b.text).join("");
      setSubExhibit(text);
      if(onUpdate) onUpdate({...estimate, scopes:{...(estimate.scopes||{}),[selTrade]:text}});
    }).catch(err=>setSubErr("Draft failed: "+err.message))
    .finally(()=>setSubLoad(false));
  };

  const copyBid = () => { navigator.clipboard.writeText(bidScope); setBidCopied(true); setTimeout(()=>setBidCopied(false),2000); };
  const copySub = () => { navigator.clipboard.writeText(subExhibit); setSubCopied(true); setTimeout(()=>setSubCopied(false),2000); };

  return (
    <div>
      {/* Trade selector */}
      <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14,marginBottom:16}}>
        <div className="flabel" style={{marginBottom:8}}>Select Trade to Scope</div>
        <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
          {trades.map(t=>(
            <button key={t} className={"btn "+(selTrade===t?"btn-primary":"btn-ghost")+" btn-sm"} onClick={()=>{setSelTrade(t);setBidScope("");const existing=(estimate.scopes||{})[t]||"";setSubExhibit(existing);}}>
              {t}
              <span style={{fontSize:10,color:selTrade===t?"rgba(255,255,255,.6)":"var(--muted)",marginLeft:4}}>({(tradeGroups[t]||[]).length})</span>
            </button>
          ))}
        </div>
        {!trades.length && <div style={{fontSize:12,color:"var(--muted)"}}>Add estimate lines first - trades are derived from your price book categories.</div>}
        {selTrade && (
          <div style={{marginTop:10,padding:"8px 12px",background:"rgba(74,124,220,.06)",border:"1px solid rgba(74,124,220,.15)",borderRadius:6}}>
            <div style={{fontSize:11,color:"var(--muted)",marginBottom:4}}>{tradeLines.length} line item{tradeLines.length!==1?"s":""} in scope</div>
            {tradeLines.map(l=><div key={l.id} style={{fontSize:12,color:"var(--white)"}}> {l.description} - {l.qty} {l.unit}</div>)}
          </div>
        )}
      </div>

      {/* Two-column layout: Bid Scope + Sub Exhibit */}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>

        {/* BID SCOPE */}
        <div>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8}}>
            <div>
              <div style={{fontFamily:"'Barlow Condensed'",fontSize:14,fontWeight:700,color:"var(--white)"}}>Bid Scope of Work</div>
              <div style={{fontSize:11,color:"var(--muted)"}}>Sent to subs when soliciting bids</div>
            </div>
            <div style={{display:"flex",gap:6}}>
              {bidScope&&<button className="btn btn-ghost btn-sm" onClick={copyBid} style={{fontSize:11}}>{bidCopied?"Copied!":"Copy"}</button>}
              <button className="btn btn-ai btn-sm" onClick={draftBidScope} disabled={!selTrade||bidLoading}>
                {bidLoading?"Drafting...":"Draft"}
              </button>
            </div>
          </div>
          {bidErr&&<div style={{fontSize:12,color:"var(--red)",marginBottom:6}}>{bidErr}</div>}
          {bidLoading&&<div style={{display:"flex",alignItems:"center",gap:8,padding:"16px 0"}}><div className="spinner" style={{width:16,height:16,borderWidth:2}}/><span style={{fontSize:12,color:"var(--muted)"}}>Drafting bid scope...</span></div>}
          {!bidScope&&!bidLoading&&(
            <div style={{border:"2px dashed var(--navy-border)",borderRadius:8,padding:24,textAlign:"center"}}>
              <div style={{fontSize:12,color:"var(--muted)"}}>{selTrade?"Click Draft to generate the bid scope for "+selTrade:"Select a trade above"}</div>
            </div>
          )}
          {bidScope&&(
            <textarea value={bidScope} onChange={e=>setBidScope(e.target.value)} style={{width:"100%",minHeight:500,background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14,fontSize:12,color:"var(--white)",lineHeight:1.7,resize:"vertical",boxSizing:"border-box"}}/>
          )}
        </div>

        {/* SUBCONTRACT EXHIBIT */}
        <div>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8}}>
            <div>
              <div style={{fontFamily:"'Barlow Condensed'",fontSize:14,fontWeight:700,color:"var(--white)"}}>Exhibit A - Subcontract Scope</div>
              <div style={{fontSize:11,color:"var(--muted)"}}>Attached to the executed subcontract</div>
            </div>
            <div style={{display:"flex",gap:6}}>
              {subExhibit&&<button className="btn btn-ghost btn-sm" onClick={copySub} style={{fontSize:11}}>{subCopied?"Copied!":"Copy"}</button>}
              <button className="btn btn-ai btn-sm" onClick={draftSubExhibit} disabled={!selTrade||subLoading}>
                {subLoading?"Drafting...":"Draft"}
              </button>
            </div>
          </div>
          {subErr&&<div style={{fontSize:12,color:"var(--red)",marginBottom:6}}>{subErr}</div>}
          {subLoading&&<div style={{display:"flex",alignItems:"center",gap:8,padding:"16px 0"}}><div className="spinner" style={{width:16,height:16,borderWidth:2}}/><span style={{fontSize:12,color:"var(--muted)"}}>Drafting subcontract exhibit...</span></div>}
          {!subExhibit&&!subLoading&&(
            <div style={{border:"2px dashed var(--navy-border)",borderRadius:8,padding:24,textAlign:"center"}}>
              <div style={{fontSize:12,color:"var(--muted)"}}>{selTrade?"Click Draft to generate Exhibit A for "+selTrade:"Select a trade above"}</div>
            </div>
          )}
          {subExhibit&&(
            <textarea value={subExhibit} onChange={e=>setSubExhibit(e.target.value)} style={{width:"100%",minHeight:500,background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14,fontSize:12,color:"var(--white)",lineHeight:1.7,resize:"vertical",boxSizing:"border-box"}}/>
          )}
        </div>
      </div>

      {(bidScope||subExhibit)&&(
        <div style={{marginTop:12,padding:"10px 14px",background:"rgba(167,139,250,.06)",border:"1px solid rgba(167,139,250,.2)",borderRadius:6,fontSize:12,color:"var(--muted)"}}>
          <span style={{color:"var(--purple)"}}>Tip: </span>
          Copy the bid scope to send to bidders. Once you award the sub and execute a subcontract, copy the Exhibit A - you can paste it directly into the Subcontracts tab on the job.
        </div>
      )}
    </div>
  );
};

// --- ESTIMATE BUILDER ---------------------------------------------------------
const EstimateBuilder = ({estimate, priceBook, opportunity, onUpdate, onClose}) => {
  const [search,    setSearch]    = useState("");
  const [showSrch,  setShowSrch]  = useState(false);
  const [aiLoad,    setAiLoad]    = useState(false);
  const [aiErr,     setAiErr]     = useState(null);
  const totals = calcEstTotals(estimate);

  const searchResults = search.length>1
    ? priceBook.filter(pb=>pb.description.toLowerCase().includes(search.toLowerCase())||pb.code.toLowerCase().includes(search.toLowerCase())).slice(0,8)
    : [];

  const addFromPB = (pb) => {
    const newLine = {id:"el"+uid(),priceBookId:pb.id,description:pb.description,qty:1,unit:pb.unit,matUnit:pb.matCost,labUnit:pb.labCost,override:false,notes:"",selfPerform:pb.selfPerform||false,laborCostCode:pb.laborCostCode||"cc30",matCostCode:pb.matCostCode||"cc32"};
    onUpdate({...estimate,lines:[...estimate.lines,newLine]});
    setSearch(""); setShowSrch(false);
  };

  const addFreeform = () => {
    onUpdate({...estimate,lines:[...estimate.lines,{id:"el"+uid(),priceBookId:null,description:"",qty:1,unit:"EA",matUnit:0,labUnit:0,override:true,notes:"",selfPerform:false,laborCostCode:"cc30",matCostCode:"cc32"}]});
  };

  const updateLine = (id, field, value) => {
    onUpdate({...estimate,lines:estimate.lines.map(l=>l.id===id?{...l,[field]:value,override:true}:l)});
  };

  const deleteLine = (id) => onUpdate({...estimate,lines:estimate.lines.filter(l=>l.id!==id)});

  const suggestLines = () => {
    if(!opportunity) return;
    setAiLoad(true); setAiErr(null);
    const pbSample = priceBook.slice(0,40).map(p=>p.code+" | "+p.description+" | "+p.unit+" | $"+((p.matCost+p.labCost).toFixed(2))+"/"+p.unit).join("\n");
    const prompt = [
      "You are a construction estimator for Westroe Construction in Charlotte NC.",
      "Project: "+opportunity.name+" - "+opportunity.projType,
      "Client: "+opportunity.client,
      "Estimated value: $"+opportunity.estValue.toLocaleString(),
      "",
      "Based on this project type, suggest estimate line items using items from this price book sample:",
      pbSample,
      "",
      "Return ONLY a JSON array of suggested lines:",
      '[{description, qty, unit, notes}]',
      "description: must match a price book description exactly if possible",
      "qty: realistic quantity estimate",
      "unit: matching price book unit",
      "notes: brief scope assumption",
      "Return 8-15 items. No markdown.",
    ].join("\n");
    fetch("https://api.anthropic.com/v1/messages",{
      method:"POST",headers:{"Content-Type":"application/json"},
      body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1500,system:"You are a construction estimator. Return ONLY valid JSON array.",messages:[{role:"user",content:prompt}]})
    }).then(r=>r.json()).then(data=>{
      if(data.error) throw new Error(data.error.message);
      const raw = data.content.filter(b=>b.type==="text").map(b=>b.text).join("");
      const cleaned = raw.split("```json").join("").split("```").join("").trim();
      const suggestions = JSON.parse(cleaned);
      const newLines = suggestions.map(s=>{
        const match = priceBook.find(pb=>pb.description.toLowerCase()===s.description.toLowerCase())||priceBook.find(pb=>pb.description.toLowerCase().includes(s.description.toLowerCase().slice(0,15)));
        return {id:"el"+uid(),priceBookId:match?match.id:null,description:s.description,qty:s.qty||1,unit:s.unit||"EA",matUnit:match?match.matCost:0,labUnit:match?match.labCost:0,override:!match,notes:s.notes||"",selfPerform:match?!!match.selfPerform:false,laborCostCode:match?match.laborCostCode||"cc30":"cc30",matCostCode:match?match.matCostCode||"cc32":"cc32"};
      });
      onUpdate({...estimate,lines:[...estimate.lines,...newLines]});
    }).catch(err=>setAiErr("Suggestion failed: "+err.message))
    .finally(()=>setAiLoad(false));
  };

  const grouped = [...new Set(estimate.lines.map(l=>priceBook.find(pb=>pb.id===l.priceBookId)?.category||"Freeform"))];

  const [estTab, setEstTab] = useState("lines");

  return (
    <div>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}>
        <div>
          <div style={{fontFamily:"'Barlow Condensed'",fontSize:18,fontWeight:700,color:"var(--white)"}}>{estimate.name}</div>
          <div style={{fontSize:12,color:"var(--muted)"}}>v{estimate.version}   Created {fmtDate(estimate.createdDate)}</div>
        </div>
        <button className="btn btn-ghost btn-sm" onClick={onClose}>x</button>
      </div>

      {/* Tabs */}
      <div className="drw-tabs" style={{marginBottom:0}}>
        {[["lines","Estimate Lines"],["docs","Documents"],["takeoff","AI Takeoff"],["bidrfis","Bid RFIs"],["matlist","Material Lists"],["scopes","Scope of Work"]].map(([k,l])=>(
          <button key={k} className={"drw-tab"+(estTab===k?" active":"")} onClick={()=>setEstTab(k)}>{l}</button>
        ))}
      </div>

      {estTab==="lines" && (
      <div>
      {/* Summary cards */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:8,marginBottom:14}}>
        {[
          {label:"Direct Cost",  val:fmt(totals.dirCost),  color:"var(--white)"},
          {label:"Overhead "+estimate.overheadPct+"%", val:fmt(totals.overhead), color:"var(--muted)"},
          {label:"Bid Total",    val:fmt(totals.bidTotal), color:"var(--accent-bright)"},
          {label:"Gross Profit", val:fmt(totals.profit),   color:"var(--green)"},
          {label:"Margin",       val:totals.marginPct.toFixed(1)+"%", color:totals.marginPct>=20?"var(--green)":totals.marginPct>=15?"var(--yellow)":"var(--red)"},
        ].map(s=><div key={s.label} className="stat-card"><div className="stat-label">{s.label}</div><div className="stat-value" style={{fontSize:14,color:s.color}}>{s.val}</div></div>)}
      </div>

      {/* Markup controls */}
      <div style={{display:"flex",gap:10,marginBottom:14,alignItems:"flex-end",background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:12}}>
        <div><div className="flabel">Overhead %</div><input className="finput" type="number" value={estimate.overheadPct} onChange={e=>onUpdate({...estimate,overheadPct:parseFloat(e.target.value)||0})} style={{width:80}}/></div>
        <div><div className="flabel">Profit %</div><input className="finput" type="number" value={estimate.profitPct} onChange={e=>onUpdate({...estimate,profitPct:parseFloat(e.target.value)||0})} style={{width:80}}/></div>
        <div style={{flex:1}}><div className="flabel">Notes / Assumptions</div><input className="finput" value={estimate.notes||""} onChange={e=>onUpdate({...estimate,notes:e.target.value})} placeholder="Key assumptions, allowances, exclusions..."/></div>
      </div>

      {/* Add line controls */}
      <div style={{display:"flex",gap:8,marginBottom:10,alignItems:"center",position:"relative"}}>
        <div style={{flex:1,position:"relative"}}>
          <input className="finput" value={search} onChange={e=>{setSearch(e.target.value);setShowSrch(true);}} onFocus={()=>setShowSrch(true)} placeholder="Search price book to add a line item..."/>
          {showSrch && searchResults.length>0 && (
            <div style={{position:"absolute",top:"100%",left:0,right:0,background:"var(--navy-dark)",border:"1px solid var(--navy-border)",borderRadius:6,zIndex:10,maxHeight:240,overflowY:"auto"}}>
              {searchResults.map(pb=>(
                <div key={pb.id} onClick={()=>addFromPB(pb)} style={{padding:"8px 12px",cursor:"pointer",borderBottom:"1px solid rgba(42,64,128,.2)",display:"flex",gap:10,alignItems:"center"}}>
                  <div style={{flex:1}}>
                    <div style={{fontSize:12,color:"var(--white)"}}>{pb.description}</div>
                    <div style={{fontSize:10,color:"var(--muted)"}}>{pb.category}   {pb.unit}</div>
                  </div>
                  <div style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:12,color:"var(--accent-bright)",flexShrink:0}}>${(pb.matCost+pb.labCost).toFixed(2)}/{pb.unit}</div>
                </div>
              ))}
            </div>
          )}
        </div>
        <button className="btn btn-ghost btn-sm" onClick={addFreeform}>+ Freeform Line</button>
        <button className="btn btn-ai btn-sm" onClick={suggestLines} disabled={aiLoad}>{aiLoad?"Thinking...":"Suggest Lines"}</button>
      </div>
      {aiErr&&<div style={{fontSize:12,color:"var(--red)",marginBottom:8}}>{aiErr}</div>}
      {/* Line items */}
      <table className="tbl" style={{tableLayout:"fixed"}}>
        <thead><tr><th>Description</th><th style={{width:60}}>Qty</th><th style={{width:55}}>Unit</th><th style={{width:90}}>$/Unit</th><th style={{width:40}}>SP</th><th style={{width:90}}>Total</th><th style={{width:30}}></th></tr></thead>
        <tbody>
          {estimate.lines.map(line=>{
            const lc = calcEstLine(line);
            const pb = priceBook.find(p=>p.id===line.priceBookId);
            return (
              <tr key={line.id}>
                <td>
                  <input className="finput" style={{fontSize:12,padding:"3px 8px"}} value={line.description} onChange={e=>updateLine(line.id,"description",e.target.value)}/>
                  <div style={{display:"flex",gap:6,paddingLeft:8,marginTop:2}}>
                    {pb&&!line.override&&<span style={{fontSize:10,color:"var(--muted)"}}>{pb.code}</span>}
                    {line.selfPerform&&<span style={{fontSize:9,color:"var(--accent-bright)",fontFamily:"'Barlow Condensed'",letterSpacing:1,background:"rgba(74,124,220,.1)",border:"1px solid rgba(74,124,220,.2)",borderRadius:2,padding:"0 4px"}}>SELF-PERFORM</span>}
                  </div>
                  {line.notes&&<div style={{fontSize:10,color:"var(--muted)",paddingLeft:8}}>{line.notes}</div>}
                </td>
                <td><input type="number" min="0" step="0.5" value={line.qty} onChange={e=>updateLine(line.id,"qty",parseFloat(e.target.value)||0)} style={{width:"100%",background:"transparent",border:"1px solid var(--navy-border)",borderRadius:4,color:"var(--white)",padding:"3px 5px",fontSize:12,fontFamily:"'IBM Plex Mono',monospace"}}/></td>
                <td><select className="fselect" style={{fontSize:11,padding:"3px 4px"}} value={line.unit} onChange={e=>updateLine(line.id,"unit",e.target.value)}>{PC_UNITS.map(u=><option key={u}>{u}</option>)}</select></td>
                <td>
                  <div style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:12,color:"var(--accent-bright)",padding:"3px 5px",fontWeight:600}}>${((line.matUnit||0)+(line.labUnit||0)).toFixed(2)}</div>
                  <div style={{fontSize:9,color:"var(--muted)",paddingLeft:5}}>mat ${(line.matUnit||0).toFixed(2)} + lab ${(line.labUnit||0).toFixed(2)}</div>
                </td>
                <td>
                  <label style={{display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",gap:2}}>
                    <input type="checkbox" checked={!!line.selfPerform} onChange={e=>updateLine(line.id,"selfPerform",e.target.checked)} style={{accentColor:"var(--accent)"}}/>
                    <span style={{fontSize:9,color:line.selfPerform?"var(--accent-bright)":"var(--muted)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>SP</span>
                  </label>
                </td>
                <td className="col-mono" style={{color:"var(--accent-bright)",fontWeight:600}}>{fmt(lc.total)}</td>
                <td><button className="btn btn-ghost btn-sm" style={{fontSize:11,color:"var(--red)"}} onClick={()=>deleteLine(line.id)}>x</button></td>
              </tr>
            );
          })}
        </tbody>
        <tfoot>
          <tr style={{borderTop:"2px solid var(--navy-border)"}}>
            <td colSpan="5" style={{padding:"8px 10px",fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:1,color:"var(--muted)"}}>
              DIRECT COST
              <span style={{marginLeft:10,color:"var(--muted)",fontWeight:400}}>mat {fmt(totals.dirMat)} + lab {fmt(totals.dirLab)}</span>
              <span style={{marginLeft:10,color:"var(--accent-bright)",fontSize:10}}>{estimate.lines.filter(l=>l.selfPerform).length} self-perform lines split on budget</span>
            </td>
            <td className="col-mono" style={{fontWeight:700,color:"var(--white)"}}>{fmt(totals.dirCost)}</td>
            <td></td>
          </tr>
          <tr>
            <td colSpan="5" style={{padding:"4px 10px",fontSize:11,color:"var(--muted)"}}>Overhead {estimate.overheadPct}%</td>
            <td className="col-mono" style={{color:"var(--muted)"}}>{fmt(totals.overhead)}</td><td></td>
          </tr>
          <tr>
            <td colSpan="5" style={{padding:"4px 10px",fontSize:11,color:"var(--muted)"}}>Profit {estimate.profitPct}% on subtotal</td>
            <td className="col-mono" style={{color:"var(--green)"}}>{fmt(totals.profit)}</td><td></td>
          </tr>
          <tr style={{background:"rgba(74,124,220,.06)"}}>
            <td colSpan="5" style={{padding:"10px",fontFamily:"'Barlow Condensed'",fontSize:13,letterSpacing:1,color:"var(--accent-bright)",fontWeight:700}}>BID TOTAL</td>
            <td className="col-mono" style={{fontSize:16,fontWeight:700,color:"var(--accent-bright)"}}>{fmt(totals.bidTotal)}</td><td></td>
          </tr>
        </tfoot>
      </table>
    </div>
      )}

      {estTab==="docs"&&<EstimateDocuments estimate={estimate} onUpdate={onUpdate}/>}
      {estTab==="takeoff"&&<AITakeoff estimate={estimate} priceBook={priceBook} onUpdate={onUpdate}/>}
      {estTab==="bidrfis"&&<BidRFIs estimate={estimate} onUpdate={onUpdate}/>}
      {estTab==="matlist"&&<MaterialTakeoff estimate={estimate} priceBook={priceBook}/>}
      {estTab==="scopes"&&<ScopeOfWork estimate={estimate} priceBook={priceBook} opportunity={opportunity} onUpdate={onUpdate}/>}
    </div>
  );
};

// --- OPPORTUNITIES LIST -------------------------------------------------------
const OpportunityList = ({opportunities, estimates, priceBook, onUpdateOpp, onAddOpp, onAddEst, onUpdateEst, onConvertToJob, jobs}) => {
  const [showAdd,   setShowAdd]  = useState(false);
  const [selEst,    setSelEst]   = useState(null);
  const [f, setF] = useState({name:"",client:"",projType:PC_PROJ_TYPES[0],stage:"Lead",estValue:"",probability:50,decisionDate:"",notes:""});
  const set = (k,v) => setF(p=>({...p,[k]:v}));

  const pipeline = PC_STAGES.filter(s=>!["Won","Lost"].includes(s)).map(stage=>({
    stage,
    opps:opportunities.filter(o=>o.stage===stage),
    total:opportunities.filter(o=>o.stage===stage).reduce((s,o)=>s+(o.estValue||0),0),
    weighted:opportunities.filter(o=>o.stage===stage).reduce((s,o)=>s+(o.estValue||0)*(o.probability||0)/100,0),
  }));
  const totalPipeline = pipeline.reduce((s,p)=>s+p.weighted,0);

  const createEstimate = (opp) => {
    const newEst = {id:"est"+uid(),opportunityId:opp.id,name:opp.name,version:1,createdDate:TODAY,lines:[],overheadPct:8,profitPct:14,notes:"",aiSuggestions:null};
    onAddEst(newEst);
    onUpdateOpp({...opp,estimateId:newEst.id});
    setSelEst(newEst.id);
  };

  const openEst = (estId) => setSelEst(estId);

  const convertToJob = (opp) => {
    const est = estimates.find(e=>e.id===opp.estimateId);
    const totals = est ? calcEstTotals(est) : null;
    onConvertToJob(opp, est, totals);
    onUpdateOpp({...opp,stage:"Won"});
  };

  if(selEst) {
    const est = estimates.find(e=>e.id===selEst);
    const opp = opportunities.find(o=>o.estimateId===selEst);
    if(!est) { setSelEst(null); return null; }
    return (
      <EstimateBuilder estimate={est} priceBook={priceBook} opportunity={opp} onUpdate={onUpdateEst} onClose={()=>setSelEst(null)}/>
    );
  }

  return (
    <div>
      {/* Pipeline summary */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:8,marginBottom:16}}>
        <div className="stat-card"><div className="stat-label">Weighted Pipeline</div><div className="stat-value" style={{fontSize:14,color:"var(--accent-bright)"}}>{fmt(totalPipeline)}</div></div>
        {pipeline.map(p=>(
          <div key={p.stage} className="stat-card">
            <div className="stat-label">{p.stage}</div>
            <div style={{fontFamily:"'Barlow Condensed'",fontSize:16,fontWeight:700,color:PC_STAGE_COLOR[p.stage]||"var(--white)"}}>{p.opps.length}</div>
            <div className="stat-sub">{fmt(p.total)}</div>
          </div>
        ))}
      </div>

      <div style={{display:"flex",justifyContent:"flex-end",marginBottom:12}}>
        <button className="btn btn-primary btn-sm" onClick={()=>setShowAdd(!showAdd)}>+ New Opportunity</button>
      </div>

      {showAdd && (
        <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14,marginBottom:14,display:"flex",flexDirection:"column",gap:10}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
            <div><div className="flabel">Project Name</div><input className="finput" value={f.name} onChange={e=>set("name",e.target.value)} placeholder="Project name..."/></div>
            <div><div className="flabel">Client</div><input className="finput" value={f.client} onChange={e=>set("client",e.target.value)} placeholder="Client name..."/></div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 120px 80px 120px",gap:10}}>
            <div><div className="flabel">Project Type</div><select className="fselect" value={f.projType} onChange={e=>set("projType",e.target.value)}>{PC_PROJ_TYPES.map(t=><option key={t}>{t}</option>)}</select></div>
            <div><div className="flabel">Stage</div><select className="fselect" value={f.stage} onChange={e=>set("stage",e.target.value)}>{PC_STAGES.filter(s=>s!=="Won"&&s!=="Lost").map(s=><option key={s}>{s}</option>)}</select></div>
            <div><div className="flabel">Prob %</div><input className="finput" type="number" value={f.probability} onChange={e=>set("probability",parseInt(e.target.value)||0)}/></div>
            <div><div className="flabel">Decision Date</div><input className="finput" type="date" value={f.decisionDate} onChange={e=>set("decisionDate",e.target.value)}/></div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"150px 1fr",gap:10}}>
            <div><div className="flabel">Est Value</div><input className="finput" type="number" value={f.estValue} onChange={e=>set("estValue",e.target.value)} placeholder="0"/></div>
            <div><div className="flabel">Notes</div><input className="finput" value={f.notes} onChange={e=>set("notes",e.target.value)} placeholder="Source, key requirements..."/></div>
          </div>
          <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
            <button className="btn btn-ghost btn-sm" onClick={()=>setShowAdd(false)}>Cancel</button>
            <button className="btn btn-primary btn-sm" onClick={()=>{
              if(!f.name.trim()) return;
              onAddOpp({...f,id:"op"+uid(),estValue:parseFloat(f.estValue)||0,estimateId:null});
              setShowAdd(false);
              setF({name:"",client:"",projType:PC_PROJ_TYPES[0],stage:"Lead",estValue:"",probability:50,decisionDate:"",notes:""});
            }}>Add Opportunity</button>
          </div>
        </div>
      )}

      {opportunities.length===0 ? <div className="empty" style={{padding:40}}>No opportunities yet. Add one above to start tracking your pipeline.</div>
       : opportunities.sort((a,b)=>PC_STAGES.indexOf(a.stage)-PC_STAGES.indexOf(b.stage)).map(opp=>{
        const est = estimates.find(e=>e.id===opp.estimateId);
        const totals = est ? calcEstTotals(est) : null;
        const isWon = opp.stage==="Won";
        const alreadyJob = isWon && jobs.find(j=>j.client===opp.client&&j.name.includes(opp.name.split(" ")[0]));
        return (
          <div key={opp.id} style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:"12px 14px",marginBottom:8}}>
            <div style={{display:"flex",alignItems:"flex-start",gap:12}}>
              <div style={{flex:1}}>
                <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:3}}>
                  <span style={{fontSize:14,color:"var(--white)",fontWeight:700}}>{opp.name}</span>
                  <span style={{fontSize:11,color:PC_STAGE_COLOR[opp.stage]||"var(--muted)",fontFamily:"'Barlow Condensed'",letterSpacing:1,background:PC_STAGE_COLOR[opp.stage]+"22",border:"1px solid "+PC_STAGE_COLOR[opp.stage]+"44",borderRadius:3,padding:"1px 7px"}}>{opp.stage.toUpperCase()}</span>
                </div>
                <div style={{fontSize:12,color:"var(--muted)"}}>{opp.client}   {opp.projType}{opp.decisionDate?"   Decision "+fmtDate(opp.decisionDate):""}</div>
                {opp.notes&&<div style={{fontSize:11,color:"var(--muted)",marginTop:3}}>{opp.notes}</div>}
              </div>
              <div style={{textAlign:"right",flexShrink:0}}>
                <div style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:15,color:"var(--accent-bright)",fontWeight:600}}>{totals?fmt(totals.bidTotal):fmt(opp.estValue||0)}</div>
                {totals&&<div style={{fontSize:11,color:"var(--green)"}}>{totals.marginPct.toFixed(1)}% margin</div>}
                <div style={{fontSize:11,color:"var(--muted)"}}>{opp.probability}% probability</div>
              </div>
            </div>
            <div style={{display:"flex",gap:8,marginTop:10,alignItems:"center"}}>
              <select className="fselect" style={{fontSize:11,maxWidth:150}} value={opp.stage} onChange={e=>onUpdateOpp({...opp,stage:e.target.value})}>
                {PC_STAGES.map(s=><option key={s}>{s}</option>)}
              </select>
              {!opp.estimateId && !isWon && (
                <button className="btn btn-ghost btn-sm" onClick={()=>createEstimate(opp)}>Build Estimate</button>
              )}
              {opp.estimateId && (
                <button className="btn btn-ghost btn-sm" onClick={()=>openEst(opp.estimateId)}>
                  {totals?"Edit Estimate ("+fmt(totals.bidTotal)+")":"Open Estimate"}
                </button>
              )}
              {isWon && !alreadyJob && (
                <button className="btn btn-primary btn-sm" onClick={()=>convertToJob(opp)}>Convert to Job</button>
              )}
              {isWon && alreadyJob && (
                <span style={{fontSize:11,color:"var(--green)",fontFamily:"'Barlow Condensed'",letterSpacing:1}}>Job created</span>
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
};

// --- PRECON TOOL WRAPPER ------------------------------------------------------
const PreConTool = ({jobs, priceBook, opportunities, estimates, onUpdatePB, onAddPB, onDeletePB, onImportPB, onUpdateOpp, onAddOpp, onUpdateEst, onAddEst, onConvertToJob}) => {
  const [tab, setTab] = useState("pipeline");
  const pendingEst = opportunities.filter(o=>o.stage==="Estimating"&&!o.estimateId).length;

  return (
    <div>
      <div style={{display:"flex",gap:0,marginBottom:0,borderBottom:"1px solid var(--navy-border)"}}>
        {[["pipeline","Pipeline",pendingEst||null],["pricebook","Price Book",null]].map(([k,l,b])=>(
          <button key={k} className={"dtab"+(tab===k?" active":"")} onClick={()=>setTab(k)}>
            {l}{b?<span className="nav-badge" style={{background:"var(--yellow)",color:"var(--navy)",marginLeft:4}}>{b}</span>:null}
          </button>
        ))}
      </div>
      <div style={{paddingTop:14}}>
        {tab==="pipeline" && (
          <OpportunityList opportunities={opportunities} estimates={estimates} priceBook={priceBook} onUpdateOpp={onUpdateOpp} onAddOpp={onAddOpp} onUpdateEst={onUpdateEst} onAddEst={onAddEst} onConvertToJob={onConvertToJob} jobs={jobs}/>
        )}
        {tab==="pricebook" && (
          <PriceBook priceBook={priceBook} onAdd={onAddPB} onUpdate={onUpdatePB} onDelete={onDeletePB} onImport={items=>onImportPB(items)}/>
        )}
      </div>
    </div>
  );
};

// --- PHOTO LIBRARY ------------------------------------------------------------
const getWeekStart = (dateStr) => {
  var d = new Date(dateStr + "T12:00:00");
  var day = d.getDay(); // 0=Sun
  d.setDate(d.getDate() - day);
  return d.toISOString().slice(0,10);
};

const fmtWeekRange = (weekStart) => {
  var s = new Date(weekStart + "T12:00:00");
  var e = new Date(weekStart + "T12:00:00");
  e.setDate(e.getDate() + 6);
  var opts = {month:"short", day:"numeric"};
  return s.toLocaleDateString("en-US",opts) + " - " + e.toLocaleDateString("en-US",opts);
};

const PhotoLightbox = ({photo, onClose, onPrev, onNext, hasPrev, hasNext}) => {
  return (
    <div className="overlay" onClick={onClose} style={{zIndex:1000}}>
      <div onClick={function(e){e.stopPropagation();}} style={{display:"flex",flexDirection:"column",alignItems:"center",maxWidth:"90vw",maxHeight:"90vh"}}>
        <img src={photo.base64} alt={photo.caption||"Site photo"} style={{maxWidth:"100%",maxHeight:"70vh",objectFit:"contain",borderRadius:8}}/>
        <div style={{marginTop:10,display:"flex",gap:12,alignItems:"center"}}>
          <button className="btn btn-ghost btn-sm" onClick={onPrev} disabled={!hasPrev} style={{opacity:hasPrev?1:.3}}>Prev</button>
          <div style={{textAlign:"center"}}>
            {photo.caption && <div style={{fontSize:13,color:"var(--white)",marginBottom:3}}>{photo.caption}</div>}
            <div style={{fontSize:11,color:"var(--muted)"}}>{fmtDate(photo.date)}</div>
            {photo.hasAI && <div style={{fontSize:10,color:"var(--purple)",marginTop:2}}>AI Analyzed</div>}
          </div>
          <button className="btn btn-ghost btn-sm" onClick={onNext} disabled={!hasNext} style={{opacity:hasNext?1:.3}}>Next</button>
        </div>
        <button className="btn btn-ghost btn-sm" onClick={onClose} style={{marginTop:8}}>Close</button>
      </div>
    </div>
  );
};

const PhotoLibrary = ({job, logs}) => {
  var [filter, setFilter] = useState("all");
  var [lbIdx,  setLbIdx]  = useState(null);

  // Gather all photos from this job's logs
  var jobLogs = logs.filter(function(l){return l.jobId===job.id;})
                    .sort(function(a,b){return b.date.localeCompare(a.date);});

  var allPhotos = [];
  jobLogs.forEach(function(log) {
    (log.photos||[]).forEach(function(p) {
      allPhotos.push({
        id:     p.id,
        base64: p.base64,
        mimeType: p.mimeType||"image/jpeg",
        caption:  p.caption||"",
        date:     log.date,
        logId:    log.id,
        hasAI:    !!log.aiAnalysis,
        hasSafety: !!(log.safety && (log.safety.incident || (log.safety.concerns||[]).length>0)),
      });
    });
  });

  // Apply filter
  var filtered = allPhotos;
  if(filter==="ai")     filtered = allPhotos.filter(function(p){return p.hasAI;});
  if(filter==="safety") filtered = allPhotos.filter(function(p){return p.hasSafety;});

  // Group by week
  var weekMap = {};
  filtered.forEach(function(p) {
    var ws = getWeekStart(p.date);
    if(!weekMap[ws]) weekMap[ws] = [];
    weekMap[ws].push(p);
  });
  var weeks = Object.keys(weekMap).sort(function(a,b){return b.localeCompare(a);});

  var lbPhoto  = lbIdx !== null ? filtered[lbIdx] : null;
  var openLb   = function(idx){setLbIdx(idx);};
  var closeLb  = function(){setLbIdx(null);};
  var prevLb   = function(){setLbIdx(function(i){return Math.max(0,i-1);});};
  var nextLb   = function(){setLbIdx(function(i){return Math.min(filtered.length-1,i+1);});};

  // Build flat index map per week for lightbox navigation
  var photoFlatIdx = {};
  var runIdx = 0;
  weeks.forEach(function(ws) {
    weekMap[ws].forEach(function(p) {
      photoFlatIdx[p.id] = runIdx++;
    });
  });

  return (
    <div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10,marginBottom:16}}>
        <div className="stat-card">
          <div className="stat-label">Total Photos</div>
          <div className="stat-value" style={{fontSize:16}}>{allPhotos.length}</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">AI Analyzed</div>
          <div className="stat-value" style={{fontSize:16,color:"var(--purple)"}}>{allPhotos.filter(function(p){return p.hasAI;}).length}</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">Weeks Covered</div>
          <div className="stat-value" style={{fontSize:16,color:"var(--muted)"}}>{Object.keys(weekMap).length}</div>
        </div>
      </div>

      <div style={{display:"flex",gap:8,marginBottom:16}}>
        {[["all","All Photos"],["ai","AI Analyzed"],["safety","Safety"]].map(function(item){
          var k=item[0]; var l=item[1];
          return (
            <button key={k} className={"btn "+(filter===k?"btn-primary":"btn-ghost")+" btn-sm"}
              onClick={function(){setFilter(k);}}>
              {l}
            </button>
          );
        })}
        <div style={{marginLeft:"auto",fontSize:12,color:"var(--muted)",alignSelf:"center"}}>
          {filtered.length} photo{filtered.length!==1?"s":""}
        </div>
      </div>

      {allPhotos.length===0 && (
        <div className="empty" style={{padding:48,textAlign:"center"}}>
          <div style={{fontSize:32,marginBottom:12,opacity:.4}}></div>
          <div style={{fontFamily:"'Barlow Condensed'",fontSize:14,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:6}}>No Photos Yet</div>
          <div style={{fontSize:12,color:"var(--muted)"}}>Photos added to daily logs will appear here, organized by week.</div>
        </div>
      )}

      {filtered.length===0 && allPhotos.length>0 && (
        <div className="empty" style={{padding:32}}>No photos match the current filter.</div>
      )}

      {weeks.map(function(ws) {
        var photos = weekMap[ws];
        // Group photos within the week by day
        var dayMap = {};
        photos.forEach(function(p) {
          if(!dayMap[p.date]) dayMap[p.date] = [];
          dayMap[p.date].push(p);
        });
        var days = Object.keys(dayMap).sort(function(a,b){return b.localeCompare(a);});
        return (
          <div key={ws} style={{marginBottom:24}}>
            <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:12,paddingBottom:6,borderBottom:"1px solid var(--navy-border)"}}>
              <div style={{fontFamily:"'Barlow Condensed'",fontSize:14,fontWeight:700,color:"var(--white)"}}>{fmtWeekRange(ws)}</div>
              <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:1,color:"var(--muted)"}}>{photos.length} PHOTO{photos.length!==1?"S":""}</div>
            </div>
            {days.map(function(date) {
              var dayPhotos = dayMap[date];
              var d = new Date(date+"T12:00:00");
              var dayLabel = d.toLocaleDateString("en-US",{weekday:"short",month:"short",day:"numeric"});
              return (
                <div key={date} style={{marginBottom:14}}>
                  <div style={{fontSize:11,fontFamily:"'IBM Plex Mono',monospace",color:"var(--muted)",marginBottom:8}}>{dayLabel}</div>
                  <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(140px,1fr))",gap:8}}>
                    {dayPhotos.map(function(p) {
                      var idx = photoFlatIdx[p.id];
                      return (
                        <div key={p.id} style={{position:"relative",cursor:"pointer"}} onClick={function(){openLb(idx);}}>
                          <img src={p.base64} alt={p.caption||"Site photo"}
                            style={{width:"100%",aspectRatio:"4/3",objectFit:"cover",borderRadius:6,display:"block",border:"1px solid var(--navy-border)"}}/>
                          {p.hasAI && (
                            <div style={{position:"absolute",top:4,left:4,background:"rgba(167,139,250,.85)",borderRadius:3,padding:"1px 5px",fontSize:9,color:"var(--white)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>AI</div>
                          )}
                          {p.hasSafety && (
                            <div style={{position:"absolute",top:4,right:4,background:"rgba(248,113,113,.85)",borderRadius:3,padding:"1px 5px",fontSize:9,color:"var(--white)",fontFamily:"'Barlow Condensed'",letterSpacing:.5}}>SAFETY</div>
                          )}
                          {p.caption && (
                            <div style={{position:"absolute",bottom:0,left:0,right:0,background:"rgba(10,18,40,.75)",borderRadius:"0 0 6px 6px",padding:"3px 6px",fontSize:10,color:"var(--white)",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{p.caption}</div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                </div>
              );
            })}
          </div>
        );
      })}

      {lbPhoto && (
        <PhotoLightbox photo={lbPhoto} onClose={closeLb} onPrev={prevLb} onNext={nextLb}
          hasPrev={lbIdx>0} hasNext={lbIdx<filtered.length-1}/>
      )}
    </div>
  );
};

// --- CLOSEOUT CHECKLIST -------------------------------------------------------
const DEFAULT_CLOSEOUT_ITEMS = [
  {id:"cl1",  category:"Punch List",       task:"Punch list complete - all items verified",          required:true},
  {id:"cl2",  category:"Inspections",      task:"Final municipal inspection passed",                  required:true},
  {id:"cl3",  category:"Inspections",      task:"Certificate of Occupancy / Completion received",     required:true},
  {id:"cl4",  category:"Lien Waivers",     task:"Conditional lien waivers collected from all subs",   required:true},
  {id:"cl5",  category:"Lien Waivers",     task:"Unconditional lien waivers collected from all subs", required:true},
  {id:"cl6",  category:"Lien Waivers",     task:"Westroe final unconditional lien waiver signed",      required:true},
  {id:"cl7",  category:"Documentation",    task:"O&M manuals delivered to owner",                     required:true},
  {id:"cl8",  category:"Documentation",    task:"Warranty documents compiled and delivered",           required:true},
  {id:"cl9",  category:"Documentation",    task:"As-built drawings provided",                         required:false},
  {id:"cl10", category:"Documentation",    task:"Attic stock / surplus materials handed over",         required:false},
  {id:"cl11", category:"Financial",        task:"Final draw submitted and approved",                   required:true},
  {id:"cl12", category:"Financial",        task:"Retainage release requested",                         required:true},
  {id:"cl13", category:"Financial",        task:"All subcontractor invoices paid",                     required:true},
  {id:"cl14", category:"Financial",        task:"Final job cost reconciliation complete",              required:true},
  {id:"cl15", category:"Site",             task:"Site cleanup and protection removed",                 required:true},
  {id:"cl16", category:"Site",             task:"Temporary utilities disconnected",                    required:false},
  {id:"cl17", category:"Owner",            task:"Owner walkthrough completed",                         required:true},
  {id:"cl18", category:"Owner",            task:"Keys, codes, and access credentials delivered",       required:true},
];

const CL_CATEGORIES = ["Punch List","Inspections","Lien Waivers","Documentation","Financial","Site","Owner"];

const CloseoutChecklist = ({job, checklist, onUpdate, onUpdateJob}) => {
  var items   = checklist && checklist.length > 0 ? checklist : DEFAULT_CLOSEOUT_ITEMS.map(function(i){return {...i, done:false, notes:"", doneDate:""};});
  var total   = items.length;
  var done    = items.filter(function(i){return i.done;}).length;
  var req     = items.filter(function(i){return i.required;}).length;
  var reqDone = items.filter(function(i){return i.required && i.done;}).length;
  var pct     = total > 0 ? Math.round(done/total*100) : 0;
  var allReqDone = reqDone === req;

  var toggle = function(id) {
    var updated = items.map(function(it){
      return it.id===id ? {...it, done:!it.done, doneDate:!it.done?TODAY:""} : it;
    });
    onUpdate(updated);
  };

  var setNote = function(id, val) {
    var updated = items.map(function(it){
      return it.id===id ? {...it, notes:val} : it;
    });
    onUpdate(updated);
  };

  var grouped = CL_CATEGORIES.map(function(cat){
    return {cat:cat, items:items.filter(function(i){return i.category===cat;})};
  }).filter(function(g){return g.items.length>0;});

  return (
    <div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:16}}>
        <div className="stat-card">
          <div className="stat-label">Progress</div>
          <div className="stat-value" style={{fontSize:16,color:pct===100?"var(--green)":pct>50?"var(--yellow)":"var(--white)"}}>{pct}%</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">Complete</div>
          <div className="stat-value" style={{fontSize:16,color:"var(--green)"}}>{done} / {total}</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">Required Items</div>
          <div className="stat-value" style={{fontSize:16,color:allReqDone?"var(--green)":"var(--yellow)"}}>{reqDone} / {req}</div>
        </div>
        <div className="stat-card">
          <div className="stat-label">Status</div>
          <div className="stat-value" style={{fontSize:13,color:allReqDone?"var(--green)":"var(--muted)"}}>{allReqDone?"Ready to Close":"In Progress"}</div>
        </div>
      </div>

      <div style={{height:6,background:"rgba(255,255,255,.06)",borderRadius:3,marginBottom:16,overflow:"hidden"}}>
        <div style={{height:"100%",width:pct+"%",background:pct===100?"var(--green)":pct>50?"var(--accent)":"var(--yellow)",transition:"width .4s",borderRadius:3}}/>
      </div>

      {allReqDone && (
        <div style={{padding:"10px 14px",background:"rgba(52,211,153,.06)",border:"1px solid rgba(52,211,153,.2)",borderRadius:8,marginBottom:14,display:"flex",alignItems:"center",gap:12}}>
          <span style={{fontSize:18,color:"var(--green)"}}></span>
          <div>
            <div style={{fontSize:13,color:"var(--green)",fontWeight:600}}>All required items complete</div>
            <div style={{fontSize:11,color:"var(--muted)"}}>Ready to close this project.</div>
          </div>
          {job.phase !== "Complete" && (
            <button className="btn btn-primary btn-sm" style={{marginLeft:"auto"}}
              onClick={function(){onUpdateJob({...job, phase:"Complete"});}}>
              Mark Job Complete
            </button>
          )}
        </div>
      )}

      {grouped.map(function(g){
        var catDone = g.items.filter(function(i){return i.done;}).length;
        return (
          <div key={g.cat} style={{marginBottom:18}}>
            <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:8,paddingBottom:4,borderBottom:"1px solid var(--navy-border)"}}>
              <span style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)"}}>{g.cat}</span>
              <span style={{fontFamily:"'Barlow Condensed'",fontSize:11,color:catDone===g.items.length?"var(--green)":"var(--muted)"}}>{catDone}/{g.items.length}</span>
            </div>
            {g.items.map(function(item){
              return (
                <div key={item.id} style={{padding:"9px 12px",background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:6,marginBottom:6}}>
                  <div style={{display:"flex",alignItems:"flex-start",gap:10}}>
                    <div style={{width:20,height:20,borderRadius:4,border:"2px solid "+(item.done?"var(--green)":"var(--navy-border)"),background:item.done?"var(--green)":"transparent",flexShrink:0,marginTop:1,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}
                      onClick={function(){toggle(item.id);}}>
                      {item.done && <span style={{fontSize:12,color:"var(--navy)",fontWeight:900}}>v</span>}
                    </div>
                    <div style={{flex:1}}>
                      <div style={{display:"flex",alignItems:"center",gap:8}}>
                        <span style={{fontSize:13,color:item.done?"var(--muted)":"var(--white)",textDecoration:item.done?"line-through":"none"}}>{item.task}</span>
                        {!item.required && <span style={{fontSize:9,color:"var(--muted)",fontFamily:"'Barlow Condensed'",letterSpacing:.5,border:"1px solid var(--navy-border)",borderRadius:2,padding:"0 4px"}}>OPTIONAL</span>}
                        {item.done && item.doneDate && <span style={{fontSize:10,color:"var(--green)",fontFamily:"'IBM Plex Mono',monospace"}}>{fmtDate(item.doneDate)}</span>}
                      </div>
                      <input className="finput" value={item.notes||""} placeholder="Notes..."
                        style={{marginTop:6,fontSize:11,padding:"3px 8px"}}
                        onChange={function(e){setNote(item.id,e.target.value);}}/>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        );
      })}
    </div>
  );
};

// --- MUNICIPAL INSPECTION TRACKER --------------------------------------------
const INSP_TYPES = [
  "Foundation / Footing","Framing","Rough Plumbing","Rough Electrical","Rough HVAC",
  "Insulation","Drywall / Fire Stop","Energy / Blower Door","Final Plumbing",
  "Final Electrical","Final HVAC","Final Building","Certificate of Occupancy","Other",
];
const INSP_RESULTS   = ["Scheduled","Passed","Failed - Correction Required","Partial Pass","Cancelled"];
const INSP_RESULT_COLOR = {
  "Scheduled":"var(--accent-bright)",
  "Passed":"var(--green)",
  "Failed - Correction Required":"var(--red)",
  "Partial Pass":"var(--yellow)",
  "Cancelled":"var(--muted)",
};

const MunicipalInspections = ({job, inspections, onAdd, onUpdate, onDelete}) => {
  var [showAdd, setShowAdd] = useState(false);
  var [f, setF] = useState({type:INSP_TYPES[0], scheduledDate:"", inspectorName:"", result:"Scheduled", corrections:"", reInspectDate:"", notes:""});
  var set = function(k,v){setF(function(p){return {...p,[k]:v};});};
  var fileRefs = useRef({});

  var handleUpload = function(e, inspId) {
    var file = e.target.files[0];
    if(!file) return;
    readFile(file).then(function(b64) {
      var updated = inspections.find(function(i){return i.id===inspId;});
      if(updated) onUpdate({...updated, pdfBase64:b64, pdfName:file.name});
    });
    e.target.value = "";
  };

  var passed  = inspections.filter(function(i){return i.result==="Passed";}).length;
  var failed  = inspections.filter(function(i){return i.result==="Failed - Correction Required";}).length;
  var pending = inspections.filter(function(i){return i.result==="Scheduled";}).length;

  return (
    <div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:16}}>
        <div className="stat-card"><div className="stat-label">Total Inspections</div><div className="stat-value" style={{fontSize:16}}>{inspections.length}</div></div>
        <div className="stat-card"><div className="stat-label">Passed</div><div className="stat-value" style={{fontSize:16,color:"var(--green)"}}>{passed}</div></div>
        <div className="stat-card"><div className="stat-label">Failed / Correction</div><div className="stat-value" style={{fontSize:16,color:failed>0?"var(--red)":"var(--muted)"}}>{failed}</div></div>
        <div className="stat-card"><div className="stat-label">Scheduled</div><div className="stat-value" style={{fontSize:16,color:pending>0?"var(--yellow)":"var(--muted)"}}>{pending}</div></div>
      </div>

      {job.permitNumber && (
        <div style={{padding:"8px 12px",background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:6,fontSize:12,color:"var(--muted)",marginBottom:12}}>
          Permit: <span style={{color:"var(--white)",fontFamily:"'IBM Plex Mono',monospace"}}>{job.permitNumber}</span>
          {job.address && <span style={{marginLeft:16}}>{job.address}</span>}
        </div>
      )}

      <div style={{display:"flex",justifyContent:"flex-end",marginBottom:12}}>
        <button className="btn btn-primary btn-sm" onClick={function(){setShowAdd(!showAdd);}}>+ Log Inspection</button>
      </div>

      {showAdd && (
        <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14,marginBottom:14,display:"flex",flexDirection:"column",gap:10}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
            <div><div className="flabel">Inspection Type</div>
              <select className="fselect" value={f.type} onChange={function(e){set("type",e.target.value);}}>
                {INSP_TYPES.map(function(t){return <option key={t}>{t}</option>;})}
              </select>
            </div>
            <div><div className="flabel">Scheduled Date</div>
              <input className="finput" type="date" value={f.scheduledDate} onChange={function(e){set("scheduledDate",e.target.value);}}/>
            </div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
            <div><div className="flabel">Inspector Name</div>
              <input className="finput" value={f.inspectorName} onChange={function(e){set("inspectorName",e.target.value);}} placeholder="Inspector name..."/>
            </div>
            <div><div className="flabel">Result</div>
              <select className="fselect" value={f.result} onChange={function(e){set("result",e.target.value);}}>
                {INSP_RESULTS.map(function(r){return <option key={r}>{r}</option>;})}
              </select>
            </div>
          </div>
          {f.result==="Failed - Correction Required" && (
            <div><div className="flabel">Required Corrections</div>
              <textarea className="ftextarea" rows={2} value={f.corrections} onChange={function(e){set("corrections",e.target.value);}} placeholder="List corrections required..."/>
            </div>
          )}
          {f.result==="Failed - Correction Required" && (
            <div><div className="flabel">Re-Inspect Date</div>
              <input className="finput" type="date" value={f.reInspectDate} onChange={function(e){set("reInspectDate",e.target.value);}} style={{maxWidth:200}}/>
            </div>
          )}
          <div><div className="flabel">Notes</div>
            <input className="finput" value={f.notes} onChange={function(e){set("notes",e.target.value);}} placeholder="Additional notes..."/>
          </div>
          <div style={{display:"flex",gap:8,justifyContent:"flex-end"}}>
            <button className="btn btn-ghost btn-sm" onClick={function(){setShowAdd(false);}}>Cancel</button>
            <button className="btn btn-primary btn-sm" onClick={function(){
              if(!f.type) return;
              onAdd({...f, id:"mi"+uid(), loggedDate:TODAY});
              setShowAdd(false);
              setF({type:INSP_TYPES[0],scheduledDate:"",inspectorName:"",result:"Scheduled",corrections:"",reInspectDate:"",notes:""});
            }}>Save Inspection</button>
          </div>
        </div>
      )}

      {inspections.length===0 ? (
        <div className="empty" style={{padding:32}}>No inspections logged yet. Log your first inspection above.</div>
      ) : (
        <div>
          {inspections.slice().sort(function(a,b){return (b.scheduledDate||b.loggedDate).localeCompare(a.scheduledDate||a.loggedDate);}).map(function(insp){
            var resColor = INSP_RESULT_COLOR[insp.result] || "var(--muted)";
            var hasFail  = insp.result==="Failed - Correction Required";
            return (
              <div key={insp.id} style={{background:"var(--navy)",border:"1px solid "+(hasFail?"rgba(248,113,113,.3)":"var(--navy-border)"),borderRadius:8,padding:"12px 14px",marginBottom:8}}>
                <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",gap:12}}>
                  <div style={{flex:1}}>
                    <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:4}}>
                      <span style={{fontSize:13,color:"var(--white)",fontWeight:600}}>{insp.type}</span>
                      <span style={{fontSize:11,color:resColor,fontFamily:"'Barlow Condensed'",letterSpacing:.5,background:resColor+"22",border:"1px solid "+resColor+"44",borderRadius:3,padding:"1px 7px"}}>{insp.result}</span>
                    </div>
                    <div style={{fontSize:11,color:"var(--muted)"}}>
                      {insp.scheduledDate && <span>Scheduled: {fmtDate(insp.scheduledDate)}</span>}
                      {insp.inspectorName && <span style={{marginLeft:12}}>Inspector: {insp.inspectorName}</span>}
                    </div>
                    {hasFail && insp.corrections && (
                      <div style={{marginTop:8,padding:"8px 10px",background:"rgba(248,113,113,.06)",border:"1px solid rgba(248,113,113,.2)",borderRadius:5,fontSize:12,color:"var(--white)"}}>
                        <div style={{fontSize:10,color:"var(--red)",fontFamily:"'Barlow Condensed'",letterSpacing:1,marginBottom:3}}>CORRECTIONS REQUIRED</div>
                        {insp.corrections}
                      </div>
                    )}
                    {hasFail && insp.reInspectDate && (
                      <div style={{fontSize:11,color:"var(--yellow)",marginTop:6}}>Re-inspect: {fmtDate(insp.reInspectDate)}</div>
                    )}
                    {insp.notes && <div style={{fontSize:11,color:"var(--muted)",marginTop:4}}>{insp.notes}</div>}
                  </div>
                  {insp.pdfBase64 ? (
                    <div style={{marginTop:8,display:"flex",alignItems:"center",gap:8,padding:"6px 10px",background:"rgba(52,211,153,.05)",border:"1px solid rgba(52,211,153,.2)",borderRadius:5}}>
                      <span style={{fontSize:12,color:"var(--green)",flex:1}}>{insp.pdfName}</span>
                      <button className="btn btn-ghost btn-sm" style={{fontSize:10,color:"var(--accent-bright)"}}
                        onClick={function(){fileRefs.current[insp.id]&&fileRefs.current[insp.id].click();}}>Replace</button>
                      <button className="btn btn-ghost btn-sm" style={{fontSize:10,color:"var(--red)"}}
                        onClick={function(){onUpdate({...insp,pdfBase64:null,pdfName:""});}}>Remove</button>
                    </div>
                  ) : (
                    <div style={{marginTop:8}}>
                      <button className="btn btn-ghost btn-sm" style={{fontSize:11}}
                        onClick={function(){fileRefs.current[insp.id]&&fileRefs.current[insp.id].click();}}>
                        Attach AHJ Result PDF
                      </button>
                    </div>
                  )}
                  <input ref={function(el){fileRefs.current[insp.id]=el;}} type="file" accept=".pdf,image/*"
                    style={{display:"none"}} onChange={function(e){handleUpload(e,insp.id);}}/>
                                    <div style={{display:"flex",gap:6,flexShrink:0}}>
                    <select className="fselect" style={{fontSize:11,padding:"3px 6px",maxWidth:160,color:resColor}}
                      value={insp.result}
                      onChange={function(e){onUpdate({...insp,result:e.target.value});}}>
                      {INSP_RESULTS.map(function(r){return <option key={r}>{r}</option>;})}
                    </select>
                    <button className="btn btn-ghost btn-sm" style={{fontSize:11,color:"var(--red)"}}
                      onClick={function(){onDelete(insp.id);}}>x</button>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

// --- SOCIAL MEDIA DRAFT TOOL --------------------------------------------------
const SocialDraftTool = ({jobs, logs}) => {
  var [selJobIds, setSelJobIds] = useState([]);
  var [dateFrom,  setDateFrom]  = useState(function(){
    var d = new Date(); d.setDate(d.getDate()-7); return d.toISOString().slice(0,10);
  }());
  var [dateTo,    setDateTo]    = useState(TODAY);
  var [selPhotos, setSelPhotos] = useState([]);
  var [platform,  setPlatform]  = useState("both");
  var [tone,      setTone]      = useState("story");
  var [loading,   setLoading]   = useState(false);
  var [drafts,    setDrafts]    = useState(null);
  var [error,     setError]     = useState(null);
  var [copied,    setCopied]    = useState("");

  // Collect all photos from selected jobs in date range
  var activeJobs = jobs.filter(function(j){return (j.phase==="Active"||j.phase==="Punch"||j.phase==="Closeout")&&!j.isTraining;});
  var filteredLogs = logs.filter(function(l){
    var inRange = l.date >= dateFrom && l.date <= dateTo;
    var inJob   = selJobIds.length===0 || selJobIds.includes(l.jobId);
    return inRange && inJob && (l.photos||[]).length>0;
  });

  var allPhotos = [];
  filteredLogs.forEach(function(log){
    var job = jobs.find(function(j){return j.id===log.jobId;});
    (log.photos||[]).forEach(function(p){
      allPhotos.push({
        id:p.id, base64:p.base64, caption:p.caption||"",
        date:log.date, jobId:log.jobId,
        jobName:job?job.name:"", jobClient:job?job.client:"",
        jobAddress:job?job.address:"", phase:job?job.phase:"",
      });
    });
  });

  var toggleJob = function(id){
    setSelJobIds(function(prev){
      return prev.includes(id) ? prev.filter(function(x){return x!==id;}) : [...prev,id];
    });
    setSelPhotos([]);
    setDrafts(null);
  };

  var togglePhoto = function(id){
    setSelPhotos(function(prev){
      return prev.includes(id) ? prev.filter(function(x){return x!==id;}) : [...prev,id];
    });
    setDrafts(null);
  };

  var selectAll  = function(){setSelPhotos(allPhotos.map(function(p){return p.id;}));};
  var clearSel   = function(){setSelPhotos([]);};

  var generate = function(){
    var photos = allPhotos.filter(function(p){return selPhotos.includes(p.id);});
    if(photos.length===0){setError("Select at least one photo."); return;}
    setLoading(true); setError(null); setDrafts(null);

    // Build context from selected photos and jobs
    var jobsInSel = [];
    var seenJobs = {};
    photos.forEach(function(p){
      if(!seenJobs[p.jobId]){
        seenJobs[p.jobId]=true;
        jobsInSel.push({name:p.jobName, client:p.jobClient, address:p.jobAddress, phase:p.phase});
      }
    });

    var photoDesc = photos.map(function(p,i){
      return "Photo "+(i+1)+(p.caption?" - "+p.caption:"")+(p.jobName?" ("+p.jobName+")":"");
    }).join("\n");

    var jobDesc = jobsInSel.map(function(j){
      return j.name+(j.client?" for "+j.client:"")+(j.address?" at "+j.address:"")+(j.phase?" ["+j.phase+"]":"");
    }).join("\n");

    var toneGuide = tone==="story"
      ? "Use a storytelling approach: set the scene, describe the challenge or craft, highlight the team."
      : tone==="technical"
      ? "Use a professional/technical tone: highlight trade expertise, quality standards, construction process."
      : "Write in a before-and-after transformation style: contrast the starting state with the progress shown.";

    var prompt = [
      "You are writing social media posts for Westroe Construction, a general contractor (GC License #105268) based in Charlotte, NC.",
      "Westroe specializes in complex new construction and renovation projects.",
      "Owner: Shane | Team: Cullen Cunningham (Field PE), Kevin Holloway (Carpenter), Kael Roberts (Laborer)",
      "",
      "PROJECT(S) FEATURED:",
      jobDesc,
      "",
      "PHOTOS SELECTED ("+photos.length+" photos):",
      photoDesc,
      "",
      "TONE DIRECTION: "+toneGuide,
      "",
      "Generate TWO posts. Return ONLY valid JSON, no markdown:",
      "{",
      '  "linkedin": "full LinkedIn post text here",',
      '  "instagram": "full Instagram caption with hashtags here"',
      "}",
      "",
      "LinkedIn guidelines: 150-250 words, professional storytelling tone, speak to owners/architects/developers, 1-2 relevant hashtags only, end with a soft CTA like inviting DMs or visits to the profile.",
      "Instagram guidelines: 50-100 words, punchy and visual-first, 15-20 hashtags including #CharlotteNC #CharlotteConstruction #GeneralContractor #Renovation #NewConstruction #Westroe #WestroeCon and neighborhood/trade-specific tags, end with a question or CTA.",
      "Do not mention specific photo numbers. Write as if the photos speak for themselves.",
      "Do not hallucinate project details not provided. Use only what is given.",
    ].join("\n");

    fetch("https://api.anthropic.com/v1/messages",{
      method:"POST",
      headers:{"Content-Type":"application/json"},
      body:JSON.stringify({
        model:"claude-sonnet-4-20250514",
        max_tokens:1000,
        system:"You are a social media copywriter for a construction company. Return ONLY valid JSON with linkedin and instagram keys. No markdown fences, no preamble.",
        messages:[{role:"user",content:prompt}],
      }),
    }).then(function(r){return r.json();})
    .then(function(data){
      if(data.error) throw new Error(data.error.message);
      var text = (data.content||[]).map(function(c){return c.text||"";}).join("");
      var clean = text.replace(/```json|```/g,"").trim();
      var parsed = JSON.parse(clean);
      setDrafts(parsed);
      setLoading(false);
    })
    .catch(function(e){
      setError("Generation failed: "+e.message);
      setLoading(false);
    });
  };

  var copyText = function(text, key){
    navigator.clipboard.writeText(text).then(function(){
      setCopied(key);
      setTimeout(function(){setCopied("");}, 2000);
    });
  };

  return (
    <div>
      <div style={{marginBottom:20}}>
        <div style={{fontFamily:"'Barlow Condensed'",fontSize:18,fontWeight:700,color:"var(--white)",marginBottom:4}}>Social Media Draft Generator</div>
        <div style={{fontSize:12,color:"var(--muted)"}}>Select photos from your recent work and generate ready-to-post LinkedIn and Instagram drafts.</div>
      </div>

      <div style={{display:"grid",gridTemplateColumns:"280px 1fr",gap:16,alignItems:"start"}}>

        {/* Left panel - controls */}
        <div style={{display:"flex",flexDirection:"column",gap:12}}>

          <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:12}}>
            <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,color:"var(--muted)",marginBottom:8}}>DATE RANGE</div>
            <div style={{display:"flex",flexDirection:"column",gap:6}}>
              <div><div className="flabel">From</div><input className="finput" type="date" value={dateFrom} onChange={function(e){setDateFrom(e.target.value);setSelPhotos([]);setDrafts(null);}}/></div>
              <div><div className="flabel">To</div><input className="finput" type="date" value={dateTo} onChange={function(e){setDateTo(e.target.value);setSelPhotos([]);setDrafts(null);}}/></div>
              <div style={{display:"flex",gap:4,flexWrap:"wrap",marginTop:4}}>
                {[["Last 7 days",7],["Last 30",30],["Last 90",90]].map(function(item){
                  var label=item[0]; var days=item[1];
                  return (
                    <button key={label} className="btn btn-ghost btn-sm" style={{fontSize:10,padding:"2px 8px"}}
                      onClick={function(){
                        var d=new Date(); d.setDate(d.getDate()-days);
                        setDateFrom(d.toISOString().slice(0,10));
                        setDateTo(TODAY); setSelPhotos([]); setDrafts(null);
                      }}>{label}</button>
                  );
                })}
              </div>
            </div>
          </div>

          <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:12}}>
            <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,color:"var(--muted)",marginBottom:8}}>JOBS</div>
            <div style={{fontSize:11,color:"var(--muted)",marginBottom:6}}>Leave all unchecked to include all jobs</div>
            {activeJobs.map(function(j){
              var isSel = selJobIds.includes(j.id);
              var photoCt = logs.filter(function(l){return l.jobId===j.id&&l.date>=dateFrom&&l.date<=dateTo;}).reduce(function(s,l){return s+(l.photos||[]).length;},0);
              return (
                <label key={j.id} style={{display:"flex",alignItems:"center",gap:8,padding:"5px 0",cursor:"pointer",borderBottom:"1px solid rgba(42,64,128,.15)"}}>
                  <input type="checkbox" checked={isSel} onChange={function(){toggleJob(j.id);}} style={{accentColor:"var(--accent)"}}/>
                  <div style={{flex:1}}>
                    <div style={{fontSize:12,color:"var(--white)"}}>{j.name}</div>
                    <div style={{fontSize:10,color:"var(--muted)"}}>{photoCt} photos in range</div>
                  </div>
                </label>
              );
            })}
            {activeJobs.length===0 && <div style={{fontSize:11,color:"var(--muted)"}}>No active jobs</div>}
          </div>

          <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:12}}>
            <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,color:"var(--muted)",marginBottom:8}}>PLATFORM</div>
            {[["both","Both"],["linkedin","LinkedIn only"],["instagram","Instagram only"]].map(function(item){
              var v=item[0]; var l=item[1];
              return (
                <label key={v} style={{display:"flex",alignItems:"center",gap:8,marginBottom:6,cursor:"pointer"}}>
                  <input type="radio" name="platform" value={v} checked={platform===v} onChange={function(){setPlatform(v); setDrafts(null);}} style={{accentColor:"var(--accent)"}}/>
                  <span style={{fontSize:12,color:"var(--white)"}}>{l}</span>
                </label>
              );
            })}
          </div>

          <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:12}}>
            <div style={{fontFamily:"'Barlow Condensed'",fontSize:11,letterSpacing:2,color:"var(--muted)",marginBottom:8}}>POST TONE</div>
            {[["story","Storytelling"],["technical","Technical / Craft"],["transform","Transformation"]].map(function(item){
              var v=item[0]; var l=item[1];
              return (
                <label key={v} style={{display:"flex",alignItems:"center",gap:8,marginBottom:6,cursor:"pointer"}}>
                  <input type="radio" name="tone" value={v} checked={tone===v} onChange={function(){setTone(v); setDrafts(null);}} style={{accentColor:"var(--accent)"}}/>
                  <span style={{fontSize:12,color:"var(--white)"}}>{l}</span>
                </label>
              );
            })}
          </div>

        </div>

        {/* Right panel - photo grid + output */}
        <div>

          {allPhotos.length===0 ? (
            <div className="empty" style={{padding:48}}>
              <div style={{fontSize:32,marginBottom:12,opacity:.4}}></div>
              <div style={{fontFamily:"'Barlow Condensed'",fontSize:13,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)"}}>No Photos in Range</div>
              <div style={{fontSize:12,color:"var(--muted)",marginTop:6}}>Adjust the date range or add photos to daily logs.</div>
            </div>
          ) : (
            <div>
              <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:12}}>
                <div style={{flex:1,fontSize:13,color:"var(--white)"}}>
                  <span style={{fontWeight:600}}>{allPhotos.length}</span> photos available
                  {selPhotos.length>0 && <span style={{color:"var(--accent-bright)",marginLeft:8}}>{selPhotos.length} selected</span>}
                </div>
                <button className="btn btn-ghost btn-sm" onClick={selectAll}>Select All</button>
                {selPhotos.length>0 && <button className="btn btn-ghost btn-sm" onClick={clearSel}>Clear</button>}
                <button className="btn btn-primary btn-sm" onClick={generate} disabled={selPhotos.length===0||loading}
                  style={{minWidth:120,opacity:selPhotos.length===0?0.4:1}}>
                  {loading ? "Generating..." : "Generate Draft"}
                </button>
              </div>

              <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(120px,1fr))",gap:8,marginBottom:16}}>
                {allPhotos.map(function(p){
                  var isSel = selPhotos.includes(p.id);
                  return (
                    <div key={p.id} onClick={function(){togglePhoto(p.id);}}
                      style={{position:"relative",cursor:"pointer",borderRadius:6,overflow:"hidden",
                        border:"2px solid "+(isSel?"var(--accent)":"transparent"),
                        boxShadow:isSel?"0 0 0 1px var(--accent)":"none"}}>
                      <img src={p.base64} alt={p.caption||"photo"}
                        style={{width:"100%",aspectRatio:"4/3",objectFit:"cover",display:"block"}}/>
                      {isSel && (
                        <div style={{position:"absolute",top:4,right:4,width:20,height:20,borderRadius:"50%",
                          background:"var(--accent)",display:"flex",alignItems:"center",justifyContent:"center",
                          fontSize:11,color:"var(--white)",fontWeight:900}}>v</div>
                      )}
                      {p.caption && (
                        <div style={{position:"absolute",bottom:0,left:0,right:0,
                          background:"rgba(10,18,40,.8)",padding:"3px 5px",fontSize:9,color:"var(--white)",
                          whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{p.caption}</div>
                      )}
                      <div style={{position:"absolute",top:4,left:4,fontSize:9,fontFamily:"'Barlow Condensed'",
                        letterSpacing:.5,color:"var(--white)",background:"rgba(10,18,40,.6)",
                        borderRadius:2,padding:"1px 4px"}}>{p.jobName.split(" ")[0]}</div>
                    </div>
                  );
                })}
              </div>

              {error && (
                <div style={{padding:"10px 14px",background:"rgba(248,113,113,.08)",border:"1px solid rgba(248,113,113,.3)",borderRadius:6,fontSize:12,color:"var(--red)",marginBottom:12}}>{error}</div>
              )}

              {drafts && (
                <div style={{display:"flex",flexDirection:"column",gap:12}}>
                  {(platform==="both"||platform==="linkedin") && (
                    <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14}}>
                      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}>
                        <div style={{fontFamily:"'Barlow Condensed'",fontSize:13,fontWeight:700,color:"var(--white)",letterSpacing:1}}>LINKEDIN</div>
                        <button className="btn btn-ghost btn-sm" style={{fontSize:11,color:copied==="li"?"var(--green)":"var(--accent-bright)"}}
                          onClick={function(){copyText(drafts.linkedin,"li");}}>
                          {copied==="li" ? "Copied!" : "Copy"}
                        </button>
                      </div>
                      <div style={{fontSize:13,color:"var(--white)",lineHeight:1.7,whiteSpace:"pre-wrap"}}>{drafts.linkedin}</div>
                    </div>
                  )}
                  {(platform==="both"||platform==="instagram") && (
                    <div style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:14}}>
                      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}>
                        <div style={{fontFamily:"'Barlow Condensed'",fontSize:13,fontWeight:700,color:"var(--white)",letterSpacing:1}}>INSTAGRAM</div>
                        <button className="btn btn-ghost btn-sm" style={{fontSize:11,color:copied==="ig"?"var(--green)":"var(--accent-bright)"}}
                          onClick={function(){copyText(drafts.instagram,"ig");}}>
                          {copied==="ig" ? "Copied!" : "Copy"}
                        </button>
                      </div>
                      <div style={{fontSize:13,color:"var(--white)",lineHeight:1.7,whiteSpace:"pre-wrap"}}>{drafts.instagram}</div>
                    </div>
                  )}
                  <div style={{fontSize:11,color:"var(--muted)",textAlign:"center"}}>Review and edit before posting. Regenerate anytime with different photo selections.</div>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

// --- MEETINGS TOOL ------------------------------------------------------------
const MTG_TYPES    = ["OAC","Sub Coordination","Owner","Internal"];
const MTG_STATUSES = ["Draft","Distributed","Archived"];
const AI_ITEM_STATUSES = ["Open","In Progress","Closed"];

const STANDING_AGENDA = {
  "OAC": [
    "Safety Report",
    "Project Status and Schedule Update",
    "Budget and Financial Summary",
    "RFIs and Submittals Review",
    "Change Orders and Potential Changes",
    "Quality and Punch List Status",
    "Action Items from Prior Meeting",
    "New Business",
    "Next Meeting Date and Time",
  ],
  "Sub Coordination": [
    "Safety and Housekeeping",
    "Schedule Coordination and Sequencing",
    "Submittal and Material Status",
    "RFIs and Field Issues",
    "Quality and Punch Items",
    "Action Items from Prior Meeting",
    "Next Meeting",
  ],
  "Owner": [
    "Project Progress Update",
    "Budget and Cost Review",
    "Schedule Update",
    "Open Items and Decisions Needed",
    "Next Steps",
  ],
  "Internal": [
    "Schedule and Manpower Review",
    "Open RFIs and Submittals",
    "Subcontractor Coordination",
    "Safety",
    "Action Items",
  ],
};

var buildBlankAgenda = function(type) {
  return (STANDING_AGENDA[type]||[]).map(function(topic,i){
    return {id:"ai"+uid(), order:i+1, topic:topic, notes:"", type:"standing"};
  });
};

var buildMeetingMinutes = function(meeting, job) {
  var lines = [
    "WESTROE CONSTRUCTION | GC License #105268",
    "Charlotte, NC | 704-962-6507",
    "================================================================",
    "",
    meeting.type.toUpperCase()+" MEETING - MINUTES AND AGENDA",
    "Meeting No. "+meeting.number,
    "Project: "+job.name+" ("+job.id+")",
    "Client: "+(job.client||""),
    "Date: "+fmtDate(meeting.date)+(meeting.time?" at "+meeting.time:""),
    "Location: "+(meeting.location||""),
    "",
    "ATTENDEES:",
  ];
  (meeting.attendees||[]).forEach(function(a){
    lines.push("  "+(a.attended?"[X]":"[ ]")+" "+a.name+(a.company?" - "+a.company:"")+(a.role?" ("+a.role+")":""));
  });
  if(meeting.progressSummary){
    lines.push("","PROGRESS SUMMARY:","",meeting.progressSummary);
  }
  if((meeting.delaysSinceLast||[]).length>0){
    lines.push("","DELAYS AND CONCERNS SINCE LAST MEETING:");
    meeting.delaysSinceLast.forEach(function(d){lines.push("  - "+d);});
  }
  if((meeting.openRfis||[]).length>0){
    lines.push("","OPEN RFIs:");
    meeting.openRfis.forEach(function(r){lines.push("  "+r.number+" - "+r.title);});
  }
  if((meeting.openPunches||[]).length>0){
    lines.push("","OPEN PUNCH ITEMS:");
    meeting.openPunches.forEach(function(p){lines.push("  ["+p.priority+"] "+p.category+" - "+p.title+" ("+p.status+")");});
  }
  if((meeting.openSubmittals||[]).length>0){
    lines.push("","OPEN SUBMITTALS:");
    meeting.openSubmittals.forEach(function(s){lines.push("  "+s.number+" - "+s.title);});
  }
  if((meeting.lookahead||[]).length>0){
    lines.push("","3-WEEK LOOK-AHEAD:");
    meeting.lookahead.forEach(function(a){lines.push("  "+fmtDate(a.startDate)+" - "+fmtDate(a.endDate)+": "+a.name);});
  }
  lines.push("","AGENDA AND DISCUSSION:");
  (meeting.agendaItems||[]).sort(function(a,b){return a.order-b.order;}).forEach(function(item){
    lines.push("","  "+item.order+". "+item.topic.toUpperCase());
    if(item.notes) lines.push("     "+item.notes);
    else lines.push("     (No notes recorded)");
  });
  if((meeting.actionItems||[]).length>0){
    lines.push("","ACTION ITEMS:");
    meeting.actionItems.forEach(function(a){
      lines.push("  ["+(a.status==="Closed"?"X":" ")+"] "+a.description+(a.owner?" | Owner: "+a.owner:"")+(a.dueDate?" | Due: "+fmtDate(a.dueDate):""));
    });
  }
  if(meeting.notes){lines.push("","ADDITIONAL NOTES:","",meeting.notes);}
  lines.push("","================================================================","Prepared by Westroe Construction | "+TODAY);
  return lines.join("\n");
};

// --- MEETING EDITOR -----------------------------------------------------------
const MeetingEditor = ({meeting, job, directory, allRfis, allSubmittals, allPunches, allActivities, phases, allLogs, onUpdate, onBack}) => {
  var [tab,      setTab]      = useState("agenda");
  var [aiLoading,setAiLoad]   = useState(false);
  var [aiError,  setAiErr]    = useState(null);
  var [copied,   setCopied]   = useState(false);

  var update = function(field, val) {
    onUpdate({...meeting, [field]: val});
  };

  var addAttendee = function(dirEntry, contact) {
    var pc = contact || getPrimaryContact(dirEntry);
    var key = dirEntry.id + (pc ? "_"+pc.id : "");
    var already = (meeting.attendees||[]).find(function(a){return a.key===key;});
    if(already) return;
    var newAtt = {key:key, dirId:dirEntry.id, name:pc?pc.name:dirEntry.company, company:dirEntry.company, role:pc?pc.role:"", email:pc?pc.email:"", phone:pc?pc.phone:"", willAttend:true, attended:false};
    var updated = [...(meeting.attendees||[]), newAtt];
    var emails = updated.filter(function(a){return a.email;}).map(function(a){return a.email;});
    onUpdate({...meeting, attendees:updated, distribution:emails.join(", ")});
  };

  var removeAttendee = function(key) {
    var updated = (meeting.attendees||[]).filter(function(a){return a.key!==key&&a.dirId!==key;});
    var emails  = updated.filter(function(a){return a.email;}).map(function(a){return a.email;});
    onUpdate({...meeting, attendees:updated, distribution:emails.join(", ")});
  };

  var toggleAttended = function(dirId) {
    update("attendees", (meeting.attendees||[]).map(function(a){
      return a.dirId===dirId ? {...a, attended:!a.attended} : a;
    }));
  };

  var updateAgendaItem = function(id, field, val) {
    update("agendaItems", (meeting.agendaItems||[]).map(function(item){
      return item.id===id ? {...item,[field]:val} : item;
    }));
  };

  var addAgendaItem = function() {
    var items  = meeting.agendaItems||[];
    var maxOrd = items.reduce(function(m,i){return Math.max(m,i.order);},0);
    update("agendaItems", [...items, {id:"ai"+uid(), order:maxOrd+1, topic:"", notes:"", type:"custom"}]);
  };

  var removeAgendaItem = function(id) {
    update("agendaItems", (meeting.agendaItems||[]).filter(function(i){return i.id!==id;}));
  };

  var addActionItem = function() {
    var acts = meeting.actionItems||[];
    update("actionItems", [...acts, {id:"act"+uid(), description:"", owner:"", dueDate:"", status:"Open"}]);
  };

  var updateAction = function(id, field, val) {
    update("actionItems", (meeting.actionItems||[]).map(function(a){
      return a.id===id ? {...a,[field]:val} : a;
    }));
  };

  var removeAction = function(id) {
    update("actionItems", (meeting.actionItems||[]).filter(function(a){return a.id!==id;}));
  };

  var runAiPrep = function() {
    setAiLoad(true); setAiErr(null);

    // Pull open punch items
    var openPunches = (allPunches||[]).filter(function(p){
      return p.jobId===job.id && ["Open","In Progress"].includes(p.status);
    }).map(function(p){return {id:p.id, title:p.title||p.description||"Untitled", category:p.category||"General", priority:p.priority||"Medium", status:p.status};});

    // Pull open RFIs
    var openRfis = allRfis.filter(function(r){return r.jobId===job.id && r.status!=="Closed" && r.status!=="Answered";}).map(function(r){return {number:r.number||r.id, title:r.title||r.question||"Untitled RFI", status:r.status};});

    // Pull pending submittals
    var openSubs = allSubmittals.filter(function(s){return s.jobId===job.id && (s.status==="Submitted"||s.status==="Pending"||s.status==="Under Review");}).map(function(s){return {number:s.number, title:s.title, status:s.status};});

    // Pull 3-week look-ahead
    var today  = new Date();
    var cutoff = new Date(); cutoff.setDate(cutoff.getDate()+21);
    var lkAhead = allActivities.filter(function(a){
      if(a.jobId!==job.id) return false;
      var s = new Date(a.startDate+"T12:00:00");
      var e = new Date(a.endDate+"T12:00:00");
      return s <= cutoff && e >= today;
    }).sort(function(a,b){return a.startDate.localeCompare(b.startDate);}).slice(0,12);

    // Get logs since last meeting or last 14 days
    var sinceDays = 14;
    var since = new Date(); since.setDate(since.getDate()-sinceDays);
    var sinceStr = since.toISOString().slice(0,10);
    var recentLogs = allLogs.filter(function(l){return l.jobId===job.id && l.date>=sinceStr;}).sort(function(a,b){return b.date.localeCompare(a.date);});

    var delays = [];
    recentLogs.forEach(function(l){(l.delays||[]).forEach(function(d){if(d.description)delays.push(fmtDate(l.date)+": "+d.description);});});

    var logSummary = recentLogs.map(function(l){
      var work   = l.workDescription||"";
      var safety = l.safety&&l.safety.incident?"SAFETY INCIDENT: "+l.safety.incidentDescription:"";
      var rfiTitles = (l.rfis||[]).map(function(r){return r.title||r.question||"";}).filter(Boolean).join(", ");
      return fmtDate(l.date)+": "+work+(safety?" | "+safety:"")+(rfiTitles?" | RFIs: "+rfiTitles:"");
    }).filter(function(s){return s.length>10;}).join("\n");

    // Store the data-driven fields immediately (no AI needed for these)
    onUpdate({...meeting,
      openRfis: openRfis,
      openSubmittals: openSubs,
      openPunches: openPunches,
      lookahead: lkAhead,
      delaysSinceLast: delays,
      aiPrepDate: TODAY,
    });

    if(!logSummary){
      setAiLoad(false);
      onUpdate({...meeting, openRfis:openRfis, openSubmittals:openSubs, openPunches:openPunches, lookahead:lkAhead, delaysSinceLast:delays, progressSummary:"No daily logs found in the last "+sinceDays+" days.", aiPrepDate:TODAY});
      return;
    }

    var prompt = [
      "You are a construction project manager summarizing recent site activity for an "+meeting.type+" meeting.",
      "Project: "+job.name+(job.client?" for "+job.client:""),
      "GC: Westroe Construction | Charlotte NC",
      "Meeting Date: "+fmtDate(meeting.date),
      "",
      "DAILY LOG SUMMARY (last "+sinceDays+" days):",
      logSummary,
      "",
      "Write a concise 2-3 paragraph progress summary suitable for an OAC meeting agenda.",
      "Cover: work completed, current status, any safety incidents, schedule status.",
      "Be professional and factual. Do not hallucinate. Only reference what is in the logs above.",
      "Do not use bullet points. Write in paragraph form.",
    ].join("\n");

    fetch("https://api.anthropic.com/v1/messages",{
      method:"POST",
      headers:{"Content-Type":"application/json"},
      body:JSON.stringify({
        model:"claude-sonnet-4-20250514",
        max_tokens:600,
        messages:[{role:"user",content:prompt}],
      }),
    }).then(function(r){return r.json();})
    .then(function(data){
      if(data.error) throw new Error(data.error.message);
      var text = (data.content||[]).map(function(c){return c.text||"";}).join("").trim();
      onUpdate({...meeting, openRfis:openRfis, openSubmittals:openSubs, openPunches:openPunches, lookahead:lkAhead, delaysSinceLast:delays, progressSummary:text, aiPrepDate:TODAY});
      setAiLoad(false);
    })
    .catch(function(e){setAiErr("AI prep failed: "+e.message); setAiLoad(false);});
  };

  var copyMinutes = function() {
    var txt = buildMeetingMinutes(meeting, job);
    navigator.clipboard.writeText(txt).then(function(){
      setCopied(true);
      setTimeout(function(){setCopied(false);},2500);
    });
  };

  var tabs = [["agenda","Agenda"],["attendees","Attendees"],["prep","Meeting Prep"],["actions","Action Items"],["notes","Notes"],["minutes","Minutes"]];

  return (
    <div style={{height:"100%",display:"flex",flexDirection:"column"}}>

      {/* Header */}
      <div style={{padding:"10px 14px",borderBottom:"1px solid var(--navy-border)",background:"var(--navy-dark)",flexShrink:0}}>
        <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:6}}>
          <div>
            <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:3}}>
              <button className="btn btn-ghost btn-sm" onClick={onBack} style={{fontSize:11,padding:"2px 8px"}}>Back</button>
              <span style={{fontFamily:"'Barlow Condensed'",fontSize:16,fontWeight:700,color:"var(--white)"}}>{meeting.type} Meeting No. {meeting.number}</span>
              <span style={{fontSize:11,fontFamily:"'Barlow Condensed'",letterSpacing:.5,color:meeting.status==="Distributed"?"var(--green)":"var(--yellow)"}}>{(meeting.status||"Draft").toUpperCase()}</span>
            </div>
            <div style={{fontSize:11,color:"var(--muted)"}}>
              {job.name} - {job.client} | {fmtDate(meeting.date)}{meeting.time?" at "+meeting.time:""} | {meeting.location||"Location TBD"}
            </div>
          </div>
          <div style={{display:"flex",gap:8}}>
            <button className="btn btn-ghost btn-sm" style={{fontSize:11,color:aiLoading?"var(--muted)":"var(--purple)"}}
              onClick={runAiPrep} disabled={aiLoading}>
              {aiLoading ? "Preparing..." : "AI Prep Agenda"}
            </button>
            <button className="btn btn-ghost btn-sm" style={{fontSize:11,color:copied?"var(--green)":"var(--accent-bright)"}}
              onClick={copyMinutes}>{copied?"Copied!":"Copy Minutes"}</button>
            <button className="btn btn-primary btn-sm" style={{fontSize:11}}
              onClick={function(){onUpdate({...meeting,status:"Distributed",distributedDate:TODAY});}}>
              {meeting.status==="Distributed"?"Distributed":"Mark Distributed"}
            </button>
          </div>
        </div>
        <div style={{display:"flex",gap:0,marginTop:6}}>
          {tabs.map(function(t){
            return (
              <button key={t[0]} className={"drw-tab"+(tab===t[0]?" active":"")} onClick={function(){setTab(t[0]);}} style={{fontSize:11,padding:"4px 10px"}}>
                {t[1]}
              </button>
            );
          })}
        </div>
      </div>

      {/* Tab content */}
      <div style={{flex:1,overflowY:"auto",padding:14}}>

        {/* Meeting header fields */}
        {tab==="agenda" && (
          <div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10,marginBottom:14}}>
              <div><div className="flabel">Meeting Type</div>
                <select className="fselect" value={meeting.type} onChange={function(e){onUpdate({...meeting,type:e.target.value,agendaItems:buildBlankAgenda(e.target.value)});}}>
                  {MTG_TYPES.map(function(t){return <option key={t}>{t}</option>;})}
                </select>
              </div>
              <div><div className="flabel">Date</div><input className="finput" type="date" value={meeting.date||""} onChange={function(e){update("date",e.target.value);}}/></div>
              <div><div className="flabel">Time</div><input className="finput" type="time" value={meeting.time||""} onChange={function(e){update("time",e.target.value);}}/></div>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:16}}>
              <div><div className="flabel">Location / Link</div><input className="finput" value={meeting.location||""} onChange={function(e){update("location",e.target.value);}} placeholder="Job site, Zoom link, address..."/></div>
              <div><div className="flabel">Distribution <span style={{fontSize:9,color:"var(--muted)",fontFamily:"'IBM Plex Mono',monospace"}}>auto-built from attendees, editable</span></div><input className="finput" value={meeting.distribution||""} onChange={function(e){update("distribution",e.target.value);}} placeholder="Auto-populated from attendees..."/></div>
            </div>

            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8}}>
              <div style={{fontFamily:"'Barlow Condensed'",fontSize:12,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)"}}>Agenda Items</div>
              <button className="btn btn-ghost btn-sm" style={{fontSize:11}} onClick={addAgendaItem}>+ Add Item</button>
            </div>

            {(meeting.agendaItems||[]).sort(function(a,b){return a.order-b.order;}).map(function(item){
              return (
                <div key={item.id} style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:6,padding:10,marginBottom:8}}>
                  <div style={{display:"flex",alignItems:"flex-start",gap:8,marginBottom:6}}>
                    <div style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:12,color:"var(--muted)",padding:"6px 0",flexShrink:0}}>{item.order}.</div>
                    <input className="finput" value={item.topic} onChange={function(e){updateAgendaItem(item.id,"topic",e.target.value);}} placeholder="Agenda topic..." style={{fontWeight:600}}/>
                    {item.type==="custom" && (
                      <button className="btn btn-ghost btn-sm" style={{color:"var(--red)",flexShrink:0,fontSize:11}} onClick={function(){removeAgendaItem(item.id);}}>x</button>
                    )}
                  </div>
                  <textarea className="ftextarea" rows={2} value={item.notes||""} onChange={function(e){updateAgendaItem(item.id,"notes",e.target.value);}} placeholder="Notes and discussion for this item..." style={{fontSize:12}}/>
                </div>
              );
            })}
          </div>
        )}

        {tab==="attendees" && (
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
            <div>
              <div style={{fontFamily:"'Barlow Condensed'",fontSize:12,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:8}}>Added to Meeting</div>
              {(meeting.attendees||[]).length===0 && <div className="empty" style={{padding:20}}>No attendees yet. Add from directory.</div>}
              {(meeting.attendees||[]).map(function(a){
                return (
                  <div key={a.dirId} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 10px",background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:6,marginBottom:6}}>
                    <input type="checkbox" checked={!!a.attended} onChange={function(){toggleAttended(a.dirId);}} style={{accentColor:"var(--green)"}} title="Attended"/>
                    <div style={{flex:1}}>
                      <div style={{fontSize:13,color:"var(--white)"}}>{a.name}</div>
                      <div style={{fontSize:10,color:"var(--muted)"}}>{a.company}{a.role?" - "+a.role:""}</div>
                      {a.email && <div style={{fontSize:10,color:"var(--accent-bright)",fontFamily:"'IBM Plex Mono',monospace"}}>{a.email}</div>}
                    </div>
                    <span style={{fontSize:10,fontFamily:"'Barlow Condensed'",letterSpacing:.5,color:a.attended?"var(--green)":"var(--muted)"}}>{a.attended?"ATTENDED":"INVITED"}</span>
                    <button className="btn btn-ghost btn-sm" style={{color:"var(--red)",fontSize:11}} onClick={function(){removeAttendee(a.key||a.dirId);}}>x</button>
                  </div>
                );
              })}
            </div>
            <div>
              <div style={{fontFamily:"'Barlow Condensed'",fontSize:12,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:8}}>Add from Directory</div>
              <div style={{maxHeight:400,overflowY:"auto"}}>
                {directory.map(function(d){
                  var dContacts = d.contacts||[];
                  return (
                    <div key={d.id} style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:6,marginBottom:6,overflow:"hidden"}}>
                      <div style={{padding:"6px 10px",borderBottom:dContacts.length>0?"1px solid rgba(42,64,128,.2)":"none"}}>
                        <div style={{fontSize:12,color:"var(--white)",fontWeight:600}}>{d.company}</div>
                        <div style={{fontSize:10,color:"var(--muted)"}}>{d.trade}</div>
                      </div>
                      {dContacts.map(function(c){
                        var ckey=d.id+"_"+c.id;
                        var already=(meeting.attendees||[]).some(function(a){return a.key===ckey;});
                        return (
                          <div key={c.id} style={{display:"flex",alignItems:"center",gap:8,padding:"5px 10px 5px 14px",opacity:already?0.4:1}}>
                            <div style={{flex:1}}>
                              <div style={{fontSize:11,color:"var(--white)"}}>{c.name}{c.primary ? <span style={{fontSize:9,color:"var(--accent-bright)",marginLeft:4}}>PRIMARY</span> : null}</div>
                              {c.role && <div style={{fontSize:9,color:"var(--muted)"}}>{c.role}</div>}
                              <div style={{fontSize:9,color:"var(--accent-bright)",fontFamily:"'IBM Plex Mono',monospace"}}>{c.email}</div>
                            </div>
                            <button className="btn btn-ghost btn-sm" style={{fontSize:10,padding:"2px 8px"}} disabled={already}
                              onClick={function(){addAttendee(d,c);}}>{already?"Added":"+Add"}</button>
                          </div>
                        );
                      })}
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        )}

        {tab==="prep" && (
          <div>
            {aiError && <div style={{padding:"8px 12px",background:"rgba(248,113,113,.08)",border:"1px solid rgba(248,113,113,.3)",borderRadius:6,color:"var(--red)",fontSize:12,marginBottom:12}}>{aiError}</div>}
            {meeting.aiPrepDate && <div style={{fontSize:11,color:"var(--muted)",marginBottom:12}}>Last prep: {fmtDate(meeting.aiPrepDate)}</div>}
            {!meeting.aiPrepDate && <div style={{fontSize:12,color:"var(--muted)",marginBottom:12}}>Click "AI Prep Agenda" at the top to automatically populate this section.</div>}

            {meeting.progressSummary && (
              <div style={{marginBottom:16}}>
                <div style={{fontFamily:"'Barlow Condensed'",fontSize:12,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:6}}>Progress Summary</div>
                <textarea className="ftextarea" rows={6} value={meeting.progressSummary} onChange={function(e){update("progressSummary",e.target.value);}} style={{fontSize:12,lineHeight:1.6}}/>
              </div>
            )}

            {(meeting.delaysSinceLast||[]).length>0 && (
              <div style={{marginBottom:16}}>
                <div style={{fontFamily:"'Barlow Condensed'",fontSize:12,letterSpacing:2,textTransform:"uppercase",color:"var(--yellow)",marginBottom:6}}>Delays and Concerns</div>
                {meeting.delaysSinceLast.map(function(d,i){return <div key={i} style={{fontSize:12,color:"var(--white)",padding:"5px 10px",background:"rgba(251,191,36,.05)",border:"1px solid rgba(251,191,36,.15)",borderRadius:4,marginBottom:4}}>{d}</div>;})}
              </div>
            )}

            {(meeting.openRfis||[]).length>0 && (
              <div style={{marginBottom:16}}>
                <div style={{fontFamily:"'Barlow Condensed'",fontSize:12,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:6}}>Open RFIs ({meeting.openRfis.length})</div>
                <div style={{display:"flex",flexDirection:"column",gap:4}}>
                  {meeting.openRfis.map(function(r){
                    return (
                      <div key={r.number} style={{display:"flex",alignItems:"center",gap:10,padding:"6px 10px",background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:5}}>
                        <span style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:11,color:"var(--accent-bright)",flexShrink:0}}>{r.number}</span>
                        <span style={{fontSize:12,color:"var(--white)",flex:1}}>{r.title}</span>
                        <span style={{fontSize:10,fontFamily:"'Barlow Condensed'",letterSpacing:.5,color:"var(--yellow)"}}>{r.status}</span>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {(meeting.openPunches||[]).length>0 && (
              <div style={{marginBottom:16}}>
                <div style={{fontFamily:"'Barlow Condensed'",fontSize:12,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:6}}>Open Punch Items ({meeting.openPunches.length})</div>
                <div style={{display:"flex",flexDirection:"column",gap:4}}>
                  {meeting.openPunches.map(function(p){
                    var prioColor={Critical:"var(--red)",High:"var(--orange)",Medium:"var(--yellow)",Low:"var(--muted)"}[p.priority]||"var(--muted)";
                    return (
                      <div key={p.id} style={{display:"flex",alignItems:"center",gap:10,padding:"6px 10px",background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:5}}>
                        <span style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:11,color:"var(--muted)",flexShrink:0,minWidth:60}}>{p.category}</span>
                        <span style={{fontSize:12,color:"var(--white)",flex:1}}>{p.title}</span>
                        <span style={{fontSize:10,fontFamily:"'Barlow Condensed'",letterSpacing:.5,color:prioColor}}>{p.priority}</span>
                        <span style={{fontSize:10,fontFamily:"'Barlow Condensed'",letterSpacing:.5,color:"var(--yellow)"}}>{p.status}</span>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {(meeting.openSubmittals||[]).length>0 && (
              <div style={{marginBottom:16}}>
                <div style={{fontFamily:"'Barlow Condensed'",fontSize:12,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:6}}>Pending Submittals ({meeting.openSubmittals.length})</div>
                <div style={{display:"flex",flexDirection:"column",gap:4}}>
                  {meeting.openSubmittals.map(function(s){
                    return (
                      <div key={s.number} style={{display:"flex",alignItems:"center",gap:10,padding:"6px 10px",background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:5}}>
                        <span style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:11,color:"var(--accent-bright)",flexShrink:0}}>{s.number}</span>
                        <span style={{fontSize:12,color:"var(--white)",flex:1}}>{s.title}</span>
                        <span style={{fontSize:10,fontFamily:"'Barlow Condensed'",letterSpacing:.5,color:"var(--yellow)"}}>{s.status}</span>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {(meeting.lookahead||[]).length>0 && (
              <div style={{marginBottom:16}}>
                <div style={{fontFamily:"'Barlow Condensed'",fontSize:12,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:6}}>3-Week Look-Ahead</div>
                <div style={{display:"flex",flexDirection:"column",gap:3}}>
                  {meeting.lookahead.map(function(a){
                    return (
                      <div key={a.id} style={{display:"flex",alignItems:"center",gap:10,padding:"5px 10px",background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:4}}>
                        <span style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:10,color:"var(--muted)",flexShrink:0,minWidth:120}}>{fmtDate(a.startDate)}</span>
                        <span style={{fontSize:12,color:"var(--white)",flex:1}}>{a.name}</span>
                        <span style={{fontSize:10,color:"var(--muted)"}}>{a.percentComplete}%</span>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}
          </div>
        )}

        {tab==="actions" && (
          <div>
            <div style={{display:"flex",justifyContent:"flex-end",marginBottom:10}}>
              <button className="btn btn-primary btn-sm" onClick={addActionItem}>+ Add Action Item</button>
            </div>
            {(meeting.actionItems||[]).length===0 && <div className="empty" style={{padding:32}}>No action items yet.</div>}
            {(meeting.actionItems||[]).map(function(a){
              var stColor = a.status==="Closed"?"var(--green)":a.status==="In Progress"?"var(--yellow)":"var(--red)";
              return (
                <div key={a.id} style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:6,padding:10,marginBottom:8,opacity:a.status==="Closed"?0.6:1}}>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 140px 140px 100px auto",gap:8,alignItems:"center"}}>
                    <input className="finput" value={a.description} onChange={function(e){updateAction(a.id,"description",e.target.value);}} placeholder="Action item description..."/>
                    <input className="finput" value={a.owner||""} onChange={function(e){updateAction(a.id,"owner",e.target.value);}} placeholder="Owner"/>
                    <input className="finput" type="date" value={a.dueDate||""} onChange={function(e){updateAction(a.id,"dueDate",e.target.value);}}/>
                    <select className="fselect" value={a.status} style={{color:stColor}} onChange={function(e){updateAction(a.id,"status",e.target.value);}}>
                      {AI_ITEM_STATUSES.map(function(s){return <option key={s}>{s}</option>;})}
                    </select>
                    <button className="btn btn-ghost btn-sm" style={{color:"var(--red)",fontSize:11}} onClick={function(){removeAction(a.id);}}>x</button>
                  </div>
                </div>
              );
            })}
          </div>
        )}

        {tab==="notes" && (
          <div>
            <div className="flabel" style={{marginBottom:6}}>General Meeting Notes</div>
            <textarea className="ftextarea" rows={14} value={meeting.notes||""} onChange={function(e){update("notes",e.target.value);}} placeholder="General notes, decisions made, discussion points not covered in agenda items..."/>
          </div>
        )}

        {tab==="minutes" && (
          <div>
            <div style={{display:"flex",justifyContent:"flex-end",marginBottom:10}}>
              <button className="btn btn-primary btn-sm" style={{color:copied?"var(--green)":"var(--white)"}} onClick={copyMinutes}>
                {copied?"Copied to Clipboard!":"Copy Full Minutes"}
              </button>
            </div>
            <pre style={{fontFamily:"'IBM Plex Mono',monospace",fontSize:11,color:"var(--white)",lineHeight:1.7,background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:16,whiteSpace:"pre-wrap",overflowY:"auto"}}>
              {buildMeetingMinutes(meeting, job)}
            </pre>
          </div>
        )}

      </div>
    </div>
  );
};

// --- MEETINGS LIST ------------------------------------------------------------
const MeetingsTool = ({job, meetings, onAdd, onUpdate, directory, allRfis, allSubmittals, allPunches, allActivities, phases, allLogs}) => {
  var [selId, setSelId] = useState(null);
  var [showNew, setShowNew] = useState(false);
  var [newType, setNewType] = useState("OAC");

  var jobMeetings = meetings.filter(function(m){return m.jobId===job.id;})
    .sort(function(a,b){return b.date.localeCompare(a.date);});

  var sel = jobMeetings.find(function(m){return m.id===selId;});

  var createMeeting = function() {
    var priorMtgs = jobMeetings.filter(function(m){return m.type===newType;});
    var prior = priorMtgs.length>0 ? priorMtgs[0] : null;
    var num   = priorMtgs.length + 1;

    // Roll over action items from prior meeting (open/in progress only)
    var rolledActions = prior ? (prior.actionItems||[]).filter(function(a){return a.status!=="Closed";}).map(function(a){return {...a, id:"act"+uid()};}) : [];

    // Roll over agenda item notes from prior (standing items)
    var agendaBase = buildBlankAgenda(newType);
    if(prior){
      agendaBase = agendaBase.map(function(item){
        var match = (prior.agendaItems||[]).find(function(p){return p.topic===item.topic;});
        return match ? {...item, notes:match.notes} : item;
      });
    }

    var newMtg = {
      id:"mtg"+uid(), jobId:job.id, type:newType, number:num,
      date:TODAY, time:"", location:"", status:"Draft",
      attendees: prior ? (prior.attendees||[]).map(function(a){return {...a, attended:false};}) : [],
      agendaItems: agendaBase,
      actionItems: rolledActions,
      progressSummary:"", delaysSinceLast:[], openRfis:[], openSubmittals:[], lookahead:[],
      notes:"", distributedDate:"", aiPrepDate:null, priorMeetingId:prior?prior.id:null,
    };
    onAdd(newMtg);
    setSelId(newMtg.id);
    setShowNew(false);
  };

  if(sel) {
    return (
      <MeetingEditor
        meeting={sel} job={job} directory={directory}
        allRfis={allRfis} allSubmittals={allSubmittals} allPunches={allPunches||[]}
        allActivities={allActivities} phases={phases} allLogs={allLogs}
        onUpdate={function(updated){onUpdate(updated);}}
        onBack={function(){setSelId(null);}}
      />
    );
  }

  return (
    <div>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:16}}>
        <div>
          <div style={{fontFamily:"'Barlow Condensed'",fontSize:18,fontWeight:700,color:"var(--white)",marginBottom:2}}>Meetings</div>
          <div style={{fontSize:11,color:"var(--muted)"}}>{job.name} - {job.client}</div>
        </div>
        <div style={{display:"flex",gap:8,alignItems:"center"}}>
          {showNew && (
            <select className="fselect" value={newType} onChange={function(e){setNewType(e.target.value);}} style={{fontSize:12}}>
              {MTG_TYPES.map(function(t){return <option key={t}>{t}</option>;})}
            </select>
          )}
          <button className="btn btn-primary btn-sm" onClick={function(){
            if(showNew){createMeeting();} else {setShowNew(true);}
          }}>
            {showNew ? "Create Meeting" : "+ New Meeting"}
          </button>
          {showNew && <button className="btn btn-ghost btn-sm" onClick={function(){setShowNew(false);}}>Cancel</button>}
        </div>
      </div>

      {jobMeetings.length===0 ? (
        <div className="empty" style={{padding:48,textAlign:"center"}}>
          <div style={{fontFamily:"'Barlow Condensed'",fontSize:14,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:6}}>No Meetings Yet</div>
          <div style={{fontSize:12,color:"var(--muted)"}}>Create your first OAC or subcontractor meeting to get started.</div>
        </div>
      ) : (
        <div>
          {["OAC","Sub Coordination","Owner","Internal"].map(function(type){
            var typeMtgs = jobMeetings.filter(function(m){return m.type===type;});
            if(typeMtgs.length===0) return null;
            return (
              <div key={type} style={{marginBottom:20}}>
                <div style={{fontFamily:"'Barlow Condensed'",fontSize:12,letterSpacing:2,textTransform:"uppercase",color:"var(--muted)",marginBottom:8,paddingBottom:4,borderBottom:"1px solid var(--navy-border)"}}>{type} Meetings</div>
                {typeMtgs.map(function(m){
                  var attCt  = (m.attendees||[]).filter(function(a){return a.attended;}).length;
                  var actCt  = (m.actionItems||[]).filter(function(a){return a.status!=="Closed";}).length;
                  var stColor = m.status==="Distributed"?"var(--green)":"var(--yellow)";
                  return (
                    <div key={m.id} onClick={function(){setSelId(m.id);}}
                      style={{background:"var(--navy)",border:"1px solid var(--navy-border)",borderRadius:8,padding:"12px 14px",marginBottom:8,cursor:"pointer"}}>
                      <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between"}}>
                        <div>
                          <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:4}}>
                            <span style={{fontFamily:"'Barlow Condensed'",fontSize:15,fontWeight:700,color:"var(--white)"}}>Meeting No. {m.number}</span>
                            <span style={{fontSize:10,fontFamily:"'Barlow Condensed'",letterSpacing:.5,color:stColor,border:"1px solid "+stColor+"44",borderRadius:3,padding:"1px 6px"}}>{(m.status||"Draft").toUpperCase()}</span>
                          </div>
                          <div style={{fontSize:12,color:"var(--muted)"}}>{fmtDate(m.date)}{m.time?" at "+m.time:""}{m.location?" - "+m.location:""}</div>
                        </div>
                        <div style={{display:"flex",gap:16,fontSize:11,color:"var(--muted)"}}>
                          {attCt>0 && <span style={{color:"var(--accent-bright)"}}>{attCt} attended</span>}
                          {actCt>0 && <span style={{color:"var(--yellow)"}}>{actCt} open actions</span>}
                          {m.aiPrepDate && <span style={{color:"var(--purple)"}}>AI prepped</span>}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

