  const doLogin = async function(email, password, allowedRoles, portalLabel){
    setAuthErr(""); setAuthInfo("");
    const { data, error } = await supabase.auth.signInWithPassword({ email: email.trim(), password });
    if(error){ setAuthErr(error.message); return; }
    const { data: profile, error: perr } = await supabase.from("profiles").select("*").eq("id", data.user.id).single();
    if(perr || !profile){
      setAuthErr("Signed in, but no profile was found for this account. Contact your admin.");
      await supabase.auth.signOut();
      return;
    }
    if(!allowedRoles.includes(profile.role)){
      setAuthErr("This account isn't set up for "+portalLabel+". Try the other sign-in tab.");
      await supabase.auth.signOut();
      return;
    }
    // onAuthStateChange listener picks up the session and sets currentUser
  };

  const doCreateCompany = async function(name, email, password, company){
    setAuthErr(""); setAuthInfo("");
    if(!name||!email||!password||password.length<8){
      setAuthErr("Please fill out every field. Password needs 8+ characters.");
      return;
    }
    const { data, error } = await supabase.auth.signUp({
      email: email.trim(), password,
      options: { data: { name: name, role: ROLES.ADMIN, company: company } }
    });
    if(error){ setAuthErr(error.message); return; }
    if(!data.session){
      setAuthInfo("Account created — check your email to confirm it, then sign in.");
      setAuthView("crew");
      return;
    }
    // Session exists immediately (email confirmations off) — onAuthStateChange handles the rest
  };

